INSERT INTO cars VALUES(3,'BMW','M3','E46',2000,2006,'00s','coupe','Germany',85742,'The E46 M3 remains the gold standard for naturally aspirated BMW motorsport heritage. Its S54 engine revs to 8000 RPM and produces 360 HP in stock form. Final M3 with a manual as factory option.','[]','2026-05-24 23:00:45.921242','warm','M3','Standard');
INSERT INTO cars VALUES(4,'Toyota','Supra','A80',1993,1998,'90s','coupe','Japan',14079,'The legendary A80 Supra with its 2JZ-GTE engine - arguably the most robust production engine ever made. 326 HP from the factory (JDM) but famously capable of handling 1000+ HP on stock bottom end. The ultimate JDM cruiser.','[]','2026-05-24 23:00:45.923109','hot','Supra','RZ');
INSERT INTO cars VALUES(5,'Ferrari','F355','F355',1994,1999,'90s','coupe','Italy',11084,'The F355 represents the end of the analog Ferrari era before electronics took over. Its 3.5L V8 built 380 HP and screamed to 8250 RPM. Fabulous gated shifter and pininfarina perfection.','[]','2026-05-24 23:00:45.923720','hot','F355','Berlinetta');
INSERT INTO cars VALUES(6,'Honda','S2000','AP1',2000,2009,'00s','roadster','Japan',66012,'Honda engineering at its finest - the AP1 S2000 revs to 9000 RPM with the F20C producing 240 HP from 2.0 liters. The ultimate front-midship roadster with razor-sharp handling and zero assistance.','[]','2026-05-24 23:00:45.924233','warm','S2000','AP1');
INSERT INTO cars VALUES(7,'Mercedes-Benz','500E','W124',1990,1995,'90s','sedan','Germany',142240,'The W140 S-Class was Mercedes maximum expression of excess - wider longer and heavier than necessary. The 500E variant packed a 5.0L V8 producing 322 HP with a surprising 0-60 of 5.0 seconds. Famously overbuilt.','[]','2026-05-24 23:00:45.924638','luxury','500E','500E');
