INSERT INTO cars VALUES(37,'BMW','3 Series','E90',2007,2011,'00s','sedan','Germany',NULL,'BMW 328i E90 with the N52B30 naturally aspirated 3.0L inline-6. The last naturally aspirated I6 BMW ever produced 窶・after this, every BMW I6 was turbocharged (N54, N55, B58). Magnesium/aluminum composite block, Valvetronic variable valve lift, 230hp. Available with 6-speed manual. The thesis: last analog BMW driver experience.','[]','2026-05-30 22:55:53.546862','warm','3 Series','328i 6MT N52');
