INSERT INTO cars VALUES(42,'Mercedes-Benz','S-Class','W222',2014,2017,'10s','sedan','Germany',NULL,'W222 S-Class pre-facelift (2014-2017) with M278 4.7L twin-turbo V8 (449hp/516lb-ft). 7G-Tronic transmission. NTG5 COMAND. AIRMATIC standard, Magic Body Control optional. Known issues: cam sensor oil wicking to ECU (#1 killer,  pigtail fix prevents + ECU death), oil cooler leaks, direct injection carbon buildup (walnut blast ~60K mi), Airmatic struts at 80K+. Aluminum hybrid body requires certified collision repair (~10 shops in USA).','[]','2026-05-30 22:55:53.573565','luxury','S-Class','S550 M278 pre-facelift');
