INSERT INTO cars VALUES(89,'Mazda','RX-7','FD3S',1992,2002,'90s','coupe','Japan',NULL,'The third-generation RX-7. Twin-turbo 13B-REW rotary, 255 hp. The definitive 90s Japanese sports car. Pop-up headlights, sequential turbos, and a 8000-rpm redline that defined an era.',NULL,'2026-06-03 00:00:00.000000','classic','RX-7','Twin Turbo');
INSERT INTO cars VALUES(90,'Mazda','RX-8','SE3P',2003,2012,'00s','coupe','Japan',NULL,'Renesis 13B-MSP naturally aspirated rotary, 232 hp. The four-seat sports car with suicide rear doors. Apex of Mazda''s rotary era before the Wankel''s emissions killed it.',NULL,'2026-06-03 00:00:00.000000','warm','RX-8','R3 (high-power)');
INSERT INTO cars VALUES(91,'Mazda','Mazda6','GJ',2014,2021,'10s','sedan','Japan',NULL,'The Skyactiv era mid-size sedan. 2.5L naturally aspirated I4, 184 hp. The closest thing to a European driving feel in a Japanese mid-sizer. Killed off in 2021 with no direct successor.',NULL,'2026-06-03 00:00:00.000000','warm','Mazda6','2.5L Skyactiv-G Touring');
INSERT INTO cars VALUES(92,'Mazda','CX-5','KF',2017,2023,'10s','SUV','Japan',NULL,'The crossover that broke Mazda''s design reputation. Skyactiv 2.5T (227 hp on premium). Often called "the driver''s crossover" ??closest thing to a sedan in SUV clothing.',NULL,'2026-06-03 00:00:00.000000','warm','CX-5','2.5T AWD');
INSERT INTO cars VALUES(93,'Subaru','WRX','VA',2015,2021,'10s','sedan','Japan',NULL,'FA20 2.0L turbo flat-4, 268 hp. The everyman AWD sport sedan. 6-spd manual or CVT. The successor to the GD WRX that made Subaru a tuner icon.',NULL,'2026-06-03 00:00:00.000000','hot','WRX','WRX Premium');
INSERT INTO cars VALUES(94,'Subaru','WRX STI','VA',2015,2021,'10s','sedan','Japan',NULL,'EJ257 2.5L turbo flat-4, 305 hp. Driver''s Controlled Center Differential (DCCD), Brembo brakes, 6-spd manual only. The last great rally-bred sedan before Subaru moved to the FA24.',NULL,'2026-06-03 00:00:00.000000','hot','WRX','STI Limited');
INSERT INTO cars VALUES(95,'Subaru','WRX','VB',2022,NULL,'modern','sedan','Japan',NULL,'FA24 2.4L turbo flat-4, 271 hp. The redesigned WRX with controversial new styling. More torque, more refinement, still 6-spd manual in the base.',NULL,'2026-06-03 00:00:00.000000','hot','WRX','WRX Premium');
INSERT INTO cars VALUES(96,'Volkswagen','Arteon','3H',2019,2024,'10s','four-door coupe','Germany',NULL,'The sleek fastback sedan that replaced the CC. EA888 2.0L turbo, 268 hp, 8-spd auto, 4Motion AWD. The understated Euro GT alternative to the A5 Sportback.',NULL,'2026-06-03 00:00:00.000000','warm','Arteon','2.0T SEL R-Line 4Motion');
INSERT INTO cars VALUES(97,'Toyota','GR Corolla','E210',2023,NULL,'modern','hatchback','Japan',NULL,'The Toyota Gazoo Racing hot hatch. 1.6L G16E-GTS 3-cylinder turbo, 300 hp, GR-Four AWD, 6-spd manual. The modern spiritual successor to the Lancia Delta Integrale. AWD, manual, 3-cyl ??pure enthusiast machine.',NULL,'2026-06-03 00:00:00.000000','hot','GR Corolla','GR Corolla Circuit Edition');
INSERT INTO cars VALUES(98,'Volvo','V60 Polestar','first',2014,2018,'10s','wagon','Sweden',NULL,'The twin-charged (supercharger + turbo) sleeper wagon. 2.0L B4204T43 I4, 367 hp, 8-spd auto, AWD. Iconic blue/gold paint. Limited US production (~1500/yr). The anti-everyone wagon.',NULL,'2026-06-03 00:00:00.000000','hot','V60','Polestar');
INSERT INTO cars VALUES(99,'Acura','Integra Type S','DE4',2024,NULL,'modern','liftback','Japan',NULL,'The Integra returns as a 4-door liftback with the Civic Type R K20C1 turbo (320 hp), 6-spd manual only, FWD with helical LSD. The anti-M340i for purists.',NULL,'2026-06-03 00:00:00.000000','hot','Integra','Type S');
INSERT INTO cars VALUES(100,'Cadillac','CT5-V Blackwing','first',2022,NULL,'modern','sedan','USA',NULL,'The 6.2L LT4 supercharged V8, 668 hp, 6-spd manual, RWD. The American M5. Magnetic Ride, Brembo brakes, carbon fiber options. The last great American super sedan before electrification.',NULL,'2026-06-03 00:00:00.000000','hyper','CT5','Blackwing');
INSERT INTO cars VALUES(101,'Audi','TT','8S',2014,2023,'10s','coupe','Germany',NULL,'The third-generation TT. 2.0L TFSI turbo I4 (220 hp), 7-spd S-tronic, FWD or quattro AWD. Light (~1330 kg), balanced, the "no-prestige" German coupe. The sleeper everyone forgot.',NULL,'2026-06-03 00:00:00.000000','warm','TT','45 TFSI');
INSERT INTO cars VALUES(102,'Mitsubishi','Lancer Evolution IX','CT9A',2005,2007,'00s','sedan','Japan',NULL,'The 4G63 turbo rally sedan. 2.0L turbo I4, 286 hp, twin-scroll turbo, 5-spd manual, AWD with ACD/AYC/Super AYC. The WRC homologation hero. The WRX STI''s only real rival from the era. Last of the 4G63 Evos.',NULL,'2026-06-03 00:00:00.000000','hot','Lancer Evolution','Evo IX MR');
INSERT INTO cars VALUES(103,'Honda','Civic Type R','EK9 (first gen)',1997,2000,'90s','hatchback','Japan',NULL,'The original JDM Civic Type R. B16B 1.6L VTEC, 185 hp at 8,200 rpm. The car that defined the hot hatch. JDM-only ??never officially sold in the US. Cult collector.',NULL,'2026-06-03 00:00:00.000000','classic','Civic','Type R (JDM only)');
INSERT INTO cars VALUES(104,'Porsche','718 Cayman','982 (third gen)',2016,NULL,'10s','coupe','Germany',NULL,'The mid-engine Porsche. 2.0L flat-4 turbo (300 hp base) or 2.5L in the S. The enthusiasts'' pick ??better balance than the 911, 6-spd manual available, mid-engine dynamics. The "real Porsche" per purists.',NULL,'2026-06-03 00:00:00.000000','warm','Cayman','718 Cayman (base)');
INSERT INTO cars VALUES(105,'Chevrolet','Corvette','C7 Z06',2015,2019,'10s','coupe','USA',NULL,'The American supercar value. 6.2L LT4 supercharged V8, 650 hp, 650 lb-ft. 0-60 in 2.95s. Originally stickered ~$80K, now $55-75K used. Carbon fiber everywhere, Brembo brakes, magnetic ride.',NULL,'2026-06-03 00:00:00.000000','hyper','Corvette','Z06');
INSERT INTO cars VALUES(106,'BMW','M3','E30 (first gen)',1986,1991,'80s','coupe','Germany',NULL,'The analog M3. S14 2.3L I4 (or 2.5L in late models), 195-215 hp, 5-spd Getrag manual, RWD. The "before M went big" M. The car that defines what an M3 is supposed to be. Rising collector market.',NULL,'2026-06-03 00:00:00.000000','classic','M3','E30 M3');
INSERT INTO cars VALUES(107,'Ford','Fiesta ST','Mk7 (sixth gen)',2014,2019,'10s','hatchback','USA',NULL,'The cheap hot hatch. 1.6L EcoBoost turbo I4, 197 hp, 6-spd manual, FWD. Curb weight 1,160 kg. The enthusiast''s first step. Under $15K used. The "we can''t afford a GTI yet" car.',NULL,'2026-06-03 00:00:00.000000','warm','Fiesta','ST');
INSERT INTO cars VALUES(108,'Toyota','AE86','E80 (4th gen Corolla)',1983,1987,'80s','coupe','Japan',NULL,'The Drift King. 1.6L 4A-GE, 128 hp, RWD, ~950 kg. The lightweight rear-drive Corolla that defined the JDM tuner era. Cheap, fragile, and eternal. The Initial D car.',NULL,'2026-06-03 00:00:00.000000','classic','Corolla','Sprinter Trueno GT-APEX');
INSERT INTO cars VALUES(109,'Mazda','RX-7','FD3S Spirit R',2002,2002,'00s','coupe','Japan',NULL,'The ultimate RX-7. 1.3L 13B-REW twin-turbo, 280 hp ??the highest-output FD ever. Bilstein shocks, Recaro seats, limited production. The collector''s RX-7.',NULL,'2026-06-03 00:00:00.000000','classic','RX-7','Spirit R Type RS');
INSERT INTO cars VALUES(110,'Nissan','300ZX','Z32 Twin Turbo',1990,1996,'90s','coupe','Japan',NULL,'The 90s JDM supercar. 3.0L VG30DETT twin-turbo V6, 300 hp, 4WS (4-wheel steering). The car that was faster than the contemporary 911 in some tests. Twin-turbo, V6, 4WS, supercar tech in 1990.',NULL,'2026-06-03 00:00:00.000000','hot','Z','Twin Turbo 2+2');
INSERT INTO cars VALUES(111,'Nissan','Silvia','S15 Spec-R',1999,2002,'90s','coupe','Japan',NULL,'The JDM drift legend. 2.0L SR20DET turbo I4, 250 hp (Spec-R), RWD, 6-spd manual, factory turbo. The last Silvia sold new. Rising collector market in US via 25-year import rule.',NULL,'2026-06-03 00:00:00.000000','classic','Silvia','Spec-R');
INSERT INTO cars VALUES(112,'Ford','Mustang Shelby GT350','S550 (sixth gen)',2015,2020,'10s','coupe','USA',NULL,'The flat-plane-crank Mustang. 5.2L Voodoo V8, 526 hp, 8,250 rpm redline. The most driver-focused Mustang of the modern era. Track-bred from the factory. The Mustang that finally beat the Camaro ZL1 on track.',NULL,'2026-06-03 00:00:00.000000','hot','Mustang','GT350');
INSERT INTO cars VALUES(113,'Acura','NSX','NA1 (first gen)',1990,2005,'90s','coupe','Japan',NULL,'The Honda supercar. 3.0L C30A V6 VTEC, 270 hp, mid-engine, manual. Ayrton Senna helped develop the chassis. Aluminum monocoque. The everyday supercar that defined 1990s Japan.',NULL,'2026-06-03 00:00:00.000000','classic','NSX','NSX (NA1)');
INSERT INTO cars VALUES(114,'Audi','RS6 Avant','C5 (first gen)',2002,2004,'00s','wagon','Germany',NULL,'The sleeper wagon. 4.2L 40V V8 twin-turbo, **450 hp**, AWD, 0-60 in 4.5s. The wagon that outran contemporary M5s. The original "don''t mess with that station wagon".',NULL,'2026-06-03 00:00:00.000000','hot','RS6','RS6 Avant (4.2 V8 twin-turbo)');
INSERT INTO cars VALUES(115,'Hyundai','Ioniq 5 N','first',2023,NULL,'modern','hatchback','South Korea',NULL,'The first real hot EV. 84 kWh battery, dual motor, **641 hp**, 0-60 in 3.0s. Simulated gear shifts via motors, fake engine noise, drift mode. The car that proves EVs can be enthusiast machines.',NULL,'2026-06-03 00:00:00.000000','hot','Ioniq','Ioniq 5 N');
INSERT INTO cars VALUES(116,'Lamborghini','Hurac??n','LB 724 (first gen)',2014,2024,'10s','coupe','Italy',NULL,'The Italian V10 supercar. 5.2L naturally aspirated V10, 571 hp, 7-spd LDF DCT, RWD (LP 580-2). The Aventador''s little sister. The last great NA V10 supercar before Lamborghini goes hybrid.',NULL,'2026-06-03 00:00:00.000000','hyper','Huracan','LP 580-2');
INSERT INTO cars VALUES(117,'Mercedes-AMG','C63 S','W206 (fifth gen)',2023,NULL,'modern','sedan','Germany',NULL,'The controversial new C63 S E-Performance. 2.0L M139 turbo I4 + electric motor (F1-derived), **671 hp combined**, 1020 Nm. The smallest engine ever in a C63. AMG purists revolted, but the numbers are wild.',NULL,'2026-06-03 00:00:00.000000','hot','C-Class','C63 S E-Performance');
INSERT INTO cars VALUES(118,'Toyota','Supra','A90 (fifth gen)',2019,NULL,'10s','coupe','Japan',NULL,'The new Supra (A90). 3.0L B58 twin-turbo I6, 382 hp, 6-spd manual (2023+) or 8-spd auto. RWD. Co-developed with BMW Z4. The "modern 2JZ" that everyone wanted to hate but actually delivered. First new-gen Supra in the DB.',NULL,'2026-06-03 00:00:00.000000','hot','Supra','GR Supra 3.0 Premium');
INSERT INTO cars VALUES(119,'Honda','Civic Type R','FL5 (sixth gen)',2023,NULL,'modern','hatchback','Japan',NULL,'The new Civic Type R (FL5). 2.0L K20C1 VTEC turbo, 315 hp, 6-spd manual only, FWD with helical LSD. The best FWD car ever made. The hot hatch benchmark. First FL5 in the DB.',NULL,'2026-06-03 00:00:00.000000','hot','Civic','FL5');
INSERT INTO cars VALUES(120,'BMW','M5','F90 (sixth gen)',2018,2024,'10s','sedan','Germany',NULL,'The modern M5. 4.4L S63 twin-turbo V8, 617 hp (Competition), 8-spd M Steptronic, M xDrive AWD with 2WD mode. 0-60 in 3.2s. The super sedan that outruns supercars. Originally $111K, now $70-90K used.',NULL,'2026-06-03 00:00:00.000000','hyper','M5','M5 Competition');
INSERT INTO cars VALUES(121,'Nissan','GT-R','R35',2009,NULL,'00s','coupe','Japan',NULL,'The R35 GT-R (2009+). 3.8L VR38DETT twin-turbo V6, 565 hp, 6-spd DCT, ATTESA E-TS AWD. The "Godzilla". 0-60 in 2.7s (Nismo 2017+). The supercar that costs $80K new. The longest-lived GT-R ever (2009-present).',NULL,'2026-06-03 00:00:00.000000','hyper','GT-R','GT-R Premium');
INSERT INTO cars VALUES(122,'Mercedes-Benz','EQS','V297 (first gen)',2022,NULL,'modern','sedan','Germany',NULL,'The S-Class of EVs. 108.4 kWh battery, dual motor, 516 hp, AWD. 0-60 in 4.3s. 350+ mile EPA range. Originally $102K, now $45-70K used. The biggest depreciation story in the luxury EV market ??Mercedes couldn''t move them new, so the used market is flooded. The "anti-Tesla" value play.',NULL,'2026-06-03 00:00:00.000000','luxury','EQS','EQS 580 4MATIC');
INSERT INTO cars VALUES(123,'BMW','iX','iX (first gen)',2022,NULL,'modern','SUV','Germany',NULL,'The electric X5. 76.6 or 111.5 kWh battery, 516 hp (xDrive50) or 610 hp (M60). AWD. 0-60 in 4.0s (xDrive50) / 3.6s (M60). 324 mi range. Originally $84K-$109K, now $50-75K. Polarizing design, but the interior and tech are class-leading.',NULL,'2026-06-03 00:00:00.000000','luxury','iX','iX xDrive50');
INSERT INTO cars VALUES(124,'Lucid','Air','first',2022,NULL,'modern','sedan','USA',NULL,'The 500+ mile EV. 92 kWh or 112 kWh battery, dual motor. Touring: 620 hp AWD. Grand Touring: 819 hp AWD. Sapphire: 1,234 hp. 0-60: 3.4s (GT) / 1.89s (Sapphire). 425-516 mi EPA range. Originally $78K-$249K, now $45-80K used for Touring/GT. The "Tesla killer" that depreciated anyway.',NULL,'2026-06-03 00:00:00.000000','luxury','Air','Air Touring');
INSERT INTO cars VALUES(125,'Audi','e-tron GT','X prototype derivative',2022,NULL,'modern','sedan','Germany',NULL,'The Taycan twin under different clothing. 93.4 kWh battery, dual motor, 469 hp (boost 522 hp), 2-speed rear auto, AWD. 0-60: 3.9s. RS version: 590 hp (boost 637 hp), 3.1s. Originally $103K-$144K, now $60-100K used. The understated Porsche alternative.',NULL,'2026-06-03 00:00:00.000000','hot','e-tron GT','e-tron GT quattro');
INSERT INTO cars VALUES(126,'Dodge','Charger','Charger SRT Hellcat',2021,NULL,'modern','sedan','USA',NULL,NULL,NULL,'2026-06-05 00:00:00','muscle',NULL,'SRT Hellcat');
INSERT INTO cars VALUES(127,'Dodge','Challenger','Challenger R/T Scat Pack',2021,NULL,'modern','coupe','USA',NULL,NULL,NULL,'2026-06-05 00:00:00','muscle',NULL,'R/T Scat Pack');
INSERT INTO cars VALUES(128,'Ford','Mustang','Mustang Ecoboost Premium',2024,NULL,'modern','coupe','USA',NULL,NULL,NULL,'2026-06-05 00:00:00','muscle',NULL,'Ecoboost Premium');
INSERT INTO cars VALUES(129,'Ford','Mustang','Mustang GT Premium',2024,NULL,'modern','coupe','USA',NULL,NULL,NULL,'2026-06-05 00:00:00','muscle',NULL,'GT Premium');
