INSERT INTO cars VALUES(163,'Genesis','G80','1st gen (DH)',2017,2020,'10s','sedan','South Korea',NULL,'G80 with Hyundai Tau 5.0 V8 窶・port-injected NA V8, Wards 10 Best engine. Same engine as G90 5.0 in lighter body. Rare: most G80s sold with 3.8L V6 or 3.3T V6.','[]','2026-06-08 20:54:42','luxury','Tau','G80 5.0 V8');
INSERT INTO cars VALUES(164,'BMW','7 Series','G11/G12',2017,2019,'10s','sedan','Germany',NULL,'BMW 740i G11 pre-LCI with B58 Gen1 3.0L turbo I6. Flagship luxury sedan with Carbon Core CFRP construction. RWD standard, xDrive optional. Avoids B58TU oil pump issue. C&D 40K mile test: zero unscheduled repairs, 26 mpg observed.','[]','2026-06-10 23:13:25','premium','7 Series','740i B58');
