INSERT INTO cars VALUES(181,'Mercedes-Benz','S-Class','W222',2018,2020,'10s','sedan','Germany',NULL,'W222 S-Class facelift (2018-2020) S560 with M176 4.0L twin-turbo V8 (463hp/516lb-ft). Hot-V turbo layout. 9G-Tronic transmission. NTG6 COMAND with CarPlay/Android Auto. AIRMATIC standard, improved Magic Body Control optional. 6000+ components redesigned in facelift. Known issues: P06DA00 oil pump solenoid (.5-9.5K on 4MATIC, engine+trans removal), cylinder deactivation lifter failures, hot-V turbo oil seal degradation, valve cover gasket requires front-end removal.','[]','2026-06-15 23:38:39','luxury','S-Class','S560 M176 facelift');
