INSERT INTO reliability VALUES(1,2,'sample',68.0,'{"IMS bearing": 3, "bore scoring": 2, "RMS leak": 2}',2000.0,2,'Good (specialist tons)','Difficult (rear engine)','{"IMS bearing failure": "Less common on turbo engines but still a risk. Carry spare.", "bore scoring": "Monitor oil temp and consumption. More common on track cars.", "996 Turbo": "Generally more robust than NA 996. M96.70 has reinforced block."}',NULL,68.0,82.0,78.0,58.0,50.0,NULL);
INSERT INTO reliability VALUES(2,3,'sample',72.0,'{"VANOS failure": 4, "subframe cracks": 3, "rod bearings": 3, "rear subframe bushings": 2}',2500.0,3,'Good (BMW parts)','Moderate (engine bay tight)','{"VANOS codes": "Inspect at 80k mi. S54 VANOS rebuild $2-3K.", "subframe plate cracking": "Race cars mostly. Weld-in reinforcement plates available.", "rod bearings": "BMW recall/extended warranty. Replace with BE bearings preventatively."}',NULL,70.0,82.0,62.0,75.0,67.0,NULL);
INSERT INTO reliability VALUES(3,4,'sample',88.0,'{"boost leaks": 2, "fuel pump": 2}',850.0,1,'Good (Toyota + afrmarket)','Moderate (turbo access)','{"2JZ-GTE nearly indestructible": "Check ancillary systems \u2014 fuel pump, boost controller, VVTi solenoid.", "Getrag V160": "Very strong transmission. Dual-mass flywheel can fail at high mileage.", "supra tax": "Parts prices inflated by JDM tax but mechanically excellent."}',NULL,92.0,90.0,82.0,78.0,92.0,NULL);
INSERT INTO reliability VALUES(4,5,'sample',62.0,'{"timing belt tensioner": 4, "water pump": 3, "valve guides": 3, "exhaust manifold cracks": 2}',1500.0,2,'Moderate (Ferrari specialist)','Difficult (mid-rear engine)','{"timing belt tensioner failure": "Replace at 15k mi or 5 years. Engine-out service $5-10K.", "water pump": "Replace with metal OEM impeller.", "valve guides": "Exhaust valve guides wear prematurely. Full rebuild indicator."}',NULL,58.0,78.0,62.0,58.0,50.0,NULL);
INSERT INTO reliability VALUES(5,6,'sample',78.0,'{"clutch fan": 2, "hardtop recall": 1, "AP1 rear suspension twitchiness": 2}',1100.0,1,'Good (Honda + aftermarket)','Moderate (F20C accessible)','{"clutch fan": "Replace at 50k mi preventatively.", "AP1 suspension": "Aggressive rear geometry causes snap oversteer. AP2 geometry retrofit common.", "F20C": "Largest displacement per liter of any production car at 120 hp/L. Robust."}',NULL,83.0,86.0,72.0,76.0,67.0,NULL);
INSERT INTO reliability VALUES(6,7,'sample',75.0,'{"brake vacuum booster": 3, "level regulation": 3}',1300.0,2,'Good (Mercedes specialist)','Difficult (wide hood)','{"brake booster cracking": "Common on high-mile W124s.", "500E specific": "Hand-assembled by Porsche at Zuffenhausen. Wider fenders, different suspension.", "parts cost": "Porsche-built means some unique parts with MB tax + Porsche tax."}',NULL,82.0,82.0,80.0,55.0,69.0,NULL);
INSERT INTO reliability VALUES(7,135,'manual',72.0,'{"fuel injection pump": 4, "drum brakes": 2}',5000.0,0,'Specialist only (MB Classic Center)','Difficult (specialist required)','{"fuel injection pump": "Bosch mechanical DI pump requires specialist rebuild.", "brakes": "Drum brakes all around \u2014 period correct but weak by modern standards."}',NULL,80.0,80.0,62.0,72.0,59.0,NULL);
INSERT INTO reliability VALUES(8,136,'manual',70.0,'{"Solex carburetors": 3, "drum brakes": 2}',3500.0,0,'Good (specialist + aftermarket)','Moderate (simple mechanicals)','{"carburetors": "Twin Solex 44PHH need periodic rebuild and sync.", "drum brakes": "All drums \u2014 adequate for cruising, not for spirited driving."}',NULL,75.0,75.0,58.0,72.0,65.0,NULL);
INSERT INTO reliability VALUES(9,137,'manual',82.0,'{"fuel injection pump": 3, "swing axle": 2}',2500.0,0,'Good (specialist network)','Moderate','{"injection pump": "Bosch mechanical injection pump needs calibration every 30k mi.", "swing axle": "Rear swing axle can cause tuck-under if driven hard."}',NULL,85.0,82.0,78.0,72.0,89.0,NULL);
INSERT INTO reliability VALUES(10,138,'manual',80.0,'{"timing chain guides": 3, "AC system": 3}',2000.0,1,'Excellent (MB Classic + aftermarket)','Good (simple V8)','{"timing chain": "Inspect/replace guides at 100k mi.", "AC": "R12 to R134a conversion needed. Compressor seal leaks common."}',NULL,82.0,82.0,78.0,58.0,93.0,NULL);
INSERT INTO reliability VALUES(11,139,'manual',75.0,'{"biodegradable wiring harness": 4, "soft top hydraulics": 3}',3000.0,2,'Good (specialist network)','Moderate (tight engine bay)','{"wiring harness": "Pre-1996 cars have biodegradable insulation that crumbles. Full harness replacement $2-4K.", "soft top": "Hydraulic cylinder seals leak over time. $800-1500 per cylinder."}',NULL,82.0,82.0,78.0,48.0,78.0,NULL);
INSERT INTO reliability VALUES(12,140,'manual',65.0,'{"dual coil packs": 4, "ADS suspension": 4, "wiring harness": 4}',5000.0,2,'Moderate (V12-specific parts scarce)','Difficult (complex V12, tight access)','{"coil packs": "Two coil packs, ~$600-1200 each. 24 spark plugs to replace.", "ADS": "Active hydraulic suspension \u2014 accumulator spheres and valve blocks fail. Very expensive.", "coolant hoses": "13+ engine coolant hoses, many buried deep. Preventative replacement recommended."}',NULL,68.0,75.0,72.0,35.0,81.0,NULL);
INSERT INTO reliability VALUES(13,141,'manual',55.0,'{"ABC suspension": 5, "SBC brakes": 4, "roof hydraulics": 3}',4500.0,3,'Good (AMG parts available)','Difficult (complex systems)','{"ABC": "Active Body Control hydraulic suspension is THE known issue. Struts, lines, pump \u2014 $5-10K+ when it fails.", "SBC": "Sensotronic Brake Control pump fails and has a 10-year/service life counter. MB extended warranty on this.", "intercooler pump": "Supercharger intercooler coolant pump fails \u2014 cheap part, causes heat soak."}',NULL,75.0,78.0,62.0,30.0,32.0,NULL);
INSERT INTO reliability VALUES(14,142,'manual',62.0,'{"turbo wastegate rattle": 3, "ABC suspension": 3, "oil consumption": 2}',3500.0,2,'Good (AMG network)','Difficult (biturbo packaging)','{"wastegate": "M157 turbo wastegate rattle under deceleration. AMG extended warranty on turbos.", "ABC": "Same ABC issues as R230 but somewhat improved.", "battery": "Multiple battery drain issues if not driven regularly."}',NULL,72.0,78.0,68.0,42.0,47.0,NULL);
INSERT INTO reliability VALUES(15,143,'manual',70.0,'{"48V system glitches": 2, "MBUX infotainment": 2, "rear axle steering sensor": 1}',2000.0,1,'Good (current dealer network)','Difficult (electronics-heavy)','{"48V": "Early 2022 models had 48V electrical system glitches \u2014 resolved via software updates.", "MBUX": "Infotainment system occasional reboots, OTA updates fix most issues.", "warranty": "Most cars still under factory warranty through 2026."}',NULL,78.0,80.0,72.0,62.0,52.0,NULL);
INSERT INTO reliability VALUES(16,47,'sample',67.2000000000000028,'["Engine mount failure (60-100K, $300-600)","722.9 conductor plate (80-130K, $2-3K)","Electronic steering lock (ESL) failure","Blower motor squeak/failure ($400-800)","Valve cover and oil pan gasket leaks (70K+)","COMAND controller knob delamination","Battery drain from SAM module","AIRMATIC air springs (if equipped, $1.5-2K/corner at 100K+)"]',1200.0,8,'Good (Mercedes specialist network)','Moderate (wide engine bay, complex electronics)','["M272 90ﾂｰ V6 still has balance shaft 窶・W212 units are post-2008 revision so catastrophic gear failure resolved","722.9 conductor plate 窶・3 versions, NOT interchangeable. Harsh 1-2 shift is early warning","ESL steering lock is W212-specific 窶・car won''t start when it fails","Takata airbag recall 窶・verify via VIN","Rear subframe rust in salt-belt states","Pre-facelift COMAND firmware more glitchy"]',NULL,70.0,65.0,72.0,68.0,62.0,'Pre-facelift W212 with late-rev M272 port-injection V6. Balance shaft gear revised after 2008 窶・catastrophic failure resolved but shaft still present. 722.9 conductor plate is the big drivetrain concern. ESL steering lock is an annoying W212-specific failure. Doug DeMuro''s low ranking is aesthetic not reliability-based.');
INSERT INTO reliability VALUES(17,31,'sample',78.0,'{"M264 balance shaft (early)": 2, "AIRMATIC air spring": 3, "9G-Tronic mechatronic": 2, "48V mild hybrid battery": 2, "MBUX electronics": 1, "EQ Boost ISG": 2}',900.0,6,'Good (Mercedes specialist network)','Moderate','{"M264": "Improved over M274; balance shaft issue largely resolved by 2019.", "48V mild hybrid": "ISG/EQ Boost component failures on 2018-2020 M256 (E450); mostly resolved by 2021.", "AIRMATIC": "Same $1.5-2K per corner exposure as W205."}',NULL,80.0,82.0,78.0,70.0,76.0,NULL);
INSERT INTO reliability VALUES(18,144,'sample',62.0,'{"M272 balance shaft wear": 4, "M271 balance shaft gear": 3, "7G-Tronic mechatronic sleeve": 3, "valve cover gasket leak (M272)": 3, "MAF sensor": 2, "thermostat": 2}',1100.0,8,'Good (Mercedes specialist network)','Moderate (tight engine bay)','{"M272 balance shaft": "Well-documented 2004-2008 design flaw; mileage-dependent. Engine out job.", "7G-Tronic 722.9 mechatronic": "Sleeve/conductor plate wears, replaced with updated unit.", "valve cover leak (M272)": "Plastic covers warp with heat; replace with aluminum OE."}',NULL,58.0,72.0,72.0,55.0,52.0,NULL);
INSERT INTO reliability VALUES(19,145,'sample',82.0,'{"M274 balance shaft wear (early)": 2, "AIRMATIC air spring": 3, "9G-Tronic conductor plate": 2, "MBUX/comand glitches": 1, "TPMS sensor": 1}',800.0,5,'Good (Mercedes specialist network)','Moderate','{"M274 balance shaft": "2015-2016 cars; later engines revised. 80-120K mile onset.", "AIRMATIC": "Air springs and struts are $1.5-2.5K per corner; many owners bypass with coil spring conversion.", "9G-Tronic 725.0": "Far more reliable than the 722.9 it replaced."}',NULL,80.0,82.0,80.0,72.0,93.0,NULL);
INSERT INTO reliability VALUES(20,146,'sample',65.0,'{"M272 balance shaft wear": 4, "7G-Tronic mechatronic sleeve": 3, "lower control arm bushings": 3, "sunroof track/electrical": 2, "transfer case (4MATIC)": 2, "PCV system": 2}',1150.0,7,'Good (Mercedes specialist network)','Moderate (heavy, but engine bay accessible)','{"M272 balance shaft": "Same design flaw as W204; engine-out to fix.", "lower control arms": "80-100K mile wear; cheap to replace ($300-500 corners).", "sunroof": "Track and drain tube issues \u2014 early 2008-2011 cars."}',NULL,62.0,75.0,72.0,55.0,58.0,NULL);
INSERT INTO reliability VALUES(21,147,'sample',73.0,'{"M276 balance shaft wear": 3, "7G-Tronic mechatronic sleeve": 2, "transfer case (4MATIC)": 2, "ignition coil/spark plugs": 2, "PCV system": 2}',850.0,4,'Good (Mercedes specialist network)','Moderate','{"M276 balance shaft": "Milder than M272; engine-out repair if it occurs (80-120K onset).", "7G-Tronic 722.9": "Last-gen 7-speed; mechatronic sleeve wear at 80-120K.", "4MATIC transfer case": "Service every 60K; otherwise robust."}',NULL,75.0,78.0,78.0,68.0,64.0,NULL);
INSERT INTO reliability VALUES(22,148,'sample',78.0,'{"M276 balance shaft wear": 2, "9G-Tronic conductor plate": 2, "AMG sport suspension bushings": 2, "brake pad/rotor wear (sport)": 2, "rear diff mount": 1}',850.0,3,'Good (Mercedes specialist network)','Moderate','{"M276 in C450": "Same M276 as C400 but less stressed; balance shaft failure rare in this tune.", "9G-Tronic 725.0": "Far more reliable than 722.9; conductor plate (~$600 part) the main wear item.", "AMG-specific": "AMG dampers and sport bushings wear faster than non-sport suspension, but no AMG engine or transmission build = no AMG maintenance premium."}',NULL,78.0,82.0,78.0,68.0,80.0,NULL);
INSERT INTO reliability VALUES(23,149,'sample',72.0,'{"48V ISG/EQ Boost (early)": 3, "48V battery (early)": 3, "AIRMATIC air spring": 3, "M256 thermostat/coolant pump": 2, "MBUX screen/comand": 1, "fuel injector (early)": 2}',1100.0,5,'Good (Mercedes specialist network)','Difficult (48V system requires dealer-level diagnostics)','{"48V ISG / EQ Boost": "2020-2021 E450s; ISG or 48V lithium battery failure, $2-3K out of warranty. Largely resolved by 2022.", "AIRMATIC": "Same $1.5-2K per corner exposure as W205/W213.", "M256": "Newer engine family; thermostat/coolant pump a minor known issue. Generally robust."}',NULL,78.0,78.0,78.0,68.0,55.0,NULL);
INSERT INTO reliability VALUES(27,83,'sample',55.0,'{"M278 balance shaft gear wear": 4, "M278 valve stem seals (oil consumption)": 3, "DI carbon buildup (intake valves)": 3, "7G-Tronic mechatronic sleeve": 3, "AIRMATIC air spring": 3, "electronic selector module": 2}',1800.0,9,'Good (Mercedes specialist network)','Difficult (V8 engine bay, 7G-Tronic service)','{"M278 balance shaft": "Same family issue as M272/M276; 80-120K onset. Engine-out job on the V8 is more expensive than the V6 (~$5-7K).", "M278 valve stem seals": "Oil consumption > 1qt/1000mi is a TSB trigger; revised seals 2016+.", "DI carbon buildup": "Walnut blasting intake valves every 80-100K ($800-1200).", "7G-Tronic 722.9": "Mechatronic sleeve at 80-120K; same as every other M272/M276 car."}',NULL,62.0,72.0,68.0,38.0,38.0,NULL);
INSERT INTO reliability VALUES(32,56,'sample',79.5999999999999943,'["Water pump weep hole leak (50-80K, $1-2.5K, updated part available)","Oil filter housing gasket leak (60-80K, $150-900)","Valve cover gasket leak (60-80K)","Coolant vent hose plastic degradation (60-80K)","PCV pressure control valve diaphragm failure (2017-2021 TSB)","Carbon buildup on intake valves (DI, walnut blast every 50-60K)","Oil pan gasket weep (60-90K)"]',1100.0,3,'Excellent (BMW dealer + independent shops everywhere)','Moderate (excellent docs + aftermarket, but BMW-specific tools needed)','["B58 has BMW lowest warranty claim rate (30% lower than N55)","Insurance data: failure rate 1 in 145 vehicles (comparable to legendary N52)","70%+ owner satisfaction at 50K+ miles on BimmerPost","63% reported coolant loss in BimmerPost poll 窶・mostly weep hole","Water pump is engine-out repair on pre-LCI (expensive)","All issues are wear items (gaskets, plastic components), not design flaws","Closed-deck block, forged crankshaft = robust bottom end","500-hour durability test passed = ~200K real-world miles","Pre-LCI issues all addressed in B58TU (LCI)"]','{"B58_revision_note":"B58A (Gen 1, mature 2018+). Forged internals, NO plastic oil pump issue (that is TU/B58C-specific per TSB 11 10 24). Shared issues with TU: VCG at 70-100k, PCV diaphragm (SIB 01 14 23 covers both gens), coolant loss. TU genuine improvements: 1-piece timing chain, split cooling. But TU also has: plastic oil pump failure risk, 48V hybrid complexity, integrated exhaust manifold head. Real gap to LCI is ~3-4 pts, not 8. Score adjusted from 72 to 75."}',78.0,90.0,82.0,78.0,68.0,'Score corrected from 75 to 79.6. B58 pre-LCI was underrated. BMW lowest warranty claim rate, failure rate comparable to legendary N52. Issues are predictable wear items (gaskets, water pump), not systemic design flaws like Lambda II oil consumption. ZF 8HP transmission alone is worth +10 over Hyundai 8-speed. The gap to LCI is real: water pump redesign, simplified timing chain, split cooling address the most common pre-LCI failure modes.');
INSERT INTO reliability VALUES(33,150,'sample',81.5999999999999943,'["Oil filter housing gasket leak (60-80K, improved vs pre-LCI)","Valve cover gasket (revised design, less prone)","Carbon buildup on intake valves (DI, walnut blast every 50-60K)","Oil pan gasket weep (60-90K)","Coolant loss (reduced vs pre-LCI, better components)"]',1000.0,2,'Excellent (BMW dealer + independent shops everywhere)','Moderate (better than pre-LCI, good aftermarket)','["B58TU (LCI) addresses ALL major pre-LCI failure modes","Water pump redesigned 窶・no more weep hole insert","Single timing chain 窶・simpler, fewer failure points","Split cooling 窶・separate head/block circuits, reduced thermal stress on gaskets","PCV integrated in revised valve cover 窶・no more separate diaphragm failure","350-bar fuel pressure 窶・better atomization, less carbon than pre-LCI 200-bar","Forged crankshaft, closed-deck block 窶・same robust bottom end","48V mild hybrid on some models adds complexity but well-engineered","ZF 8HP unchanged 窶・still the gold standard","Power increase 335hp to 382hp on same architecture = well-sorted"]',NULL,83.0,90.0,82.0,80.0,70.0,'Score corrected from 80 to 81.6. B58TU is genuinely improved over pre-LCI. Water pump redesign eliminates the most expensive repair. Single timing chain simplifies. Split cooling reduces gasket stress. The ZF 8HP at 90 is the best automatic transmission score in our database. 81.6 puts the 540i LCI as the highest-scoring modern German car 窶・and it earns it with real engineering improvements, not just badge prestige.');
INSERT INTO reliability VALUES(168,151,'sample',70.2999999999999971,'["Oil consumption epidemic (stuck piston rings)","Timing chain stretch/guide cracking (100K+)","Turbo oil feed pipe deterioration (recall)","GDI carbon buildup (no dual injection)","Oil pressure switch seal failure","Head bolt pulling from block"]',950.0,5,'Moderate (some parts back-ordered)','Difficult (limited aftermarket)','["NHTSA investigation petition (2024) for Lambda II failures","Class action lawsuits US/Canada/Australia","Oil consumption sudden onset (1qt/1-2K miles)","GDI-only 窶・carbon buildup on intake valves","Same Lambda II 3.3T as G70/G90/Stinger"]',NULL,68.0,72.0,78.0,73.0,63.0,'Score corrected from 80 to 70.3. Same Lambda II 3.3T. NHTSA investigation, class actions, oil consumption. Aisin 8-speed (not Hyundai own) is slightly better than G70/G90 but same engine issues.');
INSERT INTO reliability VALUES(169,152,'sample',72.9000000000000056,'["Dual injection helps carbon buildup vs GDI-only Lambda II","Too new for definitive failure patterns","Engine characteristically loud (not a failure)","Turbo components add risk vs NA","Valve adjustment needed at intervals"]',600.0,2,'Moderate (newer engine, dealer-dependent)','Moderate (warranty helps, but limited aftermarket)','["Smartstream Theta III 2.5T 窶・clean-sheet, NOT Lambda II","Dual injection (GDi + MPi) mitigates carbon buildup","Only 5 years of data 窶・too new for 100K+ assessment","No class actions or NHTSA investigations (yet)","Shares platform with K5 GT which had early DCT issues","10yr/100K warranty new, 5yr/60K used"]',NULL,74.0,72.0,78.0,74.0,68.0,'Score corrected from 78 to 72.9. Smartstream 2.5T is genuinely improved over Lambda II 窶・dual injection, no class actions, no NHTSA investigation. But too new for definitive assessment. Scores higher than Lambda II 3.3T on engine (74 vs 68) for this reason.');
INSERT INTO reliability VALUES(170,153,'sample',72.9000000000000056,'["Dual injection helps carbon buildup","Too new for definitive failure patterns","Turbo components add risk","SUV = more strain on drivetrain"]',650.0,2,'Moderate (dealer-dependent)','Moderate (warranty helps)','["Smartstream 2.5T same as G70 facelift","Dual injection mitigates carbon","Only 5 years of data","SUV weight adds stress vs sedan","10yr/100K warranty"]',NULL,74.0,72.0,78.0,74.0,68.0,'Score corrected from 76 to 72.9. Same Smartstream 2.5T as G70 facelift. SUV application adds drivetrain stress.');
INSERT INTO reliability VALUES(171,154,'sample',70.2999999999999971,'["Oil consumption epidemic (Lambda II)","Timing chain stretch (100K+)","Turbo oil feed pipe (recall)","GDI carbon buildup","Heaviest Genesis = most drivetrain stress"]',1100.0,5,'Moderate','Difficult (heavy SUV + Lambda complexity)','["Same Lambda II 3.3T","GV80 is heaviest Genesis 窶・most stress on same engine","NHTSA investigation, class actions","Dual injection helps but oil consumption architecture inherited"]',NULL,68.0,72.0,78.0,73.0,63.0,'Score corrected from 75 to 70.3. Lambda II 3.3T in heaviest application. Dual injection variant helps carbon but same oil consumption heritage.');
INSERT INTO reliability VALUES(172,155,'sample',75.0,'{"PCV valve failure (under supercharger)": 3, "Water pump/thermostat housing": 3, "Timing chain tensioner (5-10%)": 3, "Supercharger wear": 2, "Carbon buildup (intake valves)": 2}',1100.0,2,'Good (Audi specialist + aftermarket)','Low','{"EA837 (CAJA/CREC)": "One of Audis most reliable modern engines. Risk score 4.0/10 per Autoscore. Facelift 2015+ improved with dual injection + decoupling clutch.", "Timing chain": "At BACK of engine = engine removal for service. Startup rattle >3 seconds warrants inspection. Many 200k+ without chain service.", "ZF 8HP": "One of the best automatics. No mechatronic issues unlike DL382. Fluid change at 40-60k."}',NULL,80.0,82.0,78.0,65.0,65.0,NULL);
INSERT INTO reliability VALUES(173,29,'sample',74.0,'["Oil consumption (stuck piston rings 120-160K)","Timing chain stretch/tensioner (100K+)","Valve clearance drift (solid buckets, adj every 60K)","Oil pan and valve cover gasket leaks (100K+)","Ignition coil failures"]',650.0,3,'Good (moderate volume, Hyundai/Kia dealer network)','Moderate (valve adj expensive, but parts available)','["Lambda 3.8 avg life 150-180K miles 窶・NOT Toyota 2GR-FE tier (200-300K+)","Oil consumption starts 100K+ on 35-45% of high-mileage engines","Timing chain issues at 160K+ on 20-25% of engines","Valve adjustment every 60K (solid buckets, labor-intensive)","MPI version avoids carbon buildup (unlike GDI variant)","Forum consensus: decent at low miles, issues accumulate past 120K","Much lower production volume than 2GR-FE = less statistical confidence"]',NULL,76.0,75.0,78.0,73.0,68.0,'Score corrected from 85 to 74 窶・previous score was inflated. Lambda 3.8 MPI is a solid B-tier engine, not A-tier. Port injection avoids carbon buildup but oil consumption, timing chain issues, and 60K valve adjustments prevent Toyota-level reliability. Avg life 150-180K vs 2GR-FE at 200-300K+. The 85 implied Camry-level; the real comparison is more like a good Chrysler Pentastar.');
INSERT INTO reliability VALUES(174,38,'sample',70.2999999999999971,'["Oil consumption epidemic (stuck piston rings, 1qt/1-2K miles)","Timing chain stretch/guide cracking (100K+)","Turbo oil feed pipe deterioration (recall)","GDI carbon buildup on intake valves (no dual injection)","Oil pressure switch seal failure (60-90K)","Head bolt pulling from block (like Northstar)"]',950.0,5,'Moderate (some parts back-ordered)','Difficult (limited aftermarket, valve adj every 60K)','["NHTSA investigation petition (2024) 窶・389 complaints for 2017 Santa Fe alone","Class action lawsuits in US, Canada, Australia ($3.1B covering Lambda II)","Oil consumption can go from normal to 1qt/1000 miles suddenly","GDI-only 窶・no dual injection like Toyota D-4S, carbon buildup inevitable","Turbochargers add two more failure points vs NA","Very few high-mileage examples (170K+) exist in used market","Motorreviewer: hard to believe turbo versions will last as long as NA"]',NULL,68.0,72.0,78.0,73.0,63.0,'Score corrected from 80 to 70.3 窶・Lambda II 3.3T is NOT in the same tier as BMW B58. Active NHTSA investigation, class action lawsuits, oil consumption epidemic, turbo oil feed recall. GDI-only (no dual injection). Hyundai own 8-speed (A8LR1) rated marginal for output torque. The 80 score was giving it B58-level credit it has not earned. Market depreciation reflects this 窶・G70 3.3Ts drop fast.');
INSERT INTO reliability VALUES(175,54,'sample',70.2999999999999971,'["Oil consumption epidemic (Lambda II)","Timing chain stretch (100K+)","Turbo oil feed pipe (recall)","GDI carbon buildup","SUV = more drivetrain stress"]',1000.0,5,'Moderate','Difficult (SUV + Lambda complexity)','["Same Lambda II 3.3T as G70/G90/Stinger","NHTSA investigation, class actions","SUV weight amplifies drivetrain issues","375hp = more stress than sedan application"]',NULL,68.0,72.0,78.0,73.0,63.0,'Score corrected from 76 to 70.3. Lambda II 3.3T in SUV application 窶・more stress, same engine issues.');
INSERT INTO reliability VALUES(176,32,'sample',75.0,'{"Oil consumption": 3, "DL382+ mechatronic (S-tronic)": 3, "Water pump/thermostat": 2, "Timing chain tensioner wear": 2, "Early rocker arm (2018-early 2019)": 2}',1200.0,1,'Good (Audi specialist + aftermarket)','Low','{"EA839 (DLZA)": "Shared with Porsche Macan S, VW Touareg. Generally reliable but oil consumption most reported. NA spec deletes port injector = carbon buildup risk.", "DL382+ S-tronic": "Mechatronic is weak point. Harsh low-speed shifts. P0718, P179F codes. $2-3K mechatronic.", "Cd 0.23": "Best drag coefficient of any combustion Audi."}',NULL,80.0,72.0,82.0,72.0,69.0,NULL);
INSERT INTO reliability VALUES(177,33,'sample',80.0,'{"Carbon buildup (GDI only)": 3, "Turbo oil line leaks": 2, "Brake rotor warpage": 2}',700.0,0,'Good (Hyundai/Kia shared parts)','Moderate','{"Lambda II 3.3T": "Same as G70 3.3T. GDI-only = carbon buildup at 40-60k. Proven V6.", "Stinger GT": "Brembo brakes standard. Larger aftermarket than G70. 10yr/100k warranty.", "Discontinued 2024": "Values may hold as only Kia liftback GT."}',NULL,80.0,85.0,78.0,72.0,81.0,NULL);
INSERT INTO reliability VALUES(178,8,'sample',75.2999999999999971,'["Parts availability backorders (5.0-specific parts)","Oil pump access requires subframe + both oil pans","Cracked lower timing cover (rare, 90K+)","Air suspension maintenance (if equipped, $1-2K/corner)"]',800.0,2,'Poor (5.0-specific parts frequently back-ordered)','Difficult (rare engine, mechanics unfamiliar, parts scarce)','["2012 early production had PVD piston ring oil consumption 窶・supplier defect, fixed by late 2012","Forum teardowns show excellent internal condition at 90K with maintenance","Roller cam followers superior to tappet-style (Audi/Nissan)","Hydraulic lash adjusters = maintenance-free (vs Lambda solid buckets every 60K)","Port injection = NO carbon buildup (unlike every other Hyundai V6)","Wards 10 Best Engines winner (4.6 in 2009-2010, 5.0 in 2011+)","CRITICAL weakness: parts availability 窶・many 5.0-specific parts back-ordered","Very low production volume = limited aftermarket support","Pre-2012: ZF 6-speed (excellent). 2012+: Hyundai A8TR1 (adequate)"]',NULL,80.0,82.0,80.0,72.0,60.0,'Score corrected from 72 to 75.3 窶・PREVIOUSLY UNDERRATED. The Tau 5.0 is objectively Hyundai best engine: port injection (no carbon), roller cam followers, hydraulic lash adjusters, Wards winner. 2012 ring issue was supplier defect not design flaw. Forum teardowns pristine at 90K. BUT: parts availability is critical weakness 窶・5.0 parts frequently back-ordered, almost no aftermarket. The gap to Lexus 1UZ-FE (88.5) is still real (proven 300K+ longevity, massive production volume, better parts) but 72 was unfairly penalizing the Tau for being Korean when the engineering is solid.');
INSERT INTO reliability VALUES(179,44,'sample',70.2999999999999971,'["Oil consumption epidemic (stuck piston rings)","Timing chain stretch/guide cracking (100K+)","Turbo oil feed pipe deterioration (recall)","GDI carbon buildup (no dual injection)","Oil pressure switch seal failure","Head bolt pulling from block"]',1000.0,5,'Moderate (some parts back-ordered)','Difficult (limited aftermarket, heavier car)','["NHTSA investigation petition (2024) for Lambda II failures","Class action lawsuits US/Canada/Australia","Oil consumption sudden onset (1qt/1-2K miles)","GDI-only 窶・carbon buildup on intake valves","Turbochargers add failure points","Very few high-mileage examples","Same Lambda II as G70/Kia Stinger 窶・shared issues"]',NULL,68.0,72.0,78.0,73.0,63.0,'Score corrected from 80 to 70.3. Same Lambda II 3.3T as G70/Stinger. NHTSA investigation, class actions, oil consumption epidemic. The larger G90 body means more strain on same drivetrain. G90 3.3Ts depreciate fastest in Genesis lineup 窶・market reflecting real reliability.');
INSERT INTO reliability VALUES(180,45,'sample',71.4000000000000056,'["Oil consumption (Lambda II architecture, reduced but not eliminated)","Timing chain concerns (Lambda II heritage)","Turbo components (409hp = more stress)","Electronics complexity (new platform)","Air suspension (if equipped, maintenance item)"]',900.0,3,'Moderate (newer model, dealer-dependent)','Difficult (complex electronics, new platform)','["2nd gen uses updated Lambda II with dual injection 窶・improves carbon buildup","But oil consumption architecture inherited from Lambda II family","Too new for definitive 100K+ data","409hp higher output = more thermal and mechanical stress","New platform = fewer independent mechanic data points","10yr/100K warranty still the safety net"]',NULL,70.0,73.0,78.0,74.0,64.0,'Score corrected from 78 to 71.4. Dual injection helps vs GDI-only Lambda II but oil consumption architecture is inherited. 409hp = more stress. Too new for long-term data. Slightly better than 1st gen 3.3T due to dual injection and updated trans, but same fundamental Lambda II concerns.');
INSERT INTO reliability VALUES(181,156,'sample',78.0,'{"Oil consumption (monitor)": 2, "Sensus infotainment glitches": 2, "Premature front brake wear": 1}',650.0,1,'Good (Volvo dealer + aftermarket)','Moderate','{"VEA T5 B4204T26": "Turbo-only = simpler than T6. No supercharger clutch issues. 2019+ SPA engines resolved early piston ring and oil consumption problems. T5 is the reliability sweet spot.", "Aisin TG-81SC": "Reliable 8-speed. Aisin also supplies Toyota."}',NULL,80.0,82.0,78.0,72.0,75.0,NULL);
INSERT INTO reliability VALUES(182,157,'sample',72.0,'{"Supercharger electromagnetic clutch failure": 3, "Oil consumption (piston rings)": 3, "Turbo failure (if oil starved)": 2, "Sensus glitches": 2}',850.0,2,'Good (Volvo dealer)','Low (SC complexity)','{"VEA T6 B4204T27": "Twincharged = more failure points. SC electromagnetic clutch is the #1 issue: severe hesitation from stop, often no CEL. $2-3.5K repair.", "2019+ SPA": "Improved over early VEA but SC clutch remains a risk on all T6 years."}',NULL,72.0,78.0,75.0,62.0,70.0,NULL);
INSERT INTO reliability VALUES(183,158,'sample',78.0,'{"Oil consumption (monitor)": 2, "Sensus infotainment glitches": 2, "Body seal leakage": 1, "AC compressor issues": 1}',700.0,1,'Good (Volvo dealer + aftermarket)','Moderate','{"VEA T5 B4204T23": "Same reliable turbo-only engine as S60 T5. XC60 is one of the highest-rated luxury compact SUVs.", "Aisin TG-81SC": "Reliable 8-speed. Volvo says sealed for life; Aisin recommends fluid change at 40-50k."}',NULL,80.0,82.0,78.0,72.0,75.0,NULL);
INSERT INTO reliability VALUES(184,159,'sample',72.0,'{"Supercharger electromagnetic clutch failure": 3, "Oil consumption": 3, "Turbo failure (if oil starved)": 2, "Premature brake wear": 2}',850.0,1,'Good (Volvo dealer)','Low (SUV + SC complexity)','{"VEA T6 in XC60": "Same B4204T27 as S60 T6 but heavier vehicle. More stress on drivetrain. SC clutch is the headline issue.", "T6 discontinued": "T6 discontinued after 2020 (replaced by B6 mild hybrid)."}',NULL,72.0,78.0,75.0,62.0,70.0,NULL);
INSERT INTO reliability VALUES(185,160,'sample',70.0,'{"Supercharger clutch failure": 3, "Oil consumption": 3, "Sensus infotainment": 2, "Air suspension (if equipped)": 3}',950.0,2,'Good (Volvo dealer)','Low (flagship complexity)','{"VEA T6 in S90": "Same B4204T27 as S60 T6 but in 4,819 lb flagship. More stress on drivetrain.", "2017-2019": "Early VEA issues \u2014 oil consumption, balancer shaft, timing chain tensioner. 2020+ improved.", "S90 depreciation": "Massive depreciation from $50K+ MSRP. Used 2018-2020 examples $20-35K."}',NULL,70.0,78.0,72.0,55.0,70.0,NULL);
INSERT INTO reliability VALUES(186,98,'sample',68.0,'{"Supercharger clutch failure": 3, "Oil consumption (piston rings)": 3, "Turbo failure (if oil starved)": 2, "Polestar-specific suspension bushings": 2, "Electrical gremlins (CEM)": 1}',1100.0,1,'Limited (Polestar-specific parts)','Low','{"VEA B4204T35 Polestar tune": "Same twincharged architecture as T6 but with aggressive Polestar tune pushing 367 hp. Same SC clutch failure risk, but higher boost = more stress.", "Pre-Geely build quality": "2014-2018 Polestar models built during Volvos transition period. Electronics (CEM module) can be finicky.", "Ohlins": "Ohlins dampers are serviceable but expensive to replace."}',NULL,68.0,78.0,72.0,55.0,62.0,NULL);
INSERT INTO reliability VALUES(187,63,'sample',92.0,'{"Power steering pump whine": 1, "A/C compressor clutch (age)": 1, "Door lock actuators": 1, "Dash stitching separation (cosmetic)": 1}',400.0,0,'Fair (engine/powertrain excellent; trim/body scarce)','High','{"1UZ-FE V8": "The legend. Port-injected, NA, non-interference. Timing belt every 90K. Bulletproof bottom end. No carbon buildup possible.", "A341E 4-speed": "Indestructible. Hydraulic, not electronic. Will outlast the car.", "Age factor": "1989-1994. Engine parts everywhere (shared with Supra/SC400). Body/trim/interior parts getting scarce.", "No OBD2": "1991 and earlier = OBD1. 1993-1994 have OBD2."}',NULL,95.0,93.0,88.0,85.0,95.0,'{"engine": "1UZ-FE, overbuilt NA V8, port-injected, non-interference, forged crank", "transmission": "A341E 4-speed hydraulic, indestructible, zero failure patterns", "chassis": "Simple coils, age-related bushing wear only, no rust issues on JDM", "electronics": "Minimal electronics, OBD1 (pre-93)/OBD2, no complex modules", "ease_of_repair": "Parts everywhere (SC400/Supra/Celsior), every shop knows it, cheap maintenance"}');
INSERT INTO reliability VALUES(188,39,'sample',88.5,'{"Dashboard cracking (UV)": 1, "Door lock actuators": 1, "Air suspension (UL package only)": 2, "VVT-i oil line (early years)": 1}',450.0,1,'Good (Toyota/Lexus shared)','High','{"3UZ-FE V8": "Evolution of the 1UZ. Port-injected NA V8. Timing belt. No carbon buildup possible. Same bulletproof architecture as LS400.", "A650E 5-speed": "Proven hydraulic unit. Smooth and reliable. Not as efficient as newer boxes but unbreakable.", "Dashboard": "UV cracking common in sunbelt states. Cosmetic only. Many replaced under TSB.", "Air suspension": "ONLY on Ultra Luxury package. Standard cars have coil springs. Air bags leak at 15+ years, $2K+ per corner."}',NULL,92.0,90.0,85.0,82.0,90.0,'{"engine": "3UZ-FE, same 1UZ architecture bored to 4.3L, port-injected, timing belt", "transmission": "A650E 5-speed, proven unit, zero failure patterns", "chassis": "Standard coils (UL has air ride), well-sorted, no rust issues", "electronics": "More modules than LS400 but still pre-CAN complexity era", "ease_of_repair": "Toyota/Lexus shared parts, good dealer + indie support"}');
INSERT INTO reliability VALUES(189,40,'sample',69.7000000000000028,'{"8-speed valve body (grind/hesitation)": 3, "Air suspension (if equipped)": 3, "Timing cover oil seep": 2, "Intake manifold runner control": 2, "EVAP canister": 1}',800.0,3,'Good (Toyota/Lexus specialist)','Moderate','{"1UR-FSE V8": "D-4S dual injection = no carbon buildup. But more complex than 3UZ. Timing chain (not belt). Timing cover leak possible.", "AA80E 8-speed": "FIRST production 8-speed automatic. Valve body issues: grinding between gears, hesitation on downshift. TSB issued. $2-4K fix. Pre-2012 most affected.", "Air suspension": "Optional on all LS460s. Air bags leak at 10+ years. Compressor fails. $2-3K per corner. Most owners convert to coil springs.", "Complexity jump": "Significantly more electronics than LS430. More sensors, modules, failure points."}',NULL,88.0,45.0,78.0,72.0,75.0,'{"engine": "1UR-FSE D-4S, dual injection = no carbon buildup, sound design but more complex than 3UZ", "transmission": "AA80E 8-speed, FIRST production 8-speed auto, valve body failures (grind/hesitation), pre-2012 most affected, $2-4K fix", "chassis": "Air suspension on multiple trims (not just UL), air bags leak at 10+ years, $2-3K/corner", "electronics": "Significantly more sensors/modules than LS430, CAN bus era, more failure points", "ease_of_repair": "Lexus dealer + specialist needed, air suspension parts expensive, D-4S tools required"}');
INSERT INTO reliability VALUES(190,24,'sample',56.2999999999999971,'{"Hybrid battery degradation (10+ yr)": 3, "Inverter/converter failure": 3, "CVT unique to this model": 3, "Air suspension": 3, "Brake booster (regen hybrid)": 2}',1200.0,2,'Poor (low-volume Lexus specialist only)','Low','{"Hybrid system": "V8 + electric + AWD = most complex LS drivetrain ever. Battery at 10-15 years = $3-5K replacement. Inverter failures documented.", "CVT hybrid trans": "Planetary gear hybrid transmission unique to LS600h. Very few shops can service. Parts scarce.", "AWD system": "Permanent AWD adds complexity. Not the same as LS460 RWD.", "Value proposition": "$126K MSRP new. Depreciated hard. Repair bills dont depreciate."}',NULL,82.0,40.0,70.0,60.0,40.0,'{"engine": "2UR-FSE D-4S, sound V8 but hybrid adds thermal/electrical stress on engine", "transmission": "Unique eCVT planetary gear hybrid transaxle, no aftermarket, very few shops, $8K+ replacement", "chassis": "Air suspension STANDARD on all LS600h, permanent AWD adds wear items, heavy vehicle", "electronics": "Hybrid inverter, battery management, regen braking, most complex electronics of any LS", "ease_of_repair": "Low-volume Lexus hybrid specialist only, parts scarce, very expensive repairs"}');
INSERT INTO reliability VALUES(191,35,'sample',85.0,'{"Fuel pump recall (Denso impeller)": 2, "Timing cover seep (longitudinal, less severe)": 2, "2013 first-year issues": 2, "Serpentine belt tensioner (high mileage)": 1}',590.0,3,'Good (Toyota/Lexus shared)','Moderate','{"2GR-FSE/FKS V6": "D-4S dual injection = NO carbon buildup. Port injection cleans valves continuously. One of the best V6s ever made.", "AA81E 8-speed": "Well-sorted. Some shift logic complaints on RWD 2016+ but not reliability. AWD keeps 6-speed = bulletproof.", "Longitudinal advantage": "Timing cover leak much easier to fix on RWD longitudinal than transverse ES. Lower repair cost.", "2013 vs 2014+": "2013 has most complaints (battery, sunroof, wheel bolts). 2014+ excellent. Score reflects whole generation."}',NULL,92.0,85.0,82.0,80.0,82.0,'{"engine": "2GR-FSE/FKS D-4S dual injection = NO carbon buildup, port injection cleans valves, longitudinal mount, one of best V6s ever made", "transmission": "AA81E 8-speed RWD well-sorted, AWD gets bulletproof 6-speed, some shift complaints on 2016+ RWD but not reliability", "chassis": "Double wishbone front + multi-link rear, no air ride option, well-engineered platform", "electronics": "More complex than ES (AVS dampers, more sensors) but Lexus-quality, fuel pump recall (free fix)", "ease_of_repair": "Shared with IS350/RX350 Toyota/Lexus, longitudinal mount = easier timing cover access than transverse ES"}');
INSERT INTO reliability VALUES(192,86,'sample',87.7999999999999971,'{"Timing cover oil leak (transverse, $4.5-8K)": 3, "VVT-i oil line rupture (2007-08, LSC fix)": 2, "Water pump (60-120K)": 1, "Evaporator core leak (2007-09)": 2, "Dashboard melt (2007-08)": 1}',468.0,5,'Excellent (Toyota Camry shared platform)','High','{"2GR-FE V6": "Port-injected NA V6. Same as Camry V6, Avalon, RX 350, Highlander, Sienna. Millions made. Parts everywhere.", "Timing cover leak": "THE big 2GR issue. On transverse mount, engine removed with subframe. $4.5-8K. Manageable with heavier oil for slow seeps.", "VVT-i oil line": "2007-2008 rubber hose degrades, can burst. LSC replaced with metal line free. Check records. Fixed = non-issue.", "U660E 6-speed": "Proven Aisin unit. No known issues.", "Platform": "XXV40 = Camry platform. Every part is a Toyota part."}',NULL,90.0,88.0,82.0,80.0,95.0,'{"engine": "2GR-FE port-injected NA V6, millions produced, shared with Camry/RX350/Avalon/Sienna/Highlander, bulletproof NA design", "transmission": "U660E 6-speed Aisin, proven unit, no known failure patterns", "chassis": "XXV40 Camry platform, simple coil springs, proven suspension, no air ride", "electronics": "Standard era electronics, throttle body P0505 on some years, no major module failures", "ease_of_repair": "Camry platform = every wear part is a Toyota part, every shop knows this car, cheapest luxury car to maintain"}');
INSERT INTO reliability VALUES(193,64,'sample',80.9000000000000056,'["VQ35DE Rev-Up oil consumption (1qt/1-2K mi)","6MT 1-2 synchro grind","Subframe bushing cracking 60-80K","Door actuator failure","Bose amplifier failure","Window regulator failure"]',850.0,3,'excellent','high','["Rev-up VQ35DE (2005-07 MT only) burns oil due to revised valve timing","Synchro grind on 1-2 shift under hard driving","Dash cracking in hot climates","Catalytic converter precats disintegrate 窶・debris ingestion risk"]','{}',85.0,80.0,75.0,72.0,88.0,'VQ35DE Rev-Up is the problematic variant 窶・non-rev-up 2003-04 is better. Oil consumption is the defining flaw but engine itself rarely catastrophically fails. 6MT synchros are a known weak point. Chassis is simple and well-understood. Electronics are aging but not complex. Aftermarket support is massive 窶・parts cheap, community knowledge deep. Ease of repair is the standout at 88 窶・this is why G35 still has cult following despite engine issues.');
INSERT INTO reliability VALUES(194,34,'sample',54.8999999999999985,'["VR30DDTT wastegate rattle","High-pressure fuel pump failure","DAS steer-by-wire failure (recall PC16/PC17)","Infotainment black screen freeze","7AT valve body harsh shifting","Boost control solenoid failure","Suspension bushing premature wear","Battery drain from always-on modules"]',2200.0,7,'limited','low','["7 NHTSA recalls 窶・among highest for any luxury sedan","DAS steering can fail completely while driving 窶・6 associated deaths","VR30DDTT twin turbos difficult to access for service","Early 2014-16 models have ATTESA E-TS AWD module failures","2018+ facelift improved infotainment but DAS issues persist","2.0t variant (Mercedes M274) significantly more reliable than VR30"]',NULL,65.0,58.0,68.0,42.0,45.0,'A reliability step DOWN from the G37 it replaced. The VR30DDTT is Infiniti''s first twin-turbo V6 窶・wastegate rattle and HPFP issues are endemic. The real catastrophe is DAS steer-by-wire: NHTSA recall PC16/PC17 for steering failure while driving, 6 deaths linked to loss of control. This alone drags electronics to 42 and triggers catastrophe penalty. Ease of repair is poor at 45 窶・twin-turbo packaging is tight, DAS requires dealer calibration, and OEM parts are expensive with limited aftermarket. The 2.0t Mercedes-powered variant is notably better. Red Sport 400 is the worst Q50 variant for reliability.');
INSERT INTO reliability VALUES(198,161,'sample',71.9000000000000056,'["Engine mount failure (60-100K)","722.9 conductor plate (80-130K, less frequent than pre-FL)","ESL steering lock failure","Blower motor failure","AIRMATIC air springs (if equipped)","Valve cover gasket leaks","Cam sensor oil leak (early 2014)"]',1100.0,5,'Good','Moderate','["M276 60-degree V6 NO balance shaft","Shares architecture with Pentastar","DI carbon buildup potential","722.9 3rd-gen conductor plate improved","2015-2016 are sweet spot"]',NULL,78.0,70.0,74.0,72.0,65.0,'The return to form W212. M276 eliminates balance shaft. 4-chain timing. Updated 722.9. Post-FL COMAND improved. Owner consensus: bulletproof for maintained examples.');
INSERT INTO reliability VALUES(199,162,'sample',73.9000000000000056,'["DCT oil pump solder joint (2021-early 2022 recall)","DCT software harsh shifts (TSB SA502/SA526)","Fuel injector failures (2021-22 batch)","Carbon buildup (DI 80K+)","Engine loudness (characteristic)","Turbo wastegate rattle potential"]',450.0,6,'Good','Moderate','["Smartstream Theta III clean-sheet, NOT patched Theta II","Dual injection mitigates carbon buildup","Only 5 years of data - too new for definitive judgment","DCT solder joint recall on early cars, post-Aug 2022 fixed","NA version has piston slap concerns, turbo better","FWD no LSD = torque steer at 290hp","10yr/100K warranty new, 5yr/60K used"]',NULL,75.0,68.0,80.0,78.0,72.0,'Fun but unproven. Smartstream 2.5T improves on Theta II. Dual injection helps. DCT is weak link with early production issues. 2023+ sorted. Scores below Stinger 3.3T (80) mainly on less proven engine and DCT risk.');
INSERT INTO reliability VALUES(200,87,'sample',83.9000000000000056,'["UA80/AA81E 8-speed harsh shifting (class action)","Timing cover oil leak (80-150K)","Coolant bypass pipe leak (60-120K)","Water pump failure (60-100K)","Ignition coil failure (30-50K GR pattern)","Carbon buildup intake valves (80K+)","Valve cover gasket leak (100K+)"]',500.0,14,'Excellent','High','["2GR-FKS NOT refreshed FE - different heads block manifolds cams","D-4S dual injection: more power but more complexity","VVT-iW enables Atkinson cycle for economy","Integrated exhaust manifolds cast into heads","UA80 class action lawsuits harsh shifting and failure","2018-2020 worst for trans; 2021+ improved","Engine life 220-240K+ with maintenance","14 NHTSA recalls gen-wide (1 V6-specific: brake booster)"]',NULL,88.0,68.0,92.0,90.0,88.0,'The transmission lets down a bulletproof powertrain. 2GR-FKS with D-4S is more powerful but slightly less bulletproof than 2GR-FE. Engine 88 would be 90+ with port injection only. AA81E 8-speed is the genuine problem: class action lawsuits, $7K replacements. Chassis and electronics Toyota-perfect at 92/90. The smart play: 2021+ with improved trans calibration and 40K fluid changes.');
INSERT INTO reliability VALUES(201,163,'sample',75.7000000000000028,'["Parts availability backorders (5.0-specific parts)","Oil pump access requires subframe + both oil pans","Cracked lower timing cover (rare, 90K+)","Air suspension maintenance (if equipped, $1-2K/corner)"]',800.0,2,'Poor (5.0-specific parts frequently back-ordered, same as G90)','Difficult (rare engine, mechanics unfamiliar, parts scarce)','["Same Tau 5.0 V8 as G90 窶・port injection, roller cam followers, hydraulic lash adjusters","2012 early PVD ring issue was supplier defect, fixed by late 2012","Forum teardowns show excellent internal condition at 90K with maintenance","Lighter body (2050 vs 2150 kg) = slightly less stress on drivetrain","G80 5.0 is rarer than 3.8L/3.3T variants 窶・most were sold with V6","CRITICAL weakness: same parts availability issues as G90 5.0","Pre-2012: ZF 6-speed. 2012+: Hyundai A8TR1 (adequate for 398lb-ft)"]',NULL,80.0,82.0,80.0,72.0,62.0,'G80 5.0 Tau shares every strength and weakness of G90 5.0 Tau. Same port-injected NA V8, same Wards-winning architecture. Slightly better ease (62 vs 60) because G80 is the more common body = marginally better parts pipeline. Aggregate 75.7 vs G90 75.3. The gap to LS430 (88.5) is real: Lexus has proven 300K+ longevity, 10x production volume, and dealer-everywhere parts. But 75.7 is honest for what the Tau is 窶・Hyundai best engine in their best sedan body.');
INSERT INTO reliability VALUES(202,13,'sample',80.0,'{"water_pump": "low", "oil_filter_housing": "low", "pcv_valve": "low"}',850.0,2,'excellent','moderate','{"b58tu_water_pump": "Improved over B58 pre-TU, rare failures before 60K", "oil_filter_housing_gasket": "Minor weep common at 50-70K, cheap fix", "zf_8hp_solenoid": "Occasional harsh shift software TSB, reflash fixes"}',NULL,88.0,90.0,82.0,68.0,65.0,NULL);
INSERT INTO reliability VALUES(203,19,'sample',55.7000000000000028,'{"rod_bearings": "critical", "subframe_cracks": "critical", "vanos_hub": "high", "smg_pump": "high"}',3200.0,1,'limited','low','{"s54_rod_bearings": "Preventive replacement required $2500-4000, known BMW TSB", "rear_subframe": "Mounting points crack, reinforcement plates $2000-4000", "smg_ii_pump": "Hydraulic pump relay fails, strands car in neutral", "vanos_hub_bolts": "Back out into timing chain, catastrophic if not caught", "valve_adjustment": "Required every 30K miles, shim-under-bucket design"}',NULL,68.0,52.0,62.0,55.0,45.0,NULL);
INSERT INTO reliability VALUES(204,23,'sample',74.7000000000000028,'{"air_suspension": "moderate", "iDrive_glitches": "moderate", "door_lock_actuator": "low"}',1800.0,3,'good','low','{"b58_excellent": "Fundamentally robust I6, minor coolant weep at thermostat", "air_suspension": "Air struts leak at 80-100K miles, $1500-2500 per corner", "iDrive_crashes": "NBT-EVO occasional black screen, software update usually fixes", "battery_registration": "Required, wrong coding causes electrical gremlins"}',NULL,85.0,88.0,85.0,58.0,50.0,NULL);
INSERT INTO reliability VALUES(205,37,'sample',78.0,'["valve_cover_gasket","water_pump","oil_filter_housing_gasket","disa_valve","window_regulators","vanos_solenoid"]',950.0,2,'excellent','high','["n52_valve_cover: Oil weep from valve cover gasket at 60-120K miles. Early magnesium covers (pre-2007) more durable; post-2007 plastic covers crack. 400-600 shop, ~150 DIY","electric_water_pump: Fails WITHOUT WARNING at 60-100K miles. No serpentine belt drive. Sudden overheating triggers limp mode. Replace preventively at 80-100K with thermostat. 600-800 total","oil_filter_housing_gasket: OFHG leak at 60-120K. CRITICAL: leaking oil on serpentine belt can cause belt to slip off and get sucked into crank seal, destroying engine. Do not ignore. 500-700 shop, ~80 DIY","disa_valve: Intake manifold flap actuator failure at 80-120K. Rough idle, CEL, loss of low-end torque. 200-400 per valve","hydraulic_lifter_tick: Pre-November 2008 N52 engines prone to cold-start ticking. Post-Nov 2008 engines resolved","window_regulators: E90 chassis-wide issue. Cable mechanism fails, window slides down into door. 200-400 per window","vanos_solenoid: Dirty oil clogs solenoid screens. Clean oil changes prevent this. 200-400 cleaning, 400-600 replacement","timing_chain: Uses chain not belt. Generally robust unlike N20. Guide rails can break at 120K+ miles. Preventive replacement around 150K. 1500-3000 if needed","oil_consumption: Up to 1qt per 1000-1500 miles is within BMW normal spec. Well-maintained N52s typically 0.5-1qt per 3000-5000 miles"]',NULL,78.0,85.0,80.0,68.0,75.0,'["engine: N52 is one of BMW most reliable engines. Wards 10 Best 2006-2007. Magnesium/aluminum composite block was groundbreaking. Known issues are predictable and manageable. The failure modes help the appreciation thesis: less and less of them available","transmission: ZF 6-speed manual is excellent. One of the best manual transmissions BMW ever made","chassis: E90 chassis is well-engineered. RWD, near 50/50 weight distribution. Subframe issue from E46 largely resolved","electronics: iDrive CCC system ages poorly. Window regulators fail across the E90 range. Generally less reliable than Japanese competitors","ease_of_repair: N52 is one of the easier BMW engines to work on. Large DIY community. Most major services are weekend jobs"]');
