INSERT INTO reliability VALUES(216,28,'sample',82.0,'{"infotainment_freeze": "low", "brake_squeal": "low", "sunroof_rattle": "very_low"}',500.0,0,'excellent','high','{"K24_2.4": "Naturally aspirated K24 is one of the most reliable engines ever built - virtually bulletproof", "8DCT": "Dual-clutch transmission is smooth and reliable - Honda units have good track record", "Honda_platform": "Shared Accord platform means excellent parts availability and well-known service procedures", "ADAS_sensors": "Honda Sensing suite is generally reliable - occasional false alerts but no widespread failures"}',NULL,82.0,82.0,82.0,78.0,85.0,NULL);
INSERT INTO reliability VALUES(217,48,'sample',76.9000000000000056,'{"transmission_slip": "moderate", "power_steering_whine": "low", "oil_consumption": "low"}',700.0,1,'excellent','high','{"J35Z6": "3.5L V6 is proven and reliable - VCM cylinder deactivation can cause mount wear", "5AT_issues": "5-speed automatic is the weak link - torque converter shudder and slip reported, especially in Type S", "SH_AWD": "Super-Handling AWD is sophisticated but adds complexity - rear clutch packs can wear", "age_2007-2014": "Interior electronics are aging - navigation screen delamination and audio amp failures reported"}',NULL,80.0,72.0,78.0,68.0,85.0,NULL);
INSERT INTO reliability VALUES(218,80,'sample',82.5999999999999943,'{"oil_dilution": "low", "brake_squeal": "low", "infotainment_glitch": "very_low"}',450.0,0,'excellent','high','{"K20C1": "2.0L turbo K20 is remarkably robust - minimal issues even under track abuse", "6MT_manual": "Helical LSD manual transmission - Honda manuals are legendary for reliability and feel", "FK8_chassis": "Rigid hatchback body - suspension components are durable, brake pads are the main consumable", "oil_dilution_fix": "Early models had minor fuel-in-oil TSB - resolved in later production with ECU update"}',NULL,82.0,82.0,82.0,78.0,88.0,NULL);
INSERT INTO reliability VALUES(219,88,'sample',78.7000000000000028,'{"VCM_vibration": "moderate", "infotainment_lag": "low", "rear_brake_squeal": "low"}',600.0,0,'excellent','high','{"J37_V6": "3.7L V6 is smooth and reliable - VCM activation can cause slight vibration at highway speeds", "6AT": "6-speed automatic is a significant improvement over the 5AT in the 3rd gen TL", "Honda_reliability": "Core mechanicals are Honda-reliable - the TL 4th gen benefits from mature engineering", "electronics_aging": "Infotainment and navigation systems are dated - slow response but functional"}',NULL,80.0,78.0,80.0,72.0,82.0,NULL);
INSERT INTO reliability VALUES(220,97,'sample',77.9000000000000056,'{"clutch_judder": "moderate", "turbo_boost_control": "low", "drivetrain_binding": "very_low"}',750.0,0,'limited','moderate','{"G16E_GTS": "Same hand-finished 1.6L turbo triple as GR Yaris - robust but complex", "GR_Four_AWD": "Three limited-slip diffs and variable torque split - excellent but specialist service required", "manual_only": "Intelligent Manual Transmission with auto-rev match - robust but clutch replacement is labor-intensive", "limited_production": "Toyota GR network required for major service - independent shops may lack expertise"}',NULL,82.0,78.0,83.0,76.0,70.0,NULL);
