INSERT INTO reliability VALUES(222,103,'sample',79.7000000000000028,'{"distributor_wear": "moderate", "synchro_grind": "moderate", "rust": "moderate"}',350.0,0,'good','very_high','{"B16B": "Hand-ported 1.6L naturally aspirated - legendary Honda reliability, high-revving and durable", "S4C_LSD": "Close-ratio gearbox with LSD - syncros can grind at high mileage but boxes are rebuildable", "simplicity": "Minimal electronics - OBD1 era means simple diagnostics, parts are cheap and abundant", "JDM_import": "Many EK9s are JDM imports - verify maintenance history, rust is the primary concern", "age_1997-2000": "25+ year old car - rubber components, seals and bushings need refreshing"}',NULL,85.0,78.0,75.0,62.0,92.0,NULL);
INSERT INTO reliability VALUES(223,108,'sample',80.0999999999999943,'{"carb_rebuild": "moderate", "rust": "high", "clutch_wear": "low"}',250.0,0,'good','very_high','{"4A_GE": "Legendary 1.6L twin-cam 16-valve - incredibly reliable, parts still available from Toyota and aftermarket", "T50_gearbox": "5-speed manual is robust and rebuildable - simple design means easy maintenance", "age_1983-1987": "40+ year old car - expect electrical gremlins, degraded wiring, faded instruments", "rust_critical": "Rust is the AE86 killer - rear wheel arches, floor pans and frame rails need thorough inspection", "drift_tax": "Drifting popularity means clean examples command premium prices - many cars have been abused"}',NULL,88.0,80.0,72.0,55.0,95.0,NULL);
INSERT INTO reliability VALUES(224,113,'sample',75.0,'{"snap_ring": "moderate", "window_regulators": "moderate", "coolant_tank_crack": "low"}',2500.0,0,'limited','low','{"C30A_V6": "3.0L NA V6 designed with input from Ayrton Senna - reliable but expensive to service", "snap_ring_issue": "Early 1991-1992 transmissions have snap ring range issue - check transmission number before purchase", "aluminum_chassis": "Aluminum monocoque is lightweight and corrosion-resistant but repair requires specialist knowledge", "exotic_costs": "Mid-engine layout and exotic construction mean service costs rival European sports cars", "age_1990-2005": "Electronics and rubber components degrade - ABS pump failures and climate control issues common"}',NULL,82.0,80.0,82.0,65.0,62.0,NULL);
INSERT INTO reliability VALUES(225,118,'sample',79.5,'{"coolant_loss": "very_low", "brake_squeal": "very_low", "iDrive_glitch": "very_low"}',650.0,0,'good','moderate','{"B58_BMW": "BMW B58 3.0L turbo inline-6 has proven reliable - no widespread engine failures in Supra application", "ZF_8HP": "ZF 8-speed automatic is exceptional - smooth, reliable, and robust across BMW/Toyota applications", "BMW_electronics": "Shared electronics architecture with BMW - some iDrive quirks but generally stable", "BMW_service": "Some service requires BMW-specific tools and knowledge - Toyota dealers may be limited", "2.0T_option": "Base 2.0L 4-cylinder is also reliable but less desirable - most buyers choose the 3.0L"}',NULL,80.0,82.0,82.0,78.0,75.0,NULL);
INSERT INTO reliability VALUES(226,119,'sample',83.7999999999999971,'{"brake_dust": "very_low", "infotainment_reboot": "very_low", "tire_wear": "low"}',400.0,0,'excellent','high','{"K20C1_FL5": "315hp turbo K20 is the most powerful production K-series - no reliability concerns vs FK8", "6MT_rev_match": "Rev-match 6-speed with helical LSD - Honda''s best manual transmission to date", "11th_gen_civic": "Latest Civic platform is well-sorted - teething issues resolved from early 11th gen production", "track_capable": "Honda development at Suzuka and Nurburgring means the car is engineered for sustained track use", "best_CTR_yet": "Widely considered the most complete hot hatch ever made - reliability matches the performance"}',NULL,85.0,82.0,83.0,80.0,88.0,NULL);
INSERT INTO reliability VALUES(241,82,'sample',68.9000000000000056,'["M278 balance shaft gear wear (80-120K, engine-out job)","7G-Tronic 722.9 mechatronic sleeve (80-130K)","AIRMATIC air springs (if equipped, $1.5-2K/corner)","DI carbon buildup on intake valves (walnut blast 80-100K)","COMAND infotainment glitches (aging firmware)","Valve cover gasket leaks"]',1400.0,4,'Good (Mercedes specialist network)','Moderate (tight V8 bay, AIRMATIC complexity)','{"M278": "Same balance shaft family as M272/M276; 80-120K onset. Engine-out on V8 = $5-7K.", "722.9": "3rd-gen conductor plate improved over early versions but still a wear item. Harsh 1-2 shift is early warning.", "AIRMATIC": "Common on CLS; $1.5-2K per corner at 100K+. Coil conversion bypasses this.", "carbon_buildup": "Direct injection legacy 窶・walnut blasting every 80-100K ($800-1200)."}',NULL,72.0,70.0,72.0,68.0,62.0,NULL);
INSERT INTO reliability VALUES(242,79,'sample',70.7000000000000028,'["SBC brake pump failure (service life counter, $2-3K)","AIRMATIC air springs ($1.5-2K/corner at 80K+)","SAM module battery drain","Biodegradable wiring harness (pre-2004 models)","Fuel pump failure","COMAND display pixel fade","Catalytic converter aging"]',1600.0,6,'Good (Mercedes specialist network, parts plentiful)','Moderate (M113 very accessible, but SBC limits DIY)','{"M113_V8": "3-valve, non-DI,SOHC design 窶・simple and robust. One of Mercedes'' best V8s. No balance shaft issues.", "722.6_transmission": "5-speed automatic is one of Mercedes'' best. Extremely reliable, few known failure modes.", "SBC_nightmare": "Sensotronic Brake Control has a hard service life counter. When it triggers, brakes fail-safe to hydraulic-only. Mercedes extended warranty on this. Many owners do SBC delete (software + conventional brakes).", "AIRMATIC": "Standard W211 issue 窶・$1.5-2K per corner. Coil spring conversion is popular bypass.", "wiring": "Pre-2004 cars have biodegradable insulation that crumbles. Full harness replacement $2-4K."}',NULL,85.0,78.0,68.0,48.0,65.0,NULL);
INSERT INTO reliability VALUES(243,67,'sample',71.7999999999999971,'["Structural rust 窶・rear subframes, floor pans, spring perches, jack points","Fender lip and wheel arch rust","ASR traction control module failure","Radiator leaking (plastic end tanks)","Window regulator failure","Catalytic converter aging","Headlamp wiring degradation"]',1100.0,3,'Good (Mercedes specialist network)','Good (simple engine bay, M113 very accessible)','{"M113_AMG": "Hand-finished by AMG 窶・one of the most reliable V8s Mercedes ever built. Non-DI, 3-valve, SOHC. No balance shaft issues. 300K+ mile examples exist.", "722.6": "5-speed automatic 窶・proven and robust. AMG-fortified torque converter. Rarely fails below 200K.", "W210_rust": "Mercedes'' worst rust era. Inadequate galvanization, water traps in sill cavities. Rear subframe rust is structural and dangerous. Spring perch rust can cause suspension collapse. Pre-2003 cars are worst affected.", "electronics": "Simple by modern standards 窶・limited ECUs, no SBC, no complex infotainment. ASR module the main electronic failure point."}',NULL,88.0,80.0,45.0,70.0,68.0,NULL);
INSERT INTO reliability VALUES(244,122,'sample',72.7000000000000028,'["MBUX Hyperscreen software glitches (freezes, reboots)","12V auxiliary battery drain","AIRMATIC air springs (if equipped)","OTA update failures requiring dealer visit","HV battery preconditioning software bugs","Door handle extension mechanism","Rear axle steering calibration (early units)"]',800.0,2,'Limited (dealer-only for EV drivetrain)','Difficult (EV systems, dealer tools required)','{"electric_drivetrain": "Permanent magnet synchronous motor with single-speed reduction gear 窶・fewer than 20 moving parts vs 2000+ in ICE. Inherent reliability advantage. Battery warranty 10yr/155K mi.", "reduction_gear": "Single-speed planetary gear set 窶・extremely simple. No clutch packs, no torque converter, no shift logic. Near-zero failure mode.", "MBUX": "Hyperscreen triple-screen system is complex 窶・software bugs, occasional black screens, phantom reboots. Most fixed via OTA but some require dealer visit.", "12V_battery": "EQS uses 12V auxiliary battery for electronics 窶・can drain if car sits unused. Not the traction battery.", "repairability": "EV-specific tools and safety certification required. Independent shops largely locked out. Dealer service is primary path."}',NULL,86.0,88.0,72.0,56.0,50.0,NULL);
INSERT INTO reliability VALUES(245,53,'sample',73.4000000000000056,'["M276 balance shaft wear (80-120K, less severe than M272)","9G-Tronic conductor plate ($600 part, 80-120K)","Air suspension (AIRMATIC, if equipped)","Water pump failure","PCV system breather","Brake pad/rotor wear (AMG sport brakes)"]',1000.0,2,'Good (Mercedes dealer + specialist network)','Moderate (SUV bay accessible, but AMG parts premium)','{"M276_AMG": "AMG-modified M276 ﾎｻ 3.0L biturbo V6. Improved over M272 窶・60-degree architecture, no catastrophic balance shaft gear. AMG-specific tuning but same block family.", "9G-Tronic_725.0": "Far more reliable than 722.9 it replaced. Conductor plate the main wear item (~$600). AMG Speedshift has faster shifts but same internal architecture.", "SUV_advantage": "SUV engine bay is more accessible than C-Class sedan counterpart 窶・easier to access turbos, manifold, and accessories.", "chassis": "X253 GLC platform is well-proven. Air suspension is the main chassis expense at $1.5-2K/corner."}',NULL,76.0,78.0,72.0,70.0,68.0,NULL);
INSERT INTO reliability VALUES(246,42,'sample',64.5999999999999943,'["cam_sensor_oil_wicking","airmatic_struts","oil_cooler_leaks","7g_conductor_plate","comand_screen_aging","turbo_coolant_lines"]',1800.0,5,'Good (Mercedes dealer + specialist network)','Difficult (flagship complexity, expensive parts)','["cam_sensor_oil_wicking: The #1 S550 killer. Oil travels up cam sensor wire harness into ECU causing random misfires and transmission issues.  pigtail fix prevents + ECU death. CHECK FIRST on any used M278","cylinder_scoring: Pre-2015 Silitec liners prone to scoring. NanoSlide coating introduced ~2015. Check compression on cylinders 5/6","timing_chain_tensioner: Pre-Feb 2013 engines lack check valves. 2016 should be past cutoff but verify by engine serial","oil_cooler_leaks: Oil filter housing leaks at 80K+. Oil+coolant mix. -3000. Part of PPI","carbon_buildup: Direct injection carbon on intake valves. Walnut blast at 60K intervals. -1200","airmatic_struts: Air bags crack at 80K+. Arnott rebuilt /corner, dealer . Compressor fails from overwork","magic_body_control: If equipped, hydraulic ABC system. Pump failure -5K. Cannot coil-convert MBC cars"]',NULL,68.0,72.0,64.0,60.0,55.0,'["engine: M278 shares block with M273 but different failure modes. Cam sensor oil wicking is existential risk. Pre-2015 cylinder scoring. Direct injection carbon. Engine score dropped from 72 to 68 for these documented issues","transmission: 7G-Tronic conductor plate failures at 80K+. Rough shifting. 9G in facelift is better","chassis: AIRMATIC struts at 80K+ are a -5K wear item. MBC if equipped is worse. Score dropped from 66 to 64","electronics: ~100 ECUs. COMAND NTG5 ages poorly. No CarPlay on early models. Score dropped from 62 to 60","ease_of_repair: Aluminum hybrid bodyshell requires Mercedes Elite Certified Collision Center (only ~10 in USA). M278 is complex. Already at 55"]');
INSERT INTO reliability VALUES(247,117,'sample',60.8999999999999985,'["PHEV battery management system glitches","Rear differential failures (early production)","MBUX software bugs (freezes, black screens)","400V electrical system warning lights (false positives)","AMG Ride Control+ damper failures","Rear axle steering sensor faults","E-motor inverter thermal management (track use)","Brake-by-wire calibration issues"]',2200.0,3,'Limited (AMG dealer primary, PHEV specialist rare)','Difficult (PHEV system, dealer tools, 400V safety)','{"M139l": "AMG hand-built 2.0L turbo based on proven M139 from A45 S. Making 476hp from 2.0L is extreme specific output 窶・long-term durability at high stress unknown. Electric spool turbocharger is new technology with limited track record.", "PHEV_system": "400V lithium-ion battery + 204hp e-motor integrated into 9G-Tronic. Complex thermal management, BMS, and inverter. Battery warranty 10yr/62K mi but replacement cost is $15-20K+", "controversy": "Replaced the beloved W205 C63''s 4.0L twin-turbo V8 with a 4-cylinder hybrid. Enthusiast backlash was immense. Power output is higher (671hp combined) but character is fundamentally different.", "repairability": "PHEV system requires HV-certified technicians. Independent shops mostly locked out. 400V safety protocols limit DIY to non-hybrid components only.", "platform": "W206 is new platform with some early teething issues. Rear differential and rear axle steering had early production failures. Most resolved by 2024."}',NULL,68.0,65.0,67.0,56.0,48.0,NULL);
INSERT INTO reliability VALUES(248,10,'sample',77.5,'{"pcs_module_failure": "low", "battery_module_degradation": "low", "pcm_reboots": "moderate"}',2200.0,2,'limited','low','{"800v_architecture": "Pioneering 800V electrical system - early cars had PCS (Porsche Charge Connect) module failures requiring replacement", "battery_degradation": "Battery degradation is minimal (<8% over 100k miles) but replacement cost is extreme if out of warranty", "air_suspension": "Air suspension components may need attention at 60-80k miles - expensive Porsche dealer-only repair", "ev_motor_reliability": "Dual electric motors are inherently reliable - no turbo, no valves, no timing chain to worry about"}',NULL,82.0,88.0,88.0,72.0,55.0,NULL);
INSERT INTO reliability VALUES(249,17,'sample',73.0,'{"timing_belt": "high", "turbo_wastegate": "moderate", "head_gasket": "moderate", "oil_cooler_seals": "low"}',850.0,0,'good','moderate','{"2_5_turbo": "2.5L turbo inline-4 is robust when maintained but timing belt failure is catastrophic - must be changed every 30k miles", "turbocharger": "Original K26 turbo is durable but wastegate can stick on high-mileage examples - rebuild common at 100k+", "galvanized_body": "Fully galvanized body resists corrosion well - body shell outlasts mechanicals", "dme_relay": "DME relay is a known failure point - always carry a spare, $15 part that strands you"}',NULL,70.0,78.0,75.0,65.0,75.0,NULL);
INSERT INTO reliability VALUES(250,18,'sample',70.2000000000000028,'{"ims_bearing": "high", "rms_leak": "moderate", "cylinder_scoring": "moderate", "coolant_leak": "low"}',2800.0,1,'good','moderate','{"m96_ims": "Intermediate shaft bearing is THE known issue - single-row bearings (2000-2005) are highest risk, dual-row (1997-1999) less prone but not immune", "rms_leak": "Rear main seal weep is common - not catastrophic but annoying, IMS retrofit often done simultaneously", "cylinder_scoring": "Some M96 engines develop cylinder wall scoring - more common on 3.4L than 3.6L but both affected", "tiptronic": "5-speed Tiptronic is robust - preferred over early 6-speed manuals for reliability"}',NULL,55.0,78.0,78.0,68.0,75.0,NULL);
INSERT INTO reliability VALUES(251,21,'sample',75.5999999999999943,'{"rms_leak": "moderate", "valve_adjustment": "moderate", "coolant_tank": "low", "exhaust_manifold_crack": "low"}',3500.0,0,'limited','moderate','{"m96_70_gt1": "GT3 uses hand-assembled M96/70 with individual throttle bodies and dry sump lubrication - more robust than Carrera M96 but still M96 lineage", "valve_service": "Solid lifters require valve clearance checks every 30k miles - not cheap but prevents bigger issues", "track_use": "GT3s are often tracked - look for maintenance records showing frequent fluid changes and clutch replacements", "gt3_pricing": "GT3 parts carry a premium over standard 996 - limited production means limited aftermarket"}',NULL,68.0,85.0,88.0,70.0,68.0,NULL);
INSERT INTO reliability VALUES(252,22,'sample',75.7999999999999971,'{"oil_consumption": "low", "mmi_glitches": "moderate", "air_suspension": "low", "water_pump": "low"}',1400.0,1,'limited','low','{"3_0_tfsi_ea839": "EA839 3.0L V6 turbo is a significant improvement over the earlier EA837 supercharged unit - fewer oil consumption issues", "zf_8hp": "ZF 8-speed automatic is proven and excellent - one of the best transmissions available", "asf_aluminum": "Aluminum Space Frame construction is excellent for rigidity and weight but collision repair requires specialized Audi-certified shops", "complex_electronics": "Flagship Audi electronics - MMI, virtual cockpit, air suspension, active safety - many potential failure points, dealer-only diagnosis"}',NULL,78.0,85.0,88.0,72.0,55.0,NULL);
INSERT INTO reliability VALUES(253,43,'sample',76.5,'[{"cam_roller":"resolved_pre_06082018","piston_ringland":"low_moderate_risk","ecm_seal_recall":"recall_97EV_fixable","mib3_glitches":"low","air_suspension":"low","rear_axle_nut":"recall_42L1_fixable"}]',1500.0,1,'limited','low','[{"ea839_cam_roller":"RESOLVED - roller rockers produced before 06/08/2018 had undersized needle bearings. 2020+ production has revised part 0P2109417"},{"ea839_pistons":"Ongoing concern - 034Motorsport investigation found piston rocking causes stress risers at oil drain holes leading to ringland fracture. 3 piston revisions exist. A8 340hp tune is milder than S4/SQ5 349-354hp, reducing stress"},{"recall_97EV_ecm":"NHTSA 21V111000 - Missing sealing pin on ECM connector, moisture ingress can cause stalling. Dealer fix available"},{"recall_42L1_rear_axle":"NHTSA 21V295000 - Rear axle trailing arm lock nut could break. Dealer fix + follow-up recall 42L5 for alignment"},{"tsb_suspension_creak":"TSB 4022442058489/6 - Front suspension creaking on 2019-2022 A8/S8, control arm bushings"},{"mib3_upgrade":"Facelift uses MIB3 (Qualcomm) replacing MIB2 (Nvidia) - faster, more stable, not backward-compatible"},{"digital_matrix_led":"New DMD headlights with 1.3M micromirrors - unproven long-term aging but no widespread failures reported"}]',NULL,82.0,85.0,87.0,74.0,53.0,'[{"engine":"+3 vs 2018: cam roller failure fully resolved for post-06/2018 production. Piston ringland risk unchanged across all years but A8 tune is milder. Water pump and motor mount failures remain possible","transmission":"Same proven ZF 8HP AL552 - excellent across VAG lineup, electric oil pump for MHEV coasting","chassis":"-1 vs 2018: rear axle trailing arm recall (42L1) and front suspension creaking TSB for 2019-2022. Core ASF structure unchanged and excellent","electronics":"+1 vs 2018: MIB3 upgrade is meaningful improvement over MIB2. Offset by ECM seal recall (97EV) and instrument panel software recall. More digital systems (Digital Matrix LED, Digital OLED) add complexity","ease_of_repair":"-2 vs 2018: MIB3, Digital Matrix LED, Digital OLED, active suspension option all add repair complexity. ASF still requires certified shops for body work"}]');
INSERT INTO reliability VALUES(254,49,'sample',71.5,'{"coolant_pipe_failure": "high", "cardan_shaft_bearing": "moderate", "air_suspension": "moderate", "pcm_freezing": "low"}',1800.0,1,'good','low','{"4_8_v8": "4.8L V8 (non-turbo in base S) is generally reliable but early models had plastic coolant pipes that could fail - updated to metal", "cardan_shaft": "Bearings in the cardan shaft (driveshaft carrier bearing) can fail and cause vibration - well-documented issue", "pdk_early": "Early PDK units are robust but expensive to service - fluid changes every 40k miles recommended", "pcm3_1": "PCM 3.1 infotainment is functional but dated - screen can develop dead pixels, Bluetooth is primitive by modern standards"}',NULL,70.0,82.0,82.0,68.0,55.0,NULL);
INSERT INTO reliability VALUES(255,66,'sample',67.0,'{"turbo_failure": "high", "oil_leaks": "high", "timing_belt": "high", "diverter_valve": "moderate", "ecu_failures": "moderate"}',2200.0,0,'good','moderate','{"2_7t_bi_turbo": "2.7L V6 bi-turbo is notorious - K03 turbos fail around 80-120k miles, replacement requires engine pull or subframe drop", "timing_belt": "Timing belt service is critical and expensive - must be done every 60k miles, water pump and thermostat housing should be replaced simultaneously", "oil_leaks": "Valve cover gaskets, cam chain tensioner gaskets, and oil feed line seals all weep with age - chasing oil leaks is a way of life", "quattro_drivetrain": "Torsen center diff and drivetrain are robust - manual transmission (6-speed) is preferred and stronger than 5-speed auto"}',NULL,62.0,75.0,78.0,58.0,62.0,NULL);
INSERT INTO reliability VALUES(256,101,'sample',77.5,'{"water_pump": "low", "diverter_valve": "low", "haldex_pump": "low", "dsg_mechatronic": "low"}',700.0,0,'excellent','high','{"ea888_gen3": "EA888 Gen 3 2.0T is a massive improvement over Gen 2 - no more oil consumption issues, reliable daily driver", "dsg_dq250": "DQ250 6-speed DSG is proven and reliable with regular fluid changes every 40k miles - mechatronic unit failures are rare", "mqb_platform": "MQB platform means parts sharing with Golf GTI - excellent parts availability and aftermarket support", "haldex_quattro": "Haldex-based AWD (not Torsen) is adequate for the TT - pump failure is known but inexpensive fix"}',NULL,78.0,78.0,78.0,72.0,80.0,NULL);
INSERT INTO reliability VALUES(257,104,'sample',77.4000000000000056,'{"turbo_wastegate_rattle": "low", "rear_main_seal": "low", "spark_plug_coil": "low"}',1100.0,0,'good','low','{"2_5_turbo_flat4": "2.5L turbo flat-4 (base Cayman S) is generally reliable - no IMS issues like old M96, but purists miss NA flat-6 character", "mid_engine_access": "Mid-engine layout means engine access is terrible - even spark plug changes require significant labor", "pdk_excellence": "PDK is arguably the best dual-clutch on the market - incredibly reliable, fast shifts, manual mode is responsive", "platform_shared": "Shares platform with Boxster - excellent parts availability, strong aftermarket for consumables"}',NULL,77.0,85.0,88.0,75.0,62.0,NULL);
INSERT INTO reliability VALUES(258,114,'sample',57.6000000000000014,'{"turbo_failure": "high", "drc_suspension_failure": "high", "timing_chain": "moderate", "transmission_slip": "moderate", "electrical_gremlins": "high"}',3500.0,0,'poor','low','{"4_2_bi_turbo": "4.2L V8 twin-turbo - K03 turbos fail, replacement requires engine removal (15+ hours labor), $8-12k repair", "drc_suspension": "Dynamic Ride Control hydraulic suspension is notoriously failure-prone - many owners convert to conventional coilovers", "zf_5hp24a": "5-speed Tiptronic is the weak link - not rated for sustained 444ft-lbs, valve body issues lead to harsh shifts", "collectible_but_costly": "Only ~1300 sold in the US - increasingly collectible but maintenance costs are supercar-level, many deferred-maintenance examples exist"}',NULL,55.0,68.0,70.0,55.0,45.0,NULL);
INSERT INTO reliability VALUES(259,12,'sample',78.5,'{"water_pump_leak": "moderate", "timing_chain_tensioner": "low", "infotainment_freeze": "moderate"}',600.0,2,'excellent','high','{"EA888_evo4": "Fourth-gen EA888 2.0T is mature and generally reliable - early Mk8s had some software teething issues", "DQ381_DSG": "7-speed wet-clutch DSG is robust - fluid change every 40k mi recommended", "MQB_Evo_electronics": "Mk8 infotainment and touch controls are glitchy - multiple OTA updates released", "GTI_community": "Massive aftermarket and DIY support - one of the most owner-friendly performance cars"}',NULL,78.0,76.0,80.0,73.0,85.0,NULL);
INSERT INTO reliability VALUES(260,62,'sample',53.7999999999999971,'{"W12_coil_packs": "high", "air_suspension_failure": "high", "electrical_module_failures": "high", "coolant_leaks": "moderate"}',2800.0,3,'poor','very_low','{"W12_complexity": "The 6.0 W12 is a maintenance nightmare - two banks of VR6, 24 coils, tight engine bay makes everything difficult", "D1_platform": "Shared with Bentley Continental - luxury car complexity without luxury car dealer support", "air_suspension": "Air suspension components fail regularly and are extremely expensive - many owners convert to coils", "CAN_bus_network": "Multiple interconnected modules fail with age - chasing electrical gremlins is a Phaeton ownership rite of passage", "parts_scarcity": "Many parts are NLA (no longer available) from VW - dealers have limited interest in supporting this orphan"}',NULL,62.0,65.0,72.0,45.0,35.0,NULL);
INSERT INTO reliability VALUES(261,96,'sample',75.5,'{"water_pump": "moderate", "DQ381_mechatronic": "low", "infotainment_gremlins": "low"}',650.0,1,'good','moderate','{"EA888_gen3b": "Proven 2.0T engine - water pump weeping is the most common issue, timing chain revised from earlier gens", "MQB_platform": "Solid MQB architecture - well-proven across VW Group products globally", "DSG_7spd": "Wet-clutch DQ381 is reliable with proper fluid service - avoid neglected used examples", "comfort_coupe": "More complex than a Passat but much less than Phaeton - reasonable repair costs for the class"}',NULL,76.0,76.0,78.0,72.0,75.0,NULL);
INSERT INTO reliability VALUES(262,125,'sample',74.7999999999999971,'{"12v_battery_drain": "moderate", "HV_battery_degradation": "low", "infotainment_reboots": "low"}',1200.0,2,'limited','low','{"J1_platform": "Shared with Porsche Taycan - well-engineered electric platform, proven drivetrain components", "electric_simplicity": "Fewer moving parts than ICE - no oil changes, timing chains, or exhaust systems to fail", "software_issues": "Early models had 12V battery drain and infotainment reboots - largely resolved via OTA updates", "repair_access": "Limited to Audi/Porsche dealers and certified EV shops - independent options growing but still sparse", "battery_warranty": "8yr/100k mi battery warranty provides peace of mind - degradation has been minimal in real-world data"}',NULL,80.0,82.0,85.0,70.0,55.0,NULL);
INSERT INTO reliability VALUES(263,132,'sample',64.9000000000000056,'{"V10_TDI_injectors": "high", "air_suspension": "high", "transfer_case_chain": "moderate", "ABS_module": "moderate"}',1500.0,4,'good','moderate','{"V8_V10_options": "V8 and V10 TDI are powerful but complex and expensive to maintain - the VR6 is the sensible choice", "PL71_platform": "Co-developed with Porsche Cayenne - robust chassis but heavy components wear suspension quickly", "6spd_auto": "Aisin 6-speed is adequate but not exceptional - harsh shifting under load is common", "electrical_aging": "Early 2000s VW electronics do not age well - module failures, gauge cluster issues, CAN bus gremlins", "center_diff": "Transfer case chain can stretch and skip - repair requires dropping the entire drivetrain"}',NULL,68.0,70.0,78.0,58.0,50.0,NULL);
INSERT INTO reliability VALUES(264,133,'sample',70.5999999999999943,'{"adblue_heater": "high", "air_suspension": "moderate", "turbo_actuator": "low", "PCV_system": "moderate"}',1100.0,2,'good','moderate','{"V6_TDI_TSI": "3.0 V6 TDI and 3.6 VR6 are much more reliable than the 7L V8/V10 options", "8spd_auto": "ZF 8-speed is a major upgrade over the old Aisin 6 - smoother and more reliable", "MLB_platform": "Audi-based MLB platform is superior to PL71 - better electronics architecture, lighter weight", "AdBlue_issues": "DEF heater failures are common and expensive - a known VW Group diesel issue", "SUV_weight": "Heavy vehicle means brakes, suspension, and tires wear faster than expected"}',NULL,74.0,75.0,80.0,65.0,58.0,NULL);
INSERT INTO reliability VALUES(265,134,'sample',73.7999999999999971,'{"AdBlue_system": "moderate", "air_suspension": "moderate", "turbo_wastegate": "low"}',900.0,1,'good','moderate','{"MLB_Evo": "Latest MLB Evo platform - significant improvement in electronics and overall reliability", "V6_proven": "3.0 V6 TSI/TDI are well-proven units - major mechanical issues are rare with proper maintenance", "not_US_market": "Discontinued in US after 2017 - parts availability and dealer support are limited stateside", "Euro_complexity": "European-market tech features are advanced but add complexity - matrix LEDs, active anti-roll bars", "ZF_8spd": "Proven ZF 8HP transmission - one of the best automatics in production, reliable with service"}',NULL,78.0,78.0,82.0,70.0,60.0,NULL);
INSERT INTO reliability VALUES(266,107,'sample',77.7999999999999971,'{"blend_door_actuator": "moderate", "evap_purge_valve": "low", "input_shaft_bearing": "moderate"}',450.0,2,'excellent','high','{"cylinder_head_crack": "2013-2015 recall for 1.6 EcoBoost head cracking - verify recall completed by VIN", "coolant_loss": "Monitor coolant levels on pre-2015 models - hot spot design flaw in early heads"}',NULL,72.0,75.0,78.0,73.0,92.0,NULL);
