INSERT INTO reliability VALUES(269,129,'sample',82.5,'{"MT82_shift_forks": "low", "oil_consumption": "very_low", "SYNC_glitches": "low"}',650.0,0,'excellent','high','{"coyote_5.0": "Proven reliable V8 - minimal issues across generations", "MT82_manual": "Some shift fork wear on track-driven cars - Tremec swap is popular upgrade"}',NULL,82.0,80.0,82.0,75.0,92.0,NULL);
INSERT INTO reliability VALUES(270,112,'sample',77.2999999999999971,'{"oil_consumption": "high", "spun_bearings": "moderate", "head_gasket": "low"}',1200.0,1,'good','moderate','{"voodoo_oil_consumption": "Flat-plane 5.2L Voodoo engine known for high oil consumption - some engines consume 1qt/500mi", "engine_failures": "Some spun rod bearing failures documented - track use exacerbates", "Tremec_3160": "Transmission is robust but shifting when cold can be notchy"}',NULL,68.0,80.0,85.0,74.0,82.0,NULL);
INSERT INTO reliability VALUES(271,11,'sample',75.2000000000000028,'{"supercharger_bearing": "low", "heat_management": "moderate", "tire_wear": "high"}',1800.0,0,'limited','low','{"predator_5.2": "Supercharged 760hp - robust but complex, limited parts availability vs standard Mustang", "DCT_only": "Tremec 7-speed dual-clutch only - no manual option, expensive if failure occurs", "track_heat": "Heat management is critical under sustained track use - front coolers help"}',NULL,72.0,78.0,85.0,73.0,70.0,NULL);
INSERT INTO reliability VALUES(272,130,'sample',81.7999999999999971,'{"AFM_lifter_failure": "moderate", "water_pump": "low", "rear_diff_whine": "low"}',700.0,0,'excellent','high','{"LT1_6.2": "Proven pushrod V8 - AFM/DFM lifter failure is the main known issue", "alpha_platform": "Excellent chassis rigidity - suspension components are durable", "poor_visibility": "Not a reliability issue but terrible outward visibility affects daily usability"}',NULL,84.0,80.0,82.0,75.0,86.0,NULL);
INSERT INTO reliability VALUES(273,105,'sample',78.2000000000000028,'{"heat_soak": "high", "supercharger_bypass_valve": "moderate", "electrical_gremlins": "low"}',1100.0,1,'good','moderate','{"LT4_heat_soak": "Supercharged LT4 suffers significant heat soak on track - power drops after 2-3 hot laps", "a8_transmission": "8-speed auto has shudder TSB - fluid flush often helps", "front_engine_access": "Reasonably accessible for a front-mid engine layout"}',NULL,72.0,82.0,85.0,73.0,80.0,NULL);
INSERT INTO reliability VALUES(274,85,'sample',79.5,'{"hybrid_battery_degradation": "low", "brake_booster": "low", "infotainment_freeze": "low"}',500.0,0,'good','moderate','{"1.8_hybrid": "Mature hybrid powertrain - conservative tuning means fewer stress-related failures", "battery_warranty": "Hybrid battery covered by 8yr/100k warranty - degradation is minimal in most climates", "boring_but_reliable": "The Malibu Hybrid is about as exciting as toast but rarely breaks"}',NULL,80.0,82.0,80.0,76.0,78.0,NULL);
INSERT INTO reliability VALUES(275,27,'sample',75.4000000000000056,'{"infotainment_glitches": "moderate", "magnetic_ride_sensors": "low", "premature_brake_wear": "low"}',800.0,0,'good','moderate','{"2.0T_LSY": "Proven GM turbo-four - adequate power, decent reliability", "10spd_auto": "Shared with Camaro and other GM products - well-sorted unit", "luxury_electronics": "More features = more potential failure points in magnetic ride and infotainment"}',NULL,76.0,78.0,80.0,70.0,72.0,NULL);
INSERT INTO reliability VALUES(276,100,'sample',78.0,'{"engine_replacement_early": "low", "magnetic_ride_aging": "moderate", "brake_rotor_warp": "low"}',1500.0,0,'limited','moderate','{"hand_built_LT4": "Hand-assembled supercharged V8 - one C/D long-termer needed engine swap at 1700mi but most are robust", "manual_transmission": "6-speed manual is a joy - 62% of buyers choose it, proven Tremec unit", "magnetic_ride": "Magnetic dampers may need replacement at 60-80k miles - expensive but covered under warranty period", "best_american_sedan": "Widely regarded as the finest American performance sedan ever built"}',NULL,78.0,83.0,88.0,70.0,70.0,NULL);
INSERT INTO reliability VALUES(277,26,'sample',74.5999999999999943,'{"CUE_system_failures": "high", "8spd hesitation": "moderate", "premature_tire_wear": "low"}',900.0,0,'good','moderate','{"CUE_infotainment": "Capacitive touch system is notorious for failures and unresponsiveness - expensive to replace", "8L45_transmission": "8-speed auto has known shudder and hesitation issues - TSB for fluid exchange", "alpha_platform": "Excellent underlying chassis - GM Alpha platform is structurally sound"}',NULL,75.0,77.0,80.0,68.0,72.0,NULL);
INSERT INTO reliability VALUES(278,36,'sample',75.5,'{"CUE_system": "high", "supercharger_bypass": "low", "brake_wear": "moderate"}',1400.0,0,'good','moderate','{"LT4_supercharged": "Same LT4 as C7 Z06 but more space in sedan engine bay - robust but heat management important", "8L90_transmission": "8-speed auto is adequate but not exceptional - some shift quality issues", "CUE_infotainment": "Same problematic capacitive touch system as CTS - known failure point"}',NULL,80.0,76.0,82.0,68.0,70.0,NULL);
INSERT INTO reliability VALUES(279,69,'sample',78.5,'{"rear_diff_clunk": "moderate", "door_lock_actuator": "low", "HVAC_blower": "low"}',650.0,0,'excellent','high','{"LS2_6.0": "LS engine is legendary for reliability - nearly indestructible with basic maintenance", "T56_manual": "Tremec T56 is robust but early units can have syncro issues at high mileage", "sigma_platform": "First-gen Sigma platform - adequate but not as rigid as later Alpha", "age_2004-2007": "Electronics are dated - expect some sensor and module failures on 15+ year old cars"}',NULL,85.0,75.0,74.0,65.0,88.0,NULL);
INSERT INTO reliability VALUES(280,127,'sample',79.2999999999999971,'{"exhaust_manifold_crack": "low", "alternator": "low", "tie_rod_ends": "low"}',600.0,0,'excellent','high','{"392_hemi": "6.4L HEMI is proven and robust - one of the most reliable V8s in production", "LX_platform_age": "Platform dates to 2005 - heavy but incredibly durable, parts everywhere", "torque_management": "Robust drivetrain designed to handle massive torque from factory"}',NULL,83.0,78.0,75.0,72.0,85.0,NULL);
INSERT INTO reliability VALUES(281,126,'sample',76.0999999999999943,'{"supercharger_bearing": "low", "rear_diff": "moderate", "half_shafts": "low"}',1300.0,0,'good','moderate','{"hellcat_6.2": "Supercharged 6.2L is remarkably robust for 717hp - built with forged internals", "8HP90_transmission": "ZF 8-speed is strong but not invincible under repeated launches", "tire_consumption": "Eats rear tires at an alarming rate - not a defect but budget for it", "crude_but_robust": "Engineering philosophy: overbuild everything, refinement is secondary"}',NULL,78.0,77.0,74.0,71.0,78.0,NULL);
INSERT INTO reliability VALUES(282,92,'sample',80.5,'["Skyactiv-G 2.5T cylinder head cracking (class action, 2019-2020, redesigned 2021+)","Carbon buildup on intake valves (direct injection, 60K+ miles)","Valve stem seal oil consumption (pre-2021 2.5T, TSB issued)","MAF sensor contamination triggering fault codes (60K miles)","Cylinder deactivation ATF contamination from lockup clutch wear","Infotainment system freezes requiring reboot"]',550.0,3,'Good (Mazda dealer network + aftermarket)','Moderate (DI maintenance, tight turbo access)','["Skyactiv-G 2.5T is generally reliable 窶・not a Theta II situation","Class action lawsuit alleges cylinder head structural weakness causing coolant leaks and stalling","Covers 2019-2020 CX-5, 2016-2020 CX-9, 2018-2020 Mazda6","Mazda redesigned cylinder head and exhaust manifold gasket for 2021+ 窶・appears to fix issue","Pre-2021 cars should be checked for coolant loss","Carbon buildup is a DI issue, not Mazda-specific 窶・walnut blast every 60-80K","6-speed Aisin auto is proven with no systemic failures","Cylinder deactivation adds complexity and some ATF contamination risk","Engine bay is tight 窶・turbo replacement requires subframe drop"]',NULL,78.0,82.0,85.0,78.0,80.0,'CX-5 2.5T reliability 80.5. The Skyactiv-G 2.5T is a generally reliable turbo engine after 2021 revisions. Pre-2021 cars carry cylinder head crack risk (class action) 窶・buy 2021+ if possible. Transmission is a proven Aisin 6-speed with no systemic issues. Chassis and electronics are above average for mass-market CUV. Carbon buildup and MAF sensor are routine DI maintenance items. Deductions mainly for cylinder head risk and Mazda-tier (not Toyota-tier) electrical aging.');
INSERT INTO reliability VALUES(283,14,'sample',83.2000000000000028,'["Manual transmission synchro issues (especially 2nd/3rd gear, 5 revisions since launch)","Carbon buildup on intake valves (direct injection, 60K+ miles)","Soft top water leaks causing interior and electrical damage","Battery parasitic drain (some ND2 units)","Clutch slave cylinder failure (hydraulic leak)"]',400.0,1,'Excellent (massive Miata aftermarket + Mazda dealers)','High (simple engine bay, huge community, every mechanic knows Miatas)','["ND2 Skyactiv-G 2.0 has forged connecting rods 窶・stronger than ND1 cast rods","Engine is virtually bulletproof in stock form 窶・no engine failure reports on stock power","Transmission is the ND weak link: lightweight design (38-40kg) means material compromises","2019-2021 ND2 transmissions are the safest years; 2022-2023 have more synchro complaints","5 manual transmission revisions 窶・V1 (2016-2017) worst, V5 (2020+) improved","Carbon buildup is a DI issue mitigated by regular highway driving","Soft top leaks are well-documented 窶・check drain tubes, replace weatherstripping","Huge aftermarket support 窶・every part is available from multiple vendors","Miata.net and Reddit r/Miata are unmatched DIY resources"]',NULL,85.0,72.0,88.0,82.0,92.0,'MX-5 ND2 reliability 83.2. The engine (85) is excellent 窶・forged internals, no stock failures reported. Transmission (72) is the weak link with known synchro issues across 5 revisions; buy 2019-2021 for best odds. Chassis (88) is well-engineered with no structural concerns. Electronics (82) are simple 窶・the biggest electrical risk is soft top leaks, not component failure. Ease of repair (92) is among the highest in the database 窶・the Miata community is the gold standard for DIY support. The transmission knocks 11 points off what would otherwise be a 90+ car.');
INSERT INTO reliability VALUES(284,91,'sample',81.5,'["Cylinder head cracking (early 2014 models, TSB issued)","Carbon buildup on intake valves (direct injection, 60K+)","Thermostat housing failure (plastic, 60-120K)","MAF sensor contamination triggering fault codes","PCV valve clogging contributing to carbon buildup","Intake camshaft wear increasing engine noise (high mileage)"]',450.0,2,'Excellent (Mazda shared platform, parts everywhere)','High (simple engine bay, every mechanic can work on it)','["Skyactiv-G 2.5 NA is one of Mazda''s best engines 窶・over a decade in production with minimal issues","Early 2014 models had cylinder head problems 窶・2015+ significantly improved","No class action lawsuit for the 2.5 NA (unlike the 2.5T)","Direct injection carbon buildup is the main recurring maintenance item","Engine life expectancy 200K+ miles with regular maintenance","6-speed Aisin auto is the same proven unit used across Mazda lineup","Shared platform with CX-5 and Mazda3 means parts are everywhere","Transverse 4-cylinder engine bay is simple and accessible","European owners report excellent long-term reliability for Skyactiv-G engines"]',NULL,80.0,82.0,82.0,78.0,85.0,'Mazda6 GJ reliability 81.5. The Skyactiv-G 2.5 NA is a proven workhorse with no class actions and 200K+ mile life expectancy. Engine (80) loses points for early 2014 cylinder head issues and DI carbon buildup, but 2015+ cars are excellent. Transmission (82) is the same bulletproof Aisin 6-speed across Mazda''s lineup. Chassis (82) is solid with no structural concerns. Electronics (78) are typical Mazda 窶・not Toyota-tier but no epidemics. Ease of repair (85) benefits from shared platform and transverse simplicity. A reliable midsize sedan that just works.');
INSERT INTO reliability VALUES(285,89,'sample',60.5,'["Apex seal failure 窶・THE defining rotary weakness, requires full engine rebuild ($5K-10K)","Sequential twin turbo failure from heat cycling and oil contamination ($3K-5K rebuild)","Cooling system overheating 窶・AST cap failure, coolant pipe leaks, cracked radiator","Excessive oil consumption (1 quart per 2500 miles normal, more indicates seal failure)","Catalytic converter clogging from carbon deposits cascades into engine damage","Vacuum hose degradation causing sequential turbo system malfunction","Turbo manifold cracking from extreme heat"]',2500.0,0,'Poor (rotary specialists only, JDM import parts scarce)','Low (rotary expertise required, complex sequential turbo, frequent rebuilds)','["13B-REW apex seals are the engine killer 窶・oil starvation and pre-ignition from carbon are primary causes","Well-maintained stock engines CAN exceed 150K miles but this is exceptional, not typical","Rebuild at 40-80K miles is the expected norm, not a failure of maintenance","Sequential twin turbo system is complex and failure-prone 窶・many owners convert to single turbo","Cooling system overhaul is essential preventative maintenance","Rotary engines burn oil by design (oil metering pump) 窶・must check oil every fill-up","Compression test is CRITICAL when buying: 100psi spec, below 85psi = rebuild needed","Must use non-synthetic oil and consider premix for seal lubrication","Engine must be warmed up before shutdown to prevent flooding and carbon buildup","Parts increasingly scarce 窶・FD was never sold in large volumes outside Japan","Rotary specialists are few and far between 窶・most mechanics will not touch it"]',NULL,42.0,80.0,88.0,62.0,45.0,'RX-7 FD reliability 60.5 (catastrophe penalty applied: engine 42 < 50). The 13B-REW twin-turbo rotary defines "unreliable by design" 窶・apex seals fail at 40-80K miles requiring $5K-10K rebuilds. The sequential turbo system, cooling system, and catalytic converter all compound the engine''s inherent weaknesses. Transmission (80) and chassis (88) are excellent 窶・the FD drives like a dream WHEN the engine runs. Electronics (62) are simple but aging vacuum hoses create turbo system gremlins. Ease of repair (45) reflects rotary specialist scarcity and JDM parts unavailability. The raw score of 62.0 drops to 60.5 with the catastrophe penalty (min dim=42, penalty=0.976). This car earns its reputation: legendary chassis, unreliable engine.');
INSERT INTO reliability VALUES(286,109,'sample',65.7000000000000028,'["Apex seal failure 窶・same 13B-REW fundamental weakness (improved but not eliminated)","Sequential twin turbo aging 窶・20+ year old turbos, many already rebuilt or replaced","Cooling system aging 窶・radiator, AST cap, coolant pipes all 20+ years old","Vacuum hose degradation (rubber 20+ years old) affecting turbo operation","Oil consumption inherent to rotary design","Spirit R-specific parts unobtainium 窶・Recaro seats, BBS wheels, unique trim"]',2500.0,0,'Poor (rotary specialists only, Spirit R trim parts unobtainium)','Low (rotary expertise required, Spirit R-specific parts rare)','["Spirit R is the FINAL FD 窶・Series 8 with all refinements Mazda learned over 10 years of production","Reinforced apex seals and better cooling channels than earlier Series 6/7","Engine is marginally more reliable than 1993 FD but fundamentally the same 13B-REW","Must meet 2002 build quality 窶・these are the best-sorted FDs from the factory","Only 1,500 Spirit Rs produced 窶・Spirit R-specific parts are essentially unobtainable","Standard 13B-REW engine parts shared across all FDs 窶・engine parts not the scarcity issue","Most Spirit Rs are collector-owned and maintained to a higher standard than average FDs","Manual transmission only 窶・no auto weakness","Same rotary maintenance demands: premix, frequent oil changes, warm-up before shutdown","Compression test still critical 窶・100psi spec, below 85psi = rebuild needed"]',NULL,48.0,85.0,90.0,65.0,48.0,'RX-7 Spirit R reliability 65.7 (catastrophe penalty applied: engine 48 < 50). The best FD Mazda ever built 窶・Series 8 refinements improve reliability over earlier cars but the fundamental 13B-REW apex seal weakness remains. Engine (48) is 6 points higher than standard FD (42) thanks to reinforced seals and better cooling, but still below the catastrophe threshold. Transmission (85) benefits from manual-only specification. Chassis (90) is the highest in this Mazda batch 窶・Bilstein, cross-drilled brakes, final production quality. Electronics (65) are the most mature FD electronics. Ease of repair (48) is same as FD minus Spirit R-specific parts scarcity. The raw score of 66.1 drops minimally to 65.7 (penalty=0.994, engine is close to 50).');
INSERT INTO reliability VALUES(287,90,'sample',54.7000000000000028,'["Apex seal failure and compression loss 窶・most problematic rotary Mazda ever made","Engine flooding from short trips and cold shutdowns 窶・excess fuel soaks spark plugs","Low compression causing hot-start failure (cannot restart within 3-5 min of shutdown)","Catalytic converter clogging 窶・unburned fuel melts cat, creates backpressure, kills engine","Ignition coil pack failure 窶・chronic, causes misfires, rough idle, power loss","Starter motor failure from chronic cranking during flood-clearing procedures","Engine harness wear from component interference","Door lock actuator failure","Waterlogged headlights"]',3000.0,2,'Poor (rotary specialists only, Renesis-specific parts scarce)','Low (rotary expertise required, frequent engine attention needed)','["Renesis 13B-MSP is rated ''Not Suggested'' by multiple reliability sources","Mazda issued extended warranties for early RX-8 engines due to widespread compression loss","Many engines fail before 80-100K miles 窶・even well-maintained examples struggle to 125K","The Renesis is WORSE than the 13B-REW in the RX-7 窶・NA but more failure modes","Flooding is a design flaw: engine must be fully warmed before shutdown, no short trips","Hot-start failure (low compression when warm) is the telltale sign of engine death","Catalytic converter failure cascades: bad coils/plugs -> rich mixture -> cat melts -> backpressure -> apex seal death","Oil must be checked every fill-up 窶・rotary burns oil by design","Compression test is essential when buying: below 85psi means rebuild needed ($4K-8K)","Must use mineral oil (NOT synthetic) to prevent carbon residue","More RX-8s produced than FD RX-7s so parts slightly more available","R3 (2009-2011) is the best year 窶・improved engine, better cooling, revised ECU","Still fundamentally unreliable 窶・buy one with a fresh rebuild or budget for one"]',NULL,35.0,78.0,82.0,58.0,40.0,'RX-8 R3 reliability 54.7 (catastrophe penalty applied: engine 35 < 50). The Renesis 13B-MSP is the most problematic rotary Mazda ever made 窶・rated "Not Suggested" by reliability sources. Engine (35) scores lowest in this entire Mazda batch: apex seals, flooding, low compression, catalytic converter cascading failure, chronic coil pack issues. Most engines need rebuild by 80-100K miles. Transmission (78) is decent 窶・not the problem. Chassis (82) is excellent with brilliant handling, completely let down by the engine. Electronics (58) suffer from coil pack failures, starter motor death from chronic cranking, and harness wear. Ease of repair (40) is the lowest 窶・while parts are slightly more available than FD, the Renesis-specific failure modes make it arguably worse to own. The raw score of 57.25 drops to 54.7 with the catastrophe penalty (min dim=35, penalty=0.955). If you want the RX-8 experience, buy one that already has a fresh engine rebuild.');
INSERT INTO reliability VALUES(288,15,'sample',67.2000000000000028,'{"Fuel pump sudden failure": 3, "Excessive oil consumption": 2, "Premature timing chain wear": 2, "Brake disc corrosion (standing)": 2, "Sporadic warning lights": 2}',850.0,2,'Fair (Renault/Nissan shared engine, but Alpine-specific body parts scarce)','Low','{"MR18DDT 1.8T": "Nissan-sourced turbo four. Same as Megane RS 280/300. Generally reliable if serviced regularly. Oil consumption and timing chain wear are known issues from neglect.", "Getrag 7DCT300": "Dual-clutch, mostly reliable. Some shift hesitation reported.", "Aluminum chassis": "Bonded and riveted aluminum. Lightweight but rear wheel arch corrosion is a known weak spot.", "Fuel pump": "Sudden failure without warning. Root cause unclear (control module overheating suspected). Third-party cooling kit available.", "Niche brand": "Low volume (~20K global). Alpine dealer network thin outside Europe. Parts wait times can be long."}',NULL,72.0,78.0,80.0,65.0,45.0,NULL);
INSERT INTO reliability VALUES(289,46,'sample',59.2000000000000028,'{"5.0L SC timing chain tensioner": 3, "Water pump failure": 2, "Infotainment/can bus failures": 3, "Coolant loss (heater core)": 2, "Air suspension (if equipped)": 3}',1400.0,4,'Poor (Jaguar specialist required, many parts dealer-only)','Low','{"5.0L AJ-V8 SC": "Supercharged V8. Timing chain tensioner and water pump are known failure points. Coolant loss from heater core O-rings common.", "ZF 6HP28": "Proven unit but Jaguar-specific tuning. Generally OK at moderate mileage.", "Aluminum body": "Riv-bonded aluminum monocoque. No rust issues. Excellent chassis rigidity.", "Jaguar electronics": "THE weakness. CAN bus gremlins, infotainment crashes, module failures. Ages poorly. Many owners report constant warning lights.", "Air suspension": "Optional but when it fails, expensive. Compressor and air bags at 80-120K miles."}',NULL,70.0,72.0,75.0,42.0,40.0,NULL);
INSERT INTO reliability VALUES(290,55,'sample',51.0,'{"3.0L SC timing chain stretch": 3, "Coolant loss/leak": 3, "Air suspension failure": 3, "Electrical module failures": 3, "Infotainment black screen": 3}',1800.0,6,'Poor (expensive parts, dealer specialist required)','Low','{"3.0L SC V6": "Timing chain stretch at 60-100K. Coolant loss from multiple potential sources. Supercharger nose cone bearing whine.", "ZF 8HP": "Proven transmission but stressed in 2.3-ton SUV. Fluid changes critical.", "Air suspension": "The Achilles heel. Compressor fails, air bags leak. $3-5K per corner. Many owners convert to coils.", "Electronics": "Legendary for all the wrong reasons. Screen goes blank, modules fail, warning lights cascade. Terrain Response system adds complexity.", "Cost to own": "Among the most expensive SUVs to maintain. $2-3K/year typical after warranty."}',NULL,62.0,68.0,55.0,38.0,35.0,NULL);
INSERT INTO reliability VALUES(291,68,'sample',71.0,'{"ES9 V6 coil pack failure": 2, "Suspension bush wear": 2, "Climate control servo failure": 1, "Power window regulators": 1, "Age-related trim degradation": 1}',500.0,1,'Fair (PSA shared parts, but coupe-specific panels scarce)','Moderate','{"ES9 V6": "3.0L NA V6 (also used in Renault Laguna, Citroen C5). Proven unit. Coil packs are the main failure item.", "4-speed auto / 5-speed manual": "Both proven. Auto is old-school hydraulic, unbreakable but slow. Manual is excellent.", "Pininfarina body": "Built at Pininfarina Italy, not PSA main plant. Higher build quality than standard 406.", "Electronics": "Simple era (late 90s/early 2000s). Few electronic failure points. Analog gauges.", "Aging": "20+ years old now. Rubber components, suspension bushes, trim pieces aging. Parts getting scarce outside Europe."}',NULL,78.0,72.0,75.0,68.0,60.0,NULL);
INSERT INTO reliability VALUES(292,71,'sample',79.9000000000000056,'{"12V battery replacement (3-4 yr)": 1, "MCU/eMMC wear (pre-2018)": 2, "Phantom braking (Autopilot)": 2, "Suspension control arm (high mileage)": 2, "HV battery connector recall": 2}',450.0,10,'Good (Tesla mobile service, OTA updates, growing parts network)','Moderate','{"Electric motor": "Permanent magnet reluctance motor. Very few reported failures. No oil changes, no spark plugs, no timing belt. Revolution counts as reliability.", "Reduction gear": "Single-speed. No gears to shift, no clutches to wear. Essentially a differential. Virtually zero failures reported.", "Software": "Tesla''s strength and weakness. OTA updates fix bugs but also introduce new ones. Phantom braking, Autopilot glitches, MCU reboots.", "Build quality": "Not a reliability issue per se, but panel gaps and paint quality are inconsistent. Improving over model years.", "HV battery": "Degradation is gradual and predictable. 70-80% capacity at 150K+ miles typical. Battery connector recall on early units."}',NULL,88.0,90.0,78.0,62.0,72.0,NULL);
INSERT INTO reliability VALUES(293,70,'sample',76.2000000000000028,'{"Tri-motor inverter firmware updates": 2, "HV battery heat management (track)": 2, "MCU/infotainment resets": 3, "Air suspension (if equipped)": 2, "Complex electronics diagnostics": 2}',700.0,12,'Fair (Tesla service centers, but Plaid-specific parts limited)','Low','{"Tri-motor drivetrain": "Three motors = more complexity but individually proven. Rear motors are the same PM reluctance units as M3. Inverter firmware updates are common.", "Reduction gears": "Three separate gearsets. Proven design, no mechanical failures reported.", "Software complexity": "More systems than M3: active damping, rear steering, Track Mode. More code = more bugs. MCU reboots while driving reported.", "Platform age": "Model S platform dates to 2012. Plaid is heavily updated but some legacy architecture remains.", "Repair costs": "Out-of-warranty Tesla repairs are expensive. Battery replacement $12-20K. Motor replacement $5-10K."}',NULL,85.0,88.0,75.0,58.0,65.0,NULL);
INSERT INTO reliability VALUES(294,72,'sample',80.5,'{"12V battery (3-4 yr)": 1, "Suspension clunk (early builds)": 2, "Steering rack vibration": 1, "HV battery connector recall": 2, "Heat pump failure (cold climates)": 2}',400.0,11,'Good (most DIY-friendly Tesla, abundant parts)','High','{"Electric motor": "Same proven PM reluctance motor as M3. Highest production volume of any EV drivetrain.", "Reduction gear": "Single-speed, proven. Zero mechanical failures at scale.", "Suspension": "Early 2020-2022 builds had suspension clunk issues. Mostly resolved in later builds.", "Heat pump": "Standard on MY. Some failures in very cold climates. $1K repair.", "DIY": "Most DIY-friendly Tesla. Abundant parts, extensive community knowledge, Munro teardowns available."}',NULL,88.0,90.0,76.0,65.0,74.0,NULL);
INSERT INTO reliability VALUES(295,73,'sample',72.5,'{"Software updates (over-the-air)": 1, "Charging speed inconsistency": 2, "Infotainment quirks": 1, "Single-phase AC charging limitation": 2, "Suspension calibration (early units)": 1}',350.0,1,'Fair in China; Poor outside Asia (limited dealer network)','Low','{"Blade Battery LFP": "BYD''s crown jewel. LFP chemistry = no thermal runaway risk. 2000+ charge cycles claimed, 5000 advertised. 8-year/160K km warranty.", "Electric motor": "BYD manufactures own motors. Proven across millions of vehicles (buses, taxis, passenger cars). 93% of BYDs still within spec at 100K km.", "Reduction gear": "Single-speed, standard EV design. No reported issues.", "Infotainment": "Feels underdeveloped per reviews. Menu navigation inconsistent. Charging performance below claimed 120kW DC.", "Parts/Service": "Excellent in China and expanding markets. Limited or non-existent in most Western markets."}',NULL,80.0,82.0,75.0,65.0,55.0,NULL);
INSERT INTO reliability VALUES(296,75,'sample',56.7999999999999971,'{"Infotainment crashes/glitches": 3, "Air suspension issues": 2, "Electronic module failures": 2, "Strange cabin noises": 2, "Unproven long-term durability": 3}',600.0,0,'Poor (limited dealer network, mainly Middle East and China)','Low','{"Electric motor": "Dual-motor setup. Limited long-term data. No catastrophic failure reports yet but very small sample size.", "Air suspension": "Standard equipment. Smooth ride but repair costs unknown at high mileage.", "Electronics": "Infotainment system widely criticized as buggy and unfinished. Multiple owner reports of system crashes.", "Build quality": "Thin metal panels (hood flexes with finger push). Interior materials look premium but feel synthetic.", "Service": "Almost no service network outside China and Middle East. Parts availability essentially zero in Western markets."}',NULL,68.0,70.0,65.0,55.0,35.0,NULL);
INSERT INTO reliability VALUES(297,115,'sample',75.7999999999999971,'{"ICCU charging failure (shared E-GMP issue)": 3, "12V battery drain": 2, "N-specific brake software recall": 3, "Software/driver-assist glitches": 1, "Tire wear (performance rubber)": 1}',500.0,3,'Good (Hyundai dealer network, 10-year powertrain warranty)','Moderate','{"E-GMP motor": "Proven platform shared with EV6, Ioniq 5, Genesis GV60. Motor failures are rare.", "Reduction gear": "Standard E-GMP unit. N-tuned for faster response but mechanically proven.", "ICCU": "The known E-GMP issue. Integrated Charging Control Unit can fail, disabling DC/AC charging. Mostly pre-2023 cars. Fixed in later production.", "N brake software": "Performance models had a recall for left-foot braking logic that could reduce stopping effectiveness. Software fix.", "Warranty": "Hyundai 10-year/100K powertrain + 8-year EV component warranty. Strong safety net."}',NULL,82.0,84.0,78.0,60.0,68.0,NULL);
INSERT INTO reliability VALUES(298,116,'sample',62.5,'{"Front lift system failure": 2, "MagneRide damper failure (high mileage)": 2, "Battery drain (low use)": 1, "Carbon ceramic brake replacement cost": 3, "E-gear actuator (high mileage)": 2}',3500.0,1,'Poor (Lamborghini dealer only, parts expensive and sometimes backordered)','None','{"5.2L NA V10": "Hand-assembled at Sant''Agata. Shared architecture with Audi R8. Naturally aspirated = no turbos to fail. Proven robust at high mileage.", "LDF 7-speed DCT": "Audi-derived dual-clutch. Excellent reliability. E-gear actuator can need service at high mileage.", "Carbon-aluminum hybrid chassis": "Incredibly rigid. No structural issues reported. aerospace-grade construction.", "Electronics": "Complex when they fail: MagneRide sensors, front lift system, ECU. Expensive diagnostics. Lamborghini-specific tools required.", "Cost of ownership": "Oil change $800+. Brake job $5-10K (carbon ceramics). Annual service $3-5K. Front lift system $4K+. This is the real reliability penalty."}',NULL,80.0,82.0,85.0,62.0,25.0,NULL);
INSERT INTO reliability VALUES(299,124,'sample',64.0,'{"Infotainment/screen freezes and reboots": 3, "Rear subframe wiring harness (recall)": 3, "Rear camera display failure (recall)": 2, "Half-shaft bolts (recall)": 3, "Driver-assist faults (adaptive cruise)": 2}',900.0,5,'Poor (limited service network, startup growing pains)','Low','{"Motor/drivetrain": "Lucid miniaturized in-house motor design. Very efficient. Catastrophic motor failures are rare.", "Reduction gear": "Proven, no issues reported.", "Wiring harness recall": "2024-2025 Pure RWD models. Harness too short, strains connection, causes power loss. Recall fix is replacement.", "Software": "The Achilles heel. Screen freezes, driver-assist dropouts, CarPlay glitches, lost settings. Multiple OTA updates but still buggy.", "Service network": "Small and variable. Mobile service available in some areas. Some owners report long waits and repeat visits."}',NULL,78.0,80.0,75.0,48.0,40.0,NULL);
INSERT INTO reliability VALUES(300,76,'sample',41.8999999999999985,'{"Vehicle unresponsive (stranded)": 3, "Software crashes (infotainment, gear selector)": 3, "Lane assist malfunction (pulls wrong direction)": 3, "Rolling backward on incline": 3, "Climate control malfunction (cold air when off)": 2}',700.0,2,'Very Poor (tiny dealer network, parts unavailable, slow service)','None','{"Motor": "Basic EV motor. Functions but throttle response has >1 second delay 窶・dangerous in emergency situations.", "Reduction gear": "Functional but unremarkable.", "Software": "Worst in any production vehicle tested. Menus crash, gear selector intermittent, backup camera 240p quality, settings don''t persist between drives. Core vehicle systems dependent on unfinished software.", "Build quality": "Body squeaks and rattles. Paint color uneven. Broken parts found on delivery. Feels like a prototype rushed to market.", "Safety": "ESC and hydraulic brake assist error messages within first week. Vehicle unresponsive incidents reported. Car rolled while parked in gear."}',NULL,55.0,58.0,50.0,30.0,25.0,NULL);
INSERT INTO reliability VALUES(301,74,'sample',67.2000000000000028,'{"High complaint-to-sales ratio (239 penalty points Q1 2025)": 3, "Interior edge wear (light colors)": 1, "Energy efficiency below Tesla": 1, "Low chassis (battery damage risk)": 1, "Unusual accident rate (driver-related)": 1}',400.0,0,'Good in China; Non-existent outside China','Low','{"Motor": "Dual-motor setup, 673hp. No reported motor failures. Autobild durability test showed excellent results.", "Reduction gear": "Standard dual-motor reduction gear setup. No reported issues.", "Quality ranking": "Dead last in 2025 Q1 China Automobile Quality Network ranking for large BEV sedans. 239 penalty points, 56 above segment average. High complaint-to-sales ratio.", "Build quality": "Robotic factory, AI quality control, tight panel gaps. Physical build quality is genuinely impressive.", "Service": "5-year overall warranty, 8-year battery/motor warranty in China. Zero service infrastructure outside China. Xiaomi won''t export before 2027."}',NULL,75.0,78.0,78.0,62.0,45.0,NULL);
