INSERT INTO reliability VALUES(316,164,'librarian+analysis',77.7999999999999971,'[{"ofhg_coolant":"moderate","coolant_loss":"low_moderate","pcv_valve":"moderate_age","water_pump":"moderate","air_suspension":"moderate","ib_brake":"recall_fixable"}]',NULL,NULL,'good','moderate','[{"b58_gen1_reliability":"Widely considered BMW most reliable modern turbo engine. EngineScope 93/100. C&D 40K mile test: zero unscheduled repairs, zero oil consumption. Closed-deck block, forged crank, integrated water-to-air intercooler","ofhg_coolant_leak":"Most common B58 issue. Plastic oil filter housing combines filtration, heat exchange, coolant routing. Thermoplastic degrades under heat cycles. Fix: replace housing assembly -1500","coolant_loss":"Expansion tank cap seepage, minor hose cracks. Usually minor top-off every 10-15K mi. Monitor for rapid loss","pcv_valve_diaphragm":"SIB 01 14 23 extended warranty. Rough idle, unmetered air. Age-related, not design flaw","oil_pump_gen1":"Gen1 B58 oil pump has solid track record. Oil pump plastic adjusting ring issue affects B58TU only (2019-2022). This is the Gen1 - safe","ib_brake_recall":"NHTSA 21V-062 and 24V-104. Integrated Brake system loss of power assist, ABS, DSC. Affects all G11 7 Series. Dealer fix available","air_suspension":"Same two-axle air suspension as 750i. Rear air springs can leak at 80-120K mi. Strut replacement -3500 per corner","display_key":"Known weak point - charging issues, connectivity drops. Not critical but annoying"}]',NULL,85.0,88.0,85.0,65.0,60.0,'[{"engine":"B58 Gen1 has no fundamental design flaws. Issues are age/maintenance-related gasket and plastic component degradation, not design flaws. OFHG and coolant are predictable progressive failures. vs N63 (62): no hot-vee turbo heat, no engine-out timing chain, no valve stem seal oil consumption. +23 vs N63 is justified by EngineScope 93 vs 42 ratings and drastically lower repair costs","transmission":"Same proven ZF 8HP50 as 750i. One of the best automatics in the industry, generally reliable to 150K+ mi with fluid changes","chassis":"Same air suspension, same Carbon Core body as 750i. IB brake recall applies to all G11. Air spring leaks are age/mileage related","electronics":"Same iDrive (ID5), same Gesture Control, same DSC module as 750i. Fewer engine management sensors than N63 (single turbo vs twin, no cylinder deactivation). Display key is a known weak point. LCI gets ID6 with more complexity","ease_of_repair":"B58 I6 is FAR more accessible than N63 V8 - no engine-out jobs for timing chain or valve stem seals. OFHG and cooling jobs are standard labor. Still a 7 Series (low volume, tight bay) so parts availability harder than 3/5 Series. +14 vs N63 (46) reflects accessibility gain"}]');
