INSERT INTO reliability VALUES(328,176,'librarian+analysis',74.5999999999999943,'["cooling system failures","thrust bushing wear"]',NULL,NULL,'good','moderate','["nikasil bore wear: early M62 blocks susceptible to sulfur damage in fuel","DISA valve: intake manifold adjuster can fail causing rough idle"]',NULL,72.0,80.0,78.0,75.0,68.0,'["engine: M62 cooling and Nikasil issues lower engine score","transmission: ZF 5HP reliable with fluid changes","chassis: E38 chassis robust with minor bushing wear","electronics: EWS and module aging typical for era","ease_of_repair: decent access but some specialty tools needed"]');
INSERT INTO reliability VALUES(329,177,'librarian+analysis',70.2000000000000028,'["air suspension failures","timing chain guides"]',NULL,NULL,'good','moderate','["4.2 V8 chain tensioners: plastic guides degrade requiring engine-out service","air suspension: compressor and air bags fail with age"]',NULL,76.0,82.0,68.0,65.0,60.0,'["engine: strong V8 but chain guide failure is costly","transmission: ZF 6HP generally reliable","chassis: air suspension is Achilles heel","electronics: MMI and module failures common","ease_of_repair: ASF space frame limits access"]');
INSERT INTO reliability VALUES(330,178,'librarian+analysis',82.2000000000000028,'["vacuum system leaks","climate control servo pods"]',NULL,NULL,'good','moderate','["AC servo pods: vacuum-operated flaps degrade causing HVAC issues","wiring harness: biodegradable insulation used in early 90s units"]',NULL,85.0,88.0,73.0,83.0,82.0,'["engine: M117 legendary durability","transmission: 4-speed auto nearly indestructible","chassis: W126 tanks but bushings age","electronics: simple systems age well","ease_of_repair: excellent parts availability and simple layout"]');
INSERT INTO reliability VALUES(331,179,'librarian+analysis',67.0,'["Airmatic suspension","SBC brake system"]',NULL,NULL,'good','moderate','["Airmatic: strut and compressor failures expensive to repair","SBC brake-by-wire: pump module failure disables braking","M273 camshaft adjuster: early units had cam gear wear"]',NULL,68.0,74.0,65.0,62.0,66.0,'["engine: M273 cam adjuster issues known","transmission: 7G-Tronic generally robust","chassis: Airmatic and SBC are major failure points","electronics: COMAND and sensor failures prevalent","ease_of_repair: complex systems require STAR diagnosis"]');
INSERT INTO reliability VALUES(332,180,'librarian+analysis',71.4000000000000056,'["oil consumption","water pump failures"]',NULL,NULL,'good','moderate','["3.0 TFSI supercharger: Eaton TVS unit reliable but oil consumption can be high","thermal management: water pump and thermostat housing cracks common"]',NULL,75.0,85.0,68.0,67.0,62.0,'["engine: supercharged V6 solid but oil consumption noted","transmission: ZF 8HP excellent reliability","chassis: aluminum ASF limits repair options","electronics: MMI and sensor aging typical","ease_of_repair: aluminum construction limits DIY"]');
INSERT INTO reliability VALUES(333,181,'librarian+analysis',68.4000000000000056,'["P06DA00_oil_pump_solenoid","cylinder_deactivation_lifters","hot_v_turbo_seals","valve_cover_gasket","airmatic_struts"]',NULL,NULL,'good','moderate','["P06DA00: Oil pump solenoid in oil pan. On 4MATIC requires engine+trans removal. 5500-9500. The M176 defining failure","cylinder_deactivation: Lifters for cylinders 2,3,5,8 can fail causing rough idle. Up to 7500","hot_v_turbo: Turbos inside V means heat degradation of oil seals. 3500-5500 per turbo","valve_cover: Front end removal required for gasket service. 1500-3000","airmatic: Same family as pre-facelift but improved. Struts wear at 80-100K"]',NULL,70.0,78.0,68.0,68.0,55.0,'["engine: M176 trades M278 cam sensor ECU risk for oil pump solenoid risk. Hot-V adds turbo heat stress. Cylinder deactivation adds lifter complexity","transmission: 9G-Tronic materially better than 7G. Smoother. Fewer conductor plate issues","chassis: AIRMATIC improved but same fundamental wear pattern. MBC improved over pre-facelift","electronics: NTG6 COMAND with CarPlay is genuine usability improvement. Better driver assists. Still 100 ECUs","ease_of_repair: Same aluminum body issue. Oil pump solenoid on 4MATIC is engine+trans removal"]');
INSERT INTO reliability VALUES(334,183,'librarian+analysis',87.5999999999999943,'["vvti_gear_rattle","water_pump_weep","oil_cooler_pipe_leak","torque_converter_shudder"]',NULL,NULL,'excellent','high','["vvti_rattle: Cold start rattle from VVT-i gear assembly","u660e_tc: Torque converter shudder under light throttle"]',NULL,93.0,87.0,86.0,84.0,88.0,'["engine: 2GR-FE proven, watch VVT-i gear","transmission: U660E solid but TC shudder common","electronics: Standard Toyota reliable","ease_of_repair: Familiar platform, good parts availability"]');
INSERT INTO reliability VALUES(335,184,'librarian+analysis',85.2000000000000028,'["inverter_converter_recall","brake_booster_leak","hybrid_battery_degradation","egr_cooler_clog"]',NULL,NULL,'excellent','high','["inverter_recall: OEM recall for inverter/converter, free fix","brake_booster: Nitrogen leak causes hard pedal"]',NULL,90.0,92.0,86.0,80.0,78.0,'["engine: 2AR-FXE Atkinson cycle proven","transmission: e-CVT planetary bulletproof","electronics: Hybrid controls reliable after recalls","ease_of_repair: Hybrid systems need specialist tools"]');
INSERT INTO reliability VALUES(336,185,'librarian+analysis',84.4000000000000056,'["oil_dilution_mild","intake_valve_carbon","ac_compressor_failure","infotainment_freezes"]',NULL,NULL,'excellent','high','["oil_dilution: Direct injection, less severe than 1.5T","infotainment: 2018 head unit laggy and glitchy"]',NULL,86.0,84.0,86.0,82.0,84.0,'["engine: K20C4 derived from Type R, robust","transmission: 6MT simple and durable","electronics: Infotainment glitches common","ease_of_repair: Modern but accessible"]');
INSERT INTO reliability VALUES(337,186,'librarian+analysis',84.4000000000000056,'["vtc_actuator_rattle","oil_consumption","direct_injector_seals","display_audio_glitches"]',NULL,NULL,'excellent','high','["vtc_actuator: Cold start rattle, TSB/recall available","oil_consumption: Some K24W3 consume oil, monitor level"]',NULL,87.0,80.0,85.0,82.0,88.0,'["engine: K24W3 solid, VTC actuator is known issue","transmission: 6MT simple","electronics: Display Audio head unit laggy","ease_of_repair: Excellent parts availability and docs"]');
INSERT INTO reliability VALUES(338,187,'librarian+analysis',82.0,'["cylinder_head_crack_early","thermostat_housing","motor_mount_wear","infotainment_reboots"]',NULL,NULL,'good','high','["cylinder_head: 2014-2015 only, revised casting after","motor_mount: Passenger side mount fails early"]',NULL,84.0,84.0,82.0,76.0,84.0,'["engine: Skyactiv reliable after head revision","transmission: 6MT smooth, DMF clutch wear","electronics: Infotainment reboots occasional","ease_of_repair: Compact packaging adds time"]');
INSERT INTO reliability VALUES(339,188,'librarian+analysis',77.4000000000000056,'["ringland_failure","head_gasket","turbo_oil_coking","banjo_bolt_starvation"]',NULL,NULL,'good','high','["ringland: #4 cylinder piston ringland cracks under boost","banjo_bolt: Oil feed filter clogs, many remove"]',NULL,77.0,80.0,76.0,72.0,82.0,'["engine: EJ255 turbo has ringland and head gasket risks","transmission: 5MT robust, clutch upgrades common","chassis: AWD system reliable","ease_of_repair: Boxer access tight, head gasket expensive"]');
INSERT INTO reliability VALUES(340,189,'librarian+analysis',80.5999999999999943,'["head_gasket","timing_belt_service","rust_rockers","valve_cover_gasket"]',NULL,NULL,'good','high','["timing_belt: Interference engine, 105K interval","rust: Rocker panels and rear quarters"]',NULL,85.0,80.0,74.0,78.0,86.0,'["engine: EJ22 exceptionally durable for Subaru","transmission: 5MT durable","chassis: Rust is the real killer","ease_of_repair: Simple and well-documented"]');
INSERT INTO reliability VALUES(341,190,'librarian+analysis',86.7999999999999971,'["water_pump","vvt_oil_line"]',NULL,NULL,'excellent','high','["2GR-FE: Same engine as Camry V6 and Lexus ES350. 300k+ miles common. Rubber VVT oil line recalled. Minor water pump seep at 80-110K."]',NULL,93.0,88.0,82.0,80.0,86.0,'["2GR-FE benchmark reliability", "6-speed proven", "Same parts as Camry V6"]');
INSERT INTO reliability VALUES(342,191,'librarian+analysis',85.7000000000000028,'["rear_brake_caliper","hybrid_battery_fan"]',NULL,NULL,'excellent','high','["2.5L HSD proven across Prius and Camry Hybrid", "Rear brake caliper freeze at 40K ($700)", "Hybrid battery fan filter needs cleaning"]',NULL,88.0,92.0,82.0,80.0,82.0,'["HSD bulletproof", "eCVT planetary indestructible", "40 mpg sleeper"]');
INSERT INTO reliability VALUES(343,192,'librarian+analysis',83.4000000000000056,'["vvt_oil_line","sliding_door_latch","rear_tire_wear"]',NULL,NULL,'excellent','high','["2GR-FE same as Camry/Lexus. Rubber VVT line recalled. 8-speed (2017+) jerky at low speed. Sliding door latch recall 2011-2016. AWD rear tire wear."] ',NULL,89.0,83.0,80.0,76.0,85.0,'["2GR-FE parts everywhere", "6-speed better than 8-speed", "AWD available"]');
INSERT INTO reliability VALUES(344,193,'librarian+analysis',84.5999999999999943,'["sliding_door_sensor","3rd_row_bolt_recall"]',NULL,NULL,'excellent','high','["HSD proven track record. Hybrid system is last thing to worry about per owners. 3rd-row seatback bolt recall. Sliding door sensor issues."] ',NULL,88.0,92.0,80.0,80.0,78.0,'["Best hybrid minivan", "eCVT bulletproof", "HSD 150k+ mi battery life"]');
INSERT INTO reliability VALUES(345,194,'librarian+analysis',76.2000000000000028,'["vcm_oil_consumption","vcm_mount_failure","sliding_door_actuator","infotainment_freeze"]',NULL,NULL,'excellent','high','["VCM causes oil consumption and mount failure. VCMuzzler II $130 prevents. 9-speed (2018-19) problematic. 10-speed (2020+) much better. Sliding door actuators $300-600."] ',NULL,79.0,73.0,78.0,70.0,80.0,'["VCM is the Achilles heel", "10-speed much better than 9-speed", "VCMuzzler mandatory"]');
INSERT INTO reliability VALUES(346,195,'librarian+analysis',70.2999999999999971,'["plastic_oil_cooler","zf_9speed_valve_body","rocker_arm_failure","head_gasket"]',NULL,NULL,'good','moderate','["Plastic oil cooler cracks at 60-100K ($1000-1500, aluminum aftermarket $300). ZF 9-speed rough shifts valve body. Rocker arm failures. Head gasket rear head."] ',NULL,72.0,65.0,72.0,68.0,75.0,'["ZF 9-speed is the problem", "Plastic oil cooler must be replaced", "Pentastar itself decent if maintained"]');
INSERT INTO reliability VALUES(347,196,'librarian+analysis',66.7999999999999971,'["phev_battery_failure","eflite_transmission","charging_system","plastic_oil_cooler"]',NULL,NULL,'good','moderate','["PHEV battery replacement $7000-17000. 8yr/100k warranty only. eFlite transmission more failure-prone than Toyota eCVT. HV battery bricked failures at under 9K miles. Gas Pacifica is smarter buy."] ',NULL,74.0,62.0,72.0,60.0,65.0,'["PHEV battery cost is existential risk", "eFlite not Toyota eCVT", "Avoid unless under warranty"]');
INSERT INTO reliability VALUES(348,197,'librarian+analysis',76.5999999999999943,'["coolant_loss","infotainment_clip","5_recalls_2022"]',NULL,NULL,'good','moderate','["Lambda II 3.5L Smartstream generally good. Coolant loss emerging pattern. 5 NHTSA recalls on 2022. Too new for 200K+ data. Not the problematic 3.3L Lambda II under investigation."] ',NULL,80.0,78.0,74.0,72.0,76.0,'["Too new for definitive judgment", "Lambda II 3.5L cleaner than 3.3L", "Kia 10yr/100k powertrain warranty"]');
INSERT INTO reliability VALUES(349,198,'librarian+analysis',85.7999999999999971,'["rear_axle_seal","lower_ball_joints","frame_rust"]',NULL,NULL,'excellent','high','["1GR-FE 4.0L is bulletproof. 300K+ miles routine. Rear axle seal leaks contaminate brakes. Lower ball joints catastrophic if fail - replace at 100K. Frame rust on salt belt cars."] ',NULL,90.0,88.0,80.0,82.0,85.0,'["1GR-FE truck legend", "5-speed simple and strong", "Body-on-frame durability", "300K+ miles proven"]');
INSERT INTO reliability VALUES(350,199,'librarian+analysis',85.2000000000000028,'["melting_dashboard","vvt_oil_control_valve","oil_leaks","nav_bluetooth_glitches"]',NULL,NULL,'excellent','high','["2GR-FE same as Camry V6/Avalon. Sticky/melting dashboard 2010-2015 infamous. VVT oil control valve P0014/P0012. Navigation/radio/BT aging. Best-selling luxury SUV = massive parts availability."] ',NULL,92.0,86.0,82.0,76.0,85.0,'["2GR-FE benchmark", "Melting dash is cosmetic but expensive ($1500-2500)", "Best-selling luxury SUV parts availability"]');
INSERT INTO reliability VALUES(351,200,'librarian+analysis',85.5,'["air_injection_pump","water_pump","lower_ball_joints"]',NULL,NULL,'excellent','high','["3UR-FE 5.7L V8 is legendary. 400K+ miles documented. AIR pump P0410 at 60-100K ($2500 dealer, $200 bypass kit). Water pump 60-100K ($400-800). Lower ball joints."] ',NULL,91.0,88.0,80.0,78.0,85.0,'["3UR-FE truck legend", "400K+ miles proven", "AIR pump bypass recommended", "5.7L V8 last of the NA truck engines"]');
INSERT INTO reliability VALUES(352,201,'librarian+analysis',77.4000000000000056,'["carbon_buildup","fuel_injector_failure","vtc_actuator_rattle","cvt_whine_2015"]',NULL,NULL,'excellent','high','["Direct injection carbon buildup on intake valves (walnut blast $400-800). Fuel injector failures. VTC actuator rattle at startup. 2015 CVT whining failures. Head replacement at 38K documented."] ',NULL,78.0,75.0,76.0,78.0,80.0,'["DI carbon is the main issue", "2015 CVT avoid", "2017+ improved", "Discontinued US 2020"]');
