INSERT INTO llm_analyses VALUES(1,26,'comparison',NULL,'deepseek-v4-flash',replace('{\n  "title": "Comprehensive Luxury Sport Sedan Comparison (2010-2026)",\n  "platform_comparison": {\n    "Alpha II": "Smallest and most focused; ICE-only, no electrification, MacPherson strut front, 5-link rear. Best for aging reliability due to simplicity.",\n    "CLAR": "Modular architecture supporting ICE, PHEV, BEV; double wishbone front, multilink rear. Broad technology stack but carries structural compromise from multi-powertrain design.",\n    "M3": "Newest dedicated luxury platform; lower, wider, lighter than prior. 19% aluminum, higher torsional rigidity. Designed for sedan and SUV. Limited public documentation.",\n    "MLB Evo": "Brand-spanning matrix; used from A4 to Bentayga. Double wishbone on upper models. 48V standard. Extremely proven but carries hardpoints for heavy SUVs.",\n    "PPC": "Audi''s final combustion platform; electronics-first with E3 1.2 architecture shared with PPE EVs. MHEV Plus with 48V generator. No manual transmission."\n  },\n  "reliability_assessments": {\n    "Lexus LS430": "Gold standard for reliability; 1UZ-FE engine designed for 300k+ miles. Simple electronics.",\n    "BMW B58": "Mechanically robust; 200k+ capable. Plastic cooling system weak point. Avoid 48V variants for long-term.",\n    "Mercedes M276": "Best Mercedes engine in 20 years; timing chain improved after 2013. 200k+ service life.",\n    "Genesis G90 1st gen 3.3T": "Turbo oil pipe recall (24V191) \u2013 fire risk. 5.0L V8 more reliable.",\n    "Genesis G90 2nd gen e-supercharger": "Innovative but unproven long-term; 48V system replacement could exceed $10k.",\n    "Jaguar XJ X351": "Water pump failure common under 20k miles. Electrical gremlins (parking sensors, sticky buttons). Air suspension fails after 100k. Annual cost ~$1,200-2,500.",\n    "Infiniti Q50": "FM platform from 2001; old bones with modern engine. Decent VR30 engine but ancient chassis and electronics."\n  },\n  "cost_estimates": {\n    "annual_maintenance": {\n      "Lexus IS/GS 350": "$400-600",\n      "Acura TL Type S (6MT)": "$419",\n      "Genesis G70/G80": "$500-600",\n      "Cadillac CT5/CTS": "$650-750",\n      "BMW 540i G30": "$700-900",\n      "BMW E90 335i (N55)": "$600-800 (DIY), $1,200-1,500 (shop)",\n      "Audi A6 (C8)": "$1,000-1,500",\n      "Mercedes S-Class W222": "$1,400-1,800",\n      "Jaguar XJ": "$1,500-2,000",\n      "2000 Subaru": "$300-400 (user reported)"\n    },\n    "10_year_total": {\n      "Lexus LS430": "$5,500",\n      "Acura TL Type S": "$4,200",\n      "Cadillac CTS-V": "$6,500",\n      "BMW 540i (G30)": "$8,000",\n      "BMW E90 328i (DIY)": "$8,500",\n      "Porsche Panamera": "$25,000+"\n    }\n  },\n  "recommendations": [\n    {\n      "car": "Lexus LS430 (2001-2006)",\n      "price_range": "$8k-15k",\n      "reason": "Best built car of the era; 1UZ-FE V8, simple electronics, lowest long-term risk."\n    },\n    {\n      "car": "W212 Facelift E350 (2014-2016)",\n      "price_range": "$15k-22k",\n      "reason": "M276 V6, proven reliability, S-Class safety tech from facelift. Sweet spot between cost and durability."\n    },\n    {\n      "car": "BMW 540i G30 (2017-2019)",\n      "price_range": "$24k-32k",\n      "reason": "B58 engine, CLAR platform, balanced all-rounder. Best modern BMW value."\n    },\n    {\n      "car": "Genesis G80 2.5T (2021-2023)",\n      "price_range": "$35k-45k",\n      "reason": "Best warranty (10yr/100k), lowest running costs, newest M3 platform. Pay more upfront, worry less."\n    },\n    {\n      "car": "Cadillac CTS-V (3rd gen, 2016-2018)",\n      "price_range": "$42k-52k",\n      "reason": "Supercar performance (640hp) for price of loaded Camry. LT4 supercharged V8, manual available."\n    },\n    {\n      "car": "2000 Subaru Legacy/Outback (keep)",\n      "price_range": "$0 (already owned)",\n      "reason": "Paid off, known history, $300-400/year maintenance. Most rational financial choice."\n    }\n  ],\n  "key_insights": [\n    "GM Alpha II wins on aging reliability because it was never designed for EV/hybrid \u2013 narrow scope becomes an asset at year 10-15.",\n    "BMW CLAR is the most modular but compromised; no single powertrain gets an optimized structure.",\n    "Genesis M3 is the most interesting new dedicated luxury platform, but long-term data is thin and brand reliability is trending down.",\n    "Audi/VW 48V mild hybrid systems are a documented reliability risk; failures as early as 50k km.",\n    "The Lexus LS430 is the only car that matches the Subaru''s philosophy: overbuild, under-promise, last forever.",\n    "Jaguar XJ X351: beautiful engineering but a financial trap; budget $2k/year maintenance and expect electrical gremlins.",\n    "For a non-buyer enthusiast: studying E90, CLAR, M3, and Alpha platforms provides the best intellectual return on zero investment."\n  ],\n  "comparison_groups": [\n    "Luxury Sport Sedans (mid-size, 2015-2025): CT5-V vs 540i vs G80 3.5T vs A6 vs E-Class",\n    "Flagships (full-size, 2000-2025): LS430/460 vs 7-series vs S-class vs A8 vs G90 vs XJ",\n    "Used Market Bang-for-Buck (2017-2024): 540i G30 vs G80 3.5T vs Stinger vs Q50 Red Sport vs Lexus GS350",\n    "Reliability Tiers (2010-2026): Lexus/Acura (best), BMW B58/Cadillac Alpha (good), Audi/VW (moderate), Jaguar/Porsche (risk/reward)"\n  ]\n}','\n',char(10)),'{"cars_analyzed": 24}','2026-05-30 22:55:53.616238');
