INSERT INTO ingest_sessions VALUES(2,NULL,replace('Fiche technique et performances de la Genesis G90 3.3 T-GDi AWD 370 ch (2016-2022)\n\nCaracteristiques Genesis G90 3.3 T-GDi AWD 370 ch\nPuissance: 272kW\nCouple: 510Nm\n\nMoteur longitudinal avant 6 cylindres en V 3342 cm3 24 soupapes injection directe 2 Turbos\nPuissance Maxi: 370 ch (272 kW) a 6000 tr/min (Regime Maxi 7000 tr/min)\nCouple Maxi: 510 Nm (52 mkg) de 1300 a 4500 tr/min\nRatios: 111 ch/L (81 kW/L) - 153 Nm/L\n\nTransmission: Integrale\nBoite de vitesse automatique a 8 rapports avec mode sequentiel\nPneus: 245/45/19 AV - 275/40/19 AR\nFreins AV: Disques ventiles (360mm)\nFreins AR: Disques ventiles (340mm)\n\nDimensions: 5205 x 1915 x 1495 mm - Garde au sol: 130mm\nEmpattement: 3160 mm - Voies: AV 1640 mm / AR 1639 mm\nPorte-a-faux: AV 860 mm / AR 1185 mm\n\nPoids annonce: 2170 kg (DIN) 2245 kg (UE)\nRepartition du poids Av/Ar: 53/47 %\nRapport Poids/Puissance: 6.1 kg/ch = 120 kW/T = 163 ch/T\nRapport Couple/Poids: 225 Nm/T\n\nConsommation mixte normalisee: 9.8 L/100 - sportive: 13.9 L/100\nCapacite du reservoir: 83 L\nAutonomie ~760 km\n\nPrix de base neuf indicatif: ~94 400 EUR\n\nIndice de sportivite 103\nIndice ZePerfs 154\nRapport Perfs/Prix 90\nAvis ZePerfs 4.1\n\nPerformances Genesis G90 3.3 T-GDi AWD 370 ch\n19 mesures de performance des tests de 2 sources: Car & Driver, MotorTrend\nMoyennes des mesures des essais repertories\n400m DA: 13.9 s, vitesse de passage 162 km/h, 2 valeurs\n0 a 50 km/h: 2.0 s, 3 valeurs\n0 a 80 km/h: 4.0 s, 2 valeurs\n0 a 100 km/h: 5.7 s, 3 valeurs\n0 a 130 km/h: 9.0 s, 3 valeurs\n0 a 160 km/h: 13.8 s, 3 valeurs\n40 a 140 mini: 9.3 s\n80 a 120 mini: 4.1 s\n80 a 180 mini: 13.1 s\n100 a 0: 39.0 m, ~9.9 m/s2, 2 valeurs','\n',char(10)),'https://zeperfs.com/fiche6435-genesis-g90.htm','ZePerfs','draft',NULL,'{}','{}','[]','{}','2026-05-30 20:12:20.506484','2026-05-30 20:12:20.506487');
INSERT INTO ingest_sessions VALUES(3,NULL,replace('Fiche technique et performances de la Genesis G90 3.3 T-GDi AWD 370 ch (2016-2022)\nCaracteristiques Genesis G90 3.3 T-GDi AWD 370 ch\nPuissance: 272kW\nCouple: 510Nm\nMoteur longitudinal avant 6 cylindres en V 3342 cm3 24 soupapes injection directe 2 Turbos\nPuissance Maxi: 370 ch (272 kW) a 6000 tr/min\nCouple Maxi: 510 Nm de 1300 a 4500 tr/min\nTransmission: Integrale, automatique 8 rapports\nDimensions: 5205 x 1915 x 1495 mm\nPoids: 2170 kg\nPrix: ~94 400 EUR\nIndice ZePerfs 154\n0 a 100 km/h: 5.7 s','\n',char(10)),NULL,'ZePerfs','draft',NULL,'{}','{}','[]','{}','2026-05-30 20:12:39.478094','2026-05-30 20:12:39.478097');
