INSERT INTO build_quality VALUES(1,39,92.2999999999999971,97.0,95.0,94.0,93.0,82.0,90.0,'LS430 bespoke F1 platform. World-first laser welding on LS400 (carried forward). Welds 1.5x stronger than industry standard. Body digitization 0.001mm (10x industry). High-tensile steel cabin cage. Double-wishbone suspension all corners. Sandwich steel bulkheads with sound-insulating resin cores.','Hydraulic fluid-filled engine mounts (mini suspension for engine). Sandwich steel bulkheads. Acoustic laminated glass front+rear standard. Hollow-spoke wheels for road noise. Helmholtz resonators in door cavities. Aerodynamic underbody with flat engine cover. 58dB at 100km/h (LS400 benchmark).','Semi-aniline leather (highest automotive grade). Real California walnut, antique walnut, bird''s eye maple. Optitron electroluminescent gauges. Interior tolerance 1mm. 24 woods and multiple leathers evaluated for 2 years during development.','LS400/430 paint holds 20+ years. Multi-stage Toyota paint process. Corrosion-resistant galvanized steel. Wax and hemming sealers. No known clear coat epidemics. Owners report factory-fresh appearance at 15+ years.','Generally excellent electrical reliability. Air suspension sensors can fail (40% of UL owners). Motorized features add complexity. No systemic electrical gremlins. Mark Levinson audio holds up well.','Interior holds up remarkably at 20+ years. Semi-aniline leather ages gracefully (patina vs cracking). Real wood doesn''t delaminate. Tighter panel gaps prevent squeaks/rattles. Air suspension can sag if not maintained. Rubber components softer for NVH = degrade faster than ES.','LS430 Q-score 94.7. The benchmark car for build quality. Bespoke platform, world-first engineering, highest material grades, Tahara Takumi assembly. Deductions: air suspension aging (-3 electrical), softer rubber aging (-5 cosmetic), motorized features add failure points.','bespoke','Tahara (Aichi, Japan)','laser',3.5,'hydraulic','acoustic_laminated','semi_aniline','real_wood',5,'extensive','sample',NULL);
INSERT INTO build_quality VALUES(2,86,78.0,72.0,80.0,76.0,78.0,85.0,82.0,'Camry K-platform derivative. MacPherson strut front (not double wishbone). Pressed steel subframes (not aluminum). Standard Toyota spot welding. Panel gaps 5-7mm (good but not LS-grade 3-4mm). Shared platform = shared tooling.','Enhanced over Camry: additional sound deadening in floor pan, firewall, doors. 2GR-FE inherently smooth. Standard rubber engine mounts (not hydraulic). No acoustic laminated glass on base models. No sandwich steel bulkheads. Whisper-quiet but through insulation quantity, not engineering sophistication.','Standard leather (not semi-aniline). Real wood on some trims, wood-grain plastic on lower trims. Standard backlit gauges (not Optitron). Good soft-touch surfaces. Panel fit tighter than G35 but not LS-level. Interior tolerance standard 3-5mm.','Toyota paint of this era is average-to-good. No clear coat epidemics. Rust uncommon unless accident-damaged. Good galvanized steel. Some minor clear coat aging on horizontal surfaces at 15+ years but gradual.','Stone-cold reliable electrically. Everything works at 150K+ miles. Mark Levinson optional system holds up. No systemic gremlins. 2007-2008 had floor mat recall. GPS dated but functional.','Ages gracefully like a well-maintained Camry. 2007-2008 dash melting was addressed by Lexus warranty program ZLD (free replacement). 2010+ models avoided it. Leather holds up at 100K+. Softer plastics scratch more than LS. Faux wood can fade.','ES 350 Q-score 76.3. Honest Camry-based luxury: mechanically bulletproof, cosmetically good but shared-platform DNA shows. 80-90% of LS NVH at 70% of the materials cost.','shared','Multiple (Kyushu, Tsutsumi)','spot',5.5,'rubber','laminated','standard','real_wood',4,'above_average','sample',NULL);
INSERT INTO build_quality VALUES(3,64,48.7999999999999971,72.0,42.0,48.0,38.0,35.0,40.0,'FM platform (350Z-based) 窶・genuinely good sports car architecture. 52:48 weight distribution. Double wishbone front. But: pressed steel everywhere, standard Nissan spot welding, no structural innovations. Body construction is the one bright spot.','Minimal by design. No hydraulic mounts. No acoustic glass. No sound deadening beyond minimum. Exhaust note prominent (intentional). Tire roar significant with wider tires. Coupe body creates resonance. At 80mph it feels like 80mph.','The single most criticized aspect of long-term ownership. Endemic dashboard cracking (soft sticky mess in warm climates, Infiniti never recalled). Seat bolster foam collapses at 40-60K miles (TSB ITB07-006). Aluminum-look trim peels at 4-6K miles. Rosewood trim is wood-grain overlay on plastic. Leather is mediocre.','Clear coat failure is epidemic. Facebook group Infiniti Paint Problems has ~1000 members. Hood, roof, trunk blister and flake. Rear quarter rust on wheel arches almost universal at 100K+. Paint thin and soft. Some 2003-2005 batches had defective clear coat per body shop reports.','Bose head unit failure is nearly universal on 2003-2006. Internal amp circuit board cold solder joints = no sound. When radio dies, AC controls can stop working (integrated). Parasitic battery drain from faulty circuit. Window motor failures common.','Dashboard cracks at 8-12 years. Seat bolster tears at 40-60K. Clear coat peels at 7-10 years. Interior trim detaches at 5-8 years. Steering wheel wear at 60-80K. Headliner pulls near sunroof. The G35 ages like an athlete 窶・stays capable but everything shows.','G35 Coupe Q-score 48.5. The driving experience is genuinely good (FM platform, VQ35DE, RWD, manual) but the construction quality is objectively poor. Nissan spent money on chassis engineering and cut corners on everything else. At $5K used it is what it is.','shared','Multiple (Japan)','spot',6.0,'rubber','standard','standard','plastic',3,'minimal','sample',NULL);
INSERT INTO build_quality VALUES(4,56,74.2000000000000028,80.0,78.0,78.0,75.0,62.0,68.0,'CLAR (Cluster Architecture) shared platform across G30 5 Series, G01 X3, G11 7 Series. Mixed high-strength steel and aluminum construction 窶・aluminum hood, front fenders, doors. Multi-link front and rear suspension. Good crash structure. Panel gaps 4-5mm (competitive for class but not LS-grade). BMW''s modular approach means shared weld standards across CLAR vehicles. B-pillar and roof rail use hot-stamped ultra-high-strength steel. Body rigidity good but not bespoke-level 窶・shared platforms always trade some stiffness for commonality.','Good NVH for the segment. Hydraulic engine mounts standard on 540i (not on 520i/530i). Acoustic laminated windshield standard, acoustic side glass available on higher trims. Firewall insulation above average. B58 inherently smooth inline-6. ZF 8HP50 well-isolated. Underbody aero panels reduce wind noise. However: run-flat tires transmit road harshness noticeably (common complaint on Bimmerpost). At 80mph more refined than G35 but not LS430-quiet. Road noise on coarse surfaces above average for class.','Dakota leather standard (BMW mid-grade, below Nappa). Sensatec (synthetic) on base models. Optional Nappa leather on M Sport. Real aluminum trim standard; optional wood trim is genuine open-pore oak or fineline ridge. iDrive 6.0 system (pre-LCI rotary controller) 窶・functional but dated compared to LCI. Soft-touch surfaces on doors and dash. Stitching quality good. Fit and finish above average but not at Audi C8 level. Piano black trim scratches easily. Cup holder materials feel thin.','BMW paint quality is generally good. Multi-stage cathodic dip primer, base coat, clear coat process. Panel gaps consistent. No known epidemic clear coat failures on G30. However: some owners report orange peel on horizontal surfaces (hood, roof). Aluminum panels don''t rust, but steel structural components can if paint compromised. Stone chips on front end expose aluminum which doesn''t rust but can corrode cosmetically. Paint softness is average 窶・not Honda-soft but not ceramic-hard.','BMW electrical aging is the weak point. iDrive CCC/CIC/NBT units can develop screen delamination (purple/white spots). Battery registration required 窶・wrong battery coding causes electrical gremlins. Plastic cooling system components (expansion tank, thermostat housing, radiator end tanks) become brittle at 80-100K miles 窶・not technically electrical but electronic thermostat failures trigger limp mode. Water pump (electric, not mechanical) fails without warning. Door lock actuators fail. K-CAN bus issues cause intermittent warning lights. B58 is better than N-series engines but plastic still plastic.','Dakota leather wears reasonably 窶・develops patina at 80-100K miles rather than cracking. Steering wheel leather can get shiny/glossy at 60K+. Dashboard material holds up well (no G35-style cracking). Piano black center console scratches from keys, rings, seatbelt buckles 窶・looks tired at 5 years. Door armrest leather creases. Optional wood trim ages better than aluminum (which can pit). Overall: ages like a well-maintained German car 窶・functional but showing at 10 years.','BMW 540i G30 pre-LCI Q-score 74.15. CLAR shared platform with good construction but BMW-typical aging: plastic cooling components, electrical quirks, and cosmetic wear on trim pieces. The B58 is a significant improvement over N-series engines. Strong body rigidity and good NVH for class, but not bespoke luxury-level in any dimension. Scores above ES350 on body construction (aluminum panels, CLAR engineering) but below on electrical reliability and cosmetic aging.','shared','Dingolfing (Germany)','mixed',4.5,'hydraulic','acoustic_laminated','standard','real_wood',4,'above_average','sample',NULL);
INSERT INTO build_quality VALUES(5,150,77.2000000000000028,82.0,80.0,80.0,78.0,68.0,72.0,'Same CLAR platform as pre-LCI but production maturity improvements. 2021+ models benefit from 4 years of production refinements 窶・panel fit tighter, weld consistency improved. Mixed high-strength steel and aluminum unchanged. B58TU (technical update) engine has improved crankshaft, forged connecting rods (some sources), and better oil pump. Body construction identical architecture but better executed. Panel gaps 4-4.5mm on later builds (measured improvements on Bimmerpost owner surveys). G80 M3/M4 share this platform 窶・performance validation at higher loads.','Improvements over pre-LCI: revised acoustic glass standard on more trims. Improved door seal design reduces wind noise at highway speeds. B58TU smoother idle and better NVH calibration from factory. M Sport suspension option has adaptive dampers with better isolation in Comfort mode. Same hydraulic engine mounts (confirmed standard across all 540i LCI). Run-flat tire harshness still present but BMW updated tire specs to softer compounds. Cabin quietness at 80mph improved approximately 1-2dB per owner comparisons.','Vernasca leather replaces Dakota on LCI 窶・noticeably softer, better grain, closer to Nappa quality. Sensatec remains base option. iDrive 7.0 with larger curved display (on iDrive 8 cars), or updated 10.25-inch screen. Improved trim materials: less piano black, more brushed metal and open-pore wood options. Optional Bowers and Wilkins audio (excellent). Cognac Vernasca leather particularly well-regarded. Stitching patterns more elaborate on M Sport. Overall interior step up from pre-LCI.','Same BMW paint process as pre-LCI. Minor improvements in clear coat formulation reportedly. No systemic paint issues reported on LCI cars (too new for long-term data but early signs positive). Individual and BMW Exclusive paint options have more clear coat depth. Standard colors are consistent. Same aluminum panel considerations 窶・no rust but cosmetic corrosion risk on chips.','B58TU addresses many B58 issues: improved water pump design, better thermostat reliability, updated PCV valve (less prone to failure). iDrive 7 more stable than iDrive 6 (fewer crashes, faster response). However: complex mild-hybrid 48V system introduced on some 2022+ models adds failure points. Digital Key and OTA updates add software complexity. G20 B48 owners report similar electrical improvements 窶・BMW learning from N-series era. Still too early for definitive long-term data but trajectory positive.','Vernasca leather should age better than Dakota 窶・initial reports positive at 30-50K miles. Interior materials generally higher quality than pre-LCI. Less piano black means fewer visible scratches. Updated door card materials more durable. Still has the BMW steering wheel wear pattern (glossy at 60K+). Dashboard materials unchanged 窶・should hold up. Overall LCI cosmetic trajectory is improved. Too new for 10-year data but 3-year lease returns look much better than pre-LCI equivalents.','BMW 540i LCI G30 Q-score 77.2. The LCI fixes many pre-LCI issues: better leather (Vernasca), improved B58TU reliability, tighter panel gaps, better NVH calibration. Scores higher across every dimension. The sweet spot G30 窶・early models had B58 growing pains, LCI has them sorted. Still a shared platform with BMW-typical plastic aging, but significantly better executed.','shared','Dingolfing (Germany)','mixed',4.0,'hydraulic','acoustic_laminated','standard','real_wood',4,'above_average','sample',NULL);
INSERT INTO build_quality VALUES(6,3,53.2000000000000028,70.0,45.0,55.0,48.0,45.0,42.0,'E46 platform 窶・genuinely good chassis engineering for era. 50:50 weight distribution. MacPherson strut front, multi-link rear. High-quality steel for period. BUT: rear subframe mounting points crack on coupe and convertible (TSB SI B31 01 03, well-documented on M3Forum). Subframe reinforcement plates are the standard fix ($2000-4000). Rear differential mount bolts shear. Front strut tower mounts fatigue. Now 20+ years old 窶・even well-maintained examples show fatigue. Rust on rear quarter panels, jack points, and underbody common in northern cars. Panel gaps 5-6mm (good for 2000s, not great now).','Era-appropriate NVH 窶・acceptable in 2000, notable by modern standards. No acoustic glass. Solid rubber engine mounts (M3 specific, stiffer than 330i). No hydraulic suspension options. S54 engine is mechanically noisy (valvetrain, injectors) 窶・charming but not refined. Road noise significant with OEM 18/19-inch staggered setup. Exhaust present in cabin at all speeds (intentional M-car character). No active noise cancellation. Minimal sound deadening in pursuit of weight savings. Wind noise around mirrors and A-pillar at speed. At 80mph you hear everything.','Good for year but poor by modern standards. Sport seats well-bolstered but leather quality is mid-grade (not Nappa). Leatherette on non-CSL base models. SMG cars have leather-wrapped shift knob that wears. Door panels use a mix of soft-touch and hard plastic 窶・hard plastic scratches, soft-touch degrades sticky. Carbon fiber trim (real on some models) holds up; aluminum trim scratches. Orange peel texture on some interior plastics. Headliner sag at 15+ years common. Center console armrest vinyl cracks. Steering wheel leather thin 窶・shiny at 50K.','BMW paint quality in 2000-2006 was average. Clear coat failure on horizontal surfaces common at 15+ years 窶・hood, roof, trunk lid. Carbon black and jet black particularly susceptible. Alpine White holds up better. Stone chips on front end expose steel which rusts quickly. Rear quarter panel rust near wheel arch is nearly universal on northern cars. Underbody surface rust common even on southern cars. Paint correction community has documented E46 paint extensively 窶・clear coat is thin (~100 microns vs modern 120-140).','E46 M3 electrical is era-appropriate but aging poorly now. S54 VANOS solenoids fail ($1500-2500 per hub, two hubs). VANOS hub bolts back out and drop into timing chain 窶・catastrophic if not caught. CPS (camshaft position sensors) fail regularly. SMG pump relay fails (strands you in neutral). SMG actuator seals leak. Window regulators fail (cable mechanism design flaw 窶・replaced under warranty, aftermarket fixes exist). Instrument cluster pixels fail on temperature display (common E46 issue). HK audio amplifier fails. Battery discharge from parasitic draw common.','E46 M3 at 20+ years shows its age cosmetically regardless of maintenance. Leather cracks on bolsters at 60-80K miles. Steering wheel glossy at 50K. Dashboard doesn''t crack (better than G35 era Nissan) but fades. Door panel armrest leather wears through. Headliner sags. Exterior trim fades 窶・kidney grilles, window trim, bumper trim all go chalky. Weatherstripping shrinks and cracks causing wind noise and water leaks. Rubber suspension bushings degrade causing clunking. Subframe bushings crack. Every rubber component is 20+ years old. Well-maintained examples can look good but require constant attention.','E46 M3 Q-score 53.25. A legendary driving machine with genuine chassis engineering quality, but 20+ years of aging is unforgiving. Subframe cracking is the structural Achilles heel. S54 VANOS and SMG are the mechanical weak points. Interior and paint are era-appropriate but poor by current standards. Scores above G35 on body construction (better engineering intent) but below on electrical aging (more complex systems aging poorly). The E46 M3 rewards investment but never stops needing it.','derived','Regensburg (Germany)','spot',5.5,'rubber','standard','standard','carbon_fiber',4,'standard','sample',NULL);
INSERT INTO build_quality VALUES(7,155,72.7999999999999971,78.0,76.0,82.0,72.0,58.0,65.0,'MLB (Modularer Lﾃ､ngsbaukasten) shared platform 窶・longitudinal engine layout shared with A4 B8, Q5, Q7. Aluminum-intensive body: aluminum hood, fenders, doors, trunk, and structural components. Steel-aluminum hybrid construction with Audi Space Frame (ASF) technology partial application. Multi-link front and rear suspension (5-link front, trapezoidal-link rear). Panel gaps 4-5mm (Audi benchmark for class). Hot-stamped steel in B-pillars and roof rails. Aluminum bolted to steel at junction points 窶・potential galvanic corrosion risk in salty climates if seams compromised. Good torsional rigidity for class.','Audi NVH is a strength of the brand. Hydraulic engine mounts on 3.0T (not on 2.0T base). Acoustic laminated windshield standard, acoustic side glass on Prestige trim. Excellent firewall insulation. Supercharged 3.0T inherently smooth and quiet. 8-speed ZF torque converter well-isolated. MMI system doesn''t add mechanical noise. Underbody panels for aero and sound. However: some supercharger whine reported on early EA837 engines (considered charming by some, annoying by others). Tire noise with 19/20-inch wheels can be intrusive. Road noise on coarse surfaces moderate.','Audi interiors are the class benchmark for this era. Valcona leather standard on 3.0T Premium Plus (genuine, above BMW Dakota grade). Milano leather on Prestige. Real aluminum trim inlays (brushed, not plastic). Optional wood trims are genuine. Soft-touch surfaces everywhere 窶・doors, dash, console. MMI controls feel substantial. Gauge cluster (Virtual Cockpit on 2016+ facelift) high quality. Stitching precise. Fit and finish above BMW F10/G30 of same vintage. Center console layout clean. Only weakness: piano black trim around shifter scratches easily.','Audi paint quality is solid. Multi-stage process with cathodic e-coating. Clear coat holds up well 窶・no epidemic failures reported on C7. Aluminum body panels don''t rust. Steel substructure can rust if paint compromised but galvanizing is thorough. Some reports of clear coat micro-blistering on dark colors (Phantom Black, Moonlight Blue) at 8-10 years. Paint thickness above average (~130 microns). Stone chips on aluminum front end don''t rust but show. Overall: Audi paint quality is top-tier for mainstream luxury.','Audi electrical aging is the weak point. MMI system failures are common 窶・screen goes blank, control module fails ($1500-3000). MMI joystick/touchpad delaminates. Oil level sensor failures trigger false warnings. 3.0T has PCV valve failures (causes rough idle, check engine). Thermostat housing leaks (plastic, cracks at 70-90K). Water pump/thermostat assembly fails. Transmission mechatronic unit can fail (ZF 8HP related). Parking sensors fail individually. LED headlights (2014+ facelift) can develop moisture. Complex electrical systems = more failure points.','Audi interiors age well cosmetically 窶・the brand strength. Valcona leather wears gracefully, developing patina rather than cracking at 100K+. Steering wheel leather shows wear at 80K+. Dashboard materials hold up without cracking or fading. Soft-touch door materials can become slightly tacky at 10+ years in hot climates. Piano black trim scratches (consistent complaint). Aluminum trim holds up well. Headliner generally stays in place. Overall: best-in-class cosmetic aging among German luxury cars of this era.','Audi A6 C7 3.0T Q-score 72.75. MLB shared platform with aluminum-intensive body construction. Interior quality is the standout 窶・Audi benchmark for the era. Good NVH, solid paint. Weak points: MMI failures, plastic cooling components, oil consumption on early 3.0T engines (EA837). Scores between ES350 and G30 on build quality. The interior materials score (82) exceeds BMW G30 because Audi used better leather grades and more soft-touch surfaces.','shared','Neckarsulm (Germany)','mixed',4.5,'hydraulic','acoustic_laminated','semi_aniline','real_wood',4,'above_average','sample',NULL);
INSERT INTO build_quality VALUES(8,32,77.0,82.0,80.0,85.0,78.0,62.0,70.0,'MLB Evo (evolved MLB) 窶・significant weight reduction (~100kg vs C7) through increased aluminum content and hot-formed steel optimization. Aluminum exterior panels (hood, fenders, doors, trunk, roof on some configs). Multi-material body with structural adhesives supplementing rivets and bolts at aluminum-steel junctions. 5-link front and rear suspension (more aluminum content than C7). Panel gaps 3.5-4mm (class-leading, matching or beating BMW G30 LCI). Rear-wheel steering available (all-wheel steering). Better torsional rigidity than C7. Good crash structure.','Significant NVH improvement over C7. Hydraulic engine mounts on all 6-cylinder models. Acoustic laminated glass standard on all windows (not just windshield) on Prestige. Improved door seal design with double-lip weatherstripping. Active noise cancellation on some engine configs. 3.0T EA839 smoother than EA837 supercharger. Underbody aero panels more extensive. Cabin is whisper-quiet at 80mph 窶・competitive with E-Class W213. Road noise well-managed even with 20-inch wheels. Wind noise around mirrors reduced from C7.','Best-in-class interior for production year. Dual-screen MMI touch (upper infotainment, lower climate/control). Valcona leather standard, Milano on Prestige, Valcona/Atlas on options. Open-pore wood trims (genuine oak, walnut). Aluminum and carbon fiber options. Soft-touch surfaces everywhere including lower door panels and console sides. Stitching patterns more elaborate. MMI touch response is haptic 窶・satisfying click feedback. Material quality above BMW G30 and Mercedes E-Class W213. Night orange ambient lighting signature. Only weakness: screen-heavy design means fingerprints and glare.','Same Audi paint quality standards as C7 窶・excellent. Cathodic e-coating, multi-stage process. Clear coat depth good (~130-140 microns). Aluminum panels don''t rust. Galvanized steel substructure. No reported paint epidemics (too new for 10-year data but 5-year results positive). Optional Audi Exclusive paints have additional clear coat. Paint correction community reports C8 paint is marginally harder than C7 (easier to polish without burning through). Overall: continuation of Audi paint excellence.','Complex electrical systems are the risk. Dual-screen MMI has more failure modes than C7 single screen. Both screens can develop dead pixels or touch responsiveness issues. OTA updates sometimes brick MMI requiring dealer visit. 48V mild hybrid system on 3.0T adds complexity (belt starter generator, additional battery). Air suspension (optional) adds sensor and compressor failure points. Matrix LED headlights complex and expensive to replace. Digital gauge cluster is reliable so far but long-term unknown. More sensors = more diagnostic complexity. EA839 engine: too new for definitive long-term reliability data but early signs better than EA837.','Interior materials are higher quality than C7, should age better. Valcona leather grade holds up well (proven from C7 experience). Screens add a new aging concern 窶・fingerprints, micro-scratches, and eventual backlight degradation. Open-pore wood trim ages well (sealed properly). Soft-touch materials slightly improved formulation over C7. Piano black still present but less surface area. Steering wheel leather will show wear at 80K+ (consistent with all Audi). Overall: best-in-class cosmetic aging trajectory, but screen-dependent interior means any electronic failure is also a cosmetic failure.','Audi A6 C8 Q-score 77.0. MLB Evo with significant improvements over C7: better NVH, tighter panel gaps, lighter weight, improved materials. Interior quality is class-leading (85). Risk factors: complex dual-screen MMI, 48V mild hybrid, air suspension. EA839 engine early signs positive. Scores between BMW 540i LCI and ES350 overall. Best interior materials in this comparison set but electrical complexity drags score down.','shared','Neckarsulm (Germany)','mixed',4.0,'hydraulic','acoustic_laminated','semi_aniline','real_wood',4,'above_average','sample',NULL);
INSERT INTO build_quality VALUES(9,2,69.9000000000000056,85.0,62.0,72.0,72.0,55.0,60.0,'996 Turbo body construction is genuinely impressive for era. Steel monocoque with aluminum doors, hood, and front fenders. Turbo-specific wider body (60mm vs Carrera). Fixed front splitter and adjustable rear wing with structural integration. X50 Power Package adds larger intercoolers (structural implications). Mezger engine block (derived from GT1 race car) 窶・different from standard 996 M96 engine, no IMS bearing issue. Weld quality high 窶・Porsche Zuffenhausen production standards. Panel gaps 4-5mm (good for 1998-2005). Some reports of moisture in headlight housings (DRL/turn signal unit delaminates). Underbody cladding comprehensive.','911 Turbo NVH is a mixed bag. Porsche designed it as a daily-driveable supercar but priorities are performance. Solid rubber engine mounts (not hydraulic) for drivetrain rigidity. No acoustic glass. Twin K24 turbochargers muffled by intercoolers but turbo whoosh audible. Air-cooled heritage means less sound deadening than comparable Audi. Suspension is stiffer than standard 996. Pirelli P Zero Rosso or Michelin Pilot Sport tires (18-inch) transmit road texture. Wind noise at speed from wide-body aerodynamics. However: more refined than GT3 or GT2 of same era. Cabin quiet enough for phone calls at 70mph.','Porsche interior quality of this era is above average but not exceptional. Standard partial leather (seating surfaces only) 窶・full leather was a $3000+ option. Leather grade is standard (not semi-aniline). Optional carbon fiber, aluminum, or wood trim (genuine materials). Bose audio option. fit and finish is precise German quality. However: base models had significant shared components with Boxster (cost-cutting complaint among purists). The "fried egg" headlights and shared interior with 986 Boxster were controversial. Climate control buttons feel tactile and precise. Overall: premium but not bespoke luxury.','Porsche paint quality is above average. Multi-stage process at Zuffenhausen. Clear coat holds up reasonably well 窶・no epidemic failures on 996 Turbo. Guards Red and Speed Yellow hold color well. Black and Midnight Blue can show swirl marks more readily. Stone chips on front bumper and hood (daily-driveable supercar = highway miles = chips). Aluminum panels don''t rust. Steel chassis galvanized. Some reports of clear coat micro-checking on 25-year-old examples but not universal. Front bumper cover paint is thinner and chips faster. Paint correction community considers 996 paint average hardness 窶・workable.','996 Turbo avoids the IMS bearing issue (Mezger engine uses different design 窶・integrated ball bearing, not the problematic sealed bearing of M96). However: secondary air injection ports clog (carbon buildup, causes CEL). DME relay failure (strands car 窶・$20 part, catastrophic failure mode). Coolant tank cracks (plastic, fails at 60-80K). Ignition switch failure (common 996 issue 窶・causes electrical gremlins). Window regulators fail. Climate control final stage resistor fails (blower motor issues). Radiator fans fail (biological debris accumulation). Not as electrically fragile as F355 but more complex than Japanese cars of era.','996 Turbo cosmetic aging is moderate. Leather seats wear well with maintenance 窶・bolsters show at 80-100K miles. Dashboard doesn''t crack (better than G35 era). Steering wheel leather thins at 60K+. Door panel leather holds up. Carpet mats wear at driver heel (replaceable). Exterior: rubber seals shrink and harden at 20 years (door, window, trunk seals). Rear wing mechanism can develop play. Headlight lenses yellow slightly (polishable). Wheels: Turbo Twist design collects brake dust in crevices. Overall: a well-maintained 996 Turbo looks good at 20 years but requires active maintenance. Not as resilient as LS430 but better than F355.','Porsche 911 Turbo 996 Q-score 69.9. The Mezger engine saves it from M96 reliability nightmares. Body construction is genuinely good (85) 窶・Porsche engineering and Zuffenhausen assembly standards. Interior materials are premium but not bespoke (72). NVH is adequate but performance-prioritized (62). Electrical aging has known issues (DME relay, SAI ports, coolant tank) but manageable. Paint holds up. Scores above G35 across all dimensions, above E46 M3 on body construction but below on interior (E46 M3 carbon fiber trim). The 996 Turbo is the smart money in air-cooled-adjacent Porsches.','bespoke','Zuffenhausen (Stuttgart, Germany)','mixed',4.5,'rubber','standard','standard','carbon_fiber',4,'standard','sample',NULL);
INSERT INTO build_quality VALUES(10,5,57.5,88.0,35.0,70.0,55.0,30.0,35.0,'F355 body construction is hand-built Ferrari quality 窶・impressive and flawed simultaneously. Steel tub with aluminum body panels (hood, trunk, some fender sections). Tubular steel subframes front and rear. Panel gaps vary significantly (6-9mm) due to hand assembly 窶・no two F355s are identical. Weld quality on visible seams is good; hidden structural welds are functional but not over-engineered. Composite bumper covers. The mid-engine layout allows short overhangs but the steel tub adds weight. Pininfarina design is aerodynamically sophisticated (active underbody, downforce-generating rear diffuser). However: the body structure was designed for beauty first, manufacturing consistency second.','F355 NVH is essentially non-existent as a design priority 窶・this is a race car for the road. Solid engine mounts bolt the F129B V8 directly to the chassis. No acoustic glass. No sound deadening material. No hydraulic suspension. The 3.5L V8 at 8500rpm is the NVH 窶・it screams through Tubi Style headers. Interior resonance at cruise is significant. Tire noise with 18-inch wheels on 1995+ models is intrusive. Wind noise from targa (GTS) or spider top is notable. The F355 does not isolate you from the driving experience 窶・it amplifies it. This is by design but objectively scores low on NVH isolation.','Interior materials are exotic-grade but inconsistent. Connolly leather (English hide, among the finest available) on seating surfaces 窶・gorgeous when new. Leather-wrapped dash and door panels. Real aluminum Ferrari gated shifter (iconic). Carbon fiber trim (optional, real). However: plastics used for switchgear are Fiat-sourced and feel cheap (turn signal stalks, HVAC controls, window switches shared with Fiat Coupe). Carpet quality is adequate but not exceptional. Fit and finish varies car-to-car (hand-built). The dichotomy is stark: Connolly leather next to Fiat switchgear.','Ferrari paint quality of this era is mixed. Hand-sprayed at Maranello. Multiple clear coats for depth. Color vibrancy is exceptional (Rosso Corsa, Giallo Modena). However: paint thickness varies due to hand application (80-160 microns on same car). Clear coat micro-checking on 25+ year old cars, especially on horizontal surfaces. Stone chips on aluminum front end 窶・no rust but chips are visible on the Ferrari red. Some owners report clear coat delamination on rear quarters. Paint quality is a strength when new but doesn''t age as well as German or Japanese multi-stage factory processes.','F355 electrical is the single worst aspect of ownership. Valve guides fail on pre-1997 cars (Ferrari TSB, requires engine-out service 窶・$10-15K). Tubular steel headers crack (OEM are known failure point, aftermarket headers solve it 窶・$5-8K). Capillary coolant leak into engine bay (design flaw, seeps from thermostat housing). Motronic 2.7 ECU (pre-1996) can develop cold solder joints. Window regulators fail (Fiat-sourced). Alternator failure common. Warning lights are a permanent feature of F355 ownership 窶・most are false positives but you can never ignore them. Every electrical component is harder to access because mid-engine.','F355 cosmetic aging is harsh. Connolly leather cracks if not conditioned religiously (monthly). Dashboard leather shrinks and pulls at edges. Steering wheel leather deteriorates from hand oils. Carpet thins. Rubber seals harden and shrink (door, window, targa). Headlights yellow (polycarbonate oxidation). Clear coat ages as described above. Tubular header cracks discolor surrounding components. Engine-out service required for belt changes (every 3-5 years, $5-8K) 窶・during which cosmetic issues are addressed but at significant cost. A 25-year-old F355 either looks like a $150K concourse car or a $30K project 窶・no middle ground.','Ferrari F355 Q-score 57.5. The most polarizing car in this set. Body construction (88) reflects genuine hand-built craftsmanship with exotic materials. Interior materials (70) combine Connolly leather with Fiat switchgear. But NVH (35), electrical (30), and cosmetic aging (35) are catastrophically low 窶・the F355 demands constant, expensive attention. Valve guides and headers are $15-20K in known issues alone. Scores above G35 on body construction and interior materials (exotic vs mass-market) but below on electrical and cosmetic aging. The F355 is a masterpiece that costs masterwork money to maintain.','bespoke','Maranello (Italy)','mixed',7.5,'rubber','standard','full_aniline','carbon_fiber',5,'minimal','sample',NULL);
INSERT INTO build_quality VALUES(12,163,72.0999999999999943,74.0,72.0,79.0,70.0,66.0,68.0,'Hyundai BH-L platform (shared with Kia K900). Standard spot welding. High-tensile steel in safety cage but pressed steel subframes. Panel gaps 4-6mm 窶・better than G35 era, competitive with ES350. Body structure is rigid for the class but shared-platform DNA limits ceiling.','Tau 5.0 V8 is inherently smooth (90-degree V8, hydraulic lifters, port injection). Rubber engine mounts, not hydraulic. Standard laminated glass, no acoustic laminate. Sound deadening is adequate but achieved through insulation quantity, not engineering sophistication like LS430 sandwich bulkheads. V8 idle is refined.','Improved significantly for 2017 Genesis launch. Real wood on upper trims, wood-grain plastic on lower. Standard leather (not semi-aniline). Good soft-touch surfaces in contact areas but Hyundai-grade hard plastics in non-touch zones (lower dash, door bottoms, center console sides). Better than G35 by a wide margin, below ES350 material quality.','Korean multi-stage paint process. No clear coat epidemics like G35. Good galvanized steel. Paint thickness average for segment. Some reports of softer clear coat on horizontal surfaces. Holds up reasonably at 10+ years but not Toyota-tier durability.','Hyundai electronics architecture is adequate. 10yr/100K warranty is the safety net. Infotainment responsive but can lag with age. No systemic electrical gremlins. Simpler electronics than German competitors. Air suspension (if equipped) adds complexity and failure risk.','Interior holds up well at 5-8 years. Leather aging is decent but not LS430 patina-grade. Real wood trim ages well. Parts backordering is THE critical weakness 窶・Tau 5.0 specific parts have chronic backorder issues, almost no aftermarket. This is the single biggest risk for long-term ownership.','G80 5.0 Q-score 67.8. Best Genesis engine in a good sedan body, but shared platform limits ceiling. V8 smoothness helps NVH. Interior is a big step up from pre-2017 Hyundai. Parts backordering for Tau-specific components is the critical long-term risk 窶・essentially no aftermarket ecosystem.','shared','Ulsan (South Korea)','spot',5.0,'rubber','laminated','standard','real_wood',4,'above_average','sample',NULL);
INSERT INTO build_quality VALUES(13,8,75.2999999999999971,76.0,82.0,86.0,72.0,64.0,70.0,'Hyundai BH-L platform in long-wheelbase flagship configuration. Additional structural reinforcement vs G80. Panel gaps 4-5mm 窶・Genesis flagship gets tighter tolerances. High-tensile steel cage. Body rigidity is best among Genesis sedans but still shared-platform architecture.','Best NVH in Genesis lineup. Above-average sound deadening throughout. Tau 5.0 V8 provides inherently smooth operation. Air suspension isolates road imperfections better than coil springs. Still uses rubber engine mounts (not hydraulic). No acoustic laminated glass standard. Closest Genesis gets to LS430 NVH territory but still a significant gap.','Flagship-grade materials. Nappa leather on upper trims. Real wood with open-pore finish options. Thicker soft-touch surfaces than G80. Still Hyundai-grade hard plastics in secondary areas (glove box interior, lower console, door map pockets). Interior ambition exceeds ES350 but material honesty falls short of Lexus.','Same Korean paint process as other Genesis. No systemic issues. Flagship may get additional paint stage or quality control. Good but not exceptional. Corrosion resistance adequate with galvanized steel.','Air suspension is the primary electrical concern 窶・sensors, compressors, and air bags add failure points. Otherwise Hyundai electronics are adequate. More tech features than G80 = more potential failure points. 10yr/100K warranty critical for long-term ownership. Parts backordering for Tau + air suspension components compounds risk.','Interior ages well initially. Nappa leather holds up. Real wood is durable. Air suspension can sag if not maintained 窶・this is the primary cosmetic aging concern. Parts backordering for Tau 5.0 and air suspension components is severe 窶・this is the #1 risk factor. Almost no aftermarket exists for these unique components.','G90 5.0 Q-score 70.2. The best Genesis for build quality 窶・flagship body, best NVH, best interior materials. But shared platform DNA limits ceiling, air suspension adds complexity, and parts backordering for Tau+air suspension is the critical weakness. A 70 is honest 窶・good but not in Lexus territory.','shared','Ulsan (South Korea)','spot',4.5,'rubber','laminated','standard','real_wood',4,'above_average','sample',NULL);
INSERT INTO build_quality VALUES(14,29,71.5999999999999943,74.0,70.0,76.0,70.0,68.0,68.0,'Same BH-L platform as G80 5.0. Identical body construction 窶・difference is powertrain only. Standard spot welding, high-tensile steel cage. Panel gaps 4-6mm. Body construction score same as 5.0 because the platform is the same.','Lambda 3.8 MPI is adequate NVH-wise but not V8-smooth. Port injection eliminates carbon buildup concerns. Rubber engine mounts. Standard laminated glass. Sound deadening is standard 窶・less than G90 flagship. Engine note is present but not intrusive. Road noise comparable to ES350.','Same interior as G80 5.0 at lower trim levels. Standard leather (not Nappa). Real wood on upper trims, wood-grain on lower. Same Hyundai-grade hard plastics in non-touch areas. The 3.8L gets fewer standard luxury features but the material quality is identical to 5.0 at equivalent trim.','Identical paint process to other Genesis sedans. No systemic issues. Korean paint is average 窶・no epidemics but not exceptional durability. Same galvanized steel, same clear coat. 10-year outlook is reasonable with care.','Simpler than V8 models 窶・no air suspension, fewer tech features. This is an advantage for long-term reliability. Hyundai electronics are adequate. 3.8L Lambda has simpler ECU requirements than Tau. Fewer failure points = higher electrical score than flagship models. 10yr/100K warranty covers electronic components.','Lambda 3.8 parts are more available than Tau 5.0 窶・shared with other Hyundai/Kia models. This is a meaningful advantage. Valve adjustment every 60K is the main maintenance concern. Oil consumption at high miles (150K+) is documented. Interior aging same as G80 5.0 trim level. Parts availability better than V8.','G80 3.8L Q-score 67.0. Honest mid-range Genesis. Shared platform, solid MPI engine, simpler electronics. Slightly below G80 5.0 due to less NVH refinement (V6 vs V8) and fewer standard luxury features. But parts availability is better than Tau, which matters for long-term ownership.','shared','Ulsan (South Korea)','spot',5.0,'rubber','laminated','standard','real_wood',4,'standard','sample',NULL);
INSERT INTO build_quality VALUES(15,152,69.4000000000000056,73.0,68.0,74.0,69.0,64.0,64.0,'Hyundai i30N-based platform (compact). Smaller body = potentially better rigidity. Updated structural adhesives and weld techniques for 2022+. Panel gaps improved to 3.5-5mm range. Still shared platform at core. Body construction benefits from newer engineering.','Sport sedan tuning prioritizes feel over isolation. 2.5T turbo is quieter than old 3.3T but still a turbo four-cylinder 窶・inherent NVH penalty vs V6/V8. Rubber engine mounts. Sport-tuned suspension transmits more road feedback. Sound deadening sacrificed for weight. Smallest Genesis = least insulation real estate.','Compact interior limits material ambition. Real aluminum trim (not plastic-look). Good leather on contact surfaces but smaller cabin means more hard plastics proportionally. Newer materials and improved processes vs 2017 Genesis launch. Interior quality is genuinely improved but still below ES350.','Newer paint process (2022+) may be improved. Too new for definitive aging data. Korean paint quality should be consistent with other Genesis 窶・no epidemics expected. Slightly optimistic score based on process improvements, but unproven long-term.','Too new for definitive electrical aging data. More tech features than older Genesis = more potential failure points. Hyundai electronics architecture has improved. 10yr/100K warranty critical. Score reflects uncertainty rather than known problems 窶・could improve or decline with age.','Far too new for cosmetic aging data. Score is speculative based on material quality observations. Newer interior materials should hold up better than 2017-era Genesis. Parts availability for Smartstream is good 窶・shared across Hyundai/Kia lineup. Low confidence score due to newness.','G70 2.5T Q-score 64.1. Improved Smartstream engine with dual injection addresses carbon buildup concerns. But compact sport sedan packaging, turbo NVH, and newness limit the score. Too early for definitive build quality assessment 窶・scores are conservative projections. The dual injection is a genuine engineering improvement over the problematic 3.3T.','shared','Ulsan (South Korea)','spot',4.0,'rubber','laminated','standard','real_wood',4,'standard','sample',NULL);
INSERT INTO build_quality VALUES(16,153,70.2999999999999971,73.0,68.0,76.0,70.0,64.0,66.0,'Hyundai N3 platform (compact SUV). SUV body structure with higher center of gravity. Additional structural reinforcement for SUV duty. Panel gaps 4-5mm. Same spot welding as sedan siblings. Liftgate adds complexity and potential flex.','SUV body provides more sound insulation volume than G70. Higher driving position changes NVH character. 2.5T turbo has some boom under load. Road noise from taller tire sidewalls is reduced vs sport sedan tuning. Rubber engine mounts. Standard laminated glass. Overall slightly better NVH than G70 due to SUV packaging.','SUV interior has more surface area 窶・more soft-touch material but also more hard plastic. Same material grade as G70 at equivalent trim. Elevated seating position means different touch points. Real wood on upper trims. Interior is competitive for compact luxury SUV segment but still Hyundai-grade in non-touch areas.','Same Korean paint process as other Genesis. SUV-specific concern: larger horizontal surfaces (hood, roof) more exposed. Too new for definitive aging data. No reason to expect different paint performance than sedan siblings.','Same electrical architecture as G70 2.5T. SUV adds rear liftgate electronics, potentially air suspension sensors. Too new for definitive data. More features = more potential failure points. 10yr/100K warranty is the safety net.','Too new for definitive cosmetic aging data. SUV interior may age differently due to cargo use. Parts availability for 2.5T Smartstream is good 窶・shared across Hyundai/Kia. Score is marginally higher than G70 due to less sport-focused (fewer bolster-wear concerns).','GV70 2.5T Q-score 65.0. Smartstream 2.5T in SUV packaging provides slightly better NVH than G70 sedan. Same fundamental build quality strengths (dual injection, newer materials) and weaknesses (shared platform, rubber mounts, Hyundai-grade secondary materials). Scores are conservative projections due to newness.','shared','Ulsan (South Korea)','spot',4.5,'rubber','laminated','standard','real_wood',4,'standard','sample',NULL);
INSERT INTO build_quality VALUES(17,45,75.7999999999999971,78.0,80.0,87.0,72.0,62.0,72.0,'All-new 2nd generation G90 platform. Significantly updated structural engineering 窶・more high-tensile steel, structural adhesives, and reinforced joints than 1st gen. Panel gaps tightened to 3.5-4.5mm. Best body construction in Genesis lineup. Closest Genesis gets to bespoke feel.','Best NVH isolation in Genesis lineup. 2nd gen G90 adds more sound deadening material, improved door seals, and better engine bay insulation. Lambda II 3.5T with dual injection is smoother than old 3.3T. Air suspension (standard) provides excellent isolation. Still rubber mounts and no acoustic laminated glass 窶・engineering ceiling remains.','Best interior in Genesis lineup by a wide margin. Genuine semi-aniline leather available on top trim. Real wood with multiple finish options. Significantly improved soft-touch surface coverage 窶・fewer hard plastics than 1st gen. Still Hyundai DNA in secondary areas but the gap to Lexus is narrowed. Interior score 75 is honest.','Same Korean paint process but potentially additional QC for flagship. Too new for definitive aging data. No systemic paint issues in Genesis history. Flagship treatment suggests better process control.','Most complex electronics in Genesis lineup. Digital dash, augmented reality nav, rear-wheel steering, air suspension, extensive driver assistance. All features that add failure potential. Too new for definitive aging data. More tech = more risk. 10yr/100K warranty is critical. Electrical score is lowest dimension 窶・reflects complexity concern.','2nd gen G90 interior uses better materials that should age well. Semi-aniline leather (if equipped) ages gracefully. Real wood is durable. Air suspension remains the primary cosmetic aging concern. Too new for definitive data 窶・score is projected. Parts backordering for 2nd gen specific components may be an issue as fleet ages.','G90 2nd gen Q-score 71.0. Best Genesis overall 窶・highest body construction score, best NVH, best interior materials. The 2nd gen is a genuine improvement over 1st gen. But shared platform ceiling, air suspension complexity, and electronics density limit the score. 71 is strong but the 10yr/100K warranty is doing heavy lifting.','shared','Ulsan (South Korea)','spot',4.0,'rubber','laminated','standard','real_wood',4,'above_average','sample',NULL);
INSERT INTO build_quality VALUES(18,151,71.7000000000000028,74.0,70.0,78.0,70.0,66.0,68.0,'Same BH-L platform as G80 3.8L and 5.0. Identical body construction. Sport badge is powertrain and suspension, not structural. Panel gaps 4-6mm. Standard spot welding. Body score same as G80 siblings because platform is the same.','Lambda II 3.3T turbocharged V6 has more NVH than naturally aspirated 3.8L or 5.0 V8. Turbo spool and blow-off are audible (intentional for Sport model). Sport-tuned suspension transmits more road feel. Rubber engine mounts. Sound deadening same as G80 standard. The turbo engine fundamentally compromises NVH vs the 5.0 or even 3.8.','Same interior as G80 at equivalent trim. Sport model gets unique accents and stitching. Real wood or aluminum trim options. Same Hyundai-grade hard plastics in non-touch areas. Interior quality identical to G80 3.8/5.0 窶・the Sport designation doesn''t change material quality.','Identical paint to all Genesis sedans. No systemic issues. Korean paint, average quality, no epidemics.','Hyundai electronics adequate. Sport model adds adaptive suspension electronics. No unique electrical issues vs standard G80. 10yr/100K warranty covers all components. Lambda II oil consumption is a mechanical, not electrical, issue.','Lambda II 3.3T is the critical concern. NHTSA investigation, class action lawsuits, and oil consumption epidemic documented across Hyundai/Kia 3.3T applications. Parts are shared across platform (good availability) but the engine itself is the liability. Interior aging same as other G80 variants. Engine concern drags down cosmetic/long-term ownership confidence.','G80 3.3T Sport Q-score 66.9. Same excellent G80 body with the problematic Lambda II 3.3T. Oil consumption epidemic and NHTSA investigation are serious concerns. Score is slightly below 3.8L and 5.0 due to engine-related risk. The Sport badge gives driving engagement but the Lambda II 3.3T is the weakest link.','shared','Ulsan (South Korea)','spot',5.0,'rubber','laminated','standard','real_wood',4,'standard','sample',NULL);
INSERT INTO build_quality VALUES(19,38,69.0999999999999943,73.0,66.0,72.0,69.0,66.0,64.0,'Compact sedan platform (i30N derivative). Smaller body but sport-tuned structural bracing. Panel gaps 4-5mm. Standard spot welding. Good rigidity for the class but smallest Genesis = least structural mass for NVH isolation.','Worst NVH in Genesis lineup. Lambda II 3.3T turbo in a compact body with sport suspension 窶・the NVH penalty is triple: turbo noise, minimal insulation, sport tuning. Rubber engine mounts. No acoustic glass. Engine mounts transmit vibration under boost. At highway speeds, turbo whoosh and road noise are prominent. G70 3.3T is the loudest Genesis.','Compact interior limits material ambition. Sport-oriented cockpit with good tactile surfaces on primary touch points. But smaller cabin means proportionally more hard plastics. Real aluminum trim accents. Same Hyundai-grade secondary materials. Interior quality is good for a sport sedan but below ES350 and below G80.','Same Korean paint as all Genesis. No unique paint issues. Compact sedan = smaller paint area = potentially less exposure.','Hyundai electronics adequate. Sport model adds limited-slip diff electronics, adaptive suspension. Lambda II oil consumption is mechanical not electrical. Electrical score same as other Genesis 窶・no unique electronic issues. 10yr/100K warranty covers everything.','Lambda II 3.3T with documented oil consumption epidemic in the sportiest Genesis. Sport seats get harder use (aggressive driving). Compact interior materials may show wear faster. Engine reliability concern undermines long-term cosmetic confidence. Parts are shared (good) but the engine is the liability.','G70 3.3T Q-score 63.3. Lowest Genesis score 窶・problematic Lambda II 3.3T in the smallest, loudest body. The driving experience is engaging but build quality is the worst Genesis combination. NVH is the weakest dimension. If considering a G70, the 2.5T Smartstream is the better long-term bet despite being newer.','shared','Ulsan (South Korea)','spot',4.5,'rubber','laminated','standard','real_wood',4,'standard','sample',NULL);
INSERT INTO build_quality VALUES(20,44,75.0999999999999943,76.0,79.0,85.0,72.0,66.0,70.0,'Same flagship BH-L platform as G90 5.0. Additional structural reinforcement. Panel gaps 4-5mm. High-tensile steel cage. Body construction identical to G90 5.0 窶・engine choice doesn''t change the body.','Flagship sound deadening helps the 3.3T significantly. Air suspension standard. Above-average insulation. Lambda II 3.3T is less refined than Tau 5.0 under load but flagship isolation masks much of it. Rubber engine mounts. Standard laminated glass. NVH is good for a turbo V6 flagship but not V8-flagship smooth.','Identical interior to G90 5.0 at equivalent trim. Nappa leather, real wood, flagship-grade materials. Same Hyundai-grade hard plastics in secondary areas. Interior score same as 5.0 because the cabin is identical.','Same Korean paint process as all Genesis flagships. No systemic issues. Good galvanized steel. Flagship QC. Paint score identical to G90 5.0.','Hyundai electronics with flagship complexity. Air suspension, more driver assistance features than G80. Lambda II oil consumption is mechanical not electrical. 10yr/100K warranty critical. Same electrical architecture as G90 5.0 窶・no unique electronic concerns.','Lambda II 3.3T oil consumption concern in a flagship is particularly unfortunate 窶・this is a $70K+ car with documented engine lawsuits. Air suspension aging same as G90 5.0. Interior materials are flagship-grade and should age well. Parts for 3.3T are more available than Tau 5.0 (shared across Hyundai/Kia). Cosmetic score slightly higher than 5.0 due to better parts availability.','G90 1st gen 3.3T Q-score 70.3. Same excellent flagship body and interior as the 5.0, but Lambda II 3.3T engine concerns hold it back. Flagship isolation helps NVH despite turbo engine. The oil consumption epidemic and NHTSA investigation are serious negatives in a flagship. Slightly below G90 5.0 in NVH but slightly above in parts availability.','shared','Ulsan (South Korea)','spot',4.5,'rubber','laminated','standard','real_wood',4,'above_average','sample',NULL);
INSERT INTO build_quality VALUES(21,54,70.2000000000000028,73.0,68.0,77.0,70.0,62.0,66.0,'Hyundai N3 platform (compact SUV). Same platform as GV70 2.5T. SUV body with liftgate. Standard spot welding with structural adhesives. Panel gaps 4-5mm. Body construction identical to GV70 2.5T 窶・engine choice doesn''t change the structure.','SUV packaging provides more insulation volume than G70 sedan. 3.5T dual injection is quieter than old 3.3T but still turbo NVH under boost. Air suspension option improves ride quality. Rubber engine mounts. Standard laminated glass. Better NVH than G70 3.3T due to SUV packaging and newer engine tuning.','Same interior as GV70 2.5T at equivalent trim. Good materials on touch surfaces. SUV provides more interior volume = more material coverage. Real wood on upper trims. Same Hyundai-grade secondary materials. Interior score identical to 2.5T variant.','Same Korean paint as all Genesis SUVs. No unique issues. SUV horizontal surfaces more exposed but no paint epidemics in Genesis history. Same galvanized steel, same process.','Same electrical architecture as GV70 2.5T plus air suspension electronics if equipped. Too new for definitive data. SUV electronics (liftgate, air suspension) add complexity. 10yr/100K warranty is safety net. Newer tech = more potential failure points.','Lambda II heritage is the concern despite dual injection improvement. Oil consumption risk remains from engine family DNA. SUV cargo use may accelerate interior wear. Too new for definitive cosmetic aging. Score is conservative due to engine family history. Parts for 3.5T are shared across Hyundai/Kia (good availability).','GV70 3.5T Q-score 65.2. Dual injection improves on the problematic 3.3T but Lambda II oil consumption heritage remains. SUV packaging helps NVH vs G70 3.3T. Same fundamental Genesis strengths (newer platform, improved materials) and weaknesses (shared platform, rubber mounts). Score slightly higher than G70 3.3T due to SUV NVH advantage and newer engineering.','shared','Ulsan (South Korea)','spot',4.5,'rubber','laminated','standard','real_wood',4,'standard','sample',NULL);
INSERT INTO build_quality VALUES(22,154,70.5,73.0,70.0,78.0,70.0,62.0,66.0,'Hyundai M3 platform (mid-size SUV). Largest Genesis vehicle. Heaviest body = most stress on structure and components. Standard spot welding with structural adhesives. Panel gaps 4-5mm. Good rigidity for SUV class but heaviest application of shared platform. Long-term structural durability under max load is unproven.','Mid-size SUV provides good insulation volume. 3.5T under load moves significant mass 窶・turbo lag and boost NVH are noticeable with full payload. Air suspension (available) helps ride quality. Rubber engine mounts. Standard laminated glass. Better NVH than compact SUVs due to mass and volume, but turbo working harder than in lighter applications.','Best Genesis SUV interior. More surface area = more premium material coverage. Real wood, leather, soft-touch surfaces on all primary touch points. Still Hyundai-grade plastics in cargo area and secondary zones. Interior ambition is high for the price point. Second-row space allows more material investment.','Same Korean paint process. Largest Genesis = largest paint surface area. No systemic issues. Horizontal surfaces (large hood, roof) are exposure points. Same galvanized steel. Paint quality consistent with other Genesis vehicles.','Most electronics in Genesis SUV lineup. 3D digital dash, highway driving assist, air suspension, rear-axle steering. All complexity that can fail. Too new for definitive data. Lambda II oil consumption is mechanical. 10yr/100K warranty essential. Electrical score reflects density of tech features.','Heaviest Genesis = most stress on all components. Lambda II 3.5T working hardest in this application. Oil consumption risk from engine family heritage. Air suspension (if equipped) under max load will age faster. Interior cargo-area materials may show wear with use. Too new for definitive data 窶・score is conservative. Parts shared with Hyundai/Kia (good availability for 3.5T).','GV80 3.5T Q-score 65.6. Largest, heaviest Genesis with the most stressed Lambda II application. Good SUV interior and improved 3.5T dual injection, but maximum vehicle mass amplifies engine and component aging concerns. Score slightly above GV70 3.5T due to better interior volume/materials, but structural stress concern offsets the gain.','shared','Ulsan (South Korea)','spot',4.5,'rubber','laminated','standard','real_wood',4,'standard','sample',NULL);
INSERT INTO build_quality VALUES(23,63,88.2999999999999971,94.0,89.0,87.0,84.0,90.0,83.0,'Clean-sheet F1 platform designed to beat Mercedes S-Class. World-first laser welding on body seams (patented Toyota process). 0.005mm body panel tolerance (20x tighter than contemporaries). High-tensile steel door beams. Double-wishbone suspension all four corners. Aerodynamic flat underbody panel.','Hydraulic fluid-filled engine mounts. 2-ton sand-filled frame rails for vibration damping during development. Extensive asphalt sheet deadening in floor pan and doors. Pre-acoustic glass era but thick laminated windshield. Famous coin-balancing idle test from development 窶・1UZ-FE smooth enough to balance a coin at idle.','Semi-aniline leather standard 窶・same grade that would carry through to LS430. Real California walnut trim (genuine, not veneer). Electroluminescent gauges (predecessor to Optitron). Interior panel tolerance 5mm. First car with in-dash CD player. Climate control with plasmacluster ion purifier.','Tahara multi-coat paint process with electrostatic primer. Galvanized steel body panels. Excellent corrosion resistance for era 窶・no rust epidemics after 30+ years. Some clear coat thinning on horizontal surfaces at 25+ years but better than any German or American contemporary.','Remarkably simple electronics for a flagship 窶・this is the LS400''s secret weapon. Analog gauges, basic ECU, no touchscreen. Very few electronic failure points. A/C system reliable. Power seats and windows durable. Nearly bulletproof at 30+ years and 300K+ miles.','Premium materials age exceptionally well. Semi-aniline leather develops patina rather than cracking at 200K+. Real walnut resists delamination. Tight 4mm panel gaps prevent squeaks and rattles. Dashboard resists UV cracking better than Nissan or BMW of era. Some steering wheel wear at 200K+.','LS400 Q-score 87.8. The car that invented Japanese luxury build quality. First LS set every benchmark that LS430 later perfected. Deductions from LS430 for older NVH technology (no acoustic glass, no sandwich steel), wider panel gaps (4.0 vs 3.5mm), and simpler paint process. Electronics score (90) highest in database due to 1989 simplicity.','bespoke','Tahara Plant (Aichi, Japan)','laser',4.0,'hydraulic','laminated','semi_aniline','real_wood',5,'extensive','expert_analysis',NULL);
INSERT INTO build_quality VALUES(24,35,75.5,70.0,78.0,74.0,80.0,80.0,76.0,'Shared Toyota N platform (same as Crown and Mark X, NOT bespoke LS). Double wishbone front suspension is unusual for a shared platform and adds credibility. Multi-link rear. High-strength steel in key structural areas. Good rigidity but lacks the bespoke engineering investment of an LS.','Lexus-grade NVH tuning applied to shared platform. Hydraulic engine mounts standard 窶・unusual at this price point. Acoustic laminated front windshield. Active Noise Control available on F Sport models. Sound-deadening glass on upper trims. Notably quieter than German competitors (5 Series, E-Class) at cruise.','Quality Lexus materials but not LS-tier. Standard leather (not semi-aniline). Real aluminum trim and genuine wood options. Analog clock on dash. Good soft-touch surfaces on upper panels. Lexus Enform infotainment dated but functional. S2000-style driver-focused cockpit. Better materials than ES350.','Standard Toyota/Lexus paint process. Good quality with no known epidemics. Self-healing clear coat on darker colors. Corrosion-resistant galvanized steel throughout. Holds up well at 10+ years. Paint quality consistent across Motomachi production.','Generally reliable Lexus electronics. Some reports of navigation screen delamination at 8+ years. Adaptive variable suspension sensors can fail. Mark Levinson amp holds up well. No systemic electrical gremlins. Significantly better electrical track record than LS460 despite sharing some components.','Lexus interior quality means graceful aging. Leather holds up at 100K+ miles. Real wood trim doesn''t fade. Some center console armrest wear at high mileage. F Sport seats show minor bolster wear. Steering wheel holds up. Overall better aging than any German competitor in this class.','GS 4th gen Q-score 76.3. The best non-LS Lexus for build quality 窶・double wishbone front suspension adds engineering credibility. Shared platform prevents bespoke-level scores but Lexus-level NVH tuning and material selection elevate it above ES350. Discounted for not being bespoke and slightly below LS-tier interior materials.','shared','Motomachi Plant (Aichi, Japan)','mixed',4.5,'hydraulic','acoustic_laminated','standard','real_wood',4,'above_average','expert_analysis',NULL);
INSERT INTO build_quality VALUES(25,40,83.7000000000000028,94.0,92.0,90.0,90.0,55.0,75.0,'Bespoke LS platform with laser welding carried forward from LS430. Multi-link front and rear with standard air suspension. 0.002mm body panel tolerance (improved from LS400''s 0.005mm). Aluminum hood, doors, and fenders for weight reduction. First LS with LED headlights. Same Tahara Takumi craftsmanship.','Exceptional NVH isolation matching LS430 benchmark. Hydraulic engine mounts. Acoustic laminated glass all around including rear quarter windows. Active Noise Control. Sound-insulating resin injected into body pillars. Helmholtz resonators in wheel wells. 56dB at 100km/h cruising 窶・whisper-quiet.','Semi-aniline leather available. Shimamoku wood option is hand-sanded through a 67-day, 38-step process 窶・the most expensive wood trim in automotive production. Optitron gauges. Mark Levinson Reference audio. Executive-class rear seat with ottoman option. Interior tolerance maintained at 1mm like LS430.','Tahara multi-coat process identical to LS430. Robot-applied electrostatic primer. Self-healing clear coat on darker colors. Excellent long-term corrosion resistance with galvanized steel throughout. No clear coat epidemics documented. Paint quality fully matches LS430 after 15+ years of data.','8-speed AA80E automatic valve body failures are common 窶・harsh 2-3 and 5-6 shifts at 60-100K miles. Air suspension compressor and air bags fail at 80-120K ($3-5K repair). Brake actuator/accumulator failures documented across forums. Motorized tilt-telescope column can stick. Mark Levinson amp can fail from cold solder joints. The most complex LS before 600h.','Premium physical materials age well 窶・semi-aniline leather patinas nicely, Shimamoku wood is durable. Air suspension sag if not maintained affects vehicle stance. Motorized features can stick or fail. Better than any German competitor for cosmetic aging but below LS430 and LS400 due to complexity-induced neglect.','LS460 Q-score 82.7. Incredible physical build quality matching LS430 in every dimension except electrical aging. The 8-speed auto, air suspension, and motorized feature complexity result in a -37 point electrical deduction versus LS430 (82). Body, NVH, and materials are all 90+ 窶・it is built as well as any car. Complexity is the enemy, not construction quality.','bespoke','Tahara Plant (Aichi, Japan)','laser',3.5,'hydraulic','acoustic_laminated','semi_aniline','real_wood',5,'extensive','expert_analysis',NULL);
INSERT INTO build_quality VALUES(26,24,79.5,94.0,94.0,92.0,90.0,30.0,68.0,'Same bespoke LS460 platform with additional structural reinforcement for 150kg+ hybrid battery pack. Laser welding throughout. Same 0.002mm panel tolerance. Heaviest LS ever at 2,410kg. AWD system adds front differential and driveshaft. Battery mounted behind rear seat for weight distribution.','Best NVH isolation of any LS ever made. Hybrid system eliminates engine vibration at low speed entirely 窶・EV-only mode up to 40mph is tomb-silent. Active engine mounts supplement hydraulic mounts. Acoustic laminated glass all around including rear quarter. At idle it is the quietest production car tested by Car and Driver in 2008.','Top-shelf everything exceeding LS460. Semi-aniline leather standard. Shimamoku wood (67-day process) standard on Executive class. Alcantara headliner. Rear executive seats with massage and ottoman. Rear climate control with separate zones. Premium material selection exceeds every non-L sedan.','Same Tahara multi-coat process as LS460. Excellent quality with no known paint issues. Self-healing clear coat. Corrosion-resistant galvanized steel. Identical paint aging characteristics to LS460.','Catastrophic electrical complexity. Hybrid battery degradation at 10-15 years ($6-10K replacement). Inverter/converter failures documented across owner forums 窶・some TSBs issued. CVT uses two-motor planetary gearset, not serviceable if internal failure occurs. Air suspension failures inherited from LS460. Brake booster/actuator failures. Parking assist camera module failures. Motorized everything means everything can break. Reliability score of 56.3 is the lowest of any LS.','Same premium physical materials as LS460 but 2,410kg curb weight stresses components more. Air suspension more heavily loaded 窶・failures affect ride height visibly. Heavier doors stress hinges over time. Battery heat can affect trunk area materials. Otherwise same excellent Lexus cosmetic material quality.','LS600h Q-score 78.0. The best NVH (94) and materials (92) of any LS, but catastrophic electrical aging (30) 窶・the lowest electrical score of any Lexus ever made. Hybrid battery, inverter, CVT, air suspension, and motorized features create a $15K+ deferred maintenance time bomb. Physical build quality is LS-tier but electronics drag the overall score down 16.7 points from LS430.','bespoke','Tahara Plant (Aichi, Japan)','laser',3.5,'active','acoustic_laminated','semi_aniline','real_wood',5,'extensive','expert_analysis',NULL);
INSERT INTO build_quality VALUES(27,87,68.0,64.0,65.0,52.0,78.0,88.0,68.0,'Toyota TNGA-K platform shared with ES350, Avalon, Highlander, Sienna. MacPherson strut front (not double wishbone). Multi-link rear. High-strength steel increased significantly over previous generation. Spot welding throughout with laser screw welding on select joints. Panel gaps improved to ~4.8mm 窶・better than XV50 but not Lexus-grade.','Significant NVH improvement over previous Camry generations thanks to TNGA. Foam-injected A-pillars and B-pillars. Dash insulator pad. Standard rubber engine mounts (not hydraulic 窶・cost saving). No acoustic laminated glass on any trim. 2GR-FKS V6 is inherently smooth. Quiet for a family sedan but not Lexus-quiet.','SofTex synthetic leather on XSE and XLE trims 窶・convincing but not real. Soft-touch upper dash and door panels. Hard plastics on lower panels and console. No real wood anywhere 窶・piano black or textured aluminum-look trim. Standard gauges with small TFT screen. Entune 3.0 infotainment functional but dated. Acceptable for segment, not luxury.','Standard Toyota paint process. Good quality with no known epidemics. Electrostatic primer application. Galvanized steel panels. Some paint chipping on front bumper from low front overhang. Holds up well at 5+ years with no premature clear coat failure. Expected to age similar to typical Toyota 窶・good but not exceptional.','Extremely reliable Toyota electronics 窶・the Camry''s greatest strength. Simple infotainment by modern standards. No air suspension. No complex motorized features beyond basic power seats. 2GR-FKS V6 is a proven powertrain with no systemic issues. Everything expected to work at 200K+ miles. The electrical reliability champion of this entire batch.','Adequate aging for mass market. SofTex synthetic leather more durable than real leather 窶・resists cracking. Piano black trim scratches easily and shows dust. Cloth seats (base SE) age better than SofTex. Dashboard plastics resist UV cracking. Toyota switchgear proven durable over decades. Better than average for the segment.','Camry XV70 Q-score 69.2. Honest mass-market build quality 窶・the TNGA platform is a genuine improvement over previous Camry generations. Electrical aging (88) is best-in-class and the highest in this entire batch. Held back by shared platform construction, standard (non-hydraulic) mounts, synthetic materials, and no luxury engineering investment. Scores appropriately below ES350 (76.3) 窶・it is an ES350 minus the Lexus premium.','shared','Georgetown, Kentucky / Tsutsumi, Japan','spot',4.79999999999999982,'rubber','laminated','synthetic','none',3,'standard','expert_analysis',NULL);
INSERT INTO build_quality VALUES(28,4,63.3999999999999985,78.0,32.0,48.0,70.0,85.0,52.0,'Purpose-built A80 platform 窶・not shared with any Celica or Soarer. Steel unibody with bolt-on front and rear subframes. Double-wishbone front, multi-link rear. 30% stiffer than A70 predecessor. Spot welding throughout with structural adhesive in key areas. Floorpan heavily reinforced for 2JZ-GTE torque. Targa top option reduces structural rigidity by ~15%.','Sports car with minimal NVH isolation 窶・by design. No hydraulic mounts 窶・standard rubber. No acoustic glass. No sound deadening beyond minimum asphalt sheeting. Sequential twin-turbo spool and 2JZ exhaust note are the intended audio. Tire roar significant at speed with wide staggered rubber. Not designed for quiet cruising 窶・at 80mph you hear 80mph.','Functional sports car interior, not luxury. Standard leather on RZ trim but not premium grade 窶・more durable than soft. Plastic trim dominates dash and center console. No wood anywhere. Basic analog gauges with prominent tachometer and turbo boost gauge. Recaro-style seats supportive but not plush. Premium for 1993 Toyota sports car but a step below luxury.','Good Toyota paint quality for era. Some clear coat issues on black and white cars at 20+ years 窶・typically hood and roof. Front bumper paint chips from low stance and air dam. Rear hatch area can develop rust if weather seals fail. No epidemic rust issues like G35. Better than average for 1990s Japanese sports car.','Simple 1990s electronics 窶・the 2JZ reliability halo extends here. ECU is virtually indestructible. Analog gauges with minimal electronics. No touchscreen, no navigation (JDM only). VVTi solenoid on 1997+ models occasionally fails. Traction control basic and reliable. Window regulators can fail. Overall excellent electrical aging for a 30-year-old car.','Sports car life means everything shows wear faster. Driver seat bolster foam collapses at 80-100K miles. Steering wheel leather wears at crown. Dashboard UV damage if not garaged. Plastic trim fades and becomes brittle. Targa top weather seals degrade and leak. Many examples modified or tracked which accelerates wear.','Supra A80 Q-score 60.8. Legendary engineering 窶・purpose-built platform, 2JZ-GTE, double-wishbone all corners 窶・but not a luxury car and scores reflect that. Body construction (78) is impressive for a 1993 sports car. NVH (32) is minimal by design 窶・driver connection is the point. Interior (48) is functional. Electrical aging (85) is excellent due to 1990s simplicity. Sports car tax on NVH and cosmetic scores keeps overall Q below luxury sedans.','bespoke','Motomachi Plant (Aichi, Japan)','spot',5.0,'rubber','standard','standard','none',4,'minimal','expert_analysis',NULL);
INSERT INTO build_quality VALUES(29,6,57.6000000000000014,72.0,25.0,38.0,70.0,82.0,45.0,'Purpose-built S2000 platform 窶・not shared with any Civic or Integra. Honda X-bone frame design provides exceptional rigidity for an open-top roadster 窶・one of the stiffest convertibles of its era. High-strength steel central tunnel and side sills. Double-wishbone suspension all four corners. Spot welding with structural adhesive. Engine bay tower brace standard.','Convertible roadster with functionally zero NVH isolation 窶・the metric barely applies. Soft top provides minimal sound insulation versus hardtop. No acoustic treatments, no sound deadening material 窶・Honda saved every gram. F20C at 9000rpm is the audio experience. Wind noise significant above 60mph with top up. With top down, NVH is moot. Engine vibration felt through chassis 窶・intentional for driver connection.','Minimalist sports car interior prioritizing weight savings over comfort. Standard cloth seats (leather optional in some markets). Hard plastic dash and door panels everywhere. Metal-look trim surrounds 窶・not real metal. No wood, no luxury materials. Digital instrument cluster (novel for era). Small steering wheel. Honda AP1 interior philosophy: driving first, comfort distant second.','Good Honda paint quality. No epidemic paint issues. Some clear coat thinning on Berlina Black and New Imola Orange at 15+ years 窶・these colors are more susceptible. Front bumper paint chips from low nose. Rear fender arches can bubble if driven in winter salt. Better paint aging than Mazda MX-5 contemporaries.','Simple Honda electronics 窶・nearly no failure points. No touchscreen. Basic manual HVAC controls. Digital dash cluster is reliable. AP1 does not even have stability control until 2006. VTEC solenoid is bulletproof. No parasitic drain issues. Window regulators the only common electrical failure. Overall very good electrical aging.','Roadster life means everything ages faster. Soft top requires replacement at 8-12 years ($1-2K in aftermarket). Seat foam collapses at 60-80K. Plastic trim fades and cracks in sun exposure. Dashboard can crack in hot climates (Arizona, Texas). Steering wheel leather wears. Convertible weather seals degrade and leak. Hard to keep pristine 窶・most S2000s show their mileage.','S2000 Q-score 55.3. Lowest in this batch but appropriately so 窶・it is a purpose-built roadster evaluated on luxury build quality metrics. Body construction (72) is excellent for a roadster thanks to the X-bone frame. NVH (25) is the lowest score in the entire database 窶・a convertible at 9000rpm is not built for silence. Interior materials (38) are minimal by design. Electrical aging (82) scores well due to Honda simplicity. The score reflects engineering purpose, not quality deficiency.','bespoke','Suzuka Plant (Mie, Japan)','spot',5.5,'rubber','standard','none','none',3,'minimal','expert_analysis',NULL);
INSERT INTO build_quality VALUES(30,33,67.0,70.0,68.0,68.0,70.0,60.0,64.0,'Hyundai-Kia shared rear-drive platform (shared with Genesis G70 and Hyundai Genesis Coupe predecessor). MacPherson strut front, multi-link rear. High-strength steel in B-pillars and roof rails. Spot welding throughout. Panel gaps inconsistent across production units 窶・some tight, some 5mm+ on the same car. Korean build quality improving rapidly but not yet consistent.','Above-average effort for Kia 窶・clear intent to compete with German sport sedans. Some acoustic treatments in firewall and floor pan. Laminated front glass on GT2 trim. Sound deadening material in door panels. 3.3L twin-turbo Lambda II is refined when cruising but announces itself under boost. Road noise from 19-inch staggered wheels. Better than any previous Korean car.','Good materials for the price point 窶・punches above its class. Nappa leather available on GT2 trim (standard leather on lower trims). Real contrast stitching on dash surface. Aluminum-look trim 窶・not real metal, deceives from photos. Plastic door pull surrounds feel cheap. Harman/Kardon audio. D-shaped steering wheel with paddle shifters. Competitive with BMW 330i interior at 70% of the price.','Kia paint quality has improved dramatically over previous generations. Good clear coat depth. No known epidemics yet 窶・car is relatively new at 5-7 years. Some reports of paint chipping on front bumper from road debris. Long-term corrosion resistance unknown but no early warning signs. Korean steel quality has closed gap with Japanese.','8-speed DCT has documented issues 窶・shudder at low speed, hesitation on takeoff, rough 1-2 shift. Some reports of infotainment system freezes requiring hard reset. Blind spot monitor sensor failures noted on forums. Rearview camera can fail. Not terrible but measurably below Toyota/Honda electrical reliability standards. Long-term aging data still accumulating at 5-7 years.','Good initial quality but long-term data limited to ~7 years maximum. Nappa leather appears to hold up well. Piano black trim scratches easily and shows every fingerprint. Steering wheel wear visible at 60K+ miles. Interior plastics show scuffing at entry points. Center console armrest material thins. Better than early Korean cars but not yet Japanese-tier aging.','Stinger Q-score 60.8. The best Korean attempt at a sports sedan 窶・Albert Biermann (ex-BMW M division) oversaw chassis development and it shows. Body construction (65) is solid for shared platform. NVH effort (62) exceeds expectations for Kia. Interior materials (55) punch above price point. Electrical aging (60) held back by DCT issues. Long-term cosmetic aging uncertain 窶・only 5-7 years of data. Scores appropriately alongside Supra A80 as purpose-engineered but non-luxury.','shared','Sohari Plant (Gwangmyeong, South Korea)','spot',4.5,'rubber','laminated','standard','none',3,'standard','expert_analysis',NULL);
INSERT INTO build_quality VALUES(31,156,74.5999999999999943,76.0,78.0,74.0,75.0,72.0,73.0,'SPA platform shared with XC60/S90. Extensive use of hot-formed boron steel (40% of body). Good crash structure. MacPherson strut front, multi-link rear. Spot welding primary with structural adhesive bonding. Panel gaps 4-5mm, consistent.','SPA platform engineered for low NVH from the ground up. Hydraulic engine mounts standard. Acoustic laminated windshield. Additional sound deadening in floor pan and firewall. Engine cover insulated. T5 single-turbo is inherently smoother than T6 twin-charge. Road noise well suppressed but not LS-tier.','Minimalist Scandinavian interior. Good soft-touch surfaces on touch points. Leatherette standard on base, genuine leather on higher trims. Driftwood inlay is real wood on Inscription. Sensus portrait tablet dominates dash 窶・clean but polarizing. Fit and finish above average, materials a step below German luxury.','Volvo multi-stage paint process. Good galvanized steel. Some reports of thin paint on horizontal surfaces (hood, roof) chipping easily. Not a clear coat epidemic but more chips than expected at highway mileage. Corrosion resistance good underneath.','Sensus infotainment is the weak point. Laggy, crash-prone on early 2019 models. OTA updates improved it but never great. Otherwise electrical systems are solid. No systemic gremlins beyond infotainment. Sensor reliability good.','Interior holds up well. Leather/leatherette ages gracefully. Real wood trim doesn''t delaminate. Piano black trim scratches easily. Steering wheel wears at 80K+. Door panels stay tight. Good long-term cosmetic durability for the segment.','S60 T5 Q-score 74.6. Honest SPA platform execution with single-turbo simplicity. Strong body structure, good NVH engineering, clean interior. Not luxury-grade materials (semi-aniline, Optitron) but above-average for the $40K segment. Sensus infotainment is the main electrical liability.','shared','Torslanda (Gothenburg, Sweden)','mixed',4.5,'hydraulic','acoustic_laminated','standard','real_wood',4,'above_average','sample',NULL);
INSERT INTO build_quality VALUES(32,157,73.5,76.0,74.0,74.0,75.0,68.0,72.0,'Identical SPA body structure to T5. Same hot-formed boron steel cage, same panel gaps, same welding. AWD adds Haldex fifth-generation coupling at rear axle 窶・well-integrated, doesn''t compromise body. No body construction difference vs T5.','T6 supercharger+ turbo adds mechanical complexity and slight NVH penalty. Supercharger whine audible under hard acceleration. Hydraulic mounts same as T5. AWD system adds minor drivetrain noise. Acoustic laminated windshield same. Marginally louder than T5 at idle and cruise.','Identical interior to T5 same trim level. Same materials, same fit. No interior difference between T5 and T6 of same trim. Inscription gets real wood, leather. Momentum gets leatherette, aluminum trim.','Identical paint to T5. Same Volvo paint process, same thin-on-hood issue, same good underneath corrosion resistance.','T6 engine is the electrical/complexity penalty. Supercharger + turbo + AWD = more sensors, more vacuum lines, more potential failure points. Supercharger bearings known to fail at 80-100K. Oil consumption higher than T5. Sensus infotraction same weakness. Polestar-optimized ECU tunes can stress components.','Same cosmetic aging as T5. Interior materials identical. Engine bay runs hotter (supercharger + turbo) 窶・rubber hoses and plastic engine covers degrade faster. Cosmetic under-hood aging faster.','S60 T6 Q-score 72.0. Same excellent SPA body as T5 but twin-charge engine adds complexity without adding build quality. Supercharger is a known wear item. Scores lower than T5 on NVH (supercharger whine), electrical (more sensors/failures), and cosmetic (hotter engine bay).','shared','Torslanda (Gothenburg, Sweden)','mixed',4.5,'hydraulic','acoustic_laminated','standard','real_wood',4,'above_average','sample',NULL);
INSERT INTO build_quality VALUES(33,160,74.7999999999999971,76.0,80.0,77.0,75.0,68.0,73.0,'SPA platform stretched for S90 flagship. Same boron steel cage architecture as S60/XC60 but longer wheelbase adds torsional rigidity challenge. Air suspension available on Inscription. Panel gaps 4-5mm. Good structure but not bespoke 窶・shared with 60-series.','Best NVH in the SPA family. Longer wheelbase = more isolation. Additional sound deadening vs S60. Air suspension (optional) improves ride quality significantly. Acoustic laminated windshield standard. Side windows acoustic laminated on Inscription. Engine noise better isolated in longer engine bay. T6 supercharger still audible under load.','Flagship-level materials. Nappa leather on Inscription (upgrade from S60 standard leather). Real wood options: flame birch, linear walnut. Orrefors crystal gear selector. Broader, richer interior than S60. Fit and finish very good. Sensus portrait tablet still dominates. Not German-luxury tier but the best Volvo can do.','Same Volvo paint process as S60/XC60. Same thin paint on horizontal surfaces. Same good galvanized steel underneath. Flagship gets no paint upgrade over 60-series 窶・shared platform limitation.','T6 twin-charge same complexity as S60 T6. Supercharger bearing failures, oil consumption. Sensus infotainment same weakness 窶・actually worse on early 2017-2018 S90 (first SPA model year). Air suspension (if equipped) adds pneumatic sensor and compressor failure risk. More electrical complexity than S60.','Interior materials age well. Nappa leather superior to standard. Real wood ages gracefully. Crystal gear selector durable. Longer cabin means more interior panels 窶・slightly more rattle potential. Air suspension can sag. Overall good cosmetic longevity.','S90 T6 Q-score 73.5. Best SPA interior materials and NVH but T6 engine complexity and Sensus infotainment limit the score. Flagship positioning but shared platform means no bespoke body engineering upgrade. The car Volvo wants to sell you, not the car they engineered from scratch.','shared','Daqing (China) / Torslanda (Sweden)','mixed',4.5,'hydraulic','acoustic_laminated','semi_aniline','real_wood',4,'extensive','sample',NULL);
INSERT INTO build_quality VALUES(34,98,57.5,65.0,50.0,60.0,55.0,52.0,55.0,'P3 platform predates SPA. Conventional steel body, less boron steel. MacPherson front, multi-link rear. Standard spot welding. Panel gaps 5-7mm. Stiffer Polestar suspension (Ohlins dampers, stiffer springs, strut brace) improves structural feel but doesn''t change body construction. Aging architecture vs SPA.','Polestar tuning prioritizes handling over comfort. Stiff suspension transmits road noise directly. Ohlins monotube dampers are firm. Engine mounts stiffer than standard. T6 twin-charge engine is mechanically noisy under boost. Some sound deadening removed for weight. Acoustic windshield not standard. The enthusiast trade-off: it handles but it''s not quiet.','Polestar-specific sport seats by Polestar/Sparco (later Polestar-branded). Good bolsters, durable fabric/leather combination. Piano black trim, blue contrast stitching. Materials are adequate but not luxury 窶・this is an enthusiast special, not a luxury car. Real aluminum trim on Polestar models. Interior simpler than SPA Volvos.','P3-era Volvo paint is average. Some reports of clear coat issues on dark colors at 8-10 years. Not epidemic like Infiniti G35 but not as good as SPA-era paint. Nordic climate cars (many Polestars are Swedish-market) often have underbody corrosion from road salt.','T6 twin-charged engine is the liability. Supercharger + turbo on a 2.0L 4-cylinder running high boost. Known for oil consumption, supercharger bearing failure, PCV issues. Polestar ECU tune increases stress. Ohlins dampers need rebuild at 50-70K. Sensus infotainment of this era (pre-SPA) is worse than later versions. More electrical gremlins than SPA cars.','Sport seats hold up well. Leather/fabric combination is durable. Piano black shows scratches and fingerprints. Exterior Polestar-specific body kit (front splitter, rear diffuser, spoiler) is unpainted plastic 窶・scuffs easily. Ohlins dampers can weep fluid at 60K+. Paint on wheels chips from stiff suspension. Ages like a sports car, not a luxury car.','V60 Polestar Q-score 58.0. Enthusiast car on aging P3 platform. The driving experience is the point (350hp, AWD, Ohlins, manual available in some markets), but build quality is mid-tier. Twin-charge engine complexity, stiff NVH, aging electrics. Buy it for the drive, not the quality.','shared','Torslanda (Gothenburg, Sweden)','spot',5.5,'rubber','standard','standard','none',4,'standard','sample',NULL);
INSERT INTO build_quality VALUES(35,158,74.2000000000000028,76.0,77.0,74.0,74.0,72.0,72.0,'SPA platform SUV. Same boron steel cage as S60/S90. SUV body has higher center of gravity but good structural rigidity for the class. Hot-formed steel in B-pillars, roof rails, door reinforcements. Panel gaps 4-5mm, consistent with SPA sedan siblings. Well-engineered safety cage.','SUV form factor inherently noisier than sedan 窶・more tire roar from larger contact patch, more wind noise from taller profile. Volvo compensates with extensive sound deadening in floor, firewall, doors. Hydraulic engine mounts standard. Acoustic laminated windshield. T5 single-turbo is smooth. Not sedan-quiet but very good for SUV.','Same interior architecture as S60. Same materials at same trim levels. Inscription gets Nappa leather and real wood. Momentum gets leatherette. Portrait Sensus tablet identical. Good materials for the class, not luxury-tier. XC60 benefits from higher price point 窶・more Inscription trims sold, so average interior quality higher.','Same Volvo paint process. SUV adds more chip risk 窶・higher ride height means more stone exposure from other vehicles. Front bumper and hood take more hits. Lower body cladding helps protect doors. Good underneath, same thin-on-hood issue.','SPA electrical architecture. Sensus infotraction same weakness 窶・laggy, occasionally crashes. T5 engine is electrically simple (single turbo, fewer sensors than T6). No systemic electrical issues beyond infotainment. Sensor reliability good.','Interior ages well on Inscription trim. Nappa leather durable. Real wood ages gracefully. Piano black trim scratches (XC60 has more of it than S60). Door panels stay tight. Cargo area materials are utilitarian 窶・scratch-prone. Steering wheel wears at 80K+. Good overall.','XC60 T5 Q-score 74.0. SPA platform SUV done right. Same body engineering strengths as S60 with SUV trade-offs (more tire noise, more chip risk). T5 simplicity is an advantage. Sensus infotainment is the universal Volvo weakness. Best-selling Volvo for good reason 窶・honest quality.','shared','Torslanda (Gothenburg, Sweden) / Luqiao (China)','mixed',4.5,'hydraulic','acoustic_laminated','standard','real_wood',4,'above_average','sample',NULL);
INSERT INTO build_quality VALUES(36,159,72.7999999999999971,76.0,73.0,74.0,74.0,66.0,71.0,'Identical SPA body structure to XC60 T5. Same boron steel, same panel gaps, same safety cage. AWD adds Haldex coupling. Air suspension optional. No body construction difference vs T5.','T6 supercharger whine plus SUV tire roar = louder than T5. Supercharger adds high-frequency mechanical noise under acceleration. Hydraulic mounts same. Sound deadening same. Net result: more noise sources than T5. AWD system adds minor drivetrain whine at highway speed.','Identical interior to XC60 T5 at same trim level. No difference in materials, fit, or finish between T5 and T6.','Identical paint to XC60 T5. Same process, same chip vulnerability, same good corrosion resistance.','T6 twin-charge same issues as S60 T6 and S90 T6. Supercharger bearing failures at 80-100K. Higher oil consumption. More sensors, more vacuum lines. AWD Haldex coupling needs fluid changes or seizes. Air suspension (if equipped) adds compressor and air bladder failure risk. More electrical failure modes than T5.','Same interior aging as T5. Engine bay runs hotter 窶・under-hood rubber and plastic components degrade faster. Same exterior cosmetic aging. Same chip risk.','XC60 T6 Q-score 71.5. Same excellent SPA body as T5 but T6 complexity penalties across NVH, electrical, and cosmetic dimensions. The supercharger adds power (316 vs 250 hp) but subtracts reliability and refinement. AWD is nice in snow but Haldex is a wear item.','shared','Torslanda (Gothenburg, Sweden) / Luqiao (China)','mixed',4.5,'hydraulic','acoustic_laminated','standard','real_wood',4,'above_average','sample',NULL);
INSERT INTO build_quality VALUES(37,162,63.0,68.0,62.0,64.0,65.0,55.0,60.0,'Hyundai-Kia N3 platform (shared with Sonata, Santa Fe). Unibody steel construction. Hot-stamped steel in A/B pillars and roof rails for safety. MacPherson strut front, multi-link rear. Standard spot welding. Panel gaps 5-7mm, acceptable but not tight. Good crash test ratings (IIHS Top Safety Pick). Economy-car architecture competent but not overbuilt.','Economy-car NVH strategy: insulation quantity over sophistication. Rubber engine mounts. No acoustic laminated glass. Sound deadening in floor and firewall but basic materials. 2.5T engine is smooth at idle but boomy under boost. Exhaust is tuned for sport (loud). Tire roar with 19-inch wheels on GT. Wind noise at 75+ mph. Adequate for the price, not competitive with luxury.','GT trim gets synthetic leather (not real) with suede inserts. Heavily textured plastic trim. Piano black center console (fingerprint magnet, scratches easily). Fake aluminum trim. The panoramic curved display (dual screens under one glass) looks modern but the surrounding materials are hard plastic. Good design, mediocre materials. Above average for Kia, below luxury.','Kia/Hyundai paint of this era is thin. Multiple owner reports of easy chipping on hood and front bumper. Some early reports of clear coat hazing on dark colors. Not a known epidemic yet (too new) but history suggests average-to-below. Good galvanization underneath. 10-year corrosion warranty suggests confidence.','Too new for definitive aging data. Early signs: UVO/Connect infotainment is responsive but Korean-market software with US localization quirks. Digital key system works but fiddly. 2.5T engine has some early turbo wastegate rattle reports (carryover from Sonata N-Line). No systemic electrical issues yet but Hyundai-Kia electrical history is mixed.','Too new for long-term data. Predictions based on Kia materials: synthetic leather will crack at 60-80K miles. Piano black trim will be scratched within 20K. Suede inserts wear fast on bolsters. Steering wheel leather thin. Interior will look good for 5 years, tired at 10. Economy-grade materials throughout.','K5 GT Q-score 55.0. Honest economy-sport sedan with great design and good value. Not built like a luxury car because it isn''t one. N3 platform is competent, 2.5T is powerful, but materials are economy-grade, NVH is basic, and long-term aging will be average at best. The $32K MSRP is reflected in every dimension.','shared','West Point (Georgia, USA)','spot',5.5,'rubber','standard','synthetic','none',3,'standard','sample',NULL);
INSERT INTO build_quality VALUES(38,34,39.6000000000000014,58.0,40.0,32.0,35.0,28.0,35.0,'Nissan D-platform (Front-Mid, shared with 370Z successor, never fully updated). FM layout is theoretically good for weight distribution but execution is dated. Standard spot welding, pressed steel throughout, no structural adhesives. Panel gaps 5-7mm, inconsistent. No advanced high-strength steel usage worth noting. Underneath, it''s a 2008 platform with a 2014 body. Worse than G35 FM platform in terms of advancement.','Poor. Direct Adaptive Steering (DAS) on equipped models creates a disconnected steering feel that also transmits weird feedback. No acoustic glass. Rubber engine mounts. Minimal sound deadening 窶・Infiniti prioritized the "sporty" exhaust note. V6 VR30DDTT (twin-turbo) is mechanically noisy. Road noise with sport tires is high. Wind noise at highway speed above average. The 2014 Q50 was criticized by every reviewer for NVH regression vs the G37 it replaced.','The weakest dimension. Interior materials are a known disgrace for the brand. Hard plastics everywhere. "Leather" is thinly coated synthetic that peels at 40-50K miles. "Kacchu" aluminum trim is textured plastic. Wood trim is glossy wood-grain vinyl. The dual-screen infotraction (upper + lower) was dated at launch in 2014 and never updated meaningfully through 2024. Panel fit inside is loose. Every surface feels cheaper than a Maxima. Infiniti''s cost-cutting is palpable.','Nissan paint of this era is poor. Multiple owner reports of clear coat failure on hood, roof, trunk at 5-7 years. White and black especially vulnerable. The Q50 paint is thin and soft 窶・chips easily, scratches in car washes. No evidence of improved paint process over G35 era. Corrosion resistance below average 窶・some early rust on rear quarter panels at 80K+.','DAS (Direct Adaptive Steering) is the Q50''s signature failure. Steer-by-wire with a mechanical backup clutch that engages when the electronic system fails (which it does). Three generations of DAS, all problematic. Intouch dual-screen infotainment is universally criticized 窶・laggy, crashes, requires reboots. The 2014-2017 models are especially bad. Climate control integration means when the screen dies, you lose AC control. Electrical architecture is a mess. VR30DDTT turbo engines have sensor reliability issues.','Interior materials degrade rapidly. Synthetic leather cracks and peels at 40-50K miles (documented extensively on forums). Steering wheel wrap wears through at 50-60K. Piano black trim scratched within months. Headliner sags near sunroof at 80K+. Exterior clear coat fails at 5-7 years. The Q50 ages worse than the G35 it replaced 窶・cheaper materials, more electronics, same poor paint. A 10-year-old Q50 looks like a 15-year-old car.','Q50 Q-score 38.5. Infiniti''s worst era in one car. D-platform FM architecture never properly updated. DAS steer-by-wire is a liability. Interior materials are disgraceful for a $40-50K car. Dual-screen infotainment was bad at launch and aged terribly. Paint quality poor. The VR30DDTT engine is powerful but surrounded by cheap. G35 was a driver''s car with bad materials; Q50 is a bad car with bad materials.','shared','Tochigi (Japan)','spot',6.5,'rubber','standard','synthetic','plastic',3,'minimal','sample',NULL);
INSERT INTO build_quality VALUES(39,135,55.5,85.0,42.0,60.0,45.0,35.0,40.0,'Tubular space frame with hand-formed aluminum body panels (hood, doors, trunk lid). Extraordinary engineering for 1954 窶・direct descendant of W194 race car. Hand-fitted panels by Mercedes Sindelfingen craftsmen, but 1950s precision is not modern laser-welding.','Zero NVH engineering by modern standards. Race-bred chassis transmits every surface imperfection. No sound deadening material. Gearbox whine, engine roar, and wind noise define the driving experience. 1950s isolation technology.','Spartan 1950s racing cockpit with functional gauges and minimal luxury. Beautiful to look at but not a luxury interior by any era standard. Leather and Bakelite were period-appropriate quality materials.','70+ years means virtually every surviving Gullwing has been repainted at least once. Original nitrocellulose lacquer was period-correct but thin. Galvanizing did not exist 窶・bare aluminum panels resist corrosion but steel subframe does not.','Minimal 1950s electrical system: few circuits, simple wiring. Bosch mechanical components survive but wiring insulation becomes brittle and cracks at 50+ years. Capacitor and coil failures are routine.','Dashboard leather shrinks and cracks. Steering wheel Bakelite chips. Rubber seals harden and leak. Seat leather splits at stress points. Most surviving examples are restored, making original-condition assessment difficult.','300 SL Gullwing Q-score 55.5. Extraordinary hand-built engineering for 1954 but scored as a car, not a collectible. Body construction is the highlight 窶・tubular space frame and aluminum panels were race-bred. Every other dimension suffers from 70 years of materials aging.','bespoke','Sindelfingen (Germany)','spot',6.0,'rubber','laminated','standard','none',3,'minimal','sample',NULL);
INSERT INTO build_quality VALUES(40,136,51.5,72.0,48.0,55.0,42.0,38.0,38.0,'Monocoque steel construction, heavier and less sophisticated than the 300 SL space frame. Standard Mercedes production of the 1950s 窶・competent but not race-derived. Spot-welded steel panels with no galvanizing.','Soft-top roadster with minimal insulation. Ponton-derived chassis transmits road noise directly. Canvas top provides negligible sound barrier. Engine noise prominent at all speeds.','Entry-level positioning shows 窶・simpler materials than 300 SL. Standard vinyl and cloth trim common; leather optional. Dashboard layout functional but not luxurious. Period-correct but not Mercedes-best.','60+ years of aging on non-galvanized steel. Rust is the primary threat to survival 窶・sills, floor pans, and wheel arches are vulnerability zones. Original paint was thin nitrocellulose.','Simple 1950s electrical systems with few components. Wiring harness deterioration after 50+ years is nearly universal. Generator (not alternator) and mechanical regulator add reliability but primitive by modern standards.','Canvas tops rot at 15-20 years. Seat foam disintegrates. Dashboard vinyl cracks. Chrome pitting on all exterior brightwork. Rubber weather seals harden and fail. Most survivors have been restored.','190 SL Q-score 51.5. The 300 SL''s lesser sibling 窶・competent 1950s roadster but never possessed the race-bred engineering of the Gullwing. Monocoque steel body and entry-level materials mean it scores lower across every dimension. Rust is the existential threat.','bespoke','Sindelfingen (Germany)','spot',6.5,'rubber','standard','standard','none',3,'minimal','sample',NULL);
INSERT INTO build_quality VALUES(41,137,64.9000000000000056,88.0,60.0,72.0,55.0,45.0,50.0,'W113 unibody was meticulously engineered with the iconic pagoda-shaped hardtop providing exceptional rigidity. Hand-built at Sindelfingen with careful panel fit. Dual-circuit braking, crumple zones, and the concave hardtop were engineering firsts. Excellent for the 1960s.','Roadster with detachable hardtop 窶・inherently compromised NVH. Soft top versions transmit significant wind noise. Inline-6 is mechanically smooth but road and tire noise dominate. Some sound deadening in floor and firewall, better than British roadsters of the era.','Genuine MB-Tex and optional leather held to Mercedes standards. Real wood or leather-wrapped steering wheel. Becker radio was premium for the era. Chrome fixtures and toggle switches had a quality feel. But 1960s dashboard plastics become brittle with age.','55+ years means most Pagodas have been repainted. Original paint was high-quality for the era but pre-galvanization 窶・rust on sills, floors, and wheel arches is common in unrestored cars. Pagoda Owners International reports rust as the #1 concern.','Bosch electrical components generally durable. Points and condenser ignition requires regular maintenance. Wiring harness insulation becomes brittle at 40+ years. Fuel gauge senders fail. Simple system means fewer failure modes but no modern reliability.','Dashboard padding cracks and shrinks in UV. Leather seats develop patina (acceptable) but foam collapses. Rubber seals throughout harden and leak. Chrome exterior trim pits. Pagoda hardtop seals shrink causing water ingress. MB-Tex outperforms leather for longevity.','280 SL Pagoda Q-score 64.9. Meticulously hand-built 1960s Mercedes with engineering decades ahead of contemporaries. Body construction scores well (88) 窶・the W113 unibory was exceptional for its era. Every other dimension suffers from 55+ years of materials aging. Better than a TR6, not as good as a W124.','bespoke','Sindelfingen (Germany)','spot',5.0,'rubber','laminated','standard','real_wood',3,'standard','sample',NULL);
INSERT INTO build_quality VALUES(42,138,66.5999999999999943,82.0,58.0,68.0,65.0,55.0,58.0,'R107 chassis was overbuilt for a roadster 窶・the platform survived essentially unchanged from 1971 to 1989. Heavy gauge steel throughout, robust subframes, and the removable hardtop added structural rigidity. Not W124-tier refinement but solid Mercedes construction.','Roadster NVH compromises inherent 窶・removable hardtop improves things significantly. V8 engine is smooth but transmits vibration through rubber mounts. Soft top allows wind noise at speed. Some sound deadening material in doors and floor but not sedan-level.','Genuine leather and MB-Tex upholstery options. Real wood veneer on console and dash. Mercedes switchgear of the 1980s was satisfying and durable. But design was dated even when new 窶・the R107 interior was essentially 1971 vintage updated with minor changes through 1989.','Mercedes galvanized bodies starting mid-1980s 窶・late R107 models benefit. Paint quality is good for the era. Soft top cars suffer from moisture exposure. Hardtop seals degrade causing water ingress. Some clear coat fading on horizontal surfaces at 35+ years.','Bosch CIS fuel injection is robust. Climate control system (automatic) is the weak point 窶・servo motors and vacuum actuators fail. Power windows and locks generally reliable. Becker radio holds up. Instrument cluster capacitors can leak.','Leather seats wear at bolsters after 100K miles. Dashboard padding shrinks and cracks in sun-exposed cars. Wood veneer can delaminate at edges. Chrome exterior trim pits with age. Rubber body mounts and suspension bushings harden, causing harsh ride.','560 SL Q-score 66.6. The R107 was solid 1980s Mercedes construction but not the legendary overengineering of the W124 sedan. Roadster packaging limits NVH and interior scores. The 18-year production run meant the design aged in place while competitors advanced.','bespoke','Sindelfingen (Germany)','spot',5.0,'rubber','laminated','standard','real_wood',4,'standard','sample',NULL);
INSERT INTO build_quality VALUES(43,7,83.5,95.0,88.0,88.0,85.0,65.0,72.0,'W124 body engineered to survive 30+ years 窶・double-skinned panels, extensive galvanization, seam-sealed cavities, wax injection. 500E specifically hand-assembled by Porsche at Zuffenhausen: widened fenders, reinforced subframes, additional structural bracing. The gold standard of Mercedes body engineering.','Bank-vault isolation is real 窶・W124 development targeted 30-year durability. Hydraulic engine mounts, double-door seals, asphalt-lined floor pans, acoustic-damped dash panel. The 5.0L V8 is intrinsically smooth. Road noise almost nonexistent. Wind noise absent at autobahn speeds.','Peak Mercedes interior: real wood veneer (burled walnut or zebrano), thick leather (optional), soft-touch surfaces everywhere, precision German switchgear with satisfying detents. Tolerances measured in tenths of millimeters. The 500E added sport Recaro seats and specific trim. Nothing rattles at 30 years.','W124-era Mercedes paint on galvanized steel resists corrosion for decades. Multi-stage paint process with clear coat. 500E-specific panels were painted to Porsche standards. Rust rare unless accident-repaired. Some minor clear coat thinning on horizontal surfaces at 30+ years.','Generally excellent but the M119 V8 adds complexity 窶・wiring harness insulation degradation (biodegradable wiring insulation per Mercedes environmental mandate of the early 1990s) is a known issue. ASR traction control modules can fail. LH-SFI injection system is reliable.','Interior holds up remarkably 窶・leather develops patina rather than cracking. Real wood does not delaminate. Dashboard does not crack. Door panels stay tight. Rubber components (seals, bushings) are the primary aging items 窶・softer compounds for NVH degrade at 20-25 years.','500E W124 Q-score 83.5. The pinnacle of Mercedes-Benz build quality, elevated further by Porsche hand-assembly at Zuffenhausen. W124 platform was engineered for 30-year durability and delivers. Only deductions: biodegradable wiring insulation (-8 electrical), 30-year rubber aging (-5 cosmetic), M119 complexity.','bespoke','Porsche Zuffenhausen (Germany)','spot',3.5,'hydraulic','laminated','standard','real_wood',5,'extensive','sample',NULL);
INSERT INTO build_quality VALUES(44,139,73.5,85.0,62.0,78.0,78.0,60.0,65.0,'R129 shares the W124-era overengineering philosophy 窶・robust chassis, galvanized steel, extensive corrosion protection. Automatic roll bar and reinforced A-pillars for safety. But roadster structure can''t match sedan rigidity 窶・cowl shake present with top down on uneven surfaces.','Roadster NVH is inherently compromised 窶・soft top allows wind noise even when raised. With hardtop fitted, isolation approaches W124 levels. V8 engine is smooth. Hydraulic engine mounts help. Some cowl resonance at certain speeds. Better than any contemporary roadster.','W124-era Mercedes interior quality: real wood, thick leather, quality switchgear. Sport seats with multiple adjustments. Automatic wind deflector was innovative. But roadster packaging limits interior storage and some surfaces use harder materials than the sedan.','Galvanized body with Mercedes multi-stage paint process. Hardtop cars age better than soft-top. Soft top mechanisms require maintenance to prevent water ingress. Some rust at jack points and behind wheel arches if drains clog. Generally good for 30+ years.','Soft top mechanism adds significant electrical complexity 窶・hydraulic pump, sensors, limit switches. Roll bar deployment system. Early models had wiring harness degradation (same biodegradable insulation as W124). Climate control servo failures. Bose speaker foam disintegration.','Convertible-specific aging: soft top canvas deteriorates at 10-15 years, rear window clouds. Hydraulic top cylinders leak at 15-20 years. Seat leather wears faster due to UV exposure. Dashboard padding can shrink in sun-belt cars. Roll bar covers crack.','500 SL R129 Q-score 73.5. W124-era Mercedes engineering applied to a roadster 窶・solid but compromised by convertible architecture. Body and paint scores reflect the overengineering, NVH deduction for roadster nature. Electrical and cosmetic deductions for top mechanism complexity and UV exposure.','bespoke','Sindelfingen (Germany)','spot',4.5,'hydraulic','laminated','standard','real_wood',5,'above_average','sample',NULL);
INSERT INTO build_quality VALUES(45,140,69.5,83.0,68.0,75.0,72.0,48.0,60.0,'Same R129 platform as 500 SL with additional V12-specific reinforcements. The M120 V12 required modified subframes and engine mounts. Body construction is W124-era quality 窶・galvanized, wax-injected, overbuilt. But the V12 adds heat stress to engine bay components.','V12 is inherently smoother than V8 窶・the M120 is one of the silkiest engines ever made. NVH with hardtop is excellent, approaching W124 sedan levels. Soft top still allows wind noise. Hydraulic mounts standard. The SL 600 was the luxury-oriented SL, tuned for refinement over sport.','Nappa leather standard on SL 600, a step above 500 SL trim. Real wood veneer, specific V12 badging. Exclusive interior color combinations. Mercedes switchgear of the era at its best. But same roadster packaging limitations as the 500 SL.','Same galvanized body and paint process as 500 SL. V12 heat can accelerate paint degradation on hood over long periods. Soft top canvas and seals same as other R129 models. Hardtop cars age better.','The M120 V12 doubles the complexity 窶・two ignition coils, two distributors (early), 24 valves, two catalytic converters. Wiring harness degradation more critical with more circuits. Electronic throttle (ETA) failures. Soft top hydraulics. Climate control. The combination is significantly more failure-prone than V8 models.','Same roadster aging as 500 SL plus V12 heat effects: under-hood rubber hoses and wiring age faster. Engine bay heat accelerates plastic component embrittlement. Same soft top and hydraulic cylinder issues. Nappa leather is softer but may not wear as well as standard leather.','SL 600 R129 Q-score 69.5. The M120 V12 is magnificent but doubles the complexity penalty 窶・electrical score drops to 48. Body and interior quality remain W124-era Mercedes excellence. The V12 heat soak accelerates cosmetic aging underhood. The smoothest R129 but the most expensive to maintain.','bespoke','Sindelfingen (Germany)','spot',4.5,'hydraulic','laminated','standard','real_wood',5,'above_average','sample',NULL);
INSERT INTO build_quality VALUES(46,47,65.7999999999999971,70.0,68.0,68.0,68.0,58.0,60.0,'W212 improved over W211 with high-strength steel and aluminum hood/fenders. But pre-facelift interiors revealed DaimlerChrysler-era cost-cutting 窶・cheaper plastics, less consistent panel gaps. Body structure is safe and rigid but the "bank vault" feel of the W124 was gone.','E-Class isolation remains a Mercedes strength 窶・laminated glass, hydraulic engine mounts, sound-deadened firewall. At highway speed it is quiet. But road noise from run-flat tire options intrudes. Not W124 vault-like but competitive for the era.','Pre-facelift W212 interior was widely criticized 窶・hard plastics on center console and lower dash, three different grain patterns that didn''t match, an angular design language that felt cold. Real wood was available but the overall execution lacked the warmth of competitors.','Mercedes paint quality recovered from the W210 rust epidemic. Multi-stage process with clear coat. Some early-build W212 examples had orange peel texture. Galvanized steel throughout. No systemic rust issues reported.','Pre-facelift electronics had teething issues 窶・COMAND system freezes, Bluetooth connectivity problems, parking sensor malfunctions. SBC brake system (early models) was a known failure point. AIRMATIC suspension on V6 models can leak. Not terrible but not Mercedes-best.','Hard plastics scratch easily and show wear at contact points. Leather (where equipped) holds up adequately. Dashboard materials can develop a sheen at contact areas. Center console trim peels on early production. Post-2014 facelift materials are significantly better.','E-Class W212 pre-facelift Q-score 65.2. A decent modern Mercedes but the pre-facelift interior is a visible reminder of DaimlerChrysler cost-cutting. Body structure is safe and the car is quiet, but the materials gap vs Audi A6 and BMW 5-Series of the same era was notable.','shared','Sindelfingen (Germany)','spot',4.5,'hydraulic','laminated','standard','real_wood',4,'above_average','sample',NULL);
INSERT INTO build_quality VALUES(47,161,70.5,74.0,72.0,74.0,72.0,62.0,66.0,'Facelift addressed many pre-facelift complaints 窶・tighter panel gaps, improved body rigidity, revised front and rear structures. Aluminum hood and fenders retained. The 2014 refresh was more than cosmetic; structural improvements were made to crash performance.','Improved NVH over pre-facelift with additional sound deadening material, better door seals, and revised engine mounts. laminated glass standard. Highway cruising is very quiet. Some 4-cylinder diesel models transmit more vibration through the drivetrain.','Major interior refresh replaced the angular, cheap-feeling pre-facelift design. Softer materials on touch surfaces, better grain matching, improved switchgear feel. Real wood trim options expanded. Still not W124-tier warmth but a significant step up. The analog clock was a nice touch.','Same paint process as pre-facelift with minor improvements. Mercedes paint of this era is generally good. No systemic rust issues. Some early facelift cars had paint adhesion issues on plastic bumper covers 窶・minor but noticeable.','COMAND system improved with more stable software. SBC brake system replaced with conventional brakes (major reliability improvement). AIRMATIC still present on some models but updated. Bluetooth and connectivity more reliable. Overall electrical improvement over pre-facelift.','Better materials age better than pre-facelift 窶・the softer touch surfaces resist scratching more effectively. Leather options improved. Dashboard materials don''t develop the glossy sheen as quickly. Center console trim more durable. A genuine improvement over 2010-2013 cars.','E-Class W212 post-facelift Q-score 70.1. The 2014 facelift was a meaningful quality recovery 窶・better materials, improved electronics, and tighter assembly. Still not peak Mercedes but a clear step up from the pre-facelift. The gap to Audi A6 narrowed significantly.','shared','Sindelfingen (Germany)','mixed',4.0,'hydraulic','laminated','standard','real_wood',4,'above_average','sample',NULL);
INSERT INTO build_quality VALUES(48,83,66.0999999999999943,72.0,70.0,72.0,68.0,52.0,58.0,'Same W212 facelift body structure but the M278 biturbo V8 adds heat stress to engine bay components and front subframe. AIRMATIC suspension standard 窶・air springs add failure points. Body is well-built but the powertrain complexity taxes the platform.','Biturbo V8 provides effortless thrust but deeper exhaust note permeates cabin at throttle application. Hydraulic engine mounts contain vibration. AIRMATIC provides excellent ride isolation when functioning. Laminated glass standard. Highway cruising refined when air suspension holds.','Same improved facelift interior as other W212 models 窶・AMG-line option adds sport seats and trim. Real wood, decent leather, improved soft-touch materials. But the E550 was positioned below AMG, so some AMG-specific interior upgrades are absent.','Same Mercedes paint process as W212 facelift 窶・good quality, no systemic issues. Twin turbo heat can cause slightly faster paint aging on hood surface over very long term. Not a practical concern in normal ownership periods.','The M278 biturbo V8 is the liability 窶・turbo wastegate rattles, timing chain guide wear, coolant pipe leaks. AIRMATIC air springs fail at 80-100K miles. COMAND system updates. The combination of V8 complexity and air suspension makes electrical/aging the weakest dimension.','AIRMATIC failures leave the car undriveable 窶・not just cosmetic. Engine bay heat accelerates rubber and plastic aging underhood. Interior materials same as facelift W212 (adequate). V8 heat soak can affect under-hood cosmetic components over time.','E550 W212 Q-score 65.7. The biturbo V8 transforms the driving experience but adds significant complexity and failure risk. AIRMATIC suspension and turbo-related issues drag the electrical score to 52. Body and interior quality match the W212 facelift but the powertrain tax is real.','shared','Sindelfingen (Germany)','mixed',4.0,'hydraulic','laminated','standard','real_wood',4,'above_average','sample',NULL);
INSERT INTO build_quality VALUES(49,31,76.5999999999999943,78.0,78.0,84.0,77.0,68.0,72.0,'W213 uses aluminum-intensive body construction with laser-welded joints. Significant weight reduction despite increased dimensions. Dual-phase and ultra-high-strength steel in safety structure. Tight panel gaps. A genuine return to form for Mercedes body engineering.','Acoustic laminated glass standard 窶・a meaningful NVH upgrade over W212. Hydraulic engine mounts, extensive sound deadening in firewall and floor. Aerodynamically optimized for wind noise. The W213 is notably quieter than the W212 at highway speed.','W213 interior was named one of the best in any production car 窶・flowing dashboard design, ambient lighting with 64 colors, widescreen cockpit display, open-pore wood options, and leather-wrapped surfaces on every touch point. A leap forward from W212. Real design leadership.','Modern Mercedes multi-stage paint process with ceramic clear coat option. Excellent corrosion protection. No reported systemic paint issues. Paint depth and consistency visibly better than W212. Some early-production color matching issues on bumper covers reported.','MBUX infotainment system generally stable after early software updates. Electronic architecture is complex but well-integrated. Some 48V mild-hybrid system issues on early EQ Boost models. Driver assistance sensors can require recalibration. Not bad for the complexity level.','Interior materials are holding up well in early long-term assessments. Ambient lighting strips durable. Leather options improved over W212. Piano black trim shows fingerprints and micro-scratches. Too new for definitive 10+ year aging data but early signs are positive.','E-Class W213 Q-score 75.5. A genuine return to form for Mercedes-Benz 窶・the W213 interior was class-leading at launch and the body engineering is modern and precise. Acoustic glass and extensive sound deadening deliver excellent NVH. Complexity keeps electrical below 70 but this is the best E-Class since W124.','shared','Sindelfingen (Germany)','laser',3.5,'hydraulic','acoustic_laminated','standard','real_wood',5,'extensive','sample',NULL);
INSERT INTO build_quality VALUES(50,149,75.2000000000000028,77.0,76.0,85.0,77.0,62.0,70.0,'Same W213 aluminum-intensive body with 4MATIC hardware packaged into the front subframe 窶・minor additional stress points. AWD system adds weight but no structural compromise. Laser-welded body same as RWD W213.','Same acoustic laminated glass and extensive sound deadening as RWD W213. Inline-6 turbo is smooth but slightly more mechanically audible than V6 at cold start. AWD drivetrain adds minor gear whine. Still very quiet at highway speed.','Identical W213 interior 窶・one of the best in any production car. Same flowing dashboard, ambient lighting, widescreen displays, and premium materials. The E 450 badge doesn''t change the interior execution. Leather and wood options identical.','Same modern Mercedes paint process 窶・excellent quality with no systemic issues. Same corrosion protection and clear coat quality as standard W213. AWD hardware underneath is well-protected from corrosion.','EQ Boost 48V mild-hybrid system adds complexity 窶・integrated starter-generator (ISG) can fail, 48V battery degradation, additional control modules. 4MATIC transfer case and front differential add maintenance items. More potential failure modes than RWD version.','Same W213 interior materials that are aging well. Additional under-hood heat from turbo inline-6 and 48V system may accelerate rubber hose aging slightly. AWD adds no interior cosmetic impact. Piano black trim still shows fingerprints.','E 450 4MATIC Q-score 73.9. Same excellent W213 platform with added 4MATIC and 48V hybrid complexity 窶・electrical score drops to 62. Interior and body quality unchanged from the standard W213 (which is a compliment). The inline-6 is smooth but the added systems create more failure potential.','shared','Sindelfingen (Germany)','laser',3.5,'hydraulic','acoustic_laminated','standard','real_wood',5,'extensive','sample',NULL);
INSERT INTO build_quality VALUES(51,144,58.5,65.0,62.0,55.0,60.0,52.0,55.0,'W204 was the DaimlerChrysler-era C-Class 窶・competent safety structure but noticeably cheaper than W203 predecessor in material feel. High-strength steel in key areas but standard spot welding throughout. Panel gaps inconsistent at 5-7mm. The "Mercedes quality" reputation took a hit.','Adequate noise isolation but not E-Class level. Standard rubber engine mounts, no acoustic glass on base models. Some road noise intrusion on rough surfaces. The M272 V6 (early) or M274 turbo-4 (late) transmit different NVH signatures. Competitive with BMW 3-Series but not class-leading.','The W204 interior is where cost-cutting was most visible 窶・hard plastics on center console and lower surfaces, a slab-like dashboard design, and switchgear that felt one tier below the E-Class. Real wood was optional; wood-grain plastic was standard. Leather optional; MB-Tex standard.','Mercedes paint quality on the W204 is average 窶・some owners report clear coat issues on horizontal surfaces at 8-12 years. Not the rust epidemic of the W210, but not W124-quality either. Some paint chipping on leading edges reported.','COMAND system is the primary electrical concern 窶・navigation screen delamination, Bluetooth module failures, frozen displays. Harmon/Kardon speaker surrounds deteriorate. Window regulator failures common. Sunroof mechanism issues. Early balance shaft gear failures on M272 V6 (engine serial below 2729..30 088914).','Hard plastics scratch and show wear quickly at contact points. Leather (where equipped) wears at bolsters. MB-Tex is more durable but looks plastic. Dashboard sheen develops at driver touch points. Interior trim pieces can rattle loose at 80K+ miles.','C300 W204 Q-score 58.5. The DaimlerChrysler cost-cutting era C-Class 窶・functional but the cheapest-feeling Mercedes of the modern era. Interior materials are the weakest dimension. Body is safe but lacks the solidity of W212. Electrical gremlins are common. A car you tolerate, not admire.','shared','Bremen (Germany)','spot',6.0,'rubber','standard','standard','wood_grain',3,'standard','sample',NULL);
INSERT INTO build_quality VALUES(52,145,73.0,75.0,72.0,76.0,74.0,68.0,70.0,'W205 is aluminum-intensive with mixed laser and spot welding 窶・a dramatic improvement over W204. Tighter panel gaps, lighter weight, more rigid structure. The C-Class finally felt like a proper Mercedes again. Some early-production models had interior rattles that were addressed in later builds.','Laminated glass on higher trims, improved door seals, hydraulic engine mounts available. The W205 is noticeably quieter than W204 at speed. Some tire noise from run-flat options. The M274 turbo-4 is refined but transmits more vibration at idle than the old V6.','Massive improvement over W204 窶・flowing dashboard design previewed the W213 E-Class interior (before the E-Class got it). Real wood trim standard on upper trims. Leather options improved. Soft-touch surfaces everywhere. Not quite E-Class level but the gap narrowed dramatically.','Modern Mercedes paint quality 窶・multi-stage process with good clear coat depth. No systemic rust issues. Paint adhesion improved over W204. Some metallic colors show more orange peel than others. Overall competitive with Audi A4.','COMAND system more stable than W204 generation. Driver assistance systems added complexity but generally functional. Some early-model teething issues with Bluetooth and smartphone integration resolved via updates. Sunroof mechanism more reliable than W204. Above average for the era.','Interior materials holding up better than W204 in early long-term reports. Leather options age well. Soft-touch surfaces resist scratching better. Ambient lighting strips durable. Piano black center console shows micro-scratches. A genuine improvement over the W204 at every touch point.','C300 W205 Q-score 71.8. A dramatic quality recovery from the W204 窶・the W205 C-Class finally feels like a proper Mercedes. The interior is the highlight, previewing the W213 E-Class design language. Not E-Class tier in body engineering but competitive with the BMW 3-Series and Audi A4.','shared','Bremen (Germany)','mixed',4.5,'rubber','laminated','standard','real_wood',4,'above_average','sample',NULL);
INSERT INTO build_quality VALUES(53,147,71.2999999999999971,74.0,70.0,76.0,74.0,62.0,68.0,'Same W205 aluminum-intensive body structure as C300 with minor reinforcement for the more powerful drivetrain. 4MATIC hardware adds front differential and transfer case but no structural compromise. Panel gaps and body quality identical to C300.','Same laminated glass and improved seals as C300. Turbo V6 produces more exhaust note that permeates cabin under throttle. 4MATIC adds minor drivetrain whine. Slightly less isolated than C300 due to sportier character but still quiet at cruise.','Identical W205 interior to C300 窶・same flowing dashboard, same material quality, same trim options. The C 400 badge doesn''t add unique interior elements beyond AMG-line package availability. Same real wood and leather options.','Same modern Mercedes paint process as C300 窶・good quality, no systemic issues. Same corrosion protection. Twin-scroll turbo heat underhood is well-managed with shielding. No paint-specific concerns.','Turbo V6 adds complexity over turbo-4 窶・more sensors, more actuators, intercooler plumbing. 4MATIC transfer case and front differential add maintenance items. 7G-Tronic transmission generally reliable but more stressed. Overall more failure points than C300.','Same W205 interior materials as C300 窶・aging characteristics identical. Under-hood turbo V6 heat may slightly accelerate rubber component aging. No interior cosmetic difference from C300 ownership.','C 400 W205 Q-score 70.2. Same excellent W205 platform as C300 with turbo V6 and 4MATIC complexity 窶・electrical score drops to 62. Interior and body quality unchanged. The additional power is nice but the complexity tax is reflected in the reliability and electrical scores.','shared','Bremen (Germany)','mixed',4.5,'rubber','laminated','standard','real_wood',4,'above_average','sample',NULL);
INSERT INTO build_quality VALUES(54,148,72.7999999999999971,76.0,68.0,78.0,74.0,65.0,70.0,'W205 body with AMG-specific front subframe and suspension components. AMG Sport line received additional bracing and different suspension tuning. Slightly tighter assembly attention at Bremen for AMG-badged models. Same aluminum-intensive body structure.','Sportier tuning means more exhaust note by design 窶・AMG Sport exhaust is audible under throttle. Hydraulic engine mounts standard. Same laminated glass. Sport suspension transmits more road detail. Some tire roar from wider staggered fitment. A sporting compromise by intent.','AMG Sport interior upgrades: sport seats with enhanced bolsters, AMG-specific steering wheel with flat bottom, DINAMICA suede inserts, aluminum shift paddles, AMG-specific gauges. Real carbon fiber or aluminum trim options. A noticeable step up from C 400 interior.','Same Mercedes paint process with AMG-specific color options. Designo paint options available with enhanced depth. No quality-specific differences from standard W205 paint 窶・good quality throughout.','AMG-tuned M276 turbo V6 with 4MATIC 窶・more robust than C 400 powertrain but still complex. AMG SpeedShift transmission has more aggressive shift programming. Sport differential adds a maintenance item. Driver mode electronics add complexity but AMG-tested reliability.','AMG Sport seats hold up well 窶・DINAMICA inserts resist wear better than leather alone. Flat-bottom steering wheel leather wears at 9-and-3. Same W205 dashboard materials. AMG-specific trim (carbon fiber, aluminum) more durable than wood-grain plastic. Better overall than C 400.','C 450 AMG Q-score 72.2. AMG Sport enhancements elevate the W205 C-Class 窶・better seats, better trim, AMG-tuned powertrain. The sportier character sacrifices some NVH for driving engagement. Electrical score slightly better than C 400 due to AMG-tested components. The sweet spot in the W205 C-Class lineup.','shared','Bremen (Germany)','mixed',4.0,'hydraulic','laminated','standard','real_wood',4,'above_average','sample',NULL);
INSERT INTO build_quality VALUES(55,146,59.2000000000000028,65.0,58.0,58.0,60.0,55.0,55.0,'W204 C-Class platform adapted for SUV duty 窶・boxed sections for rigidity but the engineering budget went to the C-Class sedan first. High ride height and boxy shape create aerodynamic noise. Panel gaps at 5-6mm 窶・W204-era quality, which is to say adequate.','SUV form factor works against NVH 窶・boxy shape creates wind noise at A-pillars and mirrors. No acoustic glass. Engine bay isolation below sedan standards. Tire noise from larger SUV rubber. The M272/M274 engines are smooth but the packaging lets noise in.','Direct carryover from W204 C-Class interior 窶・same hard plastics, same angular dashboard design, same cost-cutting DaimlerChrysler era materials. SUV-specific: higher seating position and different center console but same mediocre material quality. Wood-grain plastic trim standard.','Same W204-era Mercedes paint 窶・adequate with some clear coat aging on horizontal surfaces. SUV exposure to more stone chips and road debris. Rear hatch paint more prone to chipping. Not terrible but not memorable.','Same W204-era electrical concerns 窶・COMAND system issues, Bluetooth module failures. Add SUV-specific: 4MATIC transfer case, power liftgate mechanism (failure-prone), panoramic sunroof mechanism. More things to break than the C-Class sedan.','Same W204-era interior materials that age poorly 窶・hard plastics scratch, MB-Tex holds up, leather (if equipped) wears at bolsters. SUV use patterns are harder on interiors 窶・cargo area scratches, rear seat abuse. Power liftgate struts fail at 8-10 years.','GLK350 Q-score 59.2. A W204 C-Class in SUV clothing 窶・all the DaimlerChrysler-era cost-cutting with added SUV complexity. The boxy design is distinctive but aerodynamically noisy. Interior quality is the weak point. Reliable enough mechanically but feels cheaper than a Mercedes should.','shared','Bremen (Germany)','spot',5.5,'rubber','standard','standard','wood_grain',3,'standard','sample',NULL);
INSERT INTO build_quality VALUES(56,141,54.8999999999999985,68.0,60.0,58.0,55.0,35.0,45.0,'R230 SL platform with AMG-enhanced structure 窶・front subframe reinforcement for the M113K kompressor V8. Aluminum body panels over steel passenger cell. Not the R129''s overbuilt feel. Some early R230 cars had quality issues from the DaimlerChrysler efficiency programs.','ABC (Active Body Control) hydraulic suspension provides remarkable flat cornering but the pump and accumulators create a constant low-frequency hydraulic hum. Kompressor V8 supercharger whine is audible. Vario roof (folding hardtop) seals degrade and whistle. Better with roof closed.','Early 2000s Mercedes interior 窶・adequate materials but some cost-cutting visible in switchgear feel and plastic quality. AMG-specific: sport seats, AMG steering wheel, carbon fiber or wood trim options. Real design was angular and blocky. Not as premium as the price suggested.','Mercedes paint quality of this era is average 窶・some clear coat issues reported, particularly on horizontal surfaces and the folding roof panels. Vario roof mechanical attachment points can chip. Not W124-tier paint.','ABC suspension is the Achilles heel 窶・hydraulic accumulators fail ($$$), ABC pump leaks, ABC lines corrode. SBC electronic braking system (2003-2006) is a known failure risk requiring pump replacement. Kompressor bearings wear. Vario roof hydraulic cylinders leak. Active Body Control is Active Bank Account Cleaner.','ABC fluid leaks stain and damage underbody components. Vario roof mechanism aging 窶・hydraulic cylinders leak, seals harden, alignment drifts. Dashboard materials of this era can develop sticky residue in hot climates. AMG seat bolsters wear. Folding roof panel gaps increase over time.','SL55 AMG R230 Q-score 54.9. The car that defined the "expensive to maintain AMG" stereotype. The M113K kompressor V8 is bombproof but everything around it is fragile 窶・ABC suspension, SBC brakes, Vario roof hydraulics. Body and interior are merely adequate for the era. Buy one for the engine, budget for the rest.','bespoke','Sindelfingen (Germany)','spot',5.0,'hydraulic','laminated','standard','real_wood',4,'above_average','sample',NULL);
INSERT INTO build_quality VALUES(57,142,69.2000000000000028,78.0,72.0,72.0,70.0,55.0,62.0,'R231 is all-aluminum body shell 窶・a significant improvement over R230. Lighter, stiffer, better-balanced. AMG-specific front subframe for M157 biturbo V8. Mixed laser and spot welding. Panel gaps improved to 4-5mm. The R231 feels like a proper modern Mercedes.','Vario roof (folding hardtop) is better sealed than R230. Laminated glass when roof is up. Hydraulic engine mounts. The M157 biturbo V8 has deeper exhaust note but more refined than kompressor whine. Some roadster cowl shake on rough surfaces. Much improved over R230.','Modern Mercedes interior with AMG-specific upgrades 窶・sport seats, AMG steering wheel, carbon fiber or piano black trim. Materials improved over R230 with softer surfaces and better switchgear. But the interior design is functional rather than stunning 窶・the W213 E-Class interior it shares architecture with is more impressive.','Modern Mercedes multi-stage paint process. Good clear coat depth. No systemic rust issues (aluminum body helps). Vario roof panels paint-matched and generally holding up well. Some stone chip vulnerability on front fascia typical of low-slung roadsters.','ABC suspension eliminated on most R231 models (replaced with conventional steel springs or AIRMATIC). That removes the biggest R230 failure mode. But: M157 biturbo wastegate rattles, intercooler pump failures, COMAND system updates needed. Vario roof hydraulic cylinders still leak at 8-10 years. Better than R230 but still complex.','Vario roof aging is the primary cosmetic concern 窶・hydraulic cylinders leak, seals harden, alignment drifts causing wind noise. Interior materials age reasonably well 窶・AMG seats durable, carbon fiber trim doesn''t delaminate. Paint on folding roof panels shows wear at hinge points over time.','SL63 AMG R231 Q-score 69.2. A massive improvement over the R230 窶・aluminum body eliminates rust, ABC suspension gone from most models, modern AMG build quality. The M157 is powerful but wastegate rattles are known. Vario roof hydraulics remain the long-term maintenance item. Best modern SL before the R232.','bespoke','Bremen (Germany)','mixed',4.5,'hydraulic','laminated','standard','real_wood',4,'above_average','sample',NULL);
INSERT INTO build_quality VALUES(58,143,77.0,82.0,78.0,80.0,78.0,68.0,72.0,'R232 is the first SL developed entirely by AMG 窶・not a shared platform adapted by AMG. Active aerodynamics with retractable rear spoiler integrated into the trunk lid. Aluminum-intensive body with carbon fiber structural elements. Laser-welded primary joints. Panel gaps at 3-4mm.','Acoustic laminated glass standard. Active engine mounts that adjust damping based on drive mode. Extensive sound deadening in bulkhead and floor. Fabric soft top (not folding hardtop) saves weight and improves packaging. Very quiet with top up for a roadster.','Hyper-analog dashboard with standalone instrument cluster gauges 窶・a deliberate return to classic design language. Nappa leather standard, semi-aniline available. AMG Performance seats with heating/ventilation/massage. Real aluminum and carbon fiber trim. The best SL interior in decades.','Modern AMG paint processes with MANUFAKTUR exclusive paint options. Multi-stage with ceramic clear coat. Aluminum body eliminates rust concern. Fabric top doesn''t have paint-match issues of folding hardtops. Paint quality is at Mercedes-AMG highest standards.','M177 hand-built AMG engine 窶・one man, one engine philosophy. MBUX infotainment is modern but complex. Active aerodynamics actuators are a new failure mode. Fabric top mechanism simpler than Vario roof. Too new for definitive long-term data but the architecture is cleaner than R231.','Too new for meaningful long-term aging data 窶・extrapolating from material quality and modern AMG standards. Semi-aniline leather will patina but not crack. Fabric top should be more durable than folding hardtop seals. Active aerodynamics components are unproven long-term. Materials quality suggests good aging.','SL 63 R232 Q-score 77.0. The first AMG-developed SL from the ground up 窶・and it shows. Body construction, NVH, and interior materials are all at or near the top of the Mercedes-AMG range. Deductions for new-platform uncertainty (electrical 68, cosmetic 72). The fabric soft top is a regression some will welcome and others won''t.','bespoke','Bremen AMG (Germany)','laser',3.5,'active','acoustic_laminated','semi_aniline','real_wood',5,'extensive','sample',NULL);
INSERT INTO build_quality VALUES(59,13,76.2999999999999971,82.0,78.0,78.0,78.0,68.0,70.0,'CLAR platform shared with G30 5 Series. Mixed high-strength steel and aluminum construction 窶・aluminum hood, front fenders. Hot-stamped B-pillar and roof rail. Multi-link front and rear. Panel gaps 4-4.5mm (good for segment). Production maturity from several years of CLAR production. G20 benefits from continuous refinements.','Good NVH for sport sedan. Hydraulic engine mounts standard on M340i. B58TU inherently smooth I6. Acoustic laminated windshield standard. ZF 8HP well-isolated. Run-flat tire harshness present but BMW updated tire specs. M Sport suspension option with adaptive dampers better in Comfort mode. Cabin quietness competitive for class but not 5 Series-level.','M Sport standard with Vernasca leather 窶・softer and better grain than Dakota. Sensatec on non-M Sport. iDrive 7.0 with 10.25-inch screen. Brushed aluminum trim, optional open-pore wood. Good fit and finish. Less piano black than pre-LCI G30. Optional heads-up display. Stitching quality above average. Cooled seats available.','Modern BMW paint process. Multi-stage cathodic dip primer, base coat, clear coat. No systemic paint issues reported. Standard colors consistent. Individual paint options have more clear coat depth. Aluminum panels don''t rust but cosmetic corrosion risk on chips. Paint hardness average for German cars.','iDrive 7 more stable than earlier versions. B58TU addresses many B58 issues: improved water pump, better thermostat, updated PCV. 48V mild hybrid on some models adds complexity. Digital Key and OTA updates add software complexity. Too early for definitive long-term aging data but trajectory positive.','Vernasca leather should age well 窶・positive initial reports at 30-50K miles. Less piano black means fewer visible scratches. Updated door card materials more durable. BMW steering wheel gloss pattern at 60K+. Dashboard materials holding up. Good 3-year lease return condition.','M340i G20 Q-score 76.3. B58TU + CLAR platform = solid modern BMW. Good body construction, competitive NVH, nice interior. Better than E90 in every Q dimension. Not at 5 Series level on NVH or interior but close. Strong daily driver build quality.','shared','San Luis Potosi (Mexico) / Munich (Germany)','mixed',4.20000000000000017,'hydraulic','acoustic_laminated','standard','real_wood',4,'above_average','sample',NULL);
INSERT INTO build_quality VALUES(60,19,54.7000000000000028,68.0,35.0,60.0,55.0,45.0,48.0,'E46 platform with CSL-specific lightweighting: carbon fiber roof panel, thinner rear glass, lightweight body panels. Rear subframe mounting points crack (well-documented TSB). High-quality steel for era. CSL specific: removed sound deadening, reduced insulation. Panel gaps 5-6mm. Carbon fiber roof well-bonded. Now 20+ years old, fatigue and rust on structural components.','CSL = purposefully stripped out for weight. Minimal sound deadening removed from factory. Thin rear glass. Single-mass flywheel transmits vibration. S54 mechanically noisy at all RPM. No acoustic glass. No active noise cancellation. Road noise with 19-inch staggered setup significant. Exhaust always present in cabin. At 80mph you hear everything 窶・by design. This is a track-bred car.','CSL-specific: carbon fiber bucket seats (not standard M3 sport seats). Alcantara steering wheel and handbrake. Stripped interior 窶・no rear seats in some markets. Door panels minimal. Lightweight construction throughout. Materials quality good for era but spartan. Carbon fiber trim extensive. Function over form philosophy.','BMW paint 2000-2006 average. Clear coat failure on horizontal surfaces at 15+ years. Carbon black and jet black susceptible. Stone chips on front expose steel. Rear quarter panel rust near wheel arch common on northern cars. Paint thin by modern standards (~100 microns). CSL specific: some unique colors (Silverstone Metallic, Fire Orange).','E46 electronics aging poorly. VANOS solenoids fail. SMG-II hydraulic pump electronics fail. Camshaft position sensors regular failure. Window regulators fail (cable design flaw). Instrument cluster pixel death. HK amplifier failure. SMG-specific: hydraulic control unit electronics degrade. CSL gauge cluster unique and expensive.','CSL-specific lightweight materials wear like a race car. Carbon fiber seats can develop stress marks. Alcantara steering wheel wears faster than leather. Exposed carbon fiber can yellow/crack in UV. Minimal interior means what''s there takes more abuse. Dashboard material okay. Headliner sag common. Overall: patina is part of the CSL character.','E46 M3 CSL Q-score 54.7. Purpose-built track car with road registration. Low NVH is by design, not defect. Subframe cracking is the real structural concern. SMG electronics aging poorly. Interior is spartan by choice. Scores reflect 20+ year old lightweight special 窶・built for purpose not luxury.','bespoke','Regensburg (Germany)','laser_welded',5.5,'solid_rubber','standard','alcantara','carbon_fiber',3,'minimal','sample',NULL);
INSERT INTO build_quality VALUES(61,23,78.7999999999999971,86.0,88.0,85.0,80.0,58.0,72.0,'CLAR flagship platform. Mixed high-strength steel, aluminum, and carbon fiber (CFRP) in core structure. Carbon core pillar technology from 7 Series. Aluminum hood, doors, front fenders, roof. Hot-stamped B-pillar and structural members. Panel gaps 3.5-4mm (best in BMW lineup). Excellent crash structure. Body rigidity outstanding for size and weight.','Flagship NVH 窶・BMW''s best at time of production. Hydraulic engine mounts standard. Acoustic laminated windshield and side glass standard. Extensive firewall insulation. B58 inherently smooth I6, very quiet at cruise. ZF 8HP well-isolated. Underbody aero panels reduce wind noise. Air suspension isolates road imperfections. Near S-Class quiet at highway speeds.','Nappa leather standard, optional Merino individual leather. Real wood trim 窶・open-pore oak, poplar, fineline. Aluminum trim options. iDrive 6/7 with gesture control. Excellent fit and finish. Soft-close doors standard. Ambient lighting extensive. Optional Bowers and Wilkins audio outstanding. Rear seat executive lounge option. Above average for class.','BMW premium paint process on 7 Series. Extra paint stages for Individual colors. Multi-layer clear coat. Consistent panel-to-panel color match. No systemic issues reported. Aluminum panels don''t rust. Steel structural components well-protected by cathodic dip. Paint depth above average for BMW.','Complex luxury electronics are the concern. Multiple control modules. Air suspension management. Gesture control cameras. iDrive infotainment. Driver assistance suite. Individual electronics can fail 窶・door modules, seat modules, K-CAN bus issues. Battery management critical. Many early G11 recalls for software-related issues.','Nappa leather ages well 窶・develops patina rather than cracking at 80-100K. Real wood trim holds up. Aluminum trim can show fingerprints and light scratches. Piano black surfaces scratch easily (less in 7 Series than 3/5 Series). Headliner holds up. Dashboard materials premium quality. Overall ages like a well-maintained luxury car.','740i G11 Q-score 78.8. BMW flagship build quality benefits from carbon core construction and premium materials. Best panel gaps in BMW lineup. Excellent NVH. Electronics complexity is the aging concern. B58 I6 much better reliability path than N63 V8 750i.','shared','Dingolfing (Germany)','mixed',3.79999999999999982,'hydraulic','acoustic_laminated','nappa','real_wood',5,'excellent','sample',NULL);
INSERT INTO build_quality VALUES(62,37,67.0,72.0,70.0,64.0,65.0,60.0,62.0,'E90 chassis is well-engineered with good rigidity. Mixed materials: steel body with aluminum hood. RWD architecture. No subframe cracking issues like E46. M Sport package adds aerodynamic body kit with larger intakes and rear diffuser.','Reasonable for a sport sedan. More road feel than luxury sedans. Tire noise present on run-flat tires (early E90). Sport suspension transmits more road texture. Not Lexus-quiet by design.','Below Japanese competitors. Hard plastics in lower areas. Leather quality decent but not exceptional. M Sport seats have better bolsters. iDrive knob and screen era. Some cost-cutting vs E46 apparent.','Average BMW paint. Early E90 had some paint quality issues. Galvanized body resists corrosion. No widespread rust issues reported.','iDrive CCC system (2005-2008) ages poorly. Screen delamination reported. CIC system (2009-2013) better. Window regulators fail across the E90 range. Electrical gremlins in higher-mileage examples.','Interior materials show age sooner than Japanese competitors. Hard plastics scratch easily. Leather wears well with care. Exterior trim holds up. M Sport aerodynamic pieces durable.','E90 Q-score 67.0. Below Japanese luxury competitors (LS430 92.3) but appropriate for the segment. Sport sedan design means comfort features are less prioritized. Build quality is good for a BMW but the interior is notably downmarket from Lexus/Acura of the era. Electrical aging is the weak point.','BMW E90','Munich (Germany) / Leipzig (Germany) / Oxford (UK)','laser_welded',3.79999999999999982,'hydraulic','standard','Dakota leather','real_wood',5,'average','sample',NULL);
INSERT INTO build_quality VALUES(63,41,81.7999999999999971,88.0,88.0,87.0,83.0,64.0,77.0,'Same CLAR flagship platform as 740i. Carbon core CFRP technology. Mixed high-strength steel, aluminum, carbon fiber. Excellent crash structure. Best panel gaps in BMW lineup at 3.5-4mm. V8 adds weight over front axle but body rigidity outstanding. Aluminum hood, doors, fenders. Carbon fiber B-pillar and roof rail core.','Same flagship NVH as 740i. N63 V8 slightly more present than B58 I6 but well-isolated. Hydraulic engine mounts standard. Acoustic laminated glass all around. Extensive firewall and underbody insulation. Air suspension standard. Near-silent at highway speeds. Wind noise well-managed. Tire noise the dominant source above 70mph.','Same premium interior as 740i. Nappa leather standard. Merino individual leather optional. Real wood trim abundant. Excellent fit and finish. Gesture control, touchscreen iDrive. Soft-close doors. Ambient lighting. Bowers and Wilkins optional. V8 model gets additional stitching and M Sport details standard. Above average for class.','Same BMW premium paint as 740i. Extra clear coat depth on Individual colors. Consistent application. No systemic issues. Well-protected structural steel. Aluminum panels cosmetic-only corrosion risk.','Same electronics complexity concerns as 740i. N63 adds engine management complexity 窶・twin turbo control, cylinder deactivation, additional sensors. More modules = more failure points. Air suspension electronics. Driver assistance suite. Battery management for multiple systems. Software updates critical.','Same cosmetic aging as 740i. Nappa/Merino leather ages well. Real wood durable. Aluminum trim shows wear. Piano black surfaces scratch. Premium materials overall should age gracefully with proper care.','750i G11 Q-score 78.8. Same excellent body construction and NVH as 740i. N63 V8 adds complexity and potential engine aging concerns not reflected in Q-score (that''s reliability). Build quality is flagship-level. Electronics complexity the main aging risk.','shared','Dingolfing (Germany)','mixed',3.79999999999999982,'hydraulic','acoustic_laminated','nappa','real_wood',5,'excellent','sample',NULL);
INSERT INTO build_quality VALUES(64,50,73.7000000000000028,78.0,75.0,75.0,78.0,65.0,68.0,'CLAR SUV platform shared with G20 3 Series and G30 5 Series. Mixed high-strength steel and aluminum. Aluminum hood and tailgate. Hot-stamped B-pillar. SUV body has good rigidity. Panel gaps 4-4.5mm. Good crash structure. Higher center of gravity than sedans but well-managed. Underbody protection adequate.','Good SUV NVH. B58 I6 smooth and quiet. Hydraulic engine mounts. Acoustic laminated windshield standard. Moderate firewall insulation. Road noise with SUV tire sizes. Some wind noise around mirror mounts at highway speeds. Better than F25 X3 predecessor. Run-flat tire harshness on rough surfaces. Competitive for premium compact SUV class.','M40i gets Vernasca leather (good upgrade over Sensatec base). Aluminum trim or optional wood. iDrive 7 with 10.25-inch screen. Good fit and finish. Soft-touch surfaces on upper panels. Harder plastics on lower door cards. Panoramic sunroof standard on M40i. Good ergonomics for SUV. Heated seats standard. Cooled seats available.','Modern BMW paint process. Multi-stage application. No systemic issues. Consistent color and clear coat. Aluminum panels don''t rust. Steel structure well-protected. Paint hardness average for German cars. Stone chips on front end cosmetic issue.','iDrive 7 generally stable. B58 electronics well-sorted. xDrive transfer case electronics. Panoramic sunroof electronics and drain management. Power tailgate electronics. Fewer modules than 5/7 Series. Better electronics trajectory than N-series era BMWs.','Vernasca leather aging well in initial reports. Panoramic sunroof mechanism can develop rattles. Interior trim materials durable. Less piano black than earlier models. Steering wheel gloss pattern at 60K+. Dashboard materials holding up. SUV utility means interior takes more abuse.','X3 M40i G01 Q-score 73.7. Solid premium SUV build quality. B58 powertrain a known quantity. Interior materials good but not 5 Series-level. NVH competitive for class. Electronics simpler than 5/7 Series. Good daily driver quality.','shared','Spartanburg (USA)','mixed',4.20000000000000017,'hydraulic','acoustic_laminated','standard','real_wood',4,'above_average','sample',NULL);
INSERT INTO build_quality VALUES(65,51,73.7000000000000028,78.0,75.0,75.0,78.0,65.0,68.0,'CLAR SUV platform, same construction as car_id=50. Mixed high-strength steel and aluminum. Aluminum hood and tailgate. Panel gaps 4-4.5mm. Good rigidity for SUV class.','Same NVH as car_id=50. B58 smooth, hydraulic mounts, acoustic windshield. Good SUV refinement.','Same M40i interior as car_id=50. Vernasca leather, good materials.','Same BMW paint process as car_id=50.','Same electronics as car_id=50.','Same cosmetic aging profile as car_id=50.','Duplicate X3 M40i entry (car_id=51). Same Q-score 73.7 as car_id=50.','shared','Spartanburg (USA)','mixed',4.20000000000000017,'hydraulic','acoustic_laminated','standard','real_wood',4,'above_average','sample',NULL);
INSERT INTO build_quality VALUES(66,52,76.4000000000000056,82.0,80.0,82.0,78.0,62.0,70.0,'CLAR larger SUV platform. More substantial than X3. Mixed high-strength steel and aluminum. Aluminum hood, front fenders, doors. Larger body well-engineered. Panel gaps 3.8-4.2mm (tighter than X3). Good crash structure. Air suspension optional. Underbody well-protected. Higher build investment than X3 reflects price point.','Better NVH than X3 窶・larger body absorbs more. B58 smooth I6. Hydraulic mounts standard. Acoustic laminated windshield and available side glass. Extensive insulation. Air suspension (optional) excellent for isolation. Cabin very quiet at highway speeds. Better than G05 predecessor F15. Near-7-Series quiet at cruise.','Premium interior above X3 level. Vernasca or optional Nappa leather. Real wood trim extensive. iDrive 7 with large screen. Excellent fit and finish. Panoramic sky lounge roof option (LED-illuminated). Soft-touch surfaces throughout. Good storage. Heated and cooled seats available. Third row option on some builds.','Modern BMW premium paint. Same multi-stage process. Good clear coat depth. Consistent application. No systemic issues. Well-protected structure. Aluminum panels cosmetic-only corrosion. Paint quality appropriate for price point.','More complex than X3: air suspension management, panoramic roof electronics, more driver assistance modules, third row electronics (if equipped). iDrive 7 stable but more points of failure. B58 electronics well-sorted. Larger vehicle = more wiring harnesses and connectors.','Premium materials should age well. Vernasca/Nappa leather durable. Real wood trim ages gracefully. Panoramic roof mechanism potential rattle source. Interior takes family abuse 窶・kids, cargo. Dashboard materials premium. Steering wheel typical BMW gloss pattern. Better aging trajectory than X3 due to higher-grade materials.','X5 xDrive40i G05 Q-score 76.4. Premium SUV build quality above X3 level. Better NVH, better interior materials, tighter panel gaps. B58 powertrain proven. Air suspension and electronics are aging concerns. Good choice in midsize luxury SUV class.','shared','Spartanburg (USA)','mixed',4.0,'hydraulic','acoustic_laminated','nappa','real_wood',4,'very_good','sample',NULL);
INSERT INTO build_quality VALUES(67,65,61.7000000000000028,68.0,65.0,70.0,58.0,48.0,55.0,'E39 platform 窶・legendary chassis rigidity for era. All-steel body (no aluminum panels on M5). MacPherson strut front, multi-link rear. Excellent 50:50 weight distribution. Panel gaps 4.5-5.5mm (good for 1998-2003). Strong weld quality for period. Well-documented crash structure. Now 20+ years old 窶・rust on rear quarter panels, underbody, jack points common in northern cars.','Good NVH for era. Hydraulic engine mounts. Moderate firewall insulation. S62 V8 has character 窶・audible but refined at cruise, aggressive under load. No acoustic glass. Getrag 6-speed manual well-isolated. Wind noise around mirrors at highway speed. Better than E46 M3 in refinement, not E39 540i-level quiet due to stiffer M suspension.','Often called the best M5 interior. Nappa leather sport seats (electric with memory). Real wood trim 窶・warm, traditional BMW design. Aluminum or wood trim options. Good fit and finish for era. Soft-touch upper door panels. Hard plastics lower. Manual-specific: leather-wrapped shift knob, boot. Analog gauges excellent. Interior design has aged well aesthetically.','BMW paint late 1990s/early 2000s: adequate but not outstanding. Clear coat thin by modern standards. Some colors (Le Mans Blue, Carbon Black) prone to clear coat failure at 15+ years. Stone chips expose steel. Rear quarter rust near wheel arch common. Underbody surface rust. Silver and white hold up best.','E39 electronics aging poorly now. Instrument cluster pixels fail (common E39). Window regulators fail. Final stage resistor (hedgehog) causes blower issues. Mirror motors fail. Seat memory modules fail. S62-specific: MAF sensors, VANOS solenoids, thermostat electronic failure trigger warning lights. K-bus issues. Battery drain from aging modules.','Nappa leather seats age with character 窶・cracking on bolsters at 80-100K if not conditioned. Steering wheel leather thin and glossy at 50K+. Wood trim holds up well. Dashboard material prone to cracking in sun (common E39). Door panel leather peels at edges. Headliner sag at 15+ years. Center console armrest vinyl cracks. Overall: better than E46 but showing age.','E39 M5 Q-score 61.7. Legendary car but 20+ years of aging shows. Interior design timeless but materials have degraded. Electronics are the weak point. Chassis engineering outstanding for era. The "best M5" reputation is earned through driving dynamics, not build quality.','bespoke','Dingolfing (Germany)','laser_welded',5.0,'hydraulic','standard','nappa','real_wood',3,'average','sample',NULL);
INSERT INTO build_quality VALUES(68,106,45.0,45.0,35.0,45.0,40.0,60.0,42.0,'E30 platform 窶・1980s steel body, lightweight. Box flared fenders for Group A homologation. MacPherson strut front, semi-trailing arm rear. Panel gaps 5-7mm (normal for 1980s). Good chassis rigidity for period. Now 35+ years old 窶・rust is the primary enemy. Rear quarter panels, floor pan, jack points, front fender lips, shock towers. Nearly every example has rust somewhere. Weld quality era-appropriate.','1980s NVH 窶・minimal by any modern standard. Solid rubber mounts. No acoustic glass. No sound deadening to speak of. S14 mechanically noisy 窶・valve train, intake, exhaust all audible. Wind noise around window seals at speed. Road noise with 15-inch tires (less than modern 19s actually). You feel every road seam. Charming but not refined. Purposeful.','1980s BMW sports interior. Sport seats well-bolstered for era, cloth or leather. Leatherette on base models. Hard plastics throughout. Simple analog gauges. No iDrive. Basic HVAC controls. Functional and honest. Materials quality acceptable for 1986-1991 but poor by any modern standard. headliner sag common. Seat bolster wear on driver''s side.','1980s BMW paint 窶・thin, single-stage on some colors. Clear coat failure nearly universal on original paint cars. Many examples resprayed. Stone chips everywhere on driven examples. Exposed steel rusts quickly. Paint correction community documents extensive E30 paint issues. Original paint in good condition adds significant value.','Simple 1980s Bosch Motronic electronics 窶・actually aging well because there''s less to fail. Analog gauges. Simple wiring harnesses. No modules, no bus systems. Basic relay-based electronics. Capacitor aging in ECU possible at 30+ years. OBD-I diagnostics. The simplicity is a feature 窶・easy to diagnose and repair.','35+ year old materials. Seat leather/vinyl cracked on bolsters. Dashboard cracked (UV exposure). Door panels faded. Steering wheel worn thin. Carpet worn. Headliner sag. Chrome trim pitted. Rubber seals hardened and cracked. Windshield pitted. Every cosmetic element shows age on unrestored cars. Patina adds character but not quality.','E30 M3 Q-score 45.0. A 35+ year old homologation special 窶・build quality reflects 1980s standards plus decades of aging. Rust is the dominant factor. NVH is purposeful race-car minimalism. Electronics are simple and actually reliable. Interior is spartan. Scores reflect a classic, not a modern car.','bespoke','Munich (Germany) / Regensburg (Germany)','spot_welded',6.0,'solid_rubber','standard','standard','none',2,'minimal','sample',NULL);
INSERT INTO build_quality VALUES(69,120,79.5999999999999943,88.0,78.0,85.0,82.0,65.0,72.0,'CLAR F90 platform 窶・the largest, most rigid application. Mixed high-strength steel, aluminum, carbon fiber options (CFRP roof on Competition). Aluminum hood, front fenders, doors. Hot-stamped structural members. Panel gaps 3.5-4mm (excellent). M-specific structural bracing. Excellent crash structure. Body rigidity outstanding. Production quality consistently high 窶・Dingolfing flagship line.','Impressive NVH for 617hp. Adaptive engine mounts switch between comfort and sport. Acoustic laminated glass. Extensive firewall insulation. S63 V8 well-isolated in comfort mode, muscular in sport. Active sound design supplements exhaust note. Wind noise well-managed. Tire noise from wide performance rubber. Better NVH than F10 M5. Not 7 Series quiet but impressive for an M car.','M Competition interior: Merino leather standard, extended. Carbon fiber trim standard on Competition. Alcantara headliner. M Sport seats or optional M carbon bucket seats. iDrive 7 with M-specific screens. Excellent fit and finish. Soft-close doors. Ambient lighting. Harman Kardon or optional Bowers and Wilkins. M-specific steering wheel with M1/M2 buttons. Premium throughout.','BMW premium paint on M cars. Extra quality control. Multi-layer clear coat. Competition-specific colors available. Consistent application. No systemic issues. Paint depth above average. Individual paint options have additional clear coat. Well-protected structure.','M-specific electronics complex: M drive management, adaptive damping, active M differential, M xDrive, active steering, head-up display, driving assistance professional. Multiple ECUs. Software-dependent. Too new for definitive long-term data but more complex than standard 5 Series. OTA updates add software risk.','Merino leather should age well 窶・premium grade. Alcantara headliner durable. Carbon fiber trim doesn''t degrade. M Sport seats see more aggressive use. Steering wheel M-specific thicker leather. Interior materials premium throughout. Too new for long-term aging data but materials quality suggests good trajectory. Limited-edition status means owners care for them.','F90 M5 Competition Q-score 79.6. Modern M car flagship build quality. Best panel gaps and body rigidity in M lineup. Premium interior with Merino leather throughout. NVH impressive for the power level. Electronics complexity is the aging concern. Carbon fiber options add visual and structural quality.','shared','Dingolfing (Germany)','mixed',3.70000000000000017,'adaptive_hydraulic','acoustic_laminated','merino','carbon_fiber',5,'excellent','sample',NULL);
INSERT INTO build_quality VALUES(70,123,79.7000000000000028,85.0,90.0,88.0,82.0,55.0,75.0,'CLAR-based EV platform with battery integration. CFRP (carbon fiber reinforced polymer) cell and roof cage for battery protection and body rigidity. Mixed high-strength steel, aluminum, carbon fiber. Aluminum body panels. Excellent crash structure with battery-specific crumple zones. Panel gaps 3.5-4mm. Flat floor from skateboard architecture. EV-specific structural considerations well-engineered.','Outstanding NVH 窶・EV advantage. No engine vibration or noise. Near-silent at low speeds. Wind noise very well-managed with frameless doors (impressive engineering). Extensive sound deadening. Acoustic laminated glass all around. Road noise the only significant source, and it''s well-controlled. Cabin extremely quiet at highway speeds. Among quietest SUVs regardless of powertrain.','Premium iX interior with sustainable materials focus. Olive-leaf tanned leather option. Optional lounge seats. Crystal iDrive controller. Dual curved displays. Shy Tech 窶・hidden speakers, minimalist design. Real wood options. Excellent fit and finish. Soft-touch throughout. Panoramic glass roof with electrochromic dimming. Interior design forward-looking. Materials quality at or near BMW best.','BMW premium paint on EV flagship. Extra quality control. Multi-layer application. No systemic issues. Consistent clear coat. EV-specific considerations: no heat from engine bay, different thermal cycling on paint. Too early for long-term paint data but initial quality high.','Early iX (2022-2023) recall-heavy per Consumer Reports. Multiple recalls: pedestrian sound generator, CID safety info, battery modules, steering system. Software-dependent vehicle. OTA updates critical but can introduce bugs. Connected Drive services can fail (WiFi/Internet issues reported). Many electronic modules. First-generation EV electronics risk.','Sustainable materials concept should age well. Olive leaf-tanned leather reportedly durable. Crystal controls won''t degrade. Curved displays should hold up (too new for long-term data). Electrochromic roof mechanism unknown longevity. Interior design is distinctive and well-assembled. Premium materials throughout.','iX xDrive50 Q-score 79.7. Excellent build quality typical of BMW EV flagship. Outstanding NVH from EV powertrain. Premium sustainable interior. Electronics aging the main concern 窶・early models recall-heavy. Body construction excellent with CFRP battery cage. Competitive with Mercedes EQS SUV.','ev_skateboard','Dingolfing (Germany)','mixed',3.79999999999999982,'fixed','acoustic_laminated','premium_sustainable','real_wood',5,'outstanding','sample',NULL);
INSERT INTO build_quality VALUES(71,16,72.7000000000000028,78.0,65.0,70.0,75.0,75.0,68.0,'TNGA-based with extensive modifications - carbon fiber roof panel, hand-welded body, rally-bred rigidity','Minimal sound deadening for weight savings - engine and road noise are prominent, typical rally homologation','Toyota GR interior is functional - decent materials but clearly prioritizes weight over luxury','Toyota paint quality is good - GR-specific colors like Circuit Grau are well applied','Modern Toyota electronics - reliable digital systems, no widespread aging concerns','Lightweight interior materials show wear from enthusiastic use - Recaro seats durable but surrounding trim is average','Purpose-built rally homologation car - build quality prioritizes rigidity and weight over refinement','TNGA-B platform (GR-modified)','Toyota Motomachi Plant (hand-assembled)','hand weld + structural adhesive + carbon fiber bonding',3.5,'solid hydraulic','lightweight','recaro fabric/suede','none',5,'minimal','sample',NULL);
INSERT INTO build_quality VALUES(72,20,71.2999999999999971,78.0,72.0,75.0,72.0,60.0,65.0,'Steel unibody with front crash structure - heavy but rigid, excellent for high-speed stability','Double-glazed windows and good sound deadening for the era - quiet GT cruiser when stock','High-quality interior for 1993 - leather seats, power everything, good ergonomics for a Japanese sports car','Toyota paint quality from the 90s is generally good - some clear coat issues on sun-exposed cars','90s electronics are the weak point - digital dash pixels fade, climate control actuators fail','Leather seats wear well but dashboard plastics can crack - headliner sag is common on 30+ year old cars','Excellent 90s Japanese build quality that has aged in electronics and some interior plastics','Toyota A80 platform (dedicated)','Toyota Motomachi Plant','spot weld + laser weld',4.0,'hydraulic','double-glazed','genuine leather','none',5,'good','sample',NULL);
INSERT INTO build_quality VALUES(73,28,76.0,78.0,78.0,76.0,75.0,75.0,73.0,'Honda Accord-based platform with Acura-specific tuning - good rigidity, well-engineered body structure','Active noise cancellation plus acoustic glass - quiet cabin at highway speeds, Honda luxury-tier isolation','A-Spec trim adds sport seats and good materials - above average for near-luxury segment','Honda paint quality is consistently good - clear coats hold up, metallic finishes are deep','Modern Honda electronics - infotainment is functional, driver aids are well-calibrated','Interior materials resist wear well - leather quality is good for the price point','Competent near-luxury build quality - Honda underneath means everything works and keeps working','Honda Accord platform (Acura-tuned)','Honda Marysville Auto Plant (Ohio)','spot weld + structural adhesive + laser braze',3.5,'hydraulic','acoustic laminated windshield','available leather','aluminum trim',5,'very good','sample',NULL);
INSERT INTO build_quality VALUES(74,48,70.2000000000000028,75.0,72.0,72.0,72.0,62.0,65.0,'Honda global midsize platform - adequate rigidity for a premium sedan, SH-AWD adds rear subframe complexity','Good isolation for a 2007 premium sedan - active noise cancellation helps, road noise well-suppressed','Premium materials for the era - real leather, wood or carbon trim, Type S adds sport seats','Honda paint from this era is good - some clear coat aging on dark colors in hot climates','Navigation and audio systems are dated - screen delamination and disc-read errors are common','Leather seats age reasonably well - dashboard plastics can develop squeaks, headliner may sag','Period-correct Acura build quality - good materials that have aged in electronics and some interior plastics','Honda global midsize platform','Honda Marysville Auto Plant (Ohio)','spot weld + structural adhesive',4.0,'hydraulic','acoustic laminated windshield','genuine leather','real wood or carbon fiber',5,'good','sample',NULL);
INSERT INTO build_quality VALUES(75,80,75.9000000000000056,78.0,70.0,75.0,78.0,78.0,73.0,'10th gen Civic hatchback body - good torsional rigidity, Type R specific structural adhesive additions','Moderate sound deadening - tire roar is noticeable at highway speeds, sport exhaust adds character','Honda Civic Type R interior is surprisingly good - red Recaro buckets, aluminum sport pedals, red accents','Honda paint quality is generally very good - Championship White is iconic and well-applied','Honda infotainment is functional and stable - not flashy but reliable, Apple/Android integration works well','Type R-specific interior trim holds up well - Recaro suede shows some wear patterns with heavy use','Best hot hatch build quality in its class - Honda attention to detail elevates the Civic platform','Honda 10th gen Civic platform (Type R enhanced)','Honda Swindon Plant (UK)','spot weld + structural adhesive + laser braze',3.79999999999999982,'hydraulic','tinted','recaro fabric/suede','none',5,'below_average','sample',NULL);
INSERT INTO build_quality VALUES(76,88,72.0999999999999943,76.0,74.0,74.0,73.0,65.0,68.0,'Honda global midsize platform - improved rigidity over 3rd gen, better noise isolation','Improved NVH over previous generation - active noise cancellation, better door seals','Improved materials over 3rd gen - cleaner design, better leather quality, more cohesive interior','Honda paint quality is consistent - average clear coat longevity','Navigation and electronics improved but still dated - HDD navigation system is slow by modern standards','Better aging than 3rd gen - improved materials resist wear, dashboard squeaks less common','Noticeable improvement over 3rd gen TL - better isolation and interior materials','Honda global midsize platform (revised)','Honda Marysville Auto Plant (Ohio)','spot weld + structural adhesive + laser braze',3.79999999999999982,'hydraulic','acoustic laminated windshield','genuine leather','aluminum/wood trim',5,'good','sample',NULL);
INSERT INTO build_quality VALUES(77,97,74.0,78.0,68.0,72.0,76.0,76.0,70.0,'TNGA-C platform with GR-specific reinforcements - additional bracing, aluminum hood, forged carbon roof on Morizo edition','Minimal sound deadening - 3-cylinder turbo is characterful but loud, road noise is part of the experience','Toyota GR interior with rally aesthetics - functional and well-assembled but not luxurious','Toyota paint quality is good - GR-specific colors like Circuit Red are well applied','Modern Toyota electronics - digital instruments and infotainment are current-gen and reliable','Rally-inspired interior materials are durable - Morizo edition removes rear seats for weight savings','Toyota GR build quality is purposeful - engineered for performance over comfort','TNGA-C platform (GR-modified)','Toyota Motomachi Plant (hand-assembled)','hand weld + structural adhesive + carbon fiber bonding',3.5,'solid hydraulic','lightweight','fabric/suede (Recaro available)','none',5,'minimal','sample',NULL);
INSERT INTO build_quality VALUES(78,99,77.5,78.0,76.0,78.0,78.0,78.0,76.0,'11th gen Civic platform with Acura-specific tuning - good rigidity, liftback body is well-engineered','Good isolation for a performance liftback - active sound management, decent highway quietness','Acura interior quality with Type S sport seats - aluminum trim, contrast stitching, premium feel','Acura paint quality is excellent - deep metallics, consistent coverage, premium clear coat','Modern Honda electronics - fast infotainment, good integration, reliable digital systems','Premium interior materials resist wear well - Type S sport seats are supportive and durable','Near-luxury build quality in a liftback body - best execution of the Integra name since the DC2','Honda 11th gen Civic platform (Acura-tuned)','Honda Performance Manufacturing Center (Ohio)','spot weld + structural adhesive + laser braze',3.29999999999999982,'hydraulic','acoustic laminated windshield','Type S sport fabric/leather','aluminum trim',6,'very good','sample',NULL);
INSERT INTO build_quality VALUES(79,103,63.6000000000000014,70.0,58.0,62.0,68.0,60.0,58.0,'6th gen Civic hatchback body - lightweight but not particularly rigid by modern standards','Virtually no sound deadening - VTEC crossover is the soundtrack, road noise is constant','Spartan Honda interior - basic fabrics, Type R red Recaro seats are the highlight, rest is economy Honda','Honda paint from late 90s is adequate - Championship White is iconic but thin by modern standards','Minimal electronics - no infotainment, analog gauges, simple and reliable but dated','25+ years of age shows everywhere - plastics fade, fabrics wear, headliners sag','Period Honda build quality - raw and lightweight, the car is a tool not a luxury item','Honda 6th gen Civic platform (Type R)','Honda Suzuka Plant (Japan)','spot weld',5.0,'solid rubber','tinted','recaro fabric (Type R)','none',3,'none','sample',NULL);
INSERT INTO build_quality VALUES(80,108,55.1000000000000014,62.0,52.0,52.0,58.0,52.0,50.0,'1980s Corolla body-on-frame-rear unibody - lightweight and simple, floppy by any modern standard','Zero sound deadening - you hear everything: engine, road, wind, rain. Part of the analog charm','1980s Japanese economy car interior - hard plastics, vinyl, basic instrumentation, tinny door panels','Toyota paint from the early 80s was thin - most surviving AE86s have been repainted at least once','Virtually no electronics - analog everything, points ignition on early cars, simple and durable','40+ year old economy car - most surviving examples show significant cosmetic aging, original interiors are rare','Primitive 1980s build quality - the car has soul and character but not a shred of refinement','Toyota E80 Corolla platform (RWD)','Toyota Kanto Auto Works (Japan)','spot weld',6.0,'solid rubber','tinted','none (vinyl/cloth)','none',3,'none','sample',NULL);
INSERT INTO build_quality VALUES(81,113,73.5999999999999943,82.0,72.0,78.0,75.0,62.0,65.0,'All-aluminum monocoque - groundbreaking in 1990, designed with input from Gordon Murray and Ayrton Senna','Good isolation for a mid-engine sports car - cabin is surprisingly civil at highway speeds','Premium Honda/Acura interior for 1990 - real leather, power seats, Bose audio, excellent ergonomics for mid-engine','Acura paint quality is good - some clear coat issues on 30+ year old examples, Berlina Black ages well','Age is the enemy - climate control servos fail, ABS pump failures, digital display fading','Leather seats and interior trim age gracefully with care - many NSXs were garage-kept and well-maintained','Groundbreaking aluminum construction still impresses - the chassis rigidity is remarkable for a 1990 design','Dedicated NSX aluminum monocoque','Honda Takanezawa Plant (Japan) - hand-assembled','aluminum MIG weld + adhesive bonding + rivets',3.0,'hydraulic','tinted (lightweight)','genuine leather','none',6,'good','sample',NULL);
INSERT INTO build_quality VALUES(82,118,78.0,80.0,76.0,78.0,78.0,78.0,76.0,'BMW CLAR platform with Toyota tuning - aluminum doors and hood, high-strength steel structure, excellent rigidity','BMW NVH engineering is excellent - cabin is quiet at speed, adaptive exhaust adds character without intrusion','BMW-sourced interior with Toyota-specific trim - good materials, sport seats, proper sports car cockpit','BMW paint quality is generally very good - multi-stage process, deep metallics, durable clear coat','BMW iDrive system is mature and stable - reliable electronics with good long-term support','BMW interior materials age well - leather and trim resist wear, consistent panel fit over time','BMW build quality with Toyota reliability engineering - the best of both worlds for the A90 Supra','BMW CLAR platform (Toyota-tuned)','Magna Steyr Graz (Austria)','laser weld + structural adhesive + aluminum bonding',3.20000000000000017,'hydraulic','acoustic laminated','BMW sport leather','carbon fiber trim',6,'very good','sample',NULL);
INSERT INTO build_quality VALUES(83,119,78.5,80.0,73.0,78.0,80.0,80.0,77.0,'11th gen Civic platform at its best - additional structural adhesive and bracing for Type R duties','Improved NVH over FK8 - better door seals, more sound deadening, still communicates road surface','Best Civic interior ever - premium materials, Type S-grade sport seats, aluminum shift knob, red accents','Honda paint quality is excellent on FL5 - multi-stage process, Championship White is iconic','Latest Honda electronics - Bose audio, fast infotainment, wireless connectivity, reliable systems','Premium interior materials resist wear - Type R-specific trim is durable and well-assembled','The most complete hot hatch ever built - Honda engineering at its peak with genuine quality throughout','Honda 11th gen Civic platform (Type R enhanced)','Honda Yorii Plant (Japan)','spot weld + structural adhesive + laser braze',3.29999999999999982,'hydraulic','acoustic laminated windshield','recaro fabric/suede','aluminum/carbon trim',6,'good','sample',NULL);
INSERT INTO build_quality VALUES(98,82,73.4000000000000056,77.0,75.0,78.0,75.0,64.0,68.0,'W212-derived platform with CLS-specific body 窶・sleeker roofline, frameless doors, wider rear haunches. Steel and aluminum hybrid construction with laser-brazed roof joint. Good structural rigidity despite pillarless coupe profile. Panel fit above average for the era.','Mercedes coupe standards apply 窶・acoustic laminated front glass, double door seals, asphalt-lined floor pans, hydraulic engine mounts. The twin-turbo V8 is intrinsically smooth. Wind noise well-suppressed despite frameless doors. Road noise the weakest link on rough surfaces.','CLS-specific interior with flowing dashboard design, dual-zone trim, and ambient lighting (post-facelift). Leather quality is genuine Mercedes premium 窶・not Designo-level but above E-Class sedan. Real wood or carbon fiber trim. Sport seats with good bolstering. Materials feel cohesive.','Multi-stage paint process on galvanized steel. CLS-specific panels painted to high Mercedes standards. Good corrosion resistance 窶・the C218 generation benefitted from improved galvanizing over earlier W219 CLS. Minor clear coat thinning on horizontal surfaces at 10+ years.','COMAND Online system ages 窶・slow response, outdated graphics, occasional reboots. Harmon/Kardon Logic 7 amp can develop channel dropout. Instrument cluster pixel fade on early units. Not catastrophic but noticeably dated compared to newer MBUX systems.','Interior holds up well 窶・leather develops patina rather than cracking. Dashboard materials remain tight. Soft-touch rubberized coatings on center console and door pulls begin to peel at 8-10 years. Chrome trim retains finish. Wood trim does not delaminate.','CLS 550 C218 Q-score 73.0. W212-based coupe with premium CLS-specific interior. Build quality above W212 sedan but below S-Class flagship. Body construction and interior materials are highlights. Aging COMAND electronics (-11) and soft-touch surface peeling (-7 cosmetic) are the deductions.','W212 (coupe variant)','Sindelfingen (Germany)','laser_brazed',4.0,'hydraulic','acoustic_laminated','premium','real_wood',5,'above_average','sample',NULL);
INSERT INTO build_quality VALUES(99,79,65.5999999999999943,72.0,70.0,65.0,70.0,52.0,62.0,'W211 body represents the era when Mercedes began cost-cutting from W210 peak but before W212 recovery. Steel unibody with partial galvanization 窶・better than W210 rust issues but not up to W212 standards. Panel fit is acceptable. Structural rigidity is good 窶・Mercedes still over-engineered crash structure.','Good NVH isolation for the era 窶・hydraulic engine mounts, double door seals, asphalt-lined floor pans. The M113 V8 is intrinsically smooth. Acoustic damping on firewall. Wind noise acceptable at autobahn speeds. Not W222-quiet but solid for mid-2000s.','Interior quality dip compared to W210 窶・harder plastics on lower dash and door panels, cheaper-feeling switchgear on climate controls. Upper dash and seats still use quality leather and real wood veneer. Fit and finish is precise but materials selection is the letdown. The premium-ness gap vs BMW E60 of the same era is noticeable.','Multi-stage paint on galvanized steel. Significant improvement over W210 rust issues. Pre-2004 cars less thoroughly galvanized than post-facelift. Clear coat holds up well. Rust rare unless accident-repaired. Minor paint chipping on leading edges after 15+ years.','SBC (Sensotronic Brake Control) is the defining electrical aging issue 窶・electromechanical brake system with service life counter that eventually requires pump replacement ($2-3K). COMAND navigation display pixel fade. SAM module under rear seat can develop corrosion. Pre-2004 biodegradable wiring insulation crumbles. These are real and expensive aging issues.','Dashboard upper surface holds up. Seat leather is durable Mercedes quality 窶・develops patina rather than cracking. Real wood trim does not delaminate. Lower plastics scratch easily. Soft-touch coatings on center console peel. Door panel vinyl can pucker at seams. Rubber door seals compress and leak wind noise at 15+ years.','E500 W211 Q-score 65.6. The M113 V8-powered luxury sedan from Mercedes'' cost-cutting era. Body and paint improved over W210, but interior materials dipped significantly. SBC brakes are the defining electrical aging issue (-13). Interior materials (-10 from W213) and cosmetic aging reflect 20-year-old materials technology.','W211 (E-Class)','Sindelfingen (Germany)','spot',4.5,'hydraulic','laminated','standard','real_wood',5,'good','sample',NULL);
INSERT INTO build_quality VALUES(100,67,63.2999999999999971,58.0,68.0,78.0,48.0,65.0,63.0,'W210 body is Mercedes'' rust nadir 窶・inadequate galvanization, water traps in sill cavities and rear subframes. Spot-welded steel unibody with insufficient seam sealing. E55 AMG adds AMG-specific front/reward bumper covers and side skirts but shares the same rust-prone body. Structural rust on rear subframes and spring perches is well-documented and dangerous.','Bank-vault feel from Mercedes NVH engineering. Hydraulic engine mounts isolate the AMG V8 well. Double door seals, asphalt-lined floor pans, acoustic-damped firewall. Wind noise well-controlled. The M113 AMG V8 is smooth at idle and cruise 窶・NVH was a Mercedes strength even during the rust era.','Peak Mercedes interior 窶・this is the era when MB still used premium materials. Real burled walnut or carbon fiber trim, thick leather on seats and door panels, soft-touch surfaces everywhere, precision switchgear with satisfying detents. AMG-specific sport seats with two-tone leather. The interior is where the W210 still feels expensive.','Catastrophic 窶・W210 rust is Mercedes'' worst paint/corrosion chapter. Inadequate galvanization combined with water traps in body cavities. Fender lips, wheel arches, door bottoms, rear subframes, floor pans, spring perches, jack points 窶・all rust zones. Mercedes eventually issued TSBs and extended corrosion warranties. Pre-2001 cars are worst affected.','Simple electronics by modern standards 窶・fewer ECUs, no complex infotainment, no SBC. ASR traction control module is the main failure point. Instrument cluster pixel fade on early VDO units. Wiring harness insulation degradation on pre-2000 cars (biodegradable insulation). Overall, the simplicity is an advantage 窶・fewer things to fail.','Interior materials are excellent and age beautifully 窶・leather develops rich patina, wood retains luster, dashboard does not crack. But exterior rubber components (seals, trim, window sweeps) degrade from 20+ years of exposure. Chrome trim pits in harsh climates. The disconnect: gorgeous interior, rotting exterior.','E55 AMG W210 Q-score 63.3. The tale of two cars: AMG hand-built M113 V8 with premium interior materials (78) versus Mercedes'' worst body rust era (58 body, 48 paint). Interior is peak Mercedes quality that modern cars struggle to match. But structural rust is an existential threat. The AMG engine elevates the experience; the W210 body undermines it.','W210 (E-Class)','Sindelfingen (Germany)','spot',5.0,'hydraulic','laminated','premium','real_wood',4,'good','sample',NULL);
INSERT INTO build_quality VALUES(101,122,80.9000000000000056,88.0,85.0,90.0,82.0,66.0,68.0,'Aluminum-intensive body with carbon fiber roof panel and steel reinforcements in crash structure. Purpose-built EV architecture (EVA2 platform) with no ICE packaging compromises 窶・optimal weight distribution, low center of gravity from floor-mounted battery. Laser-brazed joints, structural adhesives, and extensive use of cast aluminum nodes. Panel gaps consistently under 4mm.','Best-in-class NVH for a production car at launch 窶・0.20 Cd drag coefficient means virtually zero wind noise. Acoustic laminated glass all around, twin-door seals, and no engine noise means total silence at speed. Road noise is the only remaining sound source, well-damped by low-profile tires and acoustic wheel liners. The gold standard for EV quietness.','Premium throughout 窶・MBUX Hyperscreen spans full dashboard width. Open-pore woods, real metal trim, Nappa leather standard. Vegan leather option (artico/man-made). Dashboard wrapped in stitched leather. Optional rear executive seats with massage. Materials selection rivals Bentley Flying Spur. The interior is the EQS''s strongest statement.','Multi-stage paint process (up to 7 layers including primer, base, metallic, clear) on aluminum and steel. Electro-dip galvanization on steel components. Excellent corrosion resistance 窶・EV architecture eliminates many traditional corrosion points (no exhaust, no fuel lines under body). Paint quality is Mercedes flagship standard.','Too new for definitive aging assessment, but risks are clear: MBUX Hyperscreen relies on ongoing software support 窶・when Mercedes stops updating it, functionality will degrade. 12V auxiliary system drains if car sits. HV battery capacity will degrade over time. OTA update dependency means the car needs network connectivity to stay current.','High-quality materials should age well 窶・Nappa leather is durable, open-pore wood does not delaminate, metal trim does not corrode. But the Hyperscreen is a large glass surface vulnerable to cracking and delamination over decades. Seat comfort foam may compress. EV-specific: battery thermal management adds structural complexity to floor assembly.','EQS V297 Q-score 79.9. Purpose-built EV flagship with best-in-class body construction and NVH isolation. Aluminum-intensive EVA2 platform with laser welding and structural adhesives. Interior materials rival ultra-luxury brands. Deductions for long-term electrical aging uncertainty (software-dependent MBUX, -14) and cosmetic aging unknowns (-12). Second only to the 500E W124 among Mercedes in this database.','EVA2 (purpose-built EV)','Sindelfingen (Germany)','laser_brazed',3.5,'solid_rubber','acoustic_laminated','nappa','real_wood_open_pore',7,'outstanding','sample',NULL);
INSERT INTO build_quality VALUES(102,53,71.4000000000000056,74.0,68.0,76.0,74.0,65.0,67.0,'C-Class-based SUV platform (X253) with reinforced structure for SUV duty. Steel unibody with partial aluminum panels (hood, tailgate). Good crash structure and panel fit. Spot-welded and laser-brazed joints. Solid for the segment but not flagship-level 窶・shared platform with C-Class means structural compromises vs purpose-built.','SUV NVH is class-competitive but not S-Class level. Engine bay insulation is adequate. Acoustic laminated front glass on premium packages. Wind noise increases at SUV aerodynamics. The M276 biturbo V6 is smooth but not whisper-quiet under acceleration. Road noise from wider AMG tires is noticeable on coarse surfaces.','AMG-specific interior trim 窶・sport seats with two-tone leather, DINAMICA suede inserts, carbon fiber or brushed aluminum trim. Above average for the segment but clearly shared C-Class architecture 窶・same HVAC controls, same steering wheel base, same switchgear. Leather quality is good but not Nappa-grade standard. AMG branding throughout adds perceived quality.','Modern Mercedes multi-stage paint process on galvanized steel. Good corrosion resistance 窶・the X253 generation benefitted from improved galvanizing. AMG-specific paint options (designo colors) available at premium. Paint thickness consistent. Clear coat holds up well at 5-8 years.','MBNT infotainment (COMAND-based) ages 窶・slow response on older firmware, map updates expensive. Instrument cluster is traditional analog + small screen (pre-facelift). AMG-specific electronics (performance display, drive mode selector) are reliable. Harman/Kardon surround sound amp can develop channel dropout at 5+ years.','Interior holds up well for daily-driven SUV 窶・DINAMICA suede is more durable than leather on seat bolsters. Carbon fiber trim does not fade. Cup holder coatings wear. Steering wheel leather can show wear at 60K+ miles. SUV duty means more cargo area scuffing. Overall above average for the class.','GLC 43 X253 Q-score 70.6. AMG-enhanced C-Class SUV platform with good but not exceptional build quality. Interior materials benefit from AMG-specific trim but shared architecture with C-Class is evident. Solid paint and body construction. Electronics aging is the main concern (-5 from modern MBNT). A well-built SUV but not in the same league as S-Class or EQS.','C-Class (X253 SUV)','Bremen (Germany)','spot',4.20000000000000017,'hydraulic','laminated','premium','carbon_fiber',5,'above_average','sample',NULL);
INSERT INTO build_quality VALUES(103,42,78.2999999999999971,82.0,82.0,88.0,83.0,62.0,68.0,'Flagship Mercedes body engineering 窶・aluminum/steel hybrid with aluminum hood, front fenders, trunk lid, and doors. Laser-brazed roof joint, structural adhesives throughout, double-skinned panels in crash zones. Extensive use of hot-stamped boron steel in A/B-pillars and rockers. Panel gaps consistently under 4mm. The W222 set the benchmark for body quality in its class.','Best-in-class NVH at launch 窶・acoustic laminated glass front and rear, double-door seals, hydraulic engine mounts, extensive asphalt and foam sound deadening. Magic Body Control (optional) uses stereo camera to read road surface. The M278 twin-turbo V8 is barely perceptible at idle. Wind noise virtually absent at autobahn speeds. The gold standard for luxury sedan quietness.','The interior that defined luxury for a generation 窶・flowing dashboard design, dual 12.3 screens (post-facelift), ambient lighting with 64 colors. Designo Nappa leather, open-pore woods (eucalyptus, walnut, ash), real aluminum trim. Seat comfort unmatched 窶・hot stone massage, energizing comfort control. Rear-seat executive package available. Only the Maybach S-Class surpasses it.','Mercedes flagship paint process 窶・multi-stage with up to 7 layers including cathodic dip primer, base coat, metallic/candy layers, and clear coat. Electro-dip galvanization on all steel components. Ceramic Pro factory option available. Paint quality is the best Mercedes produces 窶・consistent thickness, deep gloss, excellent long-term durability.','Complex electronics will define the W222''s aging 窶・dual 12.3 screens will eventually have pixel/brightness issues, COMAND Online depends on cellular connectivity that Mercedes will eventually discontinue, and the car has over 100 ECUs. Magic Body Control air suspension struts are $3-5K per corner. Night vision and 360 camera systems add failure points.','Premium materials age well 窶・Nappa leather develops patina rather than cracking. Real wood does not delaminate. Metal trim retains finish. But soft-touch rubberized coatings on center console and lower trim begin to deteriorate at 8-10 years. The dual-screen setup will look dated as newer designs adopt larger integrated displays. Dashboard leather stitching holds up well.','S-Class W222 Q-score 77.2. Mercedes'' flagship from 2014-2020 窶・the benchmark for luxury sedan build quality in its era. Aluminum/steel body with laser welding. Interior materials are second only to Maybach among production cars. Deductions for electronics aging complexity (-13: 100+ ECUs, screen dependency) and soft-touch surface deterioration (-7 cosmetic). Only 1.3 points below the SL 63 R232 despite being a much higher-volume car.','W222 (S-Class)','Sindelfingen (Germany)','laser_brazed',3.79999999999999982,'hydraulic','acoustic_laminated','designo_nappa','real_wood_open_pore',7,'outstanding','sample',NULL);
INSERT INTO build_quality VALUES(104,117,72.7000000000000028,78.0,76.0,78.0,76.0,56.0,68.0,'W206 C-Class platform 窶・all-new for 2022 with significantly improved body rigidity over W205. Steel unibody with aluminum hood and front fenders. Laser-brazed roof joint. Improved spot weld density and structural adhesives over previous generation. Panel gaps tight and consistent. AMG-specific front/rear bumper covers and wider fender flares integrated cleanly.','PHEV advantage 窶・the C63 S can operate in pure EV mode making it eerily quiet at low speeds. Acoustic laminated glass, improved door sealing, and AMG-specific exhaust tuning. The 4-cylinder turbo is less sonically satisfying than the previous V8 but cabin isolation is objectively better. Wind noise well-suppressed for a compact sedan. Road noise from wider AMG rubber is the primary sound source.','W206 interior is a genuine step up from W205 窶・vertical MBUX infotainment screen inspired by S-Class, turbine-look air vents, ambient lighting with multiple zones. AMG-specific sport seats with DINAMICA suede and Nappa leather. Real metal trim (not plastic chrome). Digital-first cockpit feels modern and premium. The interior is the C63 S''s strongest quality statement.','Modern Mercedes multi-stage paint on galvanized steel 窶・good quality and consistent application. AMG-specific colors (obsidian black metallic, spectral blue) are deep and lustrous. Corrosion resistance is modern Mercedes standard 窶・well-galvanized with electro-dip process. Limited long-term data (car is 2022+) but paint quality matches Mercedes contemporary standards.','PHEV complexity is the defining aging risk 窶・400V battery management system, e-motor inverter, and integrated thermal management add significant electronic complexity beyond a conventional ICE car. MBUX system depends on OTA updates and cellular connectivity. When Mercedes stops supporting this generation, functionality will degrade. The P4HEV system is unproven beyond 5 years.','Materials are high quality and should age well in theory 窶・DINAMICA suede is durable, Nappa leather is premium, metal trim retains finish. But the car is too new (2022+) for meaningful long-term cosmetic aging data. Screen-heavy interior may look dated as display technology evolves. Limited historical precedent for 400V PHEV aging.','C63 S W206 Q-score 72.7. Well-built modern AMG with excellent interior materials and PHEV-quiet NVH. W206 platform is a genuine quality improvement over W205. But the 400V PHEV system adds unproven electronic complexity (-14 elec aging) and limited long-term cosmetic data (-7). The controversial 4-cylinder replacement for the V8 doesn''t affect build quality but colors perception of the entire car.','W206 (C-Class AMG)','Bremen (Germany)','laser_brazed',3.89999999999999991,'hydraulic','acoustic_laminated','nappa','carbon_fiber',6,'very_good','sample',NULL);
INSERT INTO build_quality VALUES(105,10,86.7000000000000028,90.0,90.0,90.0,88.0,75.0,85.0,'Multi-material construction with advanced joining techniques - aluminum, high-strength steel, composite floor for battery','Exceptional EV isolation - virtually silent at low speeds, wind noise well-managed at highway speeds, Porsche acoustic engineering at its best','Full-grain leather, Alcantara headliner, real aluminum trim - every surface is premium, optional Race-Tex adds sport luxury','Porsche paint quality is consistently excellent - deep metallics, even coverage, multiple clear coat layers','Complex 800V electronics and PCM system - many potential failure points over time, OTA updates help but hardware aging is a concern','Premium materials resist wear well - leather seats and Alcantara surfaces age gracefully with proper care','Porsche flagship build quality at its finest - the Taycan demonstrates VW Group at the top of its manufacturing game','J1 EV platform (shared with Audi e-tron GT)','Porsche Zuffenhausen (Stuttgart)','bonded + riveted + MIG weld',3.0,'solid hydraulic','acoustic laminated all-around','full-grain nappa','real aluminum/optional carbon',7,'excellent','sample',NULL);
INSERT INTO build_quality VALUES(106,17,68.0,75.0,62.0,65.0,78.0,62.0,60.0,'Galvanized steel unibody - Porsche was an early adopter of full galvanization, transaxle layout for weight distribution','Minimal sound deadening - turbo 4 is vocal, road noise prevalent, classic sports car character with no pretense of luxury','Period-appropriate materials - vinyl and cloth dominate, optional leather is thin, 80s Porsche switchgear','Galvanized body resists corrosion exceptionally well for the era - bodies outlast mechanicals','Simple 1980s electronics age acceptably - few modules, DME is reliable, minimal bus complexity','Dashboard plastics crack in UV exposure, seat bolsters wear, steering wheel degrades - 35+ year old car materials','Honest 1980s sports car build - galvanized body is the standout, interior is period-correct economy-grade Porsche','924/944 transaxle platform','Porsche Zuffenhausen/Audi Neckarsulm','spot weld',5.0,'solid rubber','tinted','optional leather','none',4,'poor','sample',NULL);
INSERT INTO build_quality VALUES(107,18,68.2999999999999971,74.0,68.0,65.0,78.0,62.0,60.0,'Steel unibody with galvanized panels - first water-cooled 911, adequate rigidity but less than later 997','Better isolation than air-cooled 911s but flat-6 character is always present - acceptable for sports car, not luxury grade','Controversial interior design - ''fried egg'' headlights divide opinion, soft-touch plastics degrade, switchgear feels cheap for Porsche','Porsche paint and galvanization hold up well - bodies are durable, metallics maintain depth','Early CAN bus architecture - some module failures, instrument cluster pixel loss, window regulator issues','Interior plastics get sticky and degrade, dashboard can crack, seat leather wears at bolsters - 20+ year aging shows','The 996 was built to a price point Porsche hadn''t targeted before - body and paint are solid, interior is the weak point','996 platform (first water-cooled 911)','Porsche Zuffenhausen (Stuttgart)','spot weld + adhesive',4.5,'solid rubber','tinted','partial leather','none',4,'below_average','sample',NULL);
INSERT INTO build_quality VALUES(108,21,72.7000000000000028,82.0,58.0,70.0,80.0,68.0,68.0,'GT3-specific lightweight construction - thinner glass, reduced sound deadening, additional structural bracing for track use','Deliberately minimal - flat-6 howl is the point, thin glass and deleted deadening make it the loudest 996 variant','Purposeful but not luxurious - GT3-specific Alcantara steering wheel and seats, some hard plastics remain, focused not fancy','Same excellent Porsche galvanization and paint as 996 Carrera - GT3-specific colors are well-executed','Same CAN bus as standard 996 with added telemetry - not more complex, just different purpose','Track-driven examples show accelerated wear - Alcantara wheels absorb oils, seat bolsters take abuse','A track tool with road registration - build quality prioritizes performance over comfort, the NVH is intentional and beloved','996 platform (GT3 enhanced)','Porsche Zuffenhausen (Stuttgart)','spot weld + adhesive + seam seal',4.20000000000000017,'solid rubber','lightweight thin','alcantara/leather sport','none',4,'minimal','sample',NULL);
INSERT INTO build_quality VALUES(109,22,86.5,92.0,90.0,91.0,88.0,72.0,82.0,'ASF (Aluminum Space Frame) fourth generation - Audi''s flagship construction, 40% more rigid than D4, mixed-material joining','Outstanding luxury isolation - double-glazed side windows available, active noise cancellation, cabin is whisper-quiet','Premium Audi interior at its best - Valcona leather, real wood or aluminum inlays, cut-and-sewn surfaces, excellent fit and finish','Audi paint quality is excellent - multiple clear coat layers, deep metallics, consistent panel coverage','MMI Touch Response system with two screens - functional but complex, long-term aging of haptic feedback is unknown','Premium materials age well - leather develops patina gracefully, aluminum trim resists wear, headliner stays intact','World-class luxury sedan build quality - the aluminum body is the star, interior materials match the price point','MLB Evo platform (D5 ASF)','Audi Neckarsulm (Germany)','self-piercing rivet + structural adhesive + laser weld',3.20000000000000017,'hydraulic','acoustic laminated all-around','valcona leather','real wood/aluminum',7,'excellent','sample',NULL);
INSERT INTO build_quality VALUES(110,43,86.7999999999999971,92.0,91.0,91.0,88.0,73.0,82.0,'Same ASF aluminum space frame as pre-facelift D5. +18mm length (5190mm), improved Cd 0.26 from 0.27. Self-piercing rivet + structural adhesive + laser weld construction unchanged','Improved MHEV coasting refinement and better aero contribute to marginally lower NVH. Same excellent acoustic laminated glass all-around. Sound deadening rated excellent','Same Valcona leather, real wood/aluminum trim. New Matrix LED reading lights in rear. S line exterior package now available. Minor trim updates only - materials quality identical to pre-facelift','Same 7-stage Audi paint process. 5 new matte paint options added (Daytona gray, florette silver, district green, glacier white). Proven corrosion resistance unchanged','MIB3 (Qualcomm) replaces MIB2 (Nvidia) - faster, more stable platform. Digital Matrix LED headlights with 1.3M micromirrors are new tech with limited long-term aging data. Digital OLED rear lights standard - unproven beyond 5 years. 48V MHEV system unchanged from 2018','Same premium materials throughout. New wheel designs 18-21 inch. Same proven interior aging characteristics as pre-facelift','Marginal improvement over 2018 (86.7 vs 86.8). NVH slightly better from MHEV refinement. Core build quality identical - facelift is cosmetic/infotainment refresh, not structural change. +40kg from larger fuel tank and new tech hardware','MLB Evo platform (D5 ASF + 48V MHEV)','Audi Neckarsulm (Germany)','self-piercing rivet + structural adhesive + laser weld',3.20000000000000017,'hydraulic','acoustic laminated all-around','valcona leather','real wood/aluminum',7,'excellent','sample',NULL);
INSERT INTO build_quality VALUES(111,49,81.2999999999999971,85.0,85.0,85.0,84.0,68.0,78.0,'MSB platform - steel-aluminum mixed construction, excellent rigidity for grand tourer duties, heavy but solid','Excellent luxury GT isolation - cabin is well-sealed from road noise, V8 is audible but refined, double-glazing available','Porsche premium quality - full leather available, real aluminum trim, excellent seat construction, center console dominates','Porsche paint quality is excellent - deep metallics, consistent clear coat, some reports of soft paint on leading edges','PCM 3.1 is dated and slow by modern standards - screen aging, Bluetooth limitations, no Apple CarPlay without retrofit','Full leather interiors age beautifully - non-leather option cars show more wear on dash and door panels','Porsche luxury GT build quality is excellent - the Panamera proved Porsche could build a proper grand tourer','MSB platform (Porsche developed)','Porsche Leipzig (Germany)','spot weld + adhesive + laser weld',3.5,'hydraulic','acoustic laminated windshield','full-grain nappa','real aluminum',6,'very good','sample',NULL);
INSERT INTO build_quality VALUES(112,66,65.7999999999999971,72.0,65.0,68.0,75.0,55.0,55.0,'B5 PL45 platform (shared with VW Passat) - galvanized steel, adequate rigidity for compact executive sedan','Moderate - bi-turbo V6 is audible, road noise at highway speeds, 90s sports sedan isolation not luxury grade','Good for the era - Audi quality above VW, some soft-touch materials, sport seats are supportive, trim is plastic-heavy','Audi galvanized body holds up well against corrosion - paint quality is above average for the era','25+ year old electronics - instrument cluster pixel loss, window regulators, central locking module failures all common','Dashboard cracks, seat bolster wear, steering wheel degradation - materials from 1997 have not aged gracefully','Period-good build quality that has aged - galvanized body is durable, interior materials are the weak point','B5 PL45 platform (Volkswagen Group)','Audi Ingolstadt (Germany)','spot weld + laser weld',4.5,'solid rubber','tinted','optional sport leather','simulated aluminum',4,'below_average','sample',NULL);
INSERT INTO build_quality VALUES(113,101,74.7000000000000028,76.0,72.0,76.0,78.0,72.0,72.0,'MQB platform with aluminum hood and trunk lid - good rigidity for small sports car, VW Golf underpinnings well-developed','Good for segment - German engineering provides decent isolation, not luxury-quiet but refined for a small coupe','Audi quality in a compact package - good leather, aluminum accents, TT-specific circular vents are a design highlight','Audi paint quality is consistent and durable - metallics hold up well, clear coat resists UV','MMI system is functional, virtual cockpit (optional) is excellent - updates slow with age but hardware is stable','Good materials throughout - leather seats wear well, aluminum trim resists scratching, steering wheel holds up','Well-built compact sports car - Audi DNA throughout, MQB platform maturity shows in consistency','MQB platform (Volkswagen Group)','Audi Gyor (Hungary)','spot weld + adhesive + laser braze',3.79999999999999982,'hydraulic','tinted','available nappa','aluminum',5,'average','sample',NULL);
INSERT INTO build_quality VALUES(114,104,79.4000000000000056,86.0,68.0,80.0,84.0,75.0,75.0,'Mid-engine aluminum-steel composite body - excellent rigidity, lightweight panels, race-derived structural design','Sports car NVH - flat-4 turbo is audible (some say sounds like a Subaru), road noise from mid-engine layout, not GT-grade','Porsche quality in the mid-engine format - good leather, Alcantara options, excellent sport seats, driver-focused cockpit','Porsche paint quality is consistently excellent - deep metallics, smooth coverage, consistent clear coats','PCM with Apple CarPlay is modern and functional - screen quality holds up, physical buttons for key functions','Premium materials age well with care - Alcantara can absorb oils on steering wheel, leather seats develop character','Porsche mid-engine build quality at its best - the 718 benefits from continuous evolution of the 981 platform','982 platform (evolved from 981)','Porsche Zuffenhausen (Stuttgart)','spot weld + adhesive bonding',3.29999999999999982,'hydraulic','tinted','available full leather','aluminum/optional carbon',6,'good','sample',NULL);
INSERT INTO build_quality VALUES(115,114,67.0,74.0,68.0,72.0,75.0,52.0,55.0,'C5 PL45+ platform with Avant body - adequate rigidity, galvanized steel, wide-body fender flares unique to RS6','Not luxury-quiet - twin-turbo V8 dominates the soundscape, Avant body allows some boom, acceptable for super-sedan of era','Audi RS-quality for early 2000s - Recaro seats excellent, some carbon fiber trim, but 20-year-old materials showing age','Audi galvanization is solid - bodies hold up well, RS6-specific paint colors are deep and consistent','20+ year old Audi electronics are the achilles heel - instrument cluster pixels, comfort module failures, CAN bus gremlins','Dashboard plastics crack, leather seats show 20+ years of wear, headliner sags - cosmetic age is the reality of C5 ownership','Period-flagship Audi build quality that hasn''t aged gracefully - the body is durable, interior and electronics are the weak points','C5 PL45+ platform (enhanced B5)','Audi Neckarsulm (Germany)','spot weld + laser weld',4.5,'solid hydraulic','tinted','recaro leather/alcantara','carbon fiber trim',4,'below_average','sample',NULL);
INSERT INTO build_quality VALUES(116,12,73.2999999999999971,75.0,72.0,74.0,73.0,72.0,72.0,'MQB Evo platform - excellent hot hatch rigidity, laser-welded roof seam, hot-stamped B-pillars','Good isolation for a hot hatch - turbo whoosh is audible but not intrusive, highway cruising is refined','GTI-typical premium over base Golf - Clark plaid seats, soft-touch upper dash, aluminum accents','VW paint quality is consistent - Osnabruck-built GTIs have deep metallics and good clear coat','MIB4 infotainment is a leap forward but Mk8 touch sliders are polarizing - reliability TBD','Interior materials hold up well - steering wheel and seat bolsters are primary wear points','Best-in-class hot hatch build quality - MQB Evo is mature and the GTI trim elevates the experience','VW MQB Evo','VW Wolfsburg / Osnabruck','laser weld + spot weld + adhesive',3.5,'hydroelectric','acoustic laminated windshield','premium cloth (Clark plaid)','aluminum trim',5,'good','sample',NULL);
INSERT INTO build_quality VALUES(117,62,82.0,90.0,92.0,90.0,82.0,55.0,78.0,'D1 platform shared with Bentley Continental - over-engineered body with 300+ laser welds, double-glazed windows','Tomb-like silence - double-sealed doors, acoustic glass, air-blanket insulation, one of the quietest sedans ever made','Bentley-grade interior - hand-stitched Connelly leather, real wood veneers, 4-zone climate, VR6 fit and finish throughout','Excellent paint quality from Transparent Factory Dresden - multiple clear coats, deep metallics','Electronics are the Achilles heel - complex CAN bus network with dozens of modules ages poorly','Premium leather and wood age gracefully - the materials quality is genuinely Bentley-level','World-class build quality undermined by electronics that became a liability - the body and interior are exceptional','VW D1 platform (Bentley Continental twin)','Glaserne Manufaktur Dresden (Transparent Factory)','laser weld + adhesive bonding + MIG weld',2.79999999999999982,'hydraulic','double-glazed acoustic all-around','connelly hand-stitched','real wood veneer',7,'exceptional','sample',NULL);
INSERT INTO build_quality VALUES(118,96,74.5999999999999943,76.0,74.0,76.0,75.0,72.0,73.0,'MQB-based fastback with long wheelbase - good torsional rigidity, frameless doors add some flex','Good isolation - fastback shape helps aero noise, acoustic windshield standard, engine is quiet at cruise','Above-average VW interior - R-Line trim adds aluminum and contrast stitching, Nappa leather available','VW Emden plant paint quality is consistent - Arteon-specific colors are well executed','MIB3 infotainment is functional - digital cockpit and touch panels are current but aging','Frameless door seals are a long-term concern - interior materials are above average for VW','Premium VW build quality in a handsome fastback - closer to Audi A5 than Passat in execution','VW MQB (stretched)','VW Emden','laser weld + spot weld + adhesive',3.60000000000000008,'hydroelectric','acoustic laminated windshield','Nappa leather (SEL Premium)','aluminum trim',5,'good','sample',NULL);
INSERT INTO build_quality VALUES(119,125,82.4000000000000056,88.0,85.0,86.0,83.0,68.0,80.0,'J1 platform shared with Porsche Taycan - aluminum-intensive space frame, carbon fiber roof option, exceptional rigidity','EV silence with active noise management - near-perfect cabin isolation, only tire noise at highway speeds','Premium Audi Sport interior - Valcona leather, Dinamca suede headliner, real carbon fiber, fit-and-finish is superb','Audi Neckarsulm paint quality - multi-stage process with ceramic clear coat, deep metallics','Complex EV electronics - 800V architecture is cutting edge but long-term aging is unknown','Premium materials throughout - leather and Alcantara resist wear well, sustainable material options available','Porsche platform + Audi interior = exceptional build quality - one of the best-built EVs on the market','Porsche J1 platform (shared with Taycan)','Audi Bollinger Hofe (Neckarsulm)','aluminum space frame bonding + rivet + weld',2.5,'solid mount (EV)','acoustic laminated all-around','valcona leather / kantara','real carbon fiber',7,'excellent','sample',NULL);
INSERT INTO build_quality VALUES(120,132,73.0,80.0,78.0,76.0,75.0,60.0,65.0,'PL71 platform co-developed with Porsche Cayenne - heavy but robust, dual-range transfer case, excellent structural rigidity','Good SUV isolation - air suspension models are especially quiet, V8 rumble present but well-damped','Premium-for-VW interior - real wood trim available, V10 TDI models got upgraded leather, Germanic solidity','VW Bratislava paint quality is good - some early models had clear coat issues in sunbelt states','Early 2000s electronics architecture - CAN bus is simpler than Phaeton but modules still age poorly','Interior plastics and leather show 15+ years of wear - steering wheel and seat bolsters are wear points','Over-engineered SUV with genuine off-road capability - build quality is solid if dated, electrical aging is the concern','PL71 platform (shared with Porsche Cayenne/Audi Q7)','VW Bratislava (Slovakia)','spot weld + MIG weld + structural adhesive',3.79999999999999982,'hydraulic','acoustic laminated windshield','available leather','real wood (V8/V10)',5,'good','sample',NULL);
INSERT INTO build_quality VALUES(121,133,75.7999999999999971,82.0,80.0,78.0,76.0,65.0,70.0,'MLB platform (Audi-based) - significant improvement over PL71, lighter, better weight distribution, excellent rigidity','Improved isolation over 7L - better door seals, acoustic glass, quieter powertrains','Step up from 7L - real aluminum trim, better leather quality, VW''s best interior before Touareg CR','Improved paint processes at Bratislava - better clear coat adhesion and metallic depth','Improved over 7L but still VW-grade electronics - FlexRay bus is more capable but modules still age','Interior materials are better than 7L - leather and plastics resist wear longer, air vent chrome peels','Major improvement over 7L thanks to MLB platform - closer to Audi Q7 in build execution','VW MLB platform (Audi Q7-derived)','VW Bratislava (Slovakia)','laser weld + spot weld + structural adhesive',3.5,'hydraulic','acoustic laminated windshield','Nappa leather (Executive)','real wood / aluminum',6,'very good','sample',NULL);
INSERT INTO build_quality VALUES(122,134,78.5999999999999943,85.0,82.0,82.0,78.0,68.0,72.0,'MLB Evo platform - latest generation with aluminum-intensive construction, 100kg lighter than 7P, exceptional rigidity','Near-luxury isolation - active noise cancellation, acoustic glass all-around, EV-quiet cabin at cruise','Approaching Audi Q8 interior quality - Innovision cockpit, premium leather, real wood and aluminum','Excellent paint quality - European-spec models get multi-stage process with premium clear coats','Digital cockpit and connected services are current - but long-term software support is a concern for orphaned US models','Premium materials resist wear well - the gap between Touareg and Audi Q8 interior is smaller than ever','The finest Touareg ever built and not available in the US - MLB Evo delivers near-Audi build quality','VW MLB Evo platform','VW Bratislava (Slovakia)','laser weld + aluminum bonding + structural adhesive',3.0,'hydraulic','acoustic laminated all-around','Nappa leather','real wood / aluminum',7,'excellent','sample',NULL);
INSERT INTO build_quality VALUES(123,107,66.4000000000000056,70.0,60.0,62.0,68.0,70.0,65.0,'B-segment economy car construction - stamped steel unibody, adequate rigidity for size','Minimal sound deadening - road and engine noise prevalent, typical hot hatch character','Hard plastics dominate - Recaro seats are excellent but rest of interior is budget Ford','Ford paint quality is average - some chipping on leading edges, metallics hold up reasonably','Simple electronics age well - few modules, minimal bus complexity','Interior plastics scratch easily, steering wheel wears at high mileage','Economy car build quality elevated slightly by sporty Recaros - noise is part of the charm','B-segment global platform','Ford Saarlouis (Germany)','spot weld',4.5,'hydroelectric','tinted','none','none',4,'poor','sample',NULL);
INSERT INTO build_quality VALUES(124,81,67.5999999999999943,72.0,63.0,65.0,68.0,68.0,66.0,'C-segment global C1 platform - good torsional rigidity, better than Fiesta','Some sound deadening added over base Focus - still noisy at highway speeds','Better than Fiesta - ST-specific trim helps but still mostly hard plastics','Similar to Fiesta - average Ford paint quality','SYNC 1 system ages poorly - slow response, dated interface','Better than Fiesta but still economy-grade wear patterns','Step up from Fiesta in build quality but still firmly economy car territory','C-segment global C1 platform','Ford Saarlouis (Germany)','spot weld + adhesive',4.20000000000000017,'hydroelectric','tinted','partial recaro','none',4,'below_average','sample',NULL);
INSERT INTO build_quality VALUES(125,128,71.4000000000000056,74.0,68.0,70.0,72.0,72.0,70.0,'S550 platform - significantly improved over S197, independent rear suspension','Better than old Mustangs - turbo 4 is quieter than V8, decent highway isolation','Premium trim adds leather and better materials - respectable for the segment','Ford paint quality improved in S550 generation - metallics look good','SYNC 3 is a major upgrade - ages better than SYNC 1/2','Interior holds up well in Premium trim - leather seats wear gracefully','Big step up from previous Mustang generations - Premium trim is worthwhile','S550 dedicated platform','Flat Rock Assembly (Michigan)','spot weld + structural adhesive',3.79999999999999982,'hydroelectric','acoustic laminated windshield','premium synthetic','none',5,'average','sample',NULL);
INSERT INTO build_quality VALUES(126,129,73.0,76.0,70.0,72.0,73.0,73.0,71.0,'S550 platform - same as Ecoboost but braced for V8 torque, excellent rigidity','V8 rumble is ever-present but not intrusive - decent isolation for muscle car','Premium leather is genuine quality - aluminum trim accents elevate the cabin','Good paint quality - Ford improved processes for S550 generation','SYNC 3 ages reasonably well - still responsive after years of use','Premium interior materials resist wear well - steering wheel may show age at high miles','The S550 GT Premium is a genuinely well-built car - best Mustang interior in decades','S550 dedicated platform','Flat Rock Assembly (Michigan)','spot weld + structural adhesive',3.79999999999999982,'hydroelectric','acoustic laminated windshield','genuine leather','aluminum trim',5,'average','sample',NULL);
INSERT INTO build_quality VALUES(127,112,73.2000000000000028,78.0,62.0,73.0,74.0,73.0,72.0,'S550 with additional bracing and carbon fiber components - track-ready rigidity','Flat-plane crank V8 is LOUD - thin sound deadening deliberately for weight savings and aural experience','Recaro seats are excellent - unique Shelby badging and materials, suede touches','Similar to GT Premium - Shelby-specific paint options are well executed','Same SYNC 3 system as GT - adequate but not class-leading','Track use accelerates cosmetic wear - seats and steering wheel take abuse','Track-focused build prioritizes performance over refinement - the NVH is intentional','S550 platform ( Shelby enhanced)','Flat Rock Assembly (Michigan)','spot weld + structural adhesive + carbon fiber bonding',3.5,'solid hydraulic','lightweight','recaro leather/suede','carbon fiber trim',5,'minimal','sample',NULL);
INSERT INTO build_quality VALUES(128,11,74.0,80.0,65.0,74.0,75.0,70.0,73.0,'Most rigid S550 variant - extensive use of carbon fiber, structural reinforcements throughout','Supercharger whine is ever-present - some additional deadening vs GT350 but still loud','Premium materials throughout - unique Shelby touches, excellent Recaros','High-quality paint finishes available - grabber lime and other heritage colors well executed','Complex performance electronics - track telemetry and drive modes add failure points','Carbon fiber trim ages well - interior materials are top-tier for Ford','The ultimate S550 build - Ford Performance pulled out all stops on construction quality','S550 platform (Ford Performance enhanced)','Flat Rock Assembly (Michigan)','spot weld + structural adhesive + carbon fiber bonding',3.20000000000000017,'solid hydraulic','lightweight','recaro leather/suede','carbon fiber',6,'minimal','sample',NULL);
INSERT INTO build_quality VALUES(129,130,70.7000000000000028,75.0,70.0,65.0,72.0,73.0,68.0,'Alpha platform provides excellent rigidity - heavier than ATS but structurally superior to 5th gen','V8 rumble present but well-isolated from road noise - decent highway cruiser','1SS interior is the weak point - hard plastics, dated design, poor visibility compounds the feeling','GM paint quality is average - some orange peel on dark colors','Infotainment system is functional but not premium - GM electronics are middle of the road','Interior plastics show wear quickly - steering wheel and seat bolsters are wear points','Great chassis wrapped in an interior that feels a generation behind - Alpha platform deserves better','GM Alpha platform','Lansing Grand River Assembly (Michigan)','spot weld + structural adhesive',4.0,'hydraulic','tinted','cloth (1SS base)','none',4,'average','sample',NULL);
INSERT INTO build_quality VALUES(130,105,75.5999999999999943,82.0,73.0,73.0,75.0,72.0,74.0,'Aluminum frame with carbon fiber panels - excellent power-to-weight, race-derived construction','Good for a mid-front engine sports car - cabin is well-isolated from road noise','Major improvement over C6 - wrapped upper dash, real aluminum trim, competition seats available','Corvette paint is generally good - some orange peel on dark colors, Z06-specific graphics hold up','Performance electronics are complex but well-engineered - some display issues reported','Composite panels resist dents - interior materials hold up well for the price point','Best Corvette interior until C8 - aluminum frame and carbon construction are exceptional for the money','Y2 sports car platform (aluminum frame)','Bowling Green Assembly (Kentucky)','aluminum mig weld + adhesive bonding + carbon fiber',3.0,'hydraulic','removable roof panel','nappa leather (3LZ)','carbon fiber trim',6,'good','sample',NULL);
INSERT INTO build_quality VALUES(131,85,70.4000000000000056,72.0,73.0,68.0,70.0,72.0,68.0,'E2XX platform - standard midsize sedan construction, adequate rigidity','Hybrid powertrain is quieter than ICE-only - EV mode masks engine noise, decent highway isolation','Mid-trim materials - nothing offensive but nothing memorable, GM corporate design','Average GM paint - some reports of clear coat issues after 5+ years','Simple infotainment - hybrid display adds complexity but system is stable','Interior plastics and fabrics show their age predictably - family car wear patterns','Competent but unremarkable - the Malibu Hybrid does nothing badly and nothing exceptionally','E2XX midsize platform','Fairfax Assembly (Kansas)','spot weld + adhesive',4.20000000000000017,'hydraulic','acoustic laminated windshield','none (cloth standard)','none',4,'average','sample',NULL);
INSERT INTO build_quality VALUES(132,27,74.5999999999999943,78.0,76.0,76.0,75.0,68.0,72.0,'Alpha platform provides excellent rigidity - shared with Camaro but tuned for comfort','Good luxury isolation - active noise cancellation helps, cabin is quiet at speed','Genuine Cadillac materials - cut-and-sewn upper trim, real aluminum accents, comfortable seats','Cadillac paint quality is generally good - clear coats hold up, metallics are deep','Infotainment is a weak point - Cadillac electronics aging faster than competitors','Leather and trim hold up reasonably well - steering wheel wear is the main concern','Good luxury sedan build quality undermined by electronics that feel dated quickly','GM Alpha platform','Lansing Grand River Assembly (Michigan)','spot weld + structural adhesive + laser weld',3.5,'hydraulic','acoustic laminated','semi-aniline','real aluminum',6,'good','sample',NULL);
INSERT INTO build_quality VALUES(133,100,79.7000000000000028,85.0,78.0,82.0,80.0,70.0,78.0,'Alpha platform at its finest - additional structural adhesive, braced for V8 torque, track-capable rigidity','Performance sedan isolation is excellent - V8 is audible but never harsh, active noise cancellation','Best Cadillac interior ever - hand-stitched leather, carbon fiber trim,Recaro options, genuine materials','Excellent paint quality - deep metallics, consistent coverage, premium clear coat','Same infotainment concerns as CT5 - complex performance electronics may age poorly','Premium materials resist wear well - Recaro leather/suede ages beautifully','The finest build quality in any American sedan - hand-assembled V8, Alpha platform perfected','GM Alpha platform (Blackwing enhanced)','Lansing Grand River Assembly (Michigan)','spot weld + structural adhesive + laser weld + additional bracing',3.0,'hydraulic performance','acoustic laminated all-around','semi-aniline recaro','real carbon fiber',7,'very good','sample',NULL);
INSERT INTO build_quality VALUES(134,26,73.0999999999999943,77.0,75.0,75.0,74.0,65.0,70.0,'Alpha platform provides excellent structural rigidity - well-engineered body','Good luxury isolation - active noise cancellation, decent cabin quietness','Good materials for the era - cut-and-sewn leather, real wood trim options','Good Cadillac paint - metallics are deep and consistent','CUE system is the Achilles heel - capacitive touch strips fail, screen delamination reported','Leather seats age reasonably - dashboard materials can develop squeaks','Strong chassis and decent materials let down by infotainment that was bad when new and worse now','GM Alpha platform','Lansing Grand River Assembly (Michigan)','spot weld + structural adhesive + laser weld',3.5,'hydraulic','acoustic laminated windshield','semi-aniline','real wood',6,'good','sample',NULL);
INSERT INTO build_quality VALUES(135,36,75.2000000000000028,80.0,76.0,78.0,76.0,65.0,72.0,'Alpha platform with V-series bracing - excellent rigidity for super sedan duties','V8 is audible but well-damped - dual-mode exhaust adds character without harshness','Premium materials throughout - V-specific Recaro seats, suede-wrapped upper trim, real carbon fiber','V-specific paint options are well executed - high-quality clear coat','Same CUE infotainment weaknesses as CTS - the system is a known problem area','Performance seats take more abuse - Recaro leather bolsters show wear with aggressive use','Excellent super sedan build quality - only the CUE system lets down an otherwise premium package','GM Alpha platform (V-Series enhanced)','Lansing Grand River Assembly (Michigan)','spot weld + structural adhesive + laser weld + V-series bracing',3.20000000000000017,'hydraulic performance','acoustic laminated','semi-aniline recaro','real carbon fiber',6,'good','sample',NULL);
INSERT INTO build_quality VALUES(136,69,65.2999999999999971,68.0,65.0,64.0,68.0,62.0,63.0,'Sigma platform - GM first-gen rear-drive architecture, adequate but not class-leading rigidity','Acceptable for early 2000s luxury - LS V8 is audible, road noise at highway speeds','Early 2000s Cadillac materials - some real leather and wood but also plenty of plastic wood grain','GM paint from this era is average - clear coat failure common on dark colors in sunbelt states','Dated electronics - digital displays fade, module failures increase with age','Interior plastics and leather show 15+ years of age - dashboard cracking in sun-exposed cars','Period-adequate build quality that has not aged gracefully - the LS engine far outlasts the cabin','GM Sigma platform','Lansing Grand River Assembly (Michigan)','spot weld',4.5,'hydraulic','tinted','base leather','simulated wood',4,'average','sample',NULL);
INSERT INTO build_quality VALUES(137,127,69.7000000000000028,72.0,70.0,68.0,70.0,70.0,67.0,'LX platform - heavy but solid, old Mercedes-derived underpinnings provide heft but not sophistication','HEMI rumble is always present - decent isolation from road noise, muscle car character','Improved over early LX cars but still behind competitors - hard plastics remain, Scat Pack trim helps','FCA paint quality is inconsistent - some report orange peel, others have no issues','Uconnect is actually one of the better systems - ages better than CUE or SYNC of similar vintage','Interior materials show wear predictably - seat bolsters and steering wheel are wear points','Old platform = old-school build quality - heavy and durable but not refined, character counts for something','LX platform (Mercedes-derived)','Brampton Assembly (Ontario, Canada)','spot weld',4.5,'hydraulic','tinted','available leather','none',4,'average','sample',NULL);
INSERT INTO build_quality VALUES(138,126,69.7999999999999971,73.0,68.0,69.0,71.0,68.0,67.0,'LX platform - same as Challenger but sedan body, heavy construction, proven durability','Supercharger whine penetrates cabin - HEMI rumble dominates, minimal effort at luxury isolation','SRT trim adds decent leather and Alcantara - better than R/T but still not luxury grade','SRT-specific paint options are well done - Hellcat branding is tastefully integrated','Uconnect system holds up - performance pages add cool data displays','Performance driving accelerates interior wear - Alcantara steering wheel shows grease easily','Brute force over refinement - 717hp in a family sedan body is hilarious and the build quality matches','LX platform (Mercedes-derived)','Brampton Assembly (Ontario, Canada)','spot weld',4.5,'hydraulic','tinted','nappa leather/alcantara','none',4,'below_average','sample',NULL);
INSERT INTO build_quality VALUES(139,92,68.7000000000000028,70.0,65.0,62.0,75.0,72.0,68.0,'Shared Mazda Skyactiv-Vehicle architecture (not bespoke). High-strength steel increased significantly over previous generation. MacPherson strut front, multi-link rear. Spot welding throughout with structural adhesive in key areas. Panel gaps ~4.5mm 窶・improved over KE generation but not luxury-tight. Good rigid construction for the CUV class.','Decent NVH for a mass-market CUV but not luxury-quiet. Standard rubber engine mounts (some liquid-filled on upper trims). Some acoustic treatment in firewall and floor pan. Laminated front windshield on Signature trim. Road noise noticeable at highway speeds from 19-inch wheels on Turbo trim. The Skyactiv-G 2.5T is characteristically loud under boost 窶・direct injection tick at idle. Better than previous generation CX-5 but below Lexus NX or Audi Q5.','Good materials for the price point 窶・above average for mainstream CUV. Available Caturra Brown Nappa leather on Signature trim (standard leather on lower trims). Real contrast stitching on dash and door panels. Santos rosewood trim on Signature (genuine wood). Aluminum-look trim on lower trims. Soft-touch upper dash and door panels, hard plastics on lower panels and console. Mazda Connect infotainment functional but aging. Above Camry RAV4 tier, below Lexus.','Good Mazda paint quality with no known epidemics. Electrostatic primer application. Galvanized steel panels throughout. Self-healing clear coat on darker colors. Paint chipping on front bumper from road debris reported. Holds up well at 5-10 years with no premature clear coat failure. Standard mass-market paint quality 窶・better than Korean competitors, not quite Japanese premium.','Modern Mazda electronics are generally reliable. Infotainment system can require reboots. Cylinder deactivation adds electronic complexity. MAF sensor contamination at 60K is more of a maintenance item than a design flaw. No systemic electrical gremlins like German competitors. Good electrical track record at 5-10 years of data. Simpler than luxury-brand electronics.','Mazda interiors age reasonably well. Nappa leather on Signature trim holds up at 100K+ miles. Standard leather shows minor bolster wear at 80K+. Piano black trim scratches easily and shows dust. Dashboard plastics resist UV cracking. Steering wheel shows wear at 100K+. Center console armrest material thins. Better than average for mass-market CUV aging.','CX-5 KF Q-score 68.7. Honest mass-market CUV build quality 窶・Mazda punches above its price class. Body construction (70) is solid for shared platform. NVH (65) is adequate but below premium competitors 窶・the 2.5T DI tick and road noise are noticeable. Interior materials (62) on Signature trim approach entry-luxury with Nappa leather and genuine wood. Paint (75) is good quality with no issues. Electrical aging (72) is above average. Cosmetic aging (68) is average for the class. The CX-5 is the best-driving CUV in its class and the build quality reflects a driver-focused, not luxury-focused, philosophy.','shared','Hofu Plant (Yamaguchi, Japan) / Ujina Plant (Hiroshima, Japan)','spot',4.5,'liquid','laminated','nappa','real_wood',4,'above_average','expert_analysis',NULL);
INSERT INTO build_quality VALUES(140,14,60.2999999999999971,75.0,30.0,45.0,72.0,75.0,50.0,'Purpose-built ND platform 窶・not shared with Mazda3 or CX-5. Exceptional rigidity for a roadster 窶・hood strut brace, undercarriage bracing, reinforced A-pillars. Aluminum hood, trunk lid, and front fenders for weight reduction. Double-wishbone front, multi-link rear. One of the best-handling cars at any price. Well-engineered lightweight structure.','Soft-top roadster with functionally minimal NVH isolation 窶・by design. Wind noise significant above 50mph with top up. No acoustic glass anywhere. Minimal sound deadening 窶・Mazda saved every gram. The Skyactiv-G at 7500rpm and exhaust note are the intended audio experience. With top down, NVH is moot 窶・you bought a roadster. Better than S2000 for isolation but not by much.','Minimalist sports car interior prioritizing weight savings over comfort. Cloth seats standard (leather optional on Grand Touring). Soft-touch surfaces limited to upper dash and door tops 窶・hard plastics dominate lower panels. No wood anywhere 窶・aluminum-look or piano black trim. Small steering wheel. Functional gauges. Mazda Connect infotainment on small screen. Updated for ND2 with slightly better materials than ND1. The driving position is perfect; the materials are not the point.','Good Mazda paint quality. No epidemic issues. Some clear coat thinning on Soul Red Crystal and Machine Gray at 10+ years 窶・these metallic colors are more susceptible. Front bumper paint chips from low nose stance. Soft top frame exposed to elements. Better paint aging than NA/NB Miata generations.','Simple electronics 窶・the Miata advantage. No complex ADAS in ND2 (2019-2024). Basic Mazda Connect infotainment. No touchscreen while driving (rotary knob only). Minimal sensors. Battery parasitic drain reported on some units. No air suspension, no motorized everything. Nearly 1990s simplicity in a modern package. Good electrical aging expected.','Roadster life accelerates cosmetic aging. Soft top requires replacement at 8-12 years ($1-2K aftermarket). Seat bolsters wear quickly from low ingress/egress. Steering wheel leather wears at crown. Interior plastics scratch and scuff easily. Dashboard can crack in hot climates (Arizona, Texas) if not garaged. Paint rock chips from low nose. Hard to keep pristine 窶・most ND2s show their mileage. Better than S2000 aging due to Mazda paint quality.','MX-5 ND2 Q-score 60.3. The lowest build quality score among the non-rotary Mazdas 窶・appropriately so for a purpose-built roadster. Body construction (75) is excellent for a roadster. NVH (30) is among the lowest in the database 窶・a soft-top roadster is not built for silence. Interior materials (45) are functional, not luxurious. Electrical aging (75) scores well due to Miata simplicity. Cosmetic aging (50) reflects the harsh reality of roadster life 窶・everything ages faster when exposed to the elements. The ND2 is evaluated as a sports car on luxury build quality metrics 窶・the low scores reflect design purpose, not quality deficiency.','bespoke','Ujina Plant (Hiroshima, Japan)','spot',5.0,'rubber','standard','none','none',4,'minimal','expert_analysis',NULL);
INSERT INTO build_quality VALUES(141,91,66.5,68.0,62.0,60.0,72.0,72.0,65.0,'Shared Mazda6 GJ platform (related to CX-5 architecture). Not bespoke. High-strength steel in key structural areas. MacPherson strut front, multi-link rear. Spot welding throughout. Panel gaps ~4.5mm 窶・decent for midsize sedan but not luxury-tight. Standard mass-market Japanese sedan construction.','Decent NVH for midsize sedan but a known weakness vs competitors. Not as quiet as Camry or Accord at cruise. The Skyactiv-G 2.5 is characteristically loud 窶・direct injection ticking at idle and under load. Standard rubber engine mounts. Some acoustic treatment in firewall. Laminated front windshield. Road noise present at highway speed. Mazda prioritized driving dynamics over isolation.','Good materials for the midsize segment. Available leather on Touring and Grand Touring trims. Soft-touch upper dash and door panels. Hard plastics on lower panels and console. Real contrast stitching. Aluminum-look trim 窶・not real metal. Piano black on center stack. No real wood anywhere. Above base Camry and Accord for material quality but below luxury. The Touring trim adds enough to feel premium without being premium.','Good Mazda paint quality with no known epidemics. Electrostatic primer. Galvanized steel panels. Some clear coat thinning on Machine Gray and Soul Red at 10+ years in sunbelt states. Paint holds up well overall. Front bumper paint chips from road debris. Standard mass-market paint 窶・better than domestic, on par with Japanese competitors.','Typical Mazda electronics 窶・functional but not bulletproof. Infotainment system can freeze requiring reboot. MAF sensor contamination is more maintenance than design flaw. No complex ADAS until later model years. Simpler electronics than German competitors in this class. Good electrical aging for 2012-2021 vintage. No systemic electrical gremlins reported.','Mazda interiors age acceptably for mass market. Leather on Touring trim shows bolster wear at 80K+ miles. Steering wheel leather wears at crown. Dashboard plastics resist UV cracking. Piano black trim scratches and shows fingerprints. Center console armrest material thins. Door panel scuffs at entry points. Better than average for Japanese midsize sedan aging.','Mazda6 GJ Q-score 66.5. Honest midsize sedan build quality 窶・Mazda prioritizes driving dynamics over isolation. Body construction (68) is standard shared-platform. NVH (62) is the weakness 窶・the Skyactiv DI tick and road noise keep it below Camry/Acord quietness. Interior materials (60) are above average for the class with leather and real stitching on Touring. Paint (72) is good quality. Electrical aging (72) is above average 窶・simple electronics by modern standards. Cosmetic aging (65) is average. The Mazda6 drives better than any midsize sedan but builds to a price, not a luxury standard.','shared','Hofu Plant (Yamaguchi, Japan)','spot',4.5,'rubber','laminated','standard','none',4,'standard','expert_analysis',NULL);
INSERT INTO build_quality VALUES(142,89,57.2000000000000028,82.0,28.0,52.0,60.0,55.0,42.0,'Purpose-built FD platform 窶・not shared with any other Mazda. Aluminum hood, doors, and hatch for weight reduction. Double-wishbone suspension all four corners 窶・race-car specification for a road car. Aerodynamic body with Cd 0.29. Dense engineering with every component purpose-placed. Panel gaps typical of early 1990s Japanese manufacturing (~5mm). Well-engineered for its era 窶・the chassis engineering is the FD''s strongest attribute.','1990s Japanese sports car with minimal NVH isolation 窶・by design. Twin-turbo 13B-REW at 8000rpm is the intended audio experience. No acoustic glass. Minimal sound deadening beyond basic asphalt sheeting. Tire roar from wide staggered rubber. Sequential turbo transition is audible and celebrated. Exhaust note dominates everything. Not designed for quiet cruising 窶・this is a driver''s car.','Period-correct 1990s Japanese sports car interior 窶・functional, not luxurious. Leather available on Touring trim but not premium grade 窶・more durable than soft. Hard plastic dash and center console dominate. No wood anywhere. Basic analog gauges with prominent tachometer. Bose stereo option. The FD interior is well-designed ergonomically but materials are standard 1992 Japanese sports car. Better than S2000 for features but below NSX or Supra TT for quality.','Adequate Mazda paint for the 1990s era. Some clear coat issues on black and red cars at 25+ years 窶・typically hood and roof from UV. Front bumper paint chips from low stance. Rust is the real concern: wheel arches, door sills, behind taillights, undercarriage, suspension components. JDM imports particularly susceptible. Better than contemporary European cars for corrosion but not exceptional by modern standards.','30-year-old electronics showing their age. Pop-up headlight mechanism is the iconic failure point 窶・switches, motors, linkages all wear. Vacuum hose degradation causes sequential turbo system malfunctions. ECU capacitors can leak. Wiring harness connectors become brittle. Dashboard warning lights triggered by vacuum leaks are common. Gauge cluster LCD segments fade. Not terrible for 1992 electronics but definitely showing three decades.','30-year-old sports car 窶・everything shows age. Dashboard UV cracking common in sun-exposed cars. Driver seat bolster foam collapses at 80-100K miles. Steering wheel leather cracks at crown. Plastic trim fades and becomes brittle. Carpet wear at driver footwell. Weather seals degrade causing leaks. Most FDs need significant cosmetic refresh at 20+ years. Pristine examples command huge premiums because most are tired.','RX-7 FD Q-score 57.2. A legendary chassis (82) with period-correct 1992 build quality in every other dimension. NVH (28) is minimal by design 窶・the rotary at full song is the soundtrack. Interior materials (52) are functional for a 1992 sports car. Paint (60) and corrosion resistance are adequate 窶・rust is the body''s enemy. Electrical aging (55) reflects 30 years of vacuum hose and wiring degradation. Cosmetic aging (42) is the lowest 窶・three decades of sports car life is unforgiving. The FD is evaluated fairly: its chassis engineering is world-class, but everything else is a 1992 Japanese sports car showing its age.','bespoke','Hiroshima Plant (Hiroshima, Japan)','spot',5.0,'rubber','standard','standard','none',4,'minimal','expert_analysis',NULL);
INSERT INTO build_quality VALUES(143,109,61.3999999999999985,85.0,30.0,58.0,65.0,60.0,45.0,'Same purpose-built FD platform but Spirit R represents the final, most-refined production version. Series 8 (1998-2002) improvements throughout. Bilstein shock absorbers standard. Cross-drilled brake rotors. BBS 17-inch forged wheels. Larger radiator and improved front bumper vents for better cooling. Tightest panel gaps of any FD generation. Best production quality of the entire 10-year FD run. The definitive FD as Mazda intended it.','Same FD NVH philosophy 窶・minimal by design. The 13B-REW at 8000rpm is the intended audio. However, Series 8 improvements include better weatherstripping, improved seals, and slightly more refined cabin isolation than Series 6/7. The difference is measurable but not transformative 窶・this is still a loud, raw sports car by design. Better than early FDs but not remotely luxury-quiet.','Best FD interior 窶・the Spirit R received premium components. Recaro full-bucket seats standard (not available on other FDs). Bose acoustic waveguide stereo. Cross-drilled brake rotors visible through BBS wheels. Same hard plastic dash as other FDs but Recaro seats elevate the interior significantly. Red accents and Spirit R badging. Better materials than standard FD but still fundamentally a 1990s Japanese sports car interior beneath the Recaros.','2002 production year means youngest FDs on the road. Better Mazda paint technology than 1993 cars. Galvanized steel panels throughout. Spirit R was available in Titanium Grey (exclusive) and Competition Yellow Mica 窶・both well-regarded for durability. Less rust risk than earlier FDs simply due to being 7-9 years newer. Still vulnerable to the same rust spots (wheel arches, sills) but fewer years of exposure.','2002 electronics are the most mature FD version. Revised ECU with improved fuel mapping and engine management. Better wiring harness quality than early production. Still uses pop-up headlights (iconic but a maintenance item). Vacuum hoses still rubber and still degrade. Connectors still age. The fundamental electronics architecture is 1992 but the implementation is the most refined. Better than any other FD for electrical reliability.','Spirit R FDs are typically garaged, babied, and collector-owned 窶・the best-preserved examples of the FD breed. Recaro seats are more durable than standard FD seats 窶・denser foam, better leather. Lower average mileage than other FDs. Spirit R-specific trim parts are essentially unobtainable if damaged. Same aging concerns as all FDs (UV, rubber, plastic) but mitigated by collector care. Better cosmetic condition than average FD simply because owners care more.','RX-7 Spirit R Q-score 61.4. The best FD ever built 窶・final production quality, Bilstein, Recaro, BBS, revised ECU. Body construction (85) is the highest in this Mazda batch. NVH (30) is still minimal by design 窶・the rotary at full song is the point. Interior (58) is elevated by Recaro seats but still a 1990s Japanese sports car underneath. Paint (65) benefits from being the youngest FD. Electrical aging (60) is the best of any FD thanks to mature Series 8 electronics. Cosmetic aging (45) is better than average FD because Spirit Rs are collector-maintained. The 4.2-point Q-score improvement over standard FD (57.2) reflects the Spirit R''s superior production quality and collector care.','bespoke','Hiroshima Plant (Hiroshima, Japan)','spot',4.79999999999999982,'rubber','standard','recaro','none',4,'minimal','expert_analysis',NULL);
INSERT INTO build_quality VALUES(144,90,56.2000000000000028,72.0,38.0,50.0,65.0,50.0,48.0,'Purpose-built RX-8 platform with unique front-midship layout (engine behind front axle). Not shared with other Mazdas. Freestyle four-door design with rear-hinged back doors (no B-pillar) is an engineering achievement. Aluminum hood and front fenders for weight reduction. MacPherson strut front, multi-link rear. Good rigidity despite the unconventional door design. Well-engineered for a 2003 sports car 窶・more modern construction techniques than FD.','Sports car with NA Renesis rotary 窶・quieter than the FD''s 13B-REW twin-turbo but still not quiet. No turbo noise but rotary whine at high RPM dominates. Some sound deadening material added compared to FD 窶・foam in A-pillars, dash insulator pad. Road noise from 19-inch wheels on R3 trim. Wind noise from freestyle door seals at speed. Better than FD for NVH but not sedan-quiet despite having four doors. The rotary engine note is still the dominant cabin sound.','Mixed bag interior. Some soft-touch surfaces on upper panels. Available leather on Grand Touring trim (R3 gets cloth/alcantara sport seats). Rotary-themed analog gauges with center tachometer. Plastics feel cheap 窶・hard and hollow-sounding. Center stack is busy with many small buttons. Rotary-shaped analog clock is a nice touch. R3 sport seats are supportive but not Recaro-quality. Materials are a step below the Spirit R''s Recaro interior. Better than FD for features and ergonomics but the plastics don''t age well.','Standard Mazda paint quality from the 2003-2012 era. No epidemic paint issues. Better paint technology than the FD (10+ years newer). Some clear coat thinning on 2003-2005 models at 15+ years 窶・Machine Gray most affected. Galvanized steel throughout. Front bumper paint chips from low nose. Better corrosion resistance than FD. No rust epidemics reported.','More complex electronics than the FD and more things to fail. Immobilizer system. More ECUs and sensors. Renesis-specific engine management. Coil pack failures are chronic 窶・when coils fail, unburned fuel dumps into the cat, creating a cascade of failures. Starter motors fail from chronic cranking during flood-clearing. Door lock actuators fail. Waterlogged headlights reported. Engine wire harness wears from interference. More electronic complexity than the FD and demonstrably worse reliability.','Sports car life means everything ages faster. R3 Recaro-style sport seats show bolster wear at 60-80K miles. Dashboard plastics can crack in hot climates. Interior plastics scratch and scuff easily at entry/exit points. Steering wheel leather wears at crown. Center console armrest thins. Engine bay heat from the Renesis rotary affects surrounding materials and paint. RX-8s tend to look tired at 100K+ miles 窶・the combination of sports car use and rotary heat is unforgiving on materials.','RX-8 R3 Q-score 56.2. The lowest build quality score in this Mazda batch 窶・the RX-8 is a brilliant chassis let down by its Renesis engine and aging materials. Body construction (72) is good with unique freestyle door engineering. NVH (38) is better than FD but still sports-car-loud. Interior materials (50) are mediocre 窶・the plastics feel cheap and the center stack is busy. Paint (65) benefits from being 10+ years newer than FD. Electrical aging (50) is the lowest 窶・coil pack failures cascade into catastrophic engine damage, starter motors die from flooding, and door locks fail. Cosmetic aging (48) reflects the combination of sports car life and rotary engine bay heat. The RX-8 is a better daily driver than the FD but ages worse electrically and cosmetically.','bespoke','Ujina Plant No. 2 (Hiroshima, Japan)','spot',4.5,'rubber','standard','none','none',4,'standard','expert_analysis',NULL);
INSERT INTO build_quality VALUES(145,15,69.2000000000000028,82.0,68.0,62.0,72.0,60.0,65.0,'Bonded and riveted aluminum chassis. Mid-engine layout. Lightweight at 1,100kg. Body panels aluminum. Rear wheel arch area prone to corrosion where bumper attaches.','Lightweight sports car compromises. No acoustic glass. Engine noise is intentional (sport exhaust). Road noise above average at highway speed. Acceptable for purpose-built sports car.','Sabelt carbon-back seats (optional) or standard sport seats. Basic infotainment (pre-Carplay units poor). Renault-sourced switchgear. Cost-conscious but purposeful. Hard plastic on lower panels.','Aluminum body panels resist corrosion well overall. Known weak spot: rear wheel arches and bumper attachment point. Clear coat holds up in moderate climates. Brake discs corrode quickly when standing.','Sporadic electrical issues reported: warning lights without cause, power windows require engine running, battery drain when standing. Fuel pump electronics suspected root cause of sudden failures.','Materials are basic but durable. Sport seats hold up well. Exterior trim and panel alignment generally good for low-volume production. Paint bubbling at rear arches is the main cosmetic concern over time.','Alpine A110 Q-score 69.2. Purpose-built lightweight sports car with aluminum chassis. Build quality is competent for low-volume but not luxury-tier. Interior is the weakest dimension 窶・cost-conscious with basic materials. Rear arch corrosion is the known cosmetic Achilles heel.','bespoke','Dieppe (Alpine, France)','bonded_aluminum',4.5,'solid','standard','sport_fabric','none',4,'minimal','sample',NULL);
INSERT INTO build_quality VALUES(146,46,75.5999999999999943,90.0,85.0,82.0,78.0,40.0,70.0,'All-aluminum riv-bonded monocoque. Lightweight and rigid. Jaguars most advanced body construction at the time. No corrosion issues with aluminum structure.','Excellent luxury sedan isolation. Hydraulic engine mounts. Acoustic laminated windshield. Active noise cancellation. Whisper-quiet at cruise. Jaguar suspension tuning absorbs road imperfections beautifully.','Premium leather throughout. Real wood veneers (multiple options). Jaguar rotary gear selector. Analog instruments on early models, virtual on later. Soft-touch surfaces everywhere. Bowers and Wilkins audio option excellent.','Good paint quality from Castle Bromwich plant. Self-healing clear coat on premium colors. No major paint epidemics. Aluminum body means no rust-through concerns.','THE weakness of the X351. CAN bus architecture ages poorly. Infotainment system crash-prone and slow. Touchscreen response degrades. Module communication failures cascade. Electrical gremlins are the #1 owner complaint.','Premium materials age well physically. Leather develops patina rather than cracking. Wood veneers hold up. But electronic failures undermine the ownership experience 窶・a beautiful cabin with a dead screen feels broken.','Jaguar XJ X351 Q-score 75.6. Physically the best-built Jaguar. Aluminum body is gorgeous and corrosion-proof. Interior materials are genuinely premium. But Jaguar electronics drag the entire score down 窶・the car that looks like a $100K car until the screen goes blank.','bespoke','Castle Bromwich (Birmingham, UK)','rivet_bonded_aluminum',3.79999999999999982,'hydraulic','acoustic_laminated','premium','real_wood',5,'extensive','sample',NULL);
INSERT INTO build_quality VALUES(147,55,69.2999999999999971,78.0,85.0,80.0,72.0,35.0,62.0,'Aluminum-intensive body on modified T5 platform. Good rigidity for SUV. Panel gaps inconsistent on early builds. Air suspension excellent for ride but adds complexity.','Excellent luxury SUV isolation. Active noise cancellation. Acoustic glass. Whisper-quiet cabin. One of the quietest SUVs at cruise.','Premium Oxford leather. Real wood trim options. Windsor leather on upper trims. Land Rover traditional rotary gear selector. Good soft-touch surfaces.','Decent paint quality but some clear coat issues reported on dark colors. Aluminum body prevents rust-through but paint adhesion can be inconsistent.','Legendary for all the wrong reasons. Screen goes blank. Modules fail and cascade warnings. Terrain Response system adds failure points. Electrical issues are THE defining characteristic of Range Rover ownership.','Physical materials are premium and hold up. Leather ages well. But the constant electronic failures erode confidence and the ownership experience. A luxury SUV with a blank infotainment screen doesn''t feel luxurious.','Range Rover Sport Q-score 69.3. When the electronics work, it''s a beautiful luxury SUV. Excellent NVH, premium interior materials, aluminum body. But the electronic aging score (35) is among the worst in the database and drags everything down.','shared','Solihull (UK)','mixed_aluminum_steel',4.20000000000000017,'hydraulic','acoustic_laminated','premium','real_wood',5,'extensive','sample',NULL);
INSERT INTO build_quality VALUES(148,68,74.2000000000000028,82.0,72.0,70.0,75.0,72.0,70.0,'Pininfarina-designed and assembled in Italy (not standard PSA plant). Steel monocoque. Higher build quality than standard 406 sedan. Good rigidity for era.','Adequate for era. Not luxury-tier isolation but well-insulated for a late-90s coupe. Engine refinement from ES9 V6 helps. Road noise moderate at highway speed.','Momo leather seats (optional). Alcantara headliner option. French design flair. Real aluminum trim (not plastic). Simple, elegant instrumentation. Feels more special than PSA parts bin would suggest.','Good European paint standards for era. Galvanized steel body. No major rust epidemics reported. Paint holds up well 20+ years on well-maintained examples.','Simple late-90s electronics are an advantage. Analog gauges, basic ECU, no touchscreen. Very few electronic failure points. What electronics exist are durable.','Materials age gracefully. Momo leather develops character. Aluminum trim doesn''t peel. Simple interior design means fewer things to break. 20+ year old examples can still look sharp.','Peugeot 406 Coupe Q-score 74.2. Pininfarina build quality elevates it above standard PSA products. Simple electronics are a feature, not a bug 窶・they age better than complex modern systems. A 20+ year old example that''s been cared for can still look and feel special.','shared','Pininfarina (Turin, Italy)','spot_weld',4.5,'solid_rubber','standard','standard','real_wood',4,'moderate','sample',NULL);
INSERT INTO build_quality VALUES(149,71,67.2999999999999971,68.0,72.0,68.0,65.0,68.0,64.0,'Steel/aluminum mixed construction. Panel gaps are Tesla''s well-documented weakness 窶・inconsistent across vehicles and even within the same car. Structural rigidity is good. Gigapress rear improves later builds.','Improved over model years but still behind luxury competition. Glass roof adds NVH. Road noise at highway speeds above average. No engine noise to mask it (it''s an EV). Highland refresh improved significantly.','Minimalist interior. Performance gets sport seats (good). Mostly hard surfaces. Wood/decorative trim is thin. The everything-on-a-screen approach means no physical buttons. Materials feel below price point.','Tesla paint is thin. Orange peel texture common. Paint chips easily from road debris. Multi-coat colors (red, blue) slightly better. Clear coat holds up acceptably but not exceptional.','MCU1 aging on early cars (eMMC wear). MCU2/AMD-based better. Software updates extend useful life but can also introduce new bugs. Over-the-air is both strength and risk.','Interior shows wear at moderate mileage. Alcantara on Performance seats holds up. Piano black trim scratches easily. Paint chips from road debris are the main cosmetic aging issue.','Tesla Model 3 Performance Q-score 64.0. The drivetrain is revolutionary but the build quality tells a different story. Panel gaps, thin paint, minimalist-cheap interior materials. Performance seats are good. Highland refresh improves many of these issues.','bespoke','Fremont / Shanghai Gigafactory','gigapress_adhesive',5.5,'solid_rubber','laminated_glass_roof','sport_leather','none',3,'moderate','sample',NULL);
INSERT INTO build_quality VALUES(150,70,66.9000000000000056,66.0,78.0,70.0,65.0,62.0,64.0,'Older platform (2012 architecture heavily updated). Panel gaps still inconsistent for a $100K+ car. Structural rigidity adequate but not class-leading. Update refreshed front/rear but core architecture dates back.','Better than M3 due to larger cabin and more insulation. Acoustic glass on newer builds. Luxury-tier effort at isolation. Wind noise from frameless doors can be an issue.','Updated interior with yoke steering (polarizing). Materials improved over pre-refresh but still below S-Class/EQS. Open-pore wood decor is nice. Screen-driven everything. Rear screen is a nice touch.','Same Tesla paint issues as M3 but more noticeable at this price point. Thin paint, orange peel, easy chipping. Unacceptable at $130K+ MSRP.','Complex electronics with tri-motor, rear steering, active damping. More failure points. MCU resets while driving reported. Software bugs on Plaid-specific features. Good OTA update cadence but bugs persist.','Similar to M3 窶・materials show wear at moderate mileage. Yoke steering material can peel. Paint chips from road debris. Interior aging below Mercedes/BMW at same price point.','Tesla Model S Plaid Q-score 63.3. For a $130K+ car, build quality should be much better. Panel gaps, thin paint, interior materials below German luxury standard. The technology and performance are incredible, but the physical build doesn''t match the price.','bespoke','Fremont Gigafactory','mixed',5.0,'solid_rubber','laminated_glass_roof','premium','none',3,'above_average','sample',NULL);
INSERT INTO build_quality VALUES(151,72,65.2999999999999971,66.0,68.0,66.0,64.0,66.0,62.0,'Same platform as M3 in SUV form. Panel gaps slightly worse than M3 (hatchback adds variability). Structural rigidity good. Gigapress rear casting on later builds improves consistency.','More road noise than M3 due to hatchback design and larger cargo area. Wind noise from roofline. Adequate for price point but not luxury. Juniper refresh should improve.','Same minimalist approach as M3. Even fewer physical buttons. Base materials feel cheaper than Performance trim. Adequate for $45K crossover but not premium.','Same thin Tesla paint. Chips easily. Orange peel common. White seats stain. Multi-coat colors slightly more durable.','Similar to M3. MCU aging on early units. Software updates help but bugs remain. Heat pump adds complexity versus M3 in cold climates.','Interior shows wear faster than M3 (family car usage). White upholstery stains. Cargo area trim scratches. Paint chips on front fascia from highway driving.','Tesla Model Y Q-score 61.6. Best-selling EV globally but build quality is the weakest of the three Teslas. Hatchback design adds panel gap challenges. Same thin paint and basic interior as M3 but in a more expensive form factor.','shared','Fremont / Shanghai / Berlin / Austin Gigafactory','gigapress_adhesive',5.79999999999999982,'solid_rubber','laminated_glass_roof','standard','none',3,'moderate','sample',NULL);
INSERT INTO build_quality VALUES(152,73,74.0,78.0,82.0,78.0,75.0,60.0,70.0,'BYD e-platform. 5-meter sedan with solid construction. Immaculate panel fit reported by reviewers. Galvanized steel body. Good rigidity.','Impressive NVH for the price point. Whisper-quiet cabin. Extensive sound deadening. "Rattling, shuddering, grinding or wind noise? Not in this rolling fortress" 窶・review quote.','Premium materials throughout. Quilted leather seats. Real wood trim. Head-up display. Spacious cabin. Feels above price point. Some infotainment menu logic is unintuitive.','Good paint quality. Multi-coat process. No reported epidemics. Consistent across BYD Changsha production.','Infotainment feels unfinished in certain aspects. Navigation commands don''t work on HUD. Menu navigation inconsistent. Software updates improving but charging logic still has quirks (70-80kW average vs 120kW claimed).','Materials hold up well in ownership reports. Leather durable. Wood trim resists fading. Interior aging appears graceful at 3-4 year mark. Limited data beyond that.','BYD Han EV Q-score 74.0. Impressive craftsmanship that punches above its price. NVH isolation is excellent. Interior materials feel premium. Main deductions for unfinished-feeling infotainment and limited long-term aging data outside China.','bespoke','BYD Changsha (Hunan, China)','robotic_weld',3.79999999999999982,'solid_rubber','acoustic_laminated','premium','real_wood',5,'above_average','sample',NULL);
INSERT INTO build_quality VALUES(153,75,61.6000000000000014,65.0,78.0,62.0,65.0,48.0,55.0,'Steel body. Thin metal panels 窶・hood visibly flexes with light finger pressure. Looks imposing but substance is lacking. Air suspension provides smooth ride.','Quiet cabin aided by air suspension and large cabin volume. Road and wind noise well-suppressed. Commendable for the class.','Looks premium at first glance but closer inspection reveals synthetic-feeling materials. Quilted seats have synthetic portions. Center console padding thin. Dashboard dominated by screens. "Feels like plastic more than leather" 窶・owner review.','Paint inconsistencies reported between body panels (top vs bottom of door). Quality varies between units. Acceptable but not premium.','Infotainment system widely criticized as "a disaster." Sound quality poor. Menu navigation difficult. Blinker sound and pace irregular. Strange cabin noises reported. Electronics feel first-generation.','Materials that look premium initially may not age as gracefully. Synthetic leather surfaces, thin padding, and electronic gremlins suggest faster cosmetic aging than true luxury competitors.','Hongqi E-HS9 Q-score 61.6. 80% of a Rolls-Royce experience from 50 feet away. Up close: thin metal panels, synthetic-feeling materials, disastrous infotainment. Air suspension provides excellent ride quality. First-gen Chinese luxury 窶・impressive ambition, execution needs work.','shared','FAW (Changchun, China)','robotic_weld',4.5,'solid_rubber','laminated','synthetic_premium','real_wood',4,'above_average','sample',NULL);
INSERT INTO build_quality VALUES(154,115,73.2999999999999971,78.0,74.0,76.0,76.0,62.0,70.0,'E-GMP platform with N-specific structural reinforcements. Good rigidity. VGIS (Virtual Gear Shift) adds drivetrain mounting complexity. Solid body construction typical of Hyundai/Kia.','Performance-tuned so NVH is intentionally compromised. Tire roar from performance rubber. Simulated engine sounds in N mode. Adequate daily comfort in Normal mode but not luxury-quiet.','N-specific sport bucket seats (excellent). Alcantara and leather combination. Physical buttons for key functions (praised). N-specific steering wheel with drive mode buttons. Good materials for the price.','Hyundai paint quality is solid. No reported paint issues specific to Ioniq 5. Good clear coat durability. Consistent quality from Ulsan production.','ICCU failures on standard Ioniq 5 are the concern. N models share the E-GMP electrical architecture. Software-dependent systems. N-specific brake software recall shows growing pains. OTA updates help.','N sport seats hold up well. Alcantara is durable. Performance tires wear faster. Interior plastics can scratch. Good but not exceptional cosmetic aging expected.','Hyundai Ioniq 5 N Q-score 72.0. Solid E-GMP platform construction with N-specific reinforcements. Sport seats and physical buttons are highlights. NVH intentionally compromised for performance character. ICCU electrical architecture is the long-term concern.','shared','Ulsan (South Korea)','robotic_weld',4.0,'solid_rubber','acoustic_laminated','sport_leather_alcantara','none',4,'above_average','sample',NULL);
INSERT INTO build_quality VALUES(155,116,84.7999999999999971,95.0,72.0,88.0,92.0,65.0,85.0,'Carbon fiber and aluminum hybrid chassis. Aerospace-grade construction. Incredibly rigid. Hand-finished body panels. Panel gaps tight and consistent for hand-built car. The gold standard of supercar body construction.','Not applicable to judge as luxury NVH 窶・this is a mid-engine supercar. Intake noise is a feature. Engine behind your head. Road noise present but character-appropriate. Cabin is well-isolated from wind noise.','Hand-stitched Alcantara and leather throughout. Carbon fiber trim. Audi-sourced switchgear (elevated quality). Fully digital cockpit. Every surface premium. The interior justifies the price.','Multi-stage hand-applied paint process. Any color available. Deep, lustrous finish. Clear coat excellent. Paint quality among the best in automotive production.','Complex electronics: MagneRide dampers, front lift system, E-gear transmission, multi-mode drive select. All work well when new but expensive when they fail. Front lift system is the most common electronic complaint.','Premium materials age beautifully. Alcantara develops character. Leather patina is prized. Carbon fiber doesn''t degrade. Hand-built quality means things stay tight. The car will look better in 10 years than most cars do new.','Lamborghini Huracan Q-score 84.8. The highest build quality score in this batch. Hand-assembled at Sant''Agata with aerospace-grade materials. Body, paint, and interior are world-class. Deductions for electronic complexity (MagneRide, lift system) and NVH (supercar, not luxury car).','bespoke','Sant''Agata Bolognese (Italy)','carbon_aluminum_hybrid',3.0,'solid_rubber','laminated','semi_aniline','carbon_fiber',7,'performance_tuned','sample',NULL);
INSERT INTO build_quality VALUES(156,124,72.7000000000000028,80.0,85.0,82.0,72.0,45.0,68.0,'Clean-sheet EV platform. Aero-optimized body. Panel gaps inconsistent for a $80K+ car 窶・some arrive nearly perfect, others need service visits for wind noise and trim alignment.','World-class NVH isolation. One of the quietest cars at any price. Extensive aero work reduces wind noise. Cabin feels insulated from the world. Strongest build quality dimension.','Beautiful materials. Glass Cockpit (34" curved display) is stunning. Nappa leather. Real wood and metal trim options. Spacious cabin (largest frunk of any EV). Materials genuinely premium.','Adequate paint quality. Some quality control misses at delivery 窶・panel gaps, wind noise from doors, trim misalignment. Not terrible but below expectations for the segment.','Software is the weak link. Screen freezes, driver-assist dropouts, CarPlay glitches. Multiple recalls for wiring harness, rear camera, coolant heater. Hardware is brilliant; software feels beta.','Physical materials hold up well. Leather, wood, metal trim age gracefully. But electronic issues (screen reboots, warning chimes) make the car FEEL less premium than it is. Confidence erodes with each glitch.','Lucid Air Q-score 72.7. Brilliant hardware let down by software. NVH isolation and interior materials are world-class. But panel gap inconsistencies and persistent software bugs prevent a higher score. The car that could be a 90 if the software worked.','bespoke','Casa Grande (Arizona, USA)','mixed',4.5,'solid_rubber','acoustic_laminated','nappa','real_wood',5,'extensive','sample',NULL);
INSERT INTO build_quality VALUES(157,76,41.8999999999999985,45.0,50.0,48.0,42.0,25.0,40.0,'Body squeaks and rattles reported by multiple owners. "Like it is going to fall apart" 窶・owner review. Thin panels. Overall structural feel below segment standard.','Poor NVH. Road and wind noise above average. Steering vibrations at normal speeds. Throttle response has >1 second delay. Feels unfinished.','Cheap materials. Back seat lever found broken in door pocket on delivery. Speakers unresponsive then blast noise. Hard plastics throughout. Below even budget EV standards.','Paint color uneven between panels (driver side top vs bottom visibly different). Frunk battery cover broken on delivery. Clear coat quality below average.','Worst production EV software tested. Menus crash, gear selector intermittent, backup camera 240p quality. Settings don''t persist between drives. ESC and brake assist failure messages within first week.','Poor. Materials that start cheap don''t age well. Paint chips. Interior scratches. Speaker failures. Trim pieces break. Everything about this car suggests rapid deterioration.','VinFast VF8 Q-score 41.9. The worst build quality score in this batch and one of the lowest in the database. "The worst production electric vehicle I''ve ever tested" 窶・EVTV review. Rushed to market with prototype-quality hardware and software.','shared','Hai Phong (Vietnam)','robotic_weld',6.0,'solid_rubber','standard','synthetic','none',3,'minimal','sample',NULL);
INSERT INTO build_quality VALUES(158,74,76.5,82.0,82.0,85.0,78.0,55.0,72.0,'State-of-art robotic factory with AI quality control. Tight, consistent panel gaps. Air suspension standard. 5m long, 2m wide. Construction quality impresses Motor Trend and other reviewers.','Extensive NVH work. Road and wind noise kept impressively low. Conversations between front and rear passengers comfortable at highway speed. Air suspension isolates cabin well.','Premium perforated leather. Bolstered sport seats. Physical buttons for key controls (praised by reviewers). Large high-quality center display with slim bezels. Airplane-style HVAC buttons. Feels premium.','Good paint quality consistent with robotic factory. No reported paint epidemics. Michelin Pilot Sport EV tires standard on 20" rims.','Too new for long-term data. 2025 Q1 China quality ranking: dead last in large BEV sedan segment (239 penalty points). High complaint-to-sales ratio. Autobild durability testing showed excellent results. Contradictory signals 窶・jury is out.','Minor edge wear reported on light-colored interiors after 1 year. Later production batches reportedly improved. Good materials suggest graceful aging but only 1-2 years of data.','Xiaomi SU7 Max Q-score 76.5. Best build quality score among Chinese EVs in this batch. State-of-art factory produces genuinely premium results. Interior materials and NVH isolation impress. Main risk: electrical aging 窶・dead last in Q1 2025 quality ranking contradicts the premium physical build.','bespoke','Xiaomi EV Factory (Beijing, China)','robotic_weld_adhesive',3.5,'solid_rubber','acoustic_laminated','premium_perforated','none',5,'extensive','sample',NULL);
INSERT INTO build_quality VALUES(159,57,70.5999999999999943,78.0,68.0,72.0,72.0,62.0,65.0,'R34 body is well-built for the era - multi-grade steel unibody with significant structural rigidity for a 90s car','RB26DETT is always audible - ATTESA pumps whine, turbo spool is present, classic GT-R character','R34 interior is typical 90s Nissan - hard plastics, but GT-R specific seats and MFD elevate it','Nissan paint from this era is decent in Japan - JDM cars in good climates hold up well, clear coat issues in sun','25+ year old electronics - MFD pixel decay is universal, HICAS/ATTESA modules age','Interior plastics scratch easily, steering wheel and shift boot wear at high mileage, seats hold up well','Period-excellent Japanese build quality - the GT-R specific components are well-engineered, age shows in electronics and materials','Nissan PM platform (FR/AWD)','Nissan Tochigi (Japan)','spot weld + laser weld',4.0,'solid hydraulic','tinted','recaro (GT-R optional)','none',5,'average','sample',NULL);
INSERT INTO build_quality VALUES(160,58,65.0999999999999943,72.0,62.0,65.0,68.0,58.0,60.0,'R32 body is lighter and simpler than R34 - adequate rigidity for late 80s, some flex in non-V-spec cars','Minimal sound deadening - RB engine noise is prominent, road noise at highway speeds','Late 80s Japanese interior - hard plastics dominate, GTS-t trim is basic but functional','35 year old paint - most R32s have been resprayed, original paint rarely survives in good condition','Dated electronics - digital dash can fade, wiring harness becomes brittle','Age shows everywhere - interior plastics crack, steering wheels wear, headliners sag','35 year old JDM car - build quality was good for the era but time takes its toll','Nissan BNR32 platform (FR/AWD)','Nissan Tochigi (Japan)','spot weld',4.5,'solid rubber','tinted','none (cloth standard)','none',4,'poor','sample',NULL);
INSERT INTO build_quality VALUES(161,59,70.0999999999999943,76.0,68.0,70.0,72.0,65.0,65.0,'R34 non-GT-R body is well-built - same basic platform without GT-R specific bracing','Better NVH than GT-R thanks to quieter RB25DET NEO - civilized daily driver','R34 interior is a step up from R32/R33 - better materials, more refined dashboard design','Similar to GT-R - Japanese market paint quality is decent, depends on climate history','Digital climate control and dash displays age - less complex than GT-R electronics','Standard Nissan interior wear - plastics and fabrics show 25 years of use','A more civilized Skyline - the R34 non-GT-R is a comfortable GT car with JDM credibility','Nissan ER34 platform (FR)','Nissan Tochigi (Japan)','spot weld + laser weld',4.0,'solid hydraulic','tinted','optional leather','none',5,'average','sample',NULL);
INSERT INTO build_quality VALUES(162,60,63.2999999999999971,68.0,58.0,60.0,65.0,65.0,60.0,'GD Impreza chassis is functional but not refined - rally-bred rigidity at the cost of refinement','Poor NVH isolation - boxer engine rumble, road noise, wind noise all present, especially in WRX trim','Early 2000s Subaru interior - hard plastics, cheap fabrics, buzzy and rattly, WRX seats are supportive though','Subaru paint from this era is thin - stone chips and clear coat issues common, especially on hood','Simple electronics age okay - few modules, but 20+ year old wiring gets brittle','Interior materials wear quickly - dashboard cracks in sun, steering wheel peels, seats hold up best','Rally car build quality - tough where it matters, cheap where it doesn''t','Subaru GC/GD platform','Subaru Gunma (Japan)','spot weld',5.0,'hydraulic','tinted','none (cloth)','none',4,'poor','sample',NULL);
INSERT INTO build_quality VALUES(163,61,69.7999999999999971,72.0,70.0,70.0,70.0,68.0,67.0,'4th gen Legacy is a significant step up from 3rd gen - better rigidity, improved platform','Much improved NVH over GD Impreza - Legacy is the refined Subaru, decent highway cruiser','Better materials than Impreza - Legacy gets softer touch surfaces and better fabrics, optional leather is nice','Subaru paint is still thin but 4th gen is better than 3rd - clear coat holds up in moderate climates','Dual-zone climate and premium audio add complexity but are generally reliable','Interior holds up better than Impreza - Legacy buyers tend to maintain their cars better too','The premium Subaru - build quality is a clear step up from Impreza, competitive with Accord/Camry of the era','Subaru BL/BP platform','Subaru Gunma (Japan)','spot weld + adhesive',4.20000000000000017,'hydraulic','acoustic laminated windshield','available leather','simulated wood',4,'average','sample',NULL);
INSERT INTO build_quality VALUES(164,84,63.7000000000000028,68.0,65.0,62.0,65.0,60.0,60.0,'2nd gen Legacy body is adequate - not as rigid as later generations, some flex on rough roads','Sub-par NVH for a wagon - boxer engine noise and road noise are constant companions','Early 2000s economy-grade materials - hard plastics, cheap cloth, functional but not pleasant','Subaru thin paint - clear coat failure on horizontal surfaces is common in sunbelt markets','Simple electronics but 25 years old - climate control displays fade, wiring insulation gets brittle','Everything shows its age - dashboard cracks, seat fabric wears, headliner sags','A 25-year-old Subaru wagon - charming but not well-built by modern standards','Subaru BH platform','Subaru Gunma (Japan)','spot weld',5.0,'hydraulic','tinted','none (cloth)','simulated wood',4,'poor','sample',NULL);
INSERT INTO build_quality VALUES(165,93,69.9000000000000056,72.0,68.0,68.0,70.0,72.0,68.0,'VA WRX on improved Impreza platform - stiffer than GD/GV, better crash structure','Improved over previous WRX generations but still noisy - boxer rumble + turbo whoosh + road noise','Big improvement over 3rd gen interior - still has hard plastics but design is more cohesive, WRX seats are supportive','Subaru paint quality improved in VA generation - still not class-leading but better than GD era','Starlink infotainment is modern but can be sluggish - software updates help','Interior wears predictably - steering wheel and seat bolsters are first to show age','The VA WRX is the first WRX that doesn''t feel punishing to daily drive - build quality is merely average though','Subaru VA platform (Impreza-based)','Subaru Gunma (Japan)','spot weld + structural adhesive',4.0,'hydraulic','acoustic laminated windshield','premium cloth (WRX)','none',5,'below_average','sample',NULL);
INSERT INTO build_quality VALUES(166,94,70.7999999999999971,75.0,65.0,70.0,70.0,72.0,68.0,'VA STI with additional bracing over WRX - stiffer strut towers, reinforced mounting points','STI-specific exhaust is louder than WRX - less sound deadening for weight savings, raw character','Recaro seats are excellent (optional on some years) - STI-specific trim adds red accents and better materials','Same Subaru paint as WRX - adequate but not premium','Same Starlink system with STI performance pages - functional but not refined','Recaro/STI seats wear well, but the rest of the interior shows age like the WRX','STI build quality is a small step above WRX - seats and bracing matter more than materials','Subaru VA platform (STI enhanced)','Subaru Gunma (Japan)','spot weld + structural adhesive + additional bracing',3.79999999999999982,'hydraulic performance','acoustic laminated windshield','recaro leather/alcantara','none',5,'below_average','sample',NULL);
INSERT INTO build_quality VALUES(167,95,74.0999999999999943,78.0,72.0,72.0,73.0,75.0,72.0,'SGP (Subaru Global Platform) - dramatically improved rigidity over VA, modern crash structure','Best NVH in WRX history - still has boxer character but road noise is significantly reduced','Major interior upgrade over VA - available 11.6" touchscreen, better materials, improved seats','Subaru paint quality continues to improve - VB generation has better clear coats','Modern infotainment is competent but still has reboot issues - OTA updates help','Too new for long-term cosmetic data but initial quality is the best WRX interior yet','The VB WRX is a genuine leap in build quality - SGP platform makes a huge difference','Subaru Global Platform (SGP)','Subaru Gunma (Japan)','spot weld + structural adhesive + laser weld',3.5,'hydraulic','acoustic laminated windshield','available leather','none',5,'average','sample',NULL);
INSERT INTO build_quality VALUES(168,102,62.1000000000000014,70.0,55.0,60.0,65.0,62.0,60.0,'Lancer-based body with Evo-specific reinforcements - aluminum hood and fenders, spot welds added','Terrible NVH - 4G63T is loud, road noise is constant, rally car that happens to have plates','Economy car interior with Recaro seats - hard plastics everywhere, Momo wheel is nice, rest is rental-grade','Mitsubishi paint from this era is average - thin clear coat, stone chips on aluminum panels','Simple electronics - AYC controller and boost solenoid are the main concerns','Interior is already showing its age - plastics scratch and rattle, Recaros are the exception','A rally homologation special with Lancer economy car build quality - the mechanicals far exceed the cabin','Mitsubishi CT9A platform (Lancer-based)','Mitsubishi Okazaki (Japan)','spot weld + additional spot welds',5.0,'solid hydraulic','lightweight','recaro (optional)','none',4,'poor','sample',NULL);
INSERT INTO build_quality VALUES(169,110,67.0999999999999943,75.0,65.0,68.0,68.0,58.0,62.0,'Z32 body was advanced for its era - good rigidity, sleek aerodynamic shape, T-top option adds flex','VG30DETT is audible but not harsh - 300ZX is more GT than sports car in NVH character','Early 90s Nissan interior is better than you''d expect - digital dash was cutting-edge, materials are adequate','35 year old Nissan paint - most Z32s need respray, original clear coat rarely survives','Digital dash failures are common - capacitors leak, displays fade, wiring harnesses get brittle','Interior plastics age poorly - T-top seals leak, dashboard cracks, seats wear at bolsters','A technological tour de force in 1990 that has not aged gracefully - complexity is both its strength and weakness','Nissan Z32 platform (FM layout)','Nissan Hiratsuka (Japan)','spot weld',4.5,'solid hydraulic','t-top glass','available leather','none',4,'below_average','sample',NULL);
INSERT INTO build_quality VALUES(170,111,66.0999999999999943,70.0,62.0,65.0,68.0,65.0,63.0,'S15 body is light and simple - adequate rigidity for a compact RWD sports car, not overbuilt','SR20DET turbo noise and exhaust are part of the experience - minimal deadening, sports car character','Best Silvia interior - S15 is a step up from S13/S14 with better materials and design, still budget-grade','Standard Nissan paint of the era - adequate in Japanese climate, depends on import history','Simple electronics - few modules, SR20 ECU is robust, 25 year old wiring gets brittle','Interior plastics scratch, seats wear at bolsters - Spec-R seats are nicer but still show age','The best-built Silvia generation - S15 is the most refined of the S-chassis family, which isn''t saying much','Nissan S15 platform (FR)','Nissan Oppama (Japan)','spot weld',4.5,'solid hydraulic','tinted','none (cloth)','none',4,'poor','sample',NULL);
INSERT INTO build_quality VALUES(171,121,77.7999999999999971,85.0,72.0,78.0,80.0,70.0,75.0,'Premium Midship platform - carbon fiber composite driveshaft tunnel, aluminum hood/fenders, excellent rigidity','GT-R is surprisingly refined when cruising - V6 is smooth, road noise is well-damped for the performance level','Early R35 interior was good for 2009 - Premium trim gets leather, later models improve significantly','Nissan paint quality on GT-R is a step above standard - special colors like Vibrant Red are deep and rich','Complex performance electronics - multi-function display, ATTESA controllers, but generally well-engineered','Interior materials age well in Premium trim - NISMO edition gets Alcantara and carbon fiber','Supercar build quality in a Nissan body - the Premium Midship platform is genuinely impressive engineering','Nissan PM platform (Premium Midship)','Nissan Tochigi (Japan - Takumi craftsmen)','spot weld + structural adhesive + laser weld + carbon fiber bonding',3.0,'solid hydraulic','acoustic laminated','premium leather','carbon fiber trim',7,'good','sample',NULL);
INSERT INTO build_quality VALUES(172,131,70.5,72.0,65.0,70.0,70.0,73.0,70.0,'Toyota/Subaru jointly developed platform - good rigidity for a lightweight RWD coupe, low center of gravity','Sports car NVH - tire noise and engine note are prominent, acceptable for the class, wind noise at speed','Better than expected for the price - Toyota influence on interior quality is evident, simple but well-assembled','Standard Subaru paint - adequate but thin, stone chips on front bumper and hood are common','Simple modern electronics - Pioneer head unit (2017) is dated but functional, few electronic issues','Interior materials hold up well for a $25k sports car - steering wheel and seats age gracefully','Joint Toyota-Subaru development shows - better build quality than pure Subaru products of the same era','Toyota/Toyota 86 platform (joint development)','Subaru Gunma Yajima (Japan)','spot weld + structural adhesive',4.0,'hydraulic','tinted','available leather/alcantara','none',5,'below_average','sample',NULL);
INSERT INTO build_quality VALUES(173,164,81.5,88.0,85.0,87.0,83.0,64.0,77.0,'Carbon Core CFRP technology - carbon fiber B-pillar and roof rail core with aluminum hood, doors, fenders. Mixed high-strength steel, aluminum, carbon fiber. 40 kg lighter than predecessor F01. Excellent torsional rigidity. Best panel gaps in BMW lineup at 3.5-4mm.','Flagship NVH isolation. Hydraulic engine mounts standard. Acoustic laminated windshield. Pre-LCI: side glass NOT acoustically laminated - wind noise at highway speeds noted by C&D long-term test. Air suspension standard. B58 I6 is silky smooth. LCI added thicker laminated glass.','Nappa leather standard. Merino individual leather optional. Real wood trim abundant. Excellent fit and finish. Soft-close doors. Ambient lighting. B&W audio optional. Same materials as 750i - no downgrade. Deductions: door check positions cost-cut vs F01, some hard plastics lower in cabin.','Same BMW premium paint as 750i. Extra clear coat depth on Individual colors. Consistent application. No systemic corrosion issues. 12-year corrosion warranty. Well-protected structural steel.','Same electronics complexity as 750i minus some N63-specific engine management. iDrive ID5 (pre-LCI) ages reasonably well. Display key is finicky and a known weak point. DSC module software faults (fixable). Gesture control adds complexity. Ambient lighting connectors can loosen.','Nappa/Merino leather ages well with proper care. Real wood durable. Aluminum trim shows wear. Piano black surfaces scratch easily. Dashboard surfaces durable. Premium materials overall age gracefully.','740i Q-score 81.5. Same excellent Carbon Core body and premium interior as 750i. Pre-LCI loses NVH points for non-laminated side glass (fixed in LCI). Build quality is flagship-level BMW. Electrical aging is the main concern - comparable to 750i minus some N63 engine management complexity.','CLAR (Carbon Core)','Dingolfing (Germany)','CFRP adhesive + self-piercing rivet + laser weld',3.70000000000000017,NULL,NULL,'Nappa leather standard',NULL,6,NULL,NULL,NULL);
