INSERT INTO build_quality VALUES(189,180,82.7000000000000028,89.0,89.0,86.0,84.0,66.0,82.0,'','','','','','',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'librarian+analysis',NULL);
INSERT INTO build_quality VALUES(190,181,81.0999999999999943,84.0,85.0,90.0,84.0,68.0,72.0,'W222 facelift aluminum hybrid bodyshell. Same 50% aluminum construction as pre-facelift. Improved panel fit from facelift production updates.','Better NVH than pre-facelift. Additional sound deadening in facelift. Improved AIRMATIC calibration. Near-silent cabin.','Facelift interior upgrades: three-spoke Nappa leather wheel, new seat controls, Energizing Comfort Control, upgraded trim options. Best S-Class interior until W223.','Mercedes paint quality excellent. Same multi-stage process. Aluminum panels resist corrosion.','NTG6 COMAND with CarPlay/Android Auto is a genuine usability improvement that extends functional life. But still ~100 ECUs. Driver assistance modules age.','Interior materials hold up well. New wheel design more durable. Steering wheel wear at 100K+ common.','W222 facelift Q-score 81.1. Improved over pre-facelift (78.3) due to better interior, better COMAND, better NVH calibration. The facelift was 6000+ components 窶・the improvements are real, not cosmetic.',NULL,NULL,NULL,NULL,NULL,NULL,'Nappa leather',NULL,7,NULL,NULL,NULL);
