INSERT INTO build_quality VALUES(209,201,69.9000000000000056,72.0,68.0,68.0,66.0,76.0,68.0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'librarian+analysis',NULL);
INSERT INTO failure_points VALUES(1,39,'timing_belt_service','engine',5,90000,800.0,1200.0,1,800.0,'Replace timing belt at 90K mi intervals. Non-negotiable 窶・interference engine.','3UZ-FE uses timing belt (not chain). Must replace every 90K mi. Interference engine 窶・belt failure = bent valves. $800-1200 at shop, $300 DIY.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(2,39,'air_suspension_ul','suspension',4,100000,6000.0,8000.0,1,1500.0,'Coil spring conversion (RS-R T284D). Only affects Ultra Luxury trim.','Ultra Luxury Package has full 4-corner air suspension. Air bags crack at 100K+. OEM replacement $6-8K. Coil conversion $1,500 all-in. Custom Luxury trim has coil springs 窶・no issue.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(3,39,'valve_cover_gasket','engine',2,120000,400.0,600.0,0,NULL,NULL,'Minor oil seepage from valve cover gaskets. Common at 120K+. $400-600 shop. Not catastrophic.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(4,63,'ecu_capacitor_leak','electronics',4,180000,200.0,400.0,1,200.0,'ECU capacitor recap kit. Install proactively if car sat unused.','ECU capacitors leak after 15-20 years, especially in cars that sat unused. Symptoms: rough idle, stalling, erratic behavior. Fix: $200-400 recap kit. Keeping prices down on otherwise bulletproof car.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(5,63,'timing_belt_service','engine',5,90000,800.0,1200.0,1,800.0,'Replace timing belt at 90K mi intervals. Same as LS430.','1UZ-FE timing belt service. Interference engine. $800-1200.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(6,178,'rust_structural','body',5,200000,1000.0,5000.0,0,NULL,NULL,'The W126 killer. Rockers, wheel arches, jack points, trunk floor. Post-1986 galvanizing helps. Pre-facelift cars worse. Must inspect before purchase 窶・structural rust is existential.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(7,178,'timing_chain_single_row','engine',5,100000,800.0,1500.0,1,800.0,'Preventive timing chain replacement at 100K mi.','M117 uses single-row timing chain known to stretch and skip at 100K+. Preventive replacement prevents engine destruction. $800-1500.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(8,178,'hydropneumatic_spheres','suspension',3,100000,200.0,400.0,0,NULL,NULL,'Rear self-leveling nitrogen spheres lose pressure at 80-120K mi. Car sits low, harsh ride. $200-400 each + labor. Not catastrophic but degrades ride quality.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(9,43,'ea839_piston_ringland','engine',4,80000,3000.0,8000.0,0,NULL,NULL,'EA839 3.0T V6 piston ringland fracture risk. 034Motorsport documented stress risers at oil drain holes. 3 piston revisions exist. A8 340hp tune is milder than S4/SQ5 窶・reduces stress. Failure rate <5% but real.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(10,43,'air_suspension_struts','suspension',4,90000,800.0,2000.0,0,NULL,NULL,'Adaptive air suspension struts crack at 80-100K mi. $800-2000 per corner. Compressor $700-1200. Standard air suspension (not predictive active) shares compressor/valve block with Q7/Cayenne.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(11,43,'bsg_48v_failure','electronics',3,80000,1500.0,3000.0,0,NULL,NULL,'48V Belt Starter Generator failure. TSB 27-23-55, campaign 27BQ. Shared with A6/A7/Q7/Q8. Rebuild market exists ($200-800 vs Audi $1500-2500). Audi extended warranty to ~10 years.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(12,43,'timing_chain_tensioner','engine',3,100000,4000.0,8000.0,0,NULL,NULL,'EA839 rear-mounted timing chain tensioner. Cam roller issue resolved pre-2018. Piston risk remains. Engine pull required for full service. $4-8K.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(13,22,'ea839_cam_roller','engine',4,60000,3000.0,6000.0,1,0.0,'Buy 2019+ production 窶・cam roller resolved pre-06/08/2018.','Early EA839 (pre-June 2018) has undersized needle bearings in roller rockers. Can fail, releasing needles into engine. Resolved part 0P2109417 from Aug 2018. 2017 model at risk.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(14,22,'air_suspension_struts','suspension',4,90000,800.0,2000.0,0,NULL,NULL,'Same as D5 facelift. Air struts at 80-100K mi.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(15,22,'bsg_48v_failure','electronics',3,80000,1500.0,3000.0,0,NULL,NULL,'Same BSG issue as facelift. TSB 27-23-55 applies.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(16,170,'ls3_water_pump','engine',3,80000,300.0,600.0,1,300.0,'Replace water pump preventively at 80K mi.','LS3 water pump failure 60-100K mi. Most commonly reported LS3 issue. $300-600. Not catastrophic if caught 窶・just overheating. Replace preventively.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(17,170,'eps_connector_recall','electronics',4,60000,0.0,0.0,1,0.0,'Verify NHTSA recall 17V-382 completed. Free dealer fix.','Electric Power Steering connector fretting corrosion causes loss of power steering while driving. NHTSA 17V-382. 2014-2016 affected. 2017 NOT included despite reports. Free dealer fix 窶・gold-plated terminals.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(18,170,'mylink_touchscreen','electronics',2,80000,200.0,400.0,0,NULL,NULL,'Chevy MyLink 8-inch touchscreen digitizer degradation. Ghost touch, dead zones, delamination. DIY digitizer replacement $200-400. Underlying infotainment module is fine.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(19,7,'wiring_harness_degradation','electronics',4,150000,1500.0,3000.0,0,NULL,NULL,'Biodegradable wiring harness insulation (1990-1995 Mercedes era). Crumbles with age. Engine harness $1500-3000. Check insulation flexibility before purchase.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(20,7,'timing_chain_v8','engine',4,100000,2000.0,4000.0,0,NULL,NULL,'M119 5.0L V8 timing chain guide rails. Plastic guides degrade. Preemptive replacement at 100K mi. $2-4K. Not as urgent as M62 but still important.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(21,164,'b58_ofhg','engine',3,80000,500.0,700.0,1,80.0,'Replace OFHG gasket at first sign of weep. DIY $80.','B58 Oil Filter Housing Gasket leak at 60-90K. CRITICAL: leaking oil on serpentine belt can cause belt to slip into crank seal, destroying engine. Do not ignore. $500-700 shop.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(22,164,'b58_water_pump','engine',3,80000,600.0,800.0,1,600.0,'Replace electric water pump preventively at 80-100K mi.','B58 electric water pump fails without warning at 70-100K. No serpentine belt drive. Sudden overheating triggers limp mode. $600-800. Replace with thermostat (labor overlaps).','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(23,164,'b58_pcv_valve','engine',2,90000,400.0,600.0,0,NULL,NULL,'B58 PCV valve diaphragm failure. Rough idle, unmetered air. SIB extended warranty on some. Age-related, not design flaw.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(24,176,'m62_timing_chain_guides','engine',5,100000,3000.0,6000.0,1,3000.0,'Preemptive timing chain guide replacement at 80-100K mi. Verify service history before purchase.','THE E38 killer. M62 plastic timing chain guides degrade and fail. Chain jumps = engine destruction. $3-6K. Pre-buy inspection mandatory. Must verify done or budget immediately.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(25,176,'m62_valve_stem_seals','engine',3,120000,2000.0,3500.0,0,NULL,NULL,'Blue smoke on cold start, oil consumption. Valve stem seals harden with age. $2-3.5K. Not catastrophic but annoying and progressive.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(26,176,'cooling_system_plastic','engine',3,80000,800.0,1500.0,1,800.0,'Preventive cooling system refresh: radiator, expansion tank, water pump, thermostat at 80K.','M62 cooling system is all plastic 窶・radiator, expansion tank, water pump, thermostat housing. All fail at 60-100K. Preventive refresh $800-1500. Ignore = overheating = head gasket.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(27,37,'n52_valve_cover_gasket','engine',3,90000,400.0,600.0,0,NULL,NULL,'Most common N52 issue. Oil weep from VCG at 60-120K. Post-2007 plastic covers crack. $400-600 shop, $150 DIY.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(28,37,'n52_electric_water_pump','engine',4,80000,600.0,800.0,1,600.0,'Replace preventively at 80-100K mi WITH thermostat.','Fails WITHOUT WARNING at 60-100K. No serpentine belt. Sudden overheating, limp mode. $600-800. Replace thermostat at same time (labor overlaps). Most important preventive item on N52.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(29,37,'n52_ofhg','engine',3,90000,500.0,700.0,1,80.0,'Replace OFHG at first sign of leak. DIY $80.','Oil Filter Housing Gasket leaks at 60-120K. CRITICAL: oil on serpentine belt = belt into crank seal = engine death. $500-700 shop, $80 DIY.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(30,37,'n52_hydraulic_lifter_tick','engine',2,90000,2000.0,3000.0,0,NULL,NULL,'Pre-November 2008 N52 engines prone to cold-start ticking. Post-Nov 2008 resolved with improved lifters. Requires camshaft removal for full fix. $2-3K.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(31,42,'m278_cam_sensor_ecu','electronics',5,90000,100.0,5000.0,1,100.0,'Install sacrificial cam sensor pigtails ($100). FIRST THING on any M278.','THE #1 S550 KILLER. Oil wicks from cam sensors through wiring harness into ECU. Random misfires, O2 codes, transmission issues. $100 pigtail fix prevents $5K+ ECU death. CHECK ALL 4 CONNECTORS at PPI.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(32,42,'m278_oil_cooler_leak','engine',4,90000,1500.0,3000.0,0,NULL,NULL,'Oil filter housing/oil cooler leaks cause oil+coolant mix at 80K+. $1500-3000 indie. Pressure test at PPI. Part of every pre-purchase checklist.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(33,42,'w222_airmatic_struts','suspension',4,90000,500.0,2500.0,0,NULL,NULL,'AIRMATIC struts crack at 80K+. Arnott rebuilt $500/corner. Dealer $1400/corner. Compressor burns out from overwork. $1200-2500 per corner. Can coil-convert (destroys ride quality).','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(34,42,'w222_aluminum_body_repair','body',5,0,0.0,0.0,0,NULL,NULL,'W222 is 50% aluminum hybrid bodyshell. MUST be repaired by Mercedes Elite Certified Collision Center 窶・only ~10 in USA. Improper repair = galvanic corrosion, lost torsional rigidity. Accident history = walk away.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(35,181,'m176_p06da00_oil_pump','engine',5,90000,5500.0,9500.0,0,NULL,NULL,'M176 defining failure. Oil pump solenoid inside oil pan. On 4MATIC, oil pan bolted to bell housing = engine+trans removal. $5500-9500. No prevention. The M176 version of the M278 cam sensor problem 窶・but 55x more expensive to fix.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(36,181,'m176_cyl_deactivation_lifters','engine',3,100000,5000.0,7500.0,0,NULL,NULL,'Cylinder deactivation lifters (cylinders 2,3,5,8) fail causing rough idle and ticking. Up to $7500. Same VCM-style problem as Honda but more expensive.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(37,181,'m176_valve_cover_gasket','engine',3,80000,1500.0,3000.0,0,NULL,NULL,'Front end of car must be removed for valve cover gasket service. Hot-V turbo layout makes access terrible. $1500-3000.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(38,195,'pentastar_oil_cooler','engine',4,80000,1000.0,1500.0,1,300.0,'Replace plastic oil cooler with aluminum aftermarket preemptively.','Plastic oil cooler/filter housing cracks at 60-100K. Near-universal. $1000-1500 OEM. Aluminum aftermarket ~$300 fixes permanently. Near-universal on Pentastar V6.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(39,195,'zf_9speed_valve_body','transmission',4,80000,2000.0,3000.0,0,NULL,NULL,'ZF 948TE 9-speed: rough shifts, hesitation, valve body failure. Problematic in every vehicle installed. Software reflashes partial fix. Valve body $2-3K. Full rebuild $4K+.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(40,196,'phev_battery_replacement','electronics',5,100000,7000.0,17000.0,0,NULL,NULL,'PHEV HV battery replacement $7,000-17,000. Only 8yr/100k warranty (NOT 10yr like Toyota). Battery bricked failures reported at under 9K miles. One out-of-warranty failure = total loss scenario for most owners.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(41,194,'vcm_mount_oil_consumption','engine',4,100000,400.0,1500.0,1,130.0,'Install VCMuzzler II / S-VCM controller ($130). Disables VCM, prevents mount wear and oil consumption.','VCM (Variable Cylinder Management) causes active engine mount failure every 50K mi ($800-1200/set), oil consumption from piston ring wear, spark plug fouling. VCMuzzler II $130 disables VCM. 2013 class action covered 1.6M vehicles.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(42,194,'honda_9speed_zf','transmission',3,60000,800.0,1500.0,0,NULL,NULL,'2018-2019 EX-L and below got ZF 9HP 9-speed. Hesitation, rough shifts, lurching. 2020+ all trims got Honda 10-speed (much better). Push-button park recall.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(43,200,'tundra_air_pump','electronics',4,80000,200.0,3500.0,1,200.0,'Install HewittTech AIR pump bypass kit ($200-400 DIY). Prevents $2500-3500 dealer bill.','Air Injection Pump (AIR) failure 窶・P0410, loud vacuum noise on cold start. Affects 2007-2021. Dealer $2500-3500. HewittTech bypass kit $200-400 DIY. Install preemptively.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(44,200,'tundra_water_pump','engine',2,80000,400.0,800.0,0,NULL,NULL,'3UR-FE water pump at 60-100K mi. $400-800. Cheap and easy. Not catastrophic 窶・just coolant leak.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(45,198,'lower_ball_joints','chassis',5,100000,1400.0,1400.0,1,1400.0,'Preemptive lower ball joint replacement at 100K mi. Failure is catastrophic.','Lower ball joint failure = wheel collapses. Catastrophic. Preemptive replacement at 100K mi. $1400 OEM for all 4. Non-negotiable on 100K+ mi 4Runner.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(46,198,'rear_axle_seal','chassis',3,100000,300.0,600.0,0,NULL,NULL,'Rear axle seal leaks contaminate rear brakes. $300-600. Common at 100K+ mi. Inspect during tire rotations.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(47,199,'melting_dashboard','interior',2,120000,1500.0,2500.0,0,NULL,NULL,'Sticky/melting dashboard and door panels 2010-2015. Infamous. Some Lexus warranty programs on other models but RX350 dash generally NOT covered. $1500-2500 replacement.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(48,199,'vvt_oil_control_valve','engine',3,120000,40.0,120.0,0,NULL,NULL,'VVT oil control valve failure (P0014/P0012 codes). $40-120 part + labor. 2GR-FE shared issue across all Toyota V6 cars.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(49,188,'ej255_banjo_bolt_filter','engine',4,80000,1200.0,2000.0,1,0.0,'Remove banjo bolt filters in AVCS oil lines (2005-2006). Free DIY.','Banjo bolt filters in AVCS oil lines clog and starve turbo of oil = turbo failure. Pre-emptive removal is standard practice. 2005-2006 specific. Free DIY.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(50,188,'ej255_head_gasket','engine',3,120000,1500.0,2000.0,0,NULL,NULL,'EJ255 turbo HG less severe than NA EJ251 (stiffer heads, MLS gasket). External leak, not internal. $1500-2000. Monitor coolant level.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(51,189,'rust_body','body',5,200000,0.0,0.0,0,NULL,NULL,'Subaru thin paint + 30-year-old car. Rust is existential 窶・rockers, wheel arches, floor pans. Engine (EJ22) will outlast the body. Find rust-free example or accept it as a parts car eventually.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(52,185,'k20c4_oil_control_rings','engine',3,80000,400.0,800.0,0,NULL,NULL,'K20C4 oil control ring sticking at 80K+ mi. Oil consumption slowly increases. Well-documented. Monitor oil level, change every 5K mi. Not catastrophic, just progressive.','2026-06-16 03:45:17');
INSERT INTO failure_points VALUES(53,197,'lambda_coolant_loss','engine',3,60000,200.0,500.0,0,NULL,NULL,'Coolant loss emerging pattern on Lambda II 3.5L Smartstream. Top up once/twice yearly. Root cause TBD. Not catastrophic but monitor. Too new for definitive 200K+ mi data.','2026-06-16 03:45:17');
