PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE cars (
	id INTEGER NOT NULL, 
	make VARCHAR(100) NOT NULL, 
	model VARCHAR(100) NOT NULL, 
	generation VARCHAR(50) NOT NULL, 
	year_start INTEGER NOT NULL, 
	year_end INTEGER, 
	era_tag VARCHAR(50), 
	body_style VARCHAR(50), 
	country VARCHAR(50), 
	production_units INTEGER, 
	description TEXT, 
	image_paths JSON, 
	created_at DATETIME NOT NULL, character VARCHAR(50), family VARCHAR(100), variant VARCHAR(100), 
	PRIMARY KEY (id)
);
CREATE TABLE comparison_sessions (
	id INTEGER NOT NULL, 
	name VARCHAR(200), 
	car_ids JSON, 
	created_at DATETIME NOT NULL, 
	last_viewed DATETIME, 
	PRIMARY KEY (id)
);
CREATE TABLE performance (
	id INTEGER NOT NULL, 
	car_id INTEGER NOT NULL, 
	source VARCHAR(200), 
	accel_0_60 FLOAT, 
	accel_0_100 FLOAT, 
	quarter_mile_time FLOAT, 
	quarter_mile_speed FLOAT, 
	top_speed_mph FLOAT, 
	power_to_weight FLOAT, 
	lateral_g FLOAT, 
	braking_60_0_ft FLOAT, 
	lap_times JSON, 
	extra JSON, 
	PRIMARY KEY (id), 
	FOREIGN KEY(car_id) REFERENCES cars (id)
);
CREATE TABLE powertrain_ev (
	id INTEGER NOT NULL, 
	car_id INTEGER NOT NULL, 
	source VARCHAR(200), 
	battery_capacity_kwh FLOAT, 
	chemistry_type VARCHAR(50), 
	charge_arch_volts FLOAT, 
	motor_layout VARCHAR(50), 
	motor_count INTEGER, 
	horsepower_bhp FLOAT, 
	torque_nm FLOAT, 
	range_mi_epa FLOAT, 
	charge_rate_peak_kw FLOAT, 
	battery_degradation_curve JSON, 
	motor_longevity_notes TEXT, 
	ground_clearance_mm INTEGER, 
	cargo_volume_liters FLOAT, 
	extra JSON, 
	PRIMARY KEY (id), 
	FOREIGN KEY(car_id) REFERENCES cars (id)
);
CREATE TABLE hybrid_systems (
	id INTEGER NOT NULL, 
	car_id INTEGER NOT NULL, 
	hybrid_type VARCHAR(50), 
	system_name VARCHAR(100), 
	system_generation VARCHAR(50), 
	power_split_ratio JSON, 
	battery_capacity_kwh FLOAT, 
	battery_chemistry VARCHAR(50), 
	battery_voltage_nominal FLOAT, 
	battery_cooling_type VARCHAR(50), 
	battery_module_count INTEGER, 
	battery_supplier VARCHAR(100), 
	battery_warranty_years INTEGER, 
	battery_warranty_miles INTEGER, 
	motor_count INTEGER, 
	motor_type VARCHAR(50), 
	motor_power_kw_total FLOAT, 
	motor_torque_nm_total FLOAT, 
	motor_position VARCHAR(50), 
	combined_system_power_bhp FLOAT, 
	combined_system_torque_nm FLOAT, 
	ev_only_power_bhp FLOAT, 
	ev_only_range_mi FLOAT, 
	ev_only_top_speed_mph FLOAT, 
	fuel_econ_combined_mpg FLOAT, 
	electric_consumption_wh_pm FLOAT, 
	regen_braking_power_kw FLOAT, 
	can_lock_ev_mode BOOLEAN NOT NULL, 
	has_charge_sustain_mode BOOLEAN NOT NULL, 
	charge_rate_max_kw FLOAT, 
	engine_engagement_strategy VARCHAR(200), 
	cold_weather_behavior TEXT, 
	cvt_behavior_notes TEXT, 
	typical_degradation_5yr_pct FLOAT, 
	degradation_knee_miles FLOAT, 
	common_failure_modes JSON, 
	system_idiosyncrasies JSON, 
	extra JSON, 
	PRIMARY KEY (id), 
	FOREIGN KEY(car_id) REFERENCES cars (id)
);
CREATE TABLE reliability (
	id INTEGER NOT NULL, 
	car_id INTEGER NOT NULL, 
	source VARCHAR(200), 
	reliability_score FLOAT, 
	common_failures JSON, 
	avg_repair_cost FLOAT, 
	recall_count INTEGER, 
	part_availability VARCHAR(100), 
	diy_friendliness VARCHAR(50), 
	known_issues JSON, 
	extra JSON, score_engine FLOAT, score_transmission FLOAT, score_chassis FLOAT, score_electronics FLOAT, score_ease_of_repair FLOAT, score_notes JSON, 
	PRIMARY KEY (id), 
	FOREIGN KEY(car_id) REFERENCES cars (id)
);
CREATE TABLE consumables_and_specs (
	id INTEGER NOT NULL, 
	car_id INTEGER NOT NULL, 
	source VARCHAR(200), 
	tire_sizes JSON, 
	bulb_types JSON, 
	fluid_capacities JSON, 
	obd_protocol VARCHAR(50), 
	lug_nut_torque_nm FLOAT, 
	known_spec_conflicts JSON, 
	technical_diagram_notes TEXT, 
	extra JSON, 
	PRIMARY KEY (id), 
	FOREIGN KEY(car_id) REFERENCES cars (id)
);
CREATE TABLE cost_to_own (
	id INTEGER NOT NULL, 
	car_id INTEGER NOT NULL, 
	source VARCHAR(200), 
	msrp_original FLOAT, 
	msrp_currency VARCHAR(10), 
	msrp_inflation_adj FLOAT, 
	fuel_econ_city_mpg FLOAT, 
	fuel_econ_hwy_mpg FLOAT, 
	annual_maintenance_est FLOAT, 
	insurance_group VARCHAR(50), 
	depreciation_5yr_pct FLOAT, 
	extra JSON, 
	PRIMARY KEY (id), 
	FOREIGN KEY(car_id) REFERENCES cars (id)
);
CREATE TABLE market_history (
	id INTEGER NOT NULL, 
	car_id INTEGER NOT NULL, 
	date_recorded DATETIME, 
	price_low FLOAT, 
	price_high FLOAT, 
	volume_sold_est INTEGER, 
	market_trend_indicator VARCHAR(50), 
	source_site VARCHAR(200), currency VARCHAR(10), price_eur FLOAT, 
	PRIMARY KEY (id), 
	FOREIGN KEY(car_id) REFERENCES cars (id)
);
CREATE TABLE repair_costs (
	id INTEGER NOT NULL, 
	car_id INTEGER NOT NULL, 
	date DATETIME, 
	mileage_at_repair INTEGER, 
	repair_category VARCHAR(100), 
	repair_name VARCHAR(200), 
	description TEXT, 
	parts_cost FLOAT, 
	labor_cost FLOAT, 
	total_cost FLOAT, 
	currency VARCHAR(10), 
	shop_type VARCHAR(50), 
	source VARCHAR(200), 
	is_warranty_covered BOOLEAN NOT NULL, 
	is_recall BOOLEAN NOT NULL, 
	notes TEXT, 
	extra JSON, 
	PRIMARY KEY (id), 
	FOREIGN KEY(car_id) REFERENCES cars (id)
);
CREATE TABLE repair_catalog (
	id INTEGER NOT NULL, 
	car_id INTEGER NOT NULL, 
	repair_name VARCHAR(200), 
	repair_category VARCHAR(100), 
	avg_cost_low FLOAT, 
	avg_cost_high FLOAT, 
	currency VARCHAR(10), 
	frequency VARCHAR(50), 
	typical_mileage_range VARCHAR(50), 
	source VARCHAR(200), 
	source_url VARCHAR(500), 
	severity VARCHAR(50), 
	diy_difficulty VARCHAR(50), 
	tools_required JSON, 
	notes TEXT, 
	extra JSON, 
	PRIMARY KEY (id), 
	FOREIGN KEY(car_id) REFERENCES cars (id)
);
CREATE TABLE historical_context (
	id INTEGER NOT NULL, 
	car_id INTEGER NOT NULL, 
	design_philosophy TEXT, 
	designer_name VARCHAR(100), 
	cultural_significance TEXT, 
	racing_pedigree TEXT, 
	innovations JSON, 
	direct_competitors JSON, 
	predecessor_id INTEGER, 
	successor_id INTEGER, 
	extra JSON, 
	PRIMARY KEY (id), 
	FOREIGN KEY(car_id) REFERENCES cars (id), 
	FOREIGN KEY(predecessor_id) REFERENCES cars (id), 
	FOREIGN KEY(successor_id) REFERENCES cars (id)
);
CREATE TABLE mod_potential (
	id INTEGER NOT NULL, 
	car_id INTEGER NOT NULL, 
	platform_limits JSON, 
	tuning_friendliness VARCHAR(50), 
	ecu_lock_status VARCHAR(50), 
	common_mods JSON, 
	aftermarket_depth VARCHAR(50), 
	known_gotchas JSON, 
	extra JSON, 
	PRIMARY KEY (id), 
	FOREIGN KEY(car_id) REFERENCES cars (id)
);
CREATE TABLE electronics (
	id INTEGER NOT NULL, 
	car_id INTEGER NOT NULL, 
	source VARCHAR(200), 
	ecu_type VARCHAR(100), 
	ecu_bitness INTEGER, 
	obd_generation VARCHAR(50), 
	flashable_ecu BOOLEAN NOT NULL, 
	ecu_open_source_support VARCHAR(50), 
	bus_topology VARCHAR(100), 
	can_bus_present BOOLEAN NOT NULL, 
	can_bus_generation VARCHAR(50), 
	can_bus_speed_kbps INTEGER, 
	can_bus_subnets INTEGER, 
	lin_bus_count INTEGER, 
	flexray_present BOOLEAN NOT NULL, 
	most_bus_present BOOLEAN NOT NULL, 
	ethernet_automotive BOOLEAN NOT NULL, 
	gateway_module_count INTEGER, 
	bus_diagrams_notes TEXT, 
	sensor_count_total INTEGER, 
	o2_sensors INTEGER, 
	knock_sensors INTEGER, 
	camshaft_sensors INTEGER, 
	crankshaft_sensors INTEGER, 
	map_sensors INTEGER, 
	maf_sensors INTEGER, 
	wheel_speed_sensors INTEGER, 
	steering_angle_sensor VARCHAR(50), 
	yaw_sensor BOOLEAN NOT NULL, 
	accelerometers INTEGER, 
	radar_sensors INTEGER, 
	lidar_sensors INTEGER, 
	ultrasonic_sensors INTEGER, 
	camera_sensors INTEGER, 
	rain_light_sensor BOOLEAN NOT NULL, 
	tpms_sensors INTEGER, 
	pressure_sensors INTEGER, 
	temperature_sensors INTEGER, 
	exhaust_sensors INTEGER, 
	extra_sensors JSON, 
	electronic_throttle BOOLEAN NOT NULL, 
	variable_valve_timing BOOLEAN NOT NULL, 
	variable_valve_lift BOOLEAN NOT NULL, 
	active_exhaust_valves BOOLEAN NOT NULL, 
	active_suspension BOOLEAN NOT NULL, 
	active_aero BOOLEAN NOT NULL, 
	electronic_diff BOOLEAN NOT NULL, 
	active_engine_mounts BOOLEAN NOT NULL, 
	active_grille_shutters BOOLEAN NOT NULL, 
	steer_by_wire BOOLEAN NOT NULL, 
	brake_by_wire BOOLEAN NOT NULL, 
	alternator_output_amps INTEGER, 
	alternator_type VARCHAR(50), 
	voltage_regulator VARCHAR(50), 
	battery_type_oe VARCHAR(50), 
	battery_capacity_ah FLOAT, 
	battery_location VARCHAR(50), 
	dual_battery_setup BOOLEAN NOT NULL, 
	dc_dc_converter_present BOOLEAN NOT NULL, 
	total_ecu_count INTEGER, 
	body_control_module VARCHAR(100), 
	transmission_tcu VARCHAR(100), 
	abs_module VARCHAR(100), 
	airbag_module VARCHAR(100), 
	instrument_cluster VARCHAR(100), 
	climate_control_module VARCHAR(100), 
	seat_control_modules INTEGER, 
	lighting_control VARCHAR(100), 
	module_interop_notes TEXT, 
	obd_connector_location VARCHAR(100), 
	diagnostic_protocol VARCHAR(50), 
	manufacturer_diag_tool VARCHAR(100), 
	can_bus_accessible BOOLEAN NOT NULL, 
	immobilizer_type VARCHAR(50), 
	key_programming TEXT, 
	security_gateway BOOLEAN NOT NULL, 
	capacitor_era VARCHAR(50), 
	capacitor_known_issues TEXT, 
	display_degradation TEXT, 
	wiring_harness_decay TEXT, 
	connector_corrosion TEXT, 
	pcb_conformal_coating BOOLEAN NOT NULL, 
	solder_whisker_risk BOOLEAN NOT NULL, 
	known_replacement_ecus JSON, 
	electronics_repairability VARCHAR(100), 
	extra JSON, 
	PRIMARY KEY (id), 
	FOREIGN KEY(car_id) REFERENCES cars (id)
);
CREATE TABLE data_sources (
	id INTEGER NOT NULL, 
	car_id INTEGER NOT NULL, 
	url VARCHAR(500), 
	site_name VARCHAR(100), 
	raw_text TEXT, 
	parsed_at DATETIME, 
	dimension VARCHAR(50), 
	PRIMARY KEY (id), 
	FOREIGN KEY(car_id) REFERENCES cars (id)
);
CREATE TABLE llm_analyses (
	id INTEGER NOT NULL, 
	car_id INTEGER NOT NULL, 
	dimension VARCHAR(50), 
	prompt_hash VARCHAR(64), 
	model_used VARCHAR(100), 
	generated_text TEXT, 
	scores JSON, 
	created_at DATETIME NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(car_id) REFERENCES cars (id)
);
CREATE TABLE powertrain_ice (
	id INTEGER NOT NULL, 
	car_id INTEGER NOT NULL, 
	source VARCHAR(200), 
	engine_layout VARCHAR(50), 
	displacement_cc FLOAT, 
	cylinders INTEGER, 
	aspiration VARCHAR(50), 
	horsepower_bhp FLOAT, 
	horsepower_rpm INTEGER, 
	torque_nm FLOAT, 
	torque_rpm INTEGER, 
	redline_rpm INTEGER, 
	compression_ratio FLOAT, 
	fuel_system VARCHAR(100), 
	transmission_type VARCHAR(50), 
	gear_count INTEGER, 
	drivetrain VARCHAR(50), 
	curb_weight_kg FLOAT, 
	weight_dist_pct VARCHAR(20), 
	suspension_fr VARCHAR(100), 
	brakes_fr VARCHAR(100), 
	drag_coefficient FLOAT, 
	is_hybrid BOOLEAN NOT NULL, 
	hybrid_system_id INTEGER, 
	ground_clearance_mm INTEGER, 
	cargo_volume_liters FLOAT, 
	extra JSON, power_kw FLOAT, specific_power_per_cylinder_w_cm2 FLOAT, bmep_bar FLOAT, mean_piston_speed_m_s FLOAT, engine_torque_nm FLOAT, fuel_consumption_mixed_l_100km FLOAT, fuel_consumption_sport_l_100km FLOAT, co2_emissions_g_km FLOAT, fuel_tank_capacity_l FLOAT, reserve_fuel_l FLOAT, top_speed_claimed_kmh FLOAT, power_reserve_pct FLOAT, engine_code VARCHAR(30), 
	PRIMARY KEY (id), 
	FOREIGN KEY(car_id) REFERENCES cars (id), 
	FOREIGN KEY(hybrid_system_id) REFERENCES hybrid_systems (id)
);
CREATE TABLE alembic_version (
	version_num VARCHAR(32) NOT NULL, 
	CONSTRAINT alembic_version_pkc PRIMARY KEY (version_num)
);
CREATE TABLE car_reviews (
	id INTEGER NOT NULL, 
	car_id INTEGER NOT NULL, 
	source_site VARCHAR(100), 
	rating_overall FLOAT, 
	rating_reliability FLOAT, 
	rating_performance FLOAT, 
	rating_comfort FLOAT, 
	rating_value FLOAT, 
	review_excerpt TEXT, 
	review_url VARCHAR(500), 
	reviewer_name VARCHAR(100), 
	review_date DATETIME, 
	extra JSON, 
	PRIMARY KEY (id), 
	FOREIGN KEY(car_id) REFERENCES cars (id)
);
CREATE TABLE dimensions (
	id INTEGER NOT NULL, 
	car_id INTEGER NOT NULL, 
	length_mm INTEGER, 
	width_mm INTEGER, 
	height_mm INTEGER, 
	wheelbase_mm INTEGER, 
	track_front_mm INTEGER, 
	track_rear_mm INTEGER, 
	front_overhang_mm INTEGER, 
	rear_overhang_mm INTEGER, 
	source VARCHAR(200), 
	extra JSON, 
	PRIMARY KEY (id), 
	FOREIGN KEY(car_id) REFERENCES cars (id), 
	UNIQUE (car_id)
);
CREATE TABLE ingest_sessions (
	id INTEGER NOT NULL, 
	car_id INTEGER, 
	raw_paste TEXT NOT NULL, 
	source_url VARCHAR(500), 
	source_site VARCHAR(100), 
	status VARCHAR(20) NOT NULL, 
	llm_model VARCHAR(50), 
	parsed_data JSON, 
	gaps_and_questions JSON, 
	agent_messages JSON, 
	final_car_data JSON, 
	created_at DATETIME NOT NULL, 
	updated_at DATETIME NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(car_id) REFERENCES cars (id)
);
CREATE TABLE performance_measurements (
	id INTEGER NOT NULL, 
	car_id INTEGER NOT NULL, 
	metric_name VARCHAR(50) NOT NULL, 
	value FLOAT NOT NULL, 
	unit VARCHAR(20) NOT NULL, 
	source_site VARCHAR(100), 
	test_date DATETIME, 
	sample_size INTEGER, 
	conditions VARCHAR(200), 
	notes TEXT, 
	extra JSON, 
	PRIMARY KEY (id), 
	FOREIGN KEY(car_id) REFERENCES cars (id)
);
CREATE TABLE zeperfs_indices (
	id INTEGER NOT NULL, 
	car_id INTEGER NOT NULL, 
	zeperfs_index FLOAT, 
	sportivity_index FLOAT, 
	perfs_prix_ratio FLOAT, 
	source VARCHAR(100), 
	recorded_date DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(car_id) REFERENCES cars (id), 
	UNIQUE (car_id)
);
CREATE TABLE agent_tool_calls (
	id INTEGER NOT NULL, 
	session_id INTEGER, 
	tool_name VARCHAR(100) NOT NULL, 
	arguments JSON, 
	result JSON, 
	status VARCHAR(20) NOT NULL, 
	error_message TEXT, 
	duration_ms INTEGER, 
	created_at DATETIME NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(session_id) REFERENCES ingest_sessions (id)
);
CREATE TABLE build_quality (
	id INTEGER NOT NULL, 
	car_id INTEGER NOT NULL, 
	q_score FLOAT, 
	score_body_construction FLOAT, 
	score_nvh_isolation FLOAT, 
	score_interior_materials FLOAT, 
	score_paint_corrosion FLOAT, 
	score_electrical_aging FLOAT, 
	score_cosmetic_aging FLOAT, 
	body_construction_notes TEXT, 
	nvh_isolation_notes TEXT, 
	interior_materials_notes TEXT, 
	paint_corrosion_notes TEXT, 
	electrical_aging_notes TEXT, 
	cosmetic_aging_notes TEXT, 
	q_score_notes TEXT, 
	platform_type VARCHAR(50), 
	assembly_plant VARCHAR(100), 
	weld_technology VARCHAR(50), 
	panel_gap_mm FLOAT, 
	engine_mount_type VARCHAR(50), 
	glass_type VARCHAR(100), 
	leather_grade VARCHAR(50), 
	wood_type VARCHAR(50), 
	paint_stages INTEGER, 
	sound_deadening_rating VARCHAR(50), 
	source VARCHAR(200), 
	extra JSON, 
	PRIMARY KEY (id), 
	FOREIGN KEY(car_id) REFERENCES cars (id), 
	UNIQUE (car_id)
);
CREATE TABLE failure_points (
    id INTEGER PRIMARY KEY,
    car_id INTEGER NOT NULL REFERENCES cars(id),
    failure_name VARCHAR(100) NOT NULL,
    component VARCHAR(50) NOT NULL DEFAULT 'engine',  -- engine, transmission, chassis, electronics, suspension, body
    severity INTEGER NOT NULL DEFAULT 3,  -- 1=cosmetic, 2=nuisance, 3=moderate, 4=major, 5=catastrophic
    typical_mileage_mi INTEGER,           -- approximate mileage when failure occurs
    repair_cost_low FLOAT,                -- USD
    repair_cost_high FLOAT,               -- USD
    is_preventive BOOLEAN DEFAULT 0,      -- can this failure be prevented?
    prevention_cost FLOAT,               -- cost of prevention (USD)
    prevention_desc TEXT,                 -- how to prevent
    description TEXT,                     -- detailed failure description
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE INDEX idx_fp_car ON failure_points(car_id);
CREATE INDEX idx_fp_component ON failure_points(component);
CREATE INDEX idx_fp_severity ON failure_points(severity);
CREATE INDEX idx_fp_preventive ON failure_points(is_preventive);
COMMIT;
